#[derive(Debug, Parser)]
#[command(name = "wfb-radio-diag")]
#[command(about = "Diagnostics for native macOS WFB USB radio bring-up")]
struct Cli {
    /// Emit JSON. Human output is the default.
    #[arg(long, global = true)]
    json: bool,

    /// Include unsupported USB devices in reports.
    #[arg(long, global = true)]
    all: bool,

    /// Write the command's JSON report to a file.
    #[arg(long, global = true, value_name = "PATH")]
    report: Option<PathBuf>,

    #[command(subcommand)]
    command: Command,
}

#[derive(Debug, Subcommand)]
enum Command {
    /// Probe USB adapters and optionally claim/release a selected candidate.
    UsbProbe(UsbProbeArgs),
    /// Inspect macOS IOKit USB state, including devices libusb cannot enumerate.
    MacosUsbState(MacosUsbStateArgs),
    /// Read USB descriptors through macOS IOUSBHost default-control transfers.
    MacosDescriptorSmoke(MacosDescriptorSmokeArgs),
    /// Configure and probe IOUSBHost interface and pipe objects without submitting bulk traffic.
    MacosInterfaceSmoke(MacosInterfaceSmokeArgs),
    /// Configure IOUSBHost interface and issue one bounded bulk-IN read request.
    MacosBulkInSmoke(MacosBulkInSmokeArgs),
    /// Configure IOUSBHost interface and issue one zero-length bulk-OUT request.
    MacosBulkOutSmoke(MacosBulkOutSmokeArgs),
    /// Open a retained IOUSBHost interface session and exercise control plus bulk pipes.
    MacosSessionSmoke(MacosSessionSmokeArgs),
    /// Read RTL8812AU registers through macOS IOUSBHost direct control transfers.
    MacosRegSmoke(RegSmokeArgs),
    /// Dump RTL8812AU EFUSE through macOS IOUSBHost direct control transfers.
    MacosEfuseDump(EfuseDumpArgs),
    /// Run guarded RTL8812AU power-on writes through macOS IOUSBHost direct control transfers.
    MacosPowerOnSmoke(PowerOnSmokeArgs),
    /// Program RTL8812A LLT entries through macOS IOUSBHost direct control transfers.
    MacosLltSmoke(LltSmokeArgs),
    /// Download RTL8812A firmware through macOS IOUSBHost direct control transfers.
    MacosFirmwareSmoke(FirmwareSmokeArgs),
    /// Program RTL8812A queue/DMA registers through macOS IOUSBHost direct control transfers.
    MacosQueueDmaSmoke(MacosQueueDmaSmokeArgs),
    /// Program RTL8812A MAC/WMAC registers through macOS IOUSBHost direct control transfers.
    MacosMacSmoke(MacSmokeArgs),
    /// Program RTL8812A BB PHY/AGC tables through macOS IOUSBHost direct control transfers.
    MacosBbSmoke(BbSmokeArgs),
    /// Program RTL8812A RF radioA/radioB tables through macOS IOUSBHost direct control transfers.
    MacosRfSmoke(RfSmokeArgs),
    /// Claim a supported adapter and perform read-only RTL8812AU register reads.
    RegSmoke(RegSmokeArgs),
    /// Dump RTL8812AU EFUSE physical bytes and decoded logical map.
    EfuseDump(EfuseDumpArgs),
    /// Drive RTL8812AU LEDCFG software LED pins with guarded register writes.
    LedSmoke(LedSmokeArgs),
    /// Run the first guarded RTL8812AU power-on/RF-reset register writes.
    PowerOnSmoke(PowerOnSmokeArgs),
    /// Download RTL8812A firmware and poll checksum/readiness with guarded writes.
    FirmwareSmoke(FirmwareSmokeArgs),
    /// Extract an RTL8812A firmware image from a Realtek driver C array.
    ExtractFirmware(ExtractFirmwareArgs),
    /// Program the RTL8812A LLT table with guarded writes and per-entry polling.
    LltSmoke(LltSmokeArgs),
    /// Program RTL8812A queue and DMA boundary registers with guarded writes.
    QueueDmaSmoke(QueueDmaSmokeArgs),
    /// Program RTL8812A MAC/WMAC registers with guarded writes.
    MacSmoke(MacSmokeArgs),
    /// Program RTL8812A BB PHY/AGC tables with guarded writes.
    BbSmoke(BbSmokeArgs),
    /// Program RTL8812A RF radioA/radioB tables with guarded writes.
    RfSmoke(RfSmokeArgs),
    /// Run integrated RTL8812AU live init diagnostics.
    Init(InitArgs),
    /// Run standalone RTL8812AU IQK evidence collection without WFB or TX traffic.
    Rtl8812aIqkDiagnostic(Rtl8812aIqkDiagnosticArgs),
    /// Run bounded live RX capture diagnostics.
    RxScan(RxScanArgs),
    /// Transmit one validated test frame over bulk OUT.
    TxOnce(TxOnceArgs),
    /// Placeholder for repeated TX diagnostics with explicit operator gating.
    TxRepeat(TxRepeatArgs),
    /// Submit one WFB distributor-style datagram through the live radio TX bridge path.
    BridgeTxOnce(BridgeTxOnceArgs),
    /// Listen for WFB distributor-style datagrams and submit them through live radio TX.
    BridgeTxListen(BridgeTxListenArgs),
    /// Run bounded WFB RX forwarding and TX injection in one retained radio session.
    BridgeRun(BridgeRunArgs),
    /// Run the production WFB radio runtime without diagnostic register experiments.
    RadioRun(RadioRunArgs),
    /// Run the production-facing WFB runtime flow with runtime-shaped telemetry.
    RuntimeFlow(RuntimeFlowArgs),
    /// Generate WFB distributor-style datagrams and submit a bounded TX throughput burst.
    BridgeTxBench(BridgeTxBenchArgs),
    /// Build a structured RF-quality report from macOS and optional Linux baseline artifacts.
    RfQualityReport(RfQualityReportArgs),
    /// Compare normalized USB trace event sequences.
    TraceCompare(TraceCompareArgs),
    /// Import Linux usbmon text into normalized USB trace JSON.
    TraceImport(TraceImportArgs),
    /// Summarize RTL8812AU vendor register writes from Linux usbmon text.
    TraceRegisters(TraceRegistersArgs),
    /// List staged verification commands and their prerequisites.
    Stages,
}

