#[derive(Debug, Serialize)]
struct PlatformInfo {
    os: &'static str,
    family: &'static str,
    arch: &'static str,
}

#[derive(Debug, Clone, Copy, Serialize, PartialEq, Eq)]
#[serde(rename_all = "snake_case")]
enum DiagnosticResult {
    Pass,
    Fail,
    NotImplemented,
}

impl DiagnosticResult {
    fn as_str(self) -> &'static str {
        match self {
            DiagnosticResult::Pass => "pass",
            DiagnosticResult::Fail => "fail",
            DiagnosticResult::NotImplemented => "not_implemented",
        }
    }

    fn exit_code(self) -> Option<i32> {
        match self {
            DiagnosticResult::Pass => None,
            DiagnosticResult::Fail => Some(1),
            DiagnosticResult::NotImplemented => Some(2),
        }
    }
}

#[derive(Debug, Serialize)]
struct DiagnosticPhase {
    id: &'static str,
    status: DiagnosticPhaseStatus,
    detail: &'static str,
}

#[derive(Debug, Clone, Copy, Serialize)]
#[serde(rename_all = "snake_case")]
enum DiagnosticPhaseStatus {
    Completed,
    Pending,
    Blocked,
}

#[derive(Debug, Default, Clone, Copy, Serialize)]
struct DiagnosticCounters {
    usb_control_reads: u64,
    usb_control_writes: u64,
    usb_bulk_in_reads: u64,
    usb_bulk_out_writes: u64,
    rx_frames: u64,
    tx_frames: u64,
    dropped_frames: u64,
}

#[derive(Debug, Serialize)]
struct DiagnosticErrorReport {
    code: &'static str,
    message: String,
}

fn runtime_radio_counters_from_diagnostic(counters: DiagnosticCounters) -> RuntimeRadioCounters {
    RuntimeRadioCounters {
        usb_control_reads: counters.usb_control_reads,
        usb_control_writes: counters.usb_control_writes,
        usb_bulk_in_reads: counters.usb_bulk_in_reads,
        usb_bulk_out_writes: counters.usb_bulk_out_writes,
        rx_frames: counters.rx_frames,
        tx_frames: counters.tx_frames,
        dropped_frames: counters.dropped_frames,
    }
}

fn diagnostic_counters_from_runtime(counters: RuntimeRadioCounters) -> DiagnosticCounters {
    DiagnosticCounters {
        usb_control_reads: counters.usb_control_reads,
        usb_control_writes: counters.usb_control_writes,
        usb_bulk_in_reads: counters.usb_bulk_in_reads,
        usb_bulk_out_writes: counters.usb_bulk_out_writes,
        rx_frames: counters.rx_frames,
        tx_frames: counters.tx_frames,
        dropped_frames: counters.dropped_frames,
    }
}

fn runtime_radio_error(error: RuntimeRadioError) -> DiagnosticErrorReport {
    DiagnosticErrorReport {
        code: error.code,
        message: error.message,
    }
}

fn runtime_radio_error_from_diagnostic(error: &DiagnosticErrorReport) -> RuntimeRadioError {
    RuntimeRadioError::new(error.code, error.message.clone())
}

fn diagnostic_phase_status_from_runtime(
    status: RuntimeSameSessionInitPhaseStatus,
) -> DiagnosticPhaseStatus {
    match status {
        RuntimeSameSessionInitPhaseStatus::Completed => DiagnosticPhaseStatus::Completed,
        RuntimeSameSessionInitPhaseStatus::Blocked => DiagnosticPhaseStatus::Blocked,
    }
}

fn init_live_phase_summary_from_runtime(
    summary: RuntimeSameSessionInitPhaseSummary,
) -> InitLivePhaseSummary {
    InitLivePhaseSummary {
        id: summary.phase.id(),
        status: diagnostic_phase_status_from_runtime(summary.status),
        detail: summary.detail,
        usb_control_reads: summary.counters.usb_control_reads,
        usb_control_writes: summary.counters.usb_control_writes,
    }
}

fn runtime_same_session_phase_completed(
    phase: Rtl8812auInitPhase,
    detail: impl Into<String>,
    before: DiagnosticCounters,
    after: DiagnosticCounters,
) -> RuntimeSameSessionInitPhaseSummary {
    RuntimeSameSessionInitPhaseSummary::completed(
        phase,
        detail,
        runtime_radio_counters_from_diagnostic(before),
        runtime_radio_counters_from_diagnostic(after),
    )
}

fn runtime_same_session_phase_completed_with_writes(
    phase: Rtl8812auInitPhase,
    detail: impl Into<String>,
    register_writes: usize,
    before: DiagnosticCounters,
    after: DiagnosticCounters,
) -> RuntimeSameSessionInitPhaseSummary {
    RuntimeSameSessionInitPhaseSummary::completed_with_writes(
        phase,
        detail,
        register_writes,
        runtime_radio_counters_from_diagnostic(before),
        runtime_radio_counters_from_diagnostic(after),
    )
}

fn runtime_same_session_phase_failure(
    phase: Rtl8812auInitPhase,
    detail: impl Into<String>,
    before: DiagnosticCounters,
    after: DiagnosticCounters,
    error: &DiagnosticErrorReport,
) -> RuntimeSameSessionInitPhaseFailure {
    RuntimeSameSessionInitPhaseFailure::new(
        RuntimeSameSessionInitPhaseSummary::blocked(
            phase,
            detail,
            runtime_radio_counters_from_diagnostic(before),
            runtime_radio_counters_from_diagnostic(after),
        ),
        runtime_radio_error_from_diagnostic(error),
    )
}

