fn tx_status_probe_report(args: &TxStatusProbeArgs) -> Option<TxStatusProbeReport> {
    tx_status_enabled(args).then(|| {
        let (registers, error) = tx_status_register_requests(args);
        TxStatusProbeReport {
            enabled: true,
            delay_ms: args.tx_status_delay_ms,
            poll_ms: args.tx_status_poll_ms,
            poll_count: args.tx_status_poll_count,
            register_count: registers.len(),
            register_source_paths: args.tx_status_registers_from.clone(),
            semantics: "read-only RTL8812AU register deltas around USB TX submission; this does not prove RF radiation",
            pre: Vec::new(),
            post: Vec::new(),
            samples: Vec::new(),
            changed: Vec::new(),
            trace_comparison: None,
            rf_summary: None,
            counters: DiagnosticCounters::default(),
            error,
            registers,
        }
    })
}

fn tx_status_enabled(args: &TxStatusProbeArgs) -> bool {
    args.tx_status || !args.tx_status_registers_from.is_empty()
}

fn tx_status_register_requests(
    args: &TxStatusProbeArgs,
) -> (Vec<TxStatusRegisterRequest>, Option<DiagnosticErrorReport>) {
    let mut requests = TX_STATUS_REGISTERS
        .iter()
        .copied()
        .map(TxStatusRegisterRequest::from)
        .collect::<Vec<_>>();

    for path in &args.tx_status_registers_from {
        let input = match fs::read_to_string(path) {
            Ok(input) => input,
            Err(error) => {
                return (
                    requests,
                    Some(DiagnosticErrorReport {
                        code: "tx_status_register_source_read_failed",
                        message: format!("read {}: {error}", path.display()),
                    }),
                );
            }
        };
        let final_writes = match parse_trace_register_final_writes_json(&input) {
            Ok(final_writes) => final_writes,
            Err(error) => {
                return (
                    requests,
                    Some(DiagnosticErrorReport {
                        code: "tx_status_register_source_parse_failed",
                        message: format!("parse {}: {error}", path.display()),
                    }),
                );
            }
        };
        for final_write in final_writes {
            let Some(width) = tx_status_width_from_trace_width(final_write.width) else {
                continue;
            };
            let expected = match tx_status_expected_from_trace(path, &final_write, width) {
                Ok(expected) => expected,
                Err(error) => {
                    return (
                        requests,
                        Some(DiagnosticErrorReport {
                            code: "tx_status_register_source_value_failed",
                            message: format!("parse {}: {error}", path.display()),
                        }),
                    );
                }
            };
            if let Some(request) = requests
                .iter_mut()
                .find(|request| request.address == final_write.address && request.width == width)
            {
                request.expected = Some(expected);
                continue;
            }
            requests.push(TxStatusRegisterRequest {
                name: format!("TRACE_{}", final_write.address_hex),
                address: final_write.address,
                width,
                expected: Some(expected),
            });
        }
    }

    (requests, None)
}

fn tx_status_expected_from_trace(
    source_path: &Path,
    final_write: &TraceRegisterFinalWriteReport,
    width: TxStatusRegisterWidth,
) -> std::result::Result<TxStatusRegisterExpected, String> {
    let value = parse_trace_value_hex(&final_write.value_le_hex)?;
    Ok(TxStatusRegisterExpected {
        source_path: source_path.to_path_buf(),
        value,
        value_hex: format_value(value, width.hex_digits()),
        data_hex: final_write.data_hex.clone(),
        write_count: final_write.write_count,
        last_event_index: final_write.last_event_index,
    })
}

fn parse_trace_value_hex(input: &str) -> std::result::Result<u32, String> {
    let stripped = input
        .strip_prefix("0x")
        .or_else(|| input.strip_prefix("0X"))
        .unwrap_or(input);
    u32::from_str_radix(stripped, 16)
        .map_err(|error| format!("invalid trace value {input}: {error}"))
}

fn parse_trace_register_final_writes_json(
    input: &str,
) -> std::result::Result<Vec<TraceRegisterFinalWriteReport>, serde_json::Error> {
    #[derive(Deserialize)]
    struct TraceRegisterFinalWriteEnvelope {
        final_writes: Vec<TraceRegisterFinalWriteReport>,
    }

    serde_json::from_str::<Vec<TraceRegisterFinalWriteReport>>(input).or_else(|_| {
        serde_json::from_str::<TraceRegisterFinalWriteEnvelope>(input)
            .map(|report| report.final_writes)
    })
}

fn tx_status_width_from_trace_width(width: usize) -> Option<TxStatusRegisterWidth> {
    match width {
        1 => Some(TxStatusRegisterWidth::U8),
        2 => Some(TxStatusRegisterWidth::U16),
        4 => Some(TxStatusRegisterWidth::U32),
        _ => None,
    }
}

fn tx_status_total_poll_ms(args: &TxStatusProbeArgs) -> u64 {
    args.tx_status_poll_ms
        .saturating_mul(u64::from(args.tx_status_poll_count))
}

fn tx_status_probe_pre<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    report: &mut Option<TxStatusProbeReport>,
) where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    if let Some(report) = report.as_mut() {
        if report.error.is_some() {
            return;
        }
        match tx_status_snapshot(registers, &report.registers, &mut report.counters) {
            Ok(snapshot) => report.pre = snapshot,
            Err(error) => report.error = Some(error),
        }
    }
}

fn tx_status_probe_post<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    report: &mut Option<TxStatusProbeReport>,
) where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    if let Some(report) = report.as_mut() {
        if report.error.is_some() {
            return;
        }
        if report.delay_ms > 0 {
            std::thread::sleep(Duration::from_millis(report.delay_ms));
        }
        match tx_status_snapshot(registers, &report.registers, &mut report.counters) {
            Ok(snapshot) => {
                report.changed = tx_status_deltas(&report.pre, &snapshot);
                report.post = snapshot.clone();
                let mut previous = snapshot;
                for index in 0..report.poll_count {
                    if report.poll_ms > 0 {
                        std::thread::sleep(Duration::from_millis(report.poll_ms));
                    }
                    match tx_status_snapshot(registers, &report.registers, &mut report.counters) {
                        Ok(sample) => {
                            let changed_from_previous = tx_status_deltas(&previous, &sample);
                            previous = sample.clone();
                            report.samples.push(TxStatusSampleReport {
                                label: format!("poll_{}", index + 1),
                                sleep_before_ms: report.poll_ms,
                                registers: sample,
                                changed_from_previous,
                            });
                        }
                        Err(error) => {
                            report.error = Some(error);
                            break;
                        }
                    }
                }
                report.trace_comparison =
                    tx_status_trace_comparison(&report.registers, &report.pre, &report.post);
            }
            Err(error) => report.error = Some(error),
        }
    }
}

fn tx_status_attach_rf_summary(
    report: &mut Option<TxStatusProbeReport>,
    submit_counters: &TxSubmitCounters,
) {
    if let Some(report) = report.as_mut() {
        report.rf_summary = Some(tx_status_rf_summary(report, submit_counters));
    }
}

fn tx_status_rf_summary(
    report: &TxStatusProbeReport,
    submit_counters: &TxSubmitCounters,
) -> TxStatusRfSummaryReport {
    let activity_registers = report
        .changed
        .iter()
        .filter(|delta| tx_status_rf_activity_register(delta.address))
        .map(|delta| delta.name.clone())
        .collect::<Vec<_>>();
    let queue_activity_registers = report
        .changed
        .iter()
        .filter(|delta| tx_status_queue_activity_register(delta.address))
        .map(|delta| delta.name.clone())
        .collect::<Vec<_>>();
    let scheduler_activity_registers = report
        .changed
        .iter()
        .filter(|delta| tx_status_scheduler_activity_register(delta.address))
        .map(|delta| delta.name.clone())
        .collect::<Vec<_>>();
    let txdma_status = report
        .post
        .iter()
        .find(|register| register.address == REG_TXDMA_STATUS && register.width == "u32")
        .cloned();
    let txdma_status_nonzero = txdma_status
        .as_ref()
        .is_some_and(|status| status.value != 0);
    let chip_activity = !activity_registers.is_empty();
    let interpretation = if report.error.is_some() {
        "status_probe_error"
    } else if submit_counters.submitted == 0 {
        "no_usb_submission"
    } else if chip_activity && txdma_status_nonzero {
        "usb_submitted_chip_activity_with_txdma_status"
    } else if chip_activity {
        "usb_submitted_chip_activity"
    } else {
        "usb_submitted_no_tracked_chip_activity"
    };

    TxStatusRfSummaryReport {
        semantics: "RF-aware summary of USB submission and tracked chip-side TX register movement; independent receiver capture is still required for RF confirmation",
        usb_submitted: submit_counters.submitted,
        usb_failed: submit_counters.failed,
        usb_short_writes: submit_counters.short_writes,
        chip_activity,
        activity_registers,
        queue_activity_registers,
        scheduler_activity_registers,
        txdma_status,
        txdma_status_nonzero,
        rf_confirmation: "not_measured_by_this_command",
        interpretation,
    }
}

fn tx_status_rf_activity_register(address: u16) -> bool {
    tx_status_queue_activity_register(address) || tx_status_scheduler_activity_register(address)
}

fn tx_status_queue_activity_register(address: u16) -> bool {
    matches!(
        address,
        REG_Q0_INFO
            | REG_Q1_INFO
            | REG_Q2_INFO
            | REG_Q3_INFO
            | REG_MGQ_INFO
            | REG_CPU_MGQ_INFORMATION
            | REG_HGQ_INFO
            | REG_BCNQ_INFO
            | REG_TXPKT_EMPTY
    )
}

fn tx_status_scheduler_activity_register(address: u16) -> bool {
    matches!(
        address,
        REG_TDECTRL
            | REG_TXDMA_STATUS
            | REG_TXDMA_OFFSET_CHK
            | REG_TRXDMA_CTRL
            | REG_FWHW_TXQ_CTRL
            | REG_TXPAUSE
            | REG_SCH_TX_CMD
    )
}

fn add_tx_status_probe_counters(
    total: &mut DiagnosticCounters,
    report: &Option<TxStatusProbeReport>,
) {
    if let Some(report) = report {
        add_diagnostic_counters(total, &report.counters);
    }
}

fn tx_status_snapshot<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    specs: &[TxStatusRegisterRequest],
    counters: &mut DiagnosticCounters,
) -> std::result::Result<Vec<TxStatusRegisterReport>, DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    specs
        .iter()
        .map(|spec| tx_status_read_register(registers, counters, spec))
        .collect()
}

fn tx_status_read_register<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    spec: &TxStatusRegisterRequest,
) -> std::result::Result<TxStatusRegisterReport, DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let value = match spec.width {
        TxStatusRegisterWidth::U8 => u32::from(
            read8_with_counter(registers, counters, spec.address)
                .map_err(|error| tx_status_read_error(spec, error))?,
        ),
        TxStatusRegisterWidth::U16 => u32::from(
            read16_with_counter(registers, counters, spec.address)
                .map_err(|error| tx_status_read_error(spec, error))?,
        ),
        TxStatusRegisterWidth::U32 => read32_with_counter(registers, counters, spec.address)
            .map_err(|error| tx_status_read_error(spec, error))?,
    };
    Ok(TxStatusRegisterReport {
        name: spec.name.clone(),
        address: spec.address,
        address_hex: format_address(spec.address),
        width: spec.width.label(),
        value,
        value_hex: format_value(value, spec.width.hex_digits()),
    })
}

fn tx_status_read_error(
    spec: &TxStatusRegisterRequest,
    error: radio_core::Rtl8812auRegisterError,
) -> DiagnosticErrorReport {
    DiagnosticErrorReport {
        code: "tx_status_read_failed",
        message: format!(
            "{} read at {} failed: {error}",
            spec.name,
            format_address(spec.address)
        ),
    }
}

fn tx_status_deltas(
    pre: &[TxStatusRegisterReport],
    post: &[TxStatusRegisterReport],
) -> Vec<TxStatusDeltaReport> {
    pre.iter()
        .zip(post.iter())
        .filter(|(before, after)| before.value != after.value)
        .map(|(before, after)| TxStatusDeltaReport {
            name: before.name.clone(),
            address: before.address,
            address_hex: before.address_hex.clone(),
            width: before.width,
            before_hex: before.value_hex.clone(),
            after_hex: after.value_hex.clone(),
            xor_hex: format_value(
                before.value ^ after.value,
                tx_status_width_digits(before.width),
            ),
        })
        .collect()
}

fn tx_status_trace_comparison(
    requests: &[TxStatusRegisterRequest],
    pre: &[TxStatusRegisterReport],
    post: &[TxStatusRegisterReport],
) -> Option<TxStatusTraceComparisonReport> {
    let expected_register_count = requests
        .iter()
        .filter(|request| request.expected.is_some())
        .count();
    if expected_register_count == 0 {
        return None;
    }
    let pre_mismatches = tx_status_trace_mismatches(requests, pre);
    let post_mismatches = tx_status_trace_mismatches(requests, post);
    Some(TxStatusTraceComparisonReport {
        semantics: "compares sampled Mac register values to Linux trace-register final writes at matching address and width; adapter-specific and volatile registers can legitimately differ",
        expected_register_count,
        pre_mismatch_count: pre_mismatches.len(),
        post_mismatch_count: post_mismatches.len(),
        pre_mismatches,
        post_mismatches,
    })
}

fn tx_status_trace_mismatches(
    requests: &[TxStatusRegisterRequest],
    observed: &[TxStatusRegisterReport],
) -> Vec<TxStatusTraceMismatchReport> {
    requests
        .iter()
        .zip(observed.iter())
        .filter_map(|(request, observed)| {
            let expected = request.expected.as_ref()?;
            (expected.value != observed.value).then(|| TxStatusTraceMismatchReport {
                name: observed.name.clone(),
                address: observed.address,
                address_hex: observed.address_hex.clone(),
                width: observed.width,
                source_path: expected.source_path.clone(),
                expected_hex: expected.value_hex.clone(),
                observed_hex: observed.value_hex.clone(),
                xor_hex: format_value(
                    expected.value ^ observed.value,
                    tx_status_width_digits(observed.width),
                ),
                trace_data_hex: expected.data_hex.clone(),
                trace_write_count: expected.write_count,
                trace_last_event_index: expected.last_event_index,
            })
        })
        .collect()
}

fn tx_status_width_digits(width: &str) -> usize {
    match width {
        "u8" => 2,
        "u16" => 4,
        _ => 8,
    }
}

fn select_supported_adapter(
    selector: DeviceSelector,
) -> std::result::Result<UsbDeviceInfo, DiagnosticErrorReport> {
    wfb_radio_runtime::select_libusb_supported_adapter(selector).map_err(runtime_transport_error)
}

fn read_smoke_register<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    spec: RegisterSmokeSpec,
) -> std::result::Result<RegisterReadReport, radio_core::Rtl8812auRegisterError>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let (value, bytes) = match spec.width {
        RegisterSmokeWidth::U8 => {
            let value = registers.read8(spec.address)?;
            (u64::from(value), vec![value])
        }
        RegisterSmokeWidth::U16 => {
            let value = registers.read16(spec.address)?;
            (u64::from(value), value.to_le_bytes().to_vec())
        }
        RegisterSmokeWidth::U32 => {
            let value = registers.read32(spec.address)?;
            (u64::from(value), value.to_le_bytes().to_vec())
        }
    };

    Ok(RegisterReadReport {
        name: spec.name,
        address: spec.address,
        address_hex: format!("0x{:04x}", spec.address),
        width: spec.width.label(),
        value,
        value_hex: format!("0x{:0width$x}", value, width = spec.width.value_digits()),
        bytes_le_hex: encode_hex(&bytes),
    })
}

fn power_on_smoke_report(args: PowerOnSmokeArgs) -> PowerOnSmokeReport {
    let selector = args.adapter.selector();
    let mut steps = Vec::new();
    let mut counters = DiagnosticCounters::default();

    if !args.i_understand_this_writes_registers {
        return power_on_smoke_failure_with_command(
            "power-on-smoke",
            &args,
            None,
            None,
            steps,
            counters,
            DiagnosticErrorReport {
                code: "missing_write_authorization",
                message: "power-on smoke writes hardware registers and requires --i-understand-this-writes-registers".to_string(),
            },
        );
    }

    let selected = match select_supported_adapter(selector) {
        Ok(device) => device,
        Err(error) => {
            return power_on_smoke_failure(&args, None, None, steps, counters, error);
        }
    };

    let claimed = match radio_core::usb::claim_usb_device(&selected) {
        Ok(claimed) => claimed,
        Err(error) => {
            return power_on_smoke_failure(
                &args,
                Some(selected),
                None,
                steps,
                counters,
                DiagnosticErrorReport {
                    code: "usb_claim_failed",
                    message: error.to_string(),
                },
            );
        }
    };

    let adapter = claimed.info.clone();
    let endpoints = claimed.endpoints.clone();
    let registers =
        Rtl8812auRegisterAccess::new(&claimed).with_timeout(Duration::from_millis(args.timeout_ms));

    if let Err(error) = run_power_on_sequence(&registers, &args, &mut counters, &mut steps) {
        return power_on_smoke_failure(
            &args,
            Some(adapter),
            Some(endpoints),
            steps,
            counters,
            error,
        );
    }

    PowerOnSmokeReport {
        schema_version: 1,
        command: "power-on-smoke",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        timeout_ms: args.timeout_ms,
        poll_attempts: args.poll_attempts,
        poll_delay_us: args.poll_delay_us,
        result: DiagnosticResult::Pass,
        adapter: Some(adapter),
        endpoints: Some(endpoints),
        steps,
        counters,
        error: None,
        notes: vec![
            "guarded hardware write test: power-on/RF-reset registers were written",
            "no firmware download, bulk traffic, channel tuning, or TX operation was issued",
        ],
    }
}

fn macos_power_on_smoke_report(args: PowerOnSmokeArgs) -> PowerOnSmokeReport {
    let selector = args.adapter.selector();
    let mut steps = Vec::new();
    let mut counters = DiagnosticCounters::default();

    if !args.i_understand_this_writes_registers {
        return power_on_smoke_failure_with_command(
            "macos-power-on-smoke",
            &args,
            None,
            None,
            steps,
            counters,
            DiagnosticErrorReport {
                code: "missing_write_authorization",
                message: "macOS IOUSBHost power-on smoke writes hardware registers and requires --i-understand-this-writes-registers".to_string(),
            },
        );
    }

    #[cfg(not(target_os = "macos"))]
    {
        return power_on_smoke_failure_with_command(
            "macos-power-on-smoke",
            &args,
            None,
            None,
            steps,
            counters,
            DiagnosticErrorReport {
                code: "unsupported_platform",
                message: "macos-power-on-smoke requires macOS IOUSBHost".to_string(),
            },
        );
    }

    #[cfg(target_os = "macos")]
    {
        let Some(vid) = selector.vid else {
            return power_on_smoke_failure_with_command(
                "macos-power-on-smoke",
                &args,
                None,
                None,
                steps,
                counters,
                DiagnosticErrorReport {
                    code: "missing_vid",
                    message: "macos-power-on-smoke requires --vid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };
        let Some(pid) = selector.pid else {
            return power_on_smoke_failure_with_command(
                "macos-power-on-smoke",
                &args,
                None,
                None,
                steps,
                counters,
                DiagnosticErrorReport {
                    code: "missing_pid",
                    message: "macos-power-on-smoke requires --pid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };

        let device = match macos_usbhost::MacosUsbHostDevice::open(vid, pid) {
            Ok(device) => device,
            Err(error) => {
                return power_on_smoke_failure_with_command(
                    "macos-power-on-smoke",
                    &args,
                    None,
                    None,
                    steps,
                    counters,
                    DiagnosticErrorReport {
                        code: "macos_usbhost_open_failed",
                        message: error,
                    },
                );
            }
        };

        let registers = Rtl8812auRegisterAccess::new(&device)
            .with_timeout(Duration::from_millis(args.timeout_ms));
        if let Err(error) = run_power_on_sequence(&registers, &args, &mut counters, &mut steps) {
            return power_on_smoke_failure_with_command(
                "macos-power-on-smoke",
                &args,
                None,
                None,
                steps,
                counters,
                error,
            );
        }

        PowerOnSmokeReport {
            schema_version: 1,
            command: "macos-power-on-smoke",
            started_at_unix_ms: started_at_unix_ms(),
            platform: platform_info(),
            selector,
            timeout_ms: args.timeout_ms,
            poll_attempts: args.poll_attempts,
            poll_delay_us: args.poll_delay_us,
            result: DiagnosticResult::Pass,
            adapter: None,
            endpoints: None,
            steps,
            counters,
            error: None,
            notes: vec![
                "macOS IOUSBHost guarded hardware write test: power-on/RF-reset registers were written through default-control transfers",
                "no libusb enumeration, USB interface claim, firmware download, bulk traffic, channel tuning, or TX operation was issued",
            ],
        }
    }
}

fn power_on_smoke_failure(
    args: &PowerOnSmokeArgs,
    adapter: Option<UsbDeviceInfo>,
    endpoints: Option<UsbEndpoints>,
    steps: Vec<PowerOnStepReport>,
    counters: DiagnosticCounters,
    error: DiagnosticErrorReport,
) -> PowerOnSmokeReport {
    power_on_smoke_failure_with_command(
        "power-on-smoke",
        args,
        adapter,
        endpoints,
        steps,
        counters,
        error,
    )
}

fn power_on_smoke_failure_with_command(
    command: &'static str,
    args: &PowerOnSmokeArgs,
    adapter: Option<UsbDeviceInfo>,
    endpoints: Option<UsbEndpoints>,
    steps: Vec<PowerOnStepReport>,
    counters: DiagnosticCounters,
    error: DiagnosticErrorReport,
) -> PowerOnSmokeReport {
    PowerOnSmokeReport {
        schema_version: 1,
        command,
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector: args.adapter.selector(),
        timeout_ms: args.timeout_ms,
        poll_attempts: args.poll_attempts,
        poll_delay_us: args.poll_delay_us,
        result: DiagnosticResult::Fail,
        adapter,
        endpoints,
        steps,
        counters,
        error: Some(error),
        notes: vec![
            "guarded hardware write test aborted before firmware download, bulk traffic, channel tuning, or TX operation",
        ],
    }
}

fn extract_firmware_report(args: ExtractFirmwareArgs) -> ExtractFirmwareReport {
    let output_existed = args.out.exists();
    if output_existed && !args.overwrite {
        return extract_firmware_failure(
            &args,
            output_existed,
            DiagnosticErrorReport {
                code: "output_exists",
                message: format!(
                    "{} already exists; pass --overwrite to replace it",
                    args.out.display()
                ),
            },
        );
    }

    let image = match FirmwareImage::load_realtek_c_array(&args.source, &args.array) {
        Ok(image) => image,
        Err(error) => {
            return extract_firmware_failure(
                &args,
                output_existed,
                DiagnosticErrorReport {
                    code: "firmware_array_parse_failed",
                    message: error.to_string(),
                },
            );
        }
    };

    if let Some(parent) = args
        .out
        .parent()
        .filter(|parent| !parent.as_os_str().is_empty())
    {
        if let Err(error) = fs::create_dir_all(parent) {
            return extract_firmware_failure(
                &args,
                output_existed,
                DiagnosticErrorReport {
                    code: "output_parent_create_failed",
                    message: format!("failed to create {}: {error}", parent.display()),
                },
            );
        }
    }

    if let Err(error) = fs::write(&args.out, image.bytes()) {
        return extract_firmware_failure(
            &args,
            output_existed,
            DiagnosticErrorReport {
                code: "output_write_failed",
                message: format!("failed to write {}: {error}", args.out.display()),
            },
        );
    }

    let firmware = match firmware_report_from_image(&args.source, &image) {
        Ok(report) => report,
        Err(message) => {
            return extract_firmware_failure(
                &args,
                output_existed,
                DiagnosticErrorReport {
                    code: "firmware_report_failed",
                    message,
                },
            );
        }
    };
    let payload = image.realtek_download_payload();

    ExtractFirmwareReport {
        schema_version: 1,
        command: "extract-firmware",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        source: args.source,
        array: args.array,
        out: args.out,
        overwrite: args.overwrite,
        output_existed,
        firmware: Some(firmware),
        firmware_payload_offset: Some(payload.offset),
        firmware_payload_len: Some(payload.bytes.len()),
        firmware_signature_hex: payload.signature.map(|value| format_value(value, 4)),
        result: DiagnosticResult::Pass,
        error: None,
        notes: vec![
            "firmware was extracted from a Realtek driver C array; no USB or hardware operation was issued",
            "the output image includes the Realtek firmware header when present, matching existing firmware loader expectations",
        ],
    }
}

fn extract_firmware_failure(
    args: &ExtractFirmwareArgs,
    output_existed: bool,
    error: DiagnosticErrorReport,
) -> ExtractFirmwareReport {
    ExtractFirmwareReport {
        schema_version: 1,
        command: "extract-firmware",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        source: args.source.clone(),
        array: args.array.clone(),
        out: args.out.clone(),
        overwrite: args.overwrite,
        output_existed,
        firmware: None,
        firmware_payload_offset: None,
        firmware_payload_len: None,
        firmware_signature_hex: None,
        result: DiagnosticResult::Fail,
        error: Some(error),
        notes: vec!["firmware extraction aborted before writing a usable image"],
    }
}

fn firmware_smoke_report(args: FirmwareSmokeArgs) -> FirmwareSmokeReport {
    let selector = args.adapter.selector();
    let mut steps = Vec::new();
    let mut counters = DiagnosticCounters::default();
    let mut stats = FirmwareRunStats::default();

    if !args.i_understand_this_writes_registers {
        return firmware_smoke_failure(
            &args,
            FirmwareSmokeFailureInput {
                firmware: None,
                adapter: None,
                endpoints: None,
                steps,
                counters,
                stats,
                error: DiagnosticErrorReport {
                    code: "missing_write_authorization",
                    message: "firmware smoke writes hardware registers and requires --i-understand-this-writes-registers".to_string(),
                },
            },
        );
    }

    if args.download_attempts == 0 {
        return firmware_smoke_failure(
            &args,
            FirmwareSmokeFailureInput {
                firmware: None,
                adapter: None,
                endpoints: None,
                steps,
                counters,
                stats,
                error: DiagnosticErrorReport {
                    code: "invalid_download_attempts",
                    message: "--download-attempts must be at least 1".to_string(),
                },
            },
        );
    }

    let (firmware_image, firmware) = match load_firmware_with_report(&args.firmware) {
        Ok((image, report)) => (image, report),
        Err(message) => {
            return firmware_smoke_failure(
                &args,
                FirmwareSmokeFailureInput {
                    firmware: None,
                    adapter: None,
                    endpoints: None,
                    steps,
                    counters,
                    stats,
                    error: DiagnosticErrorReport {
                        code: "firmware_load_failed",
                        message,
                    },
                },
            );
        }
    };
    let firmware_payload = firmware_image.realtek_download_payload();
    stats.firmware_payload_offset = Some(firmware_payload.offset);
    stats.firmware_payload_len = Some(firmware_payload.bytes.len());
    stats.firmware_signature = firmware_payload.signature;

    if firmware_page_count(firmware_payload.bytes.len()) > MAX_FIRMWARE_DOWNLOAD_PAGES {
        return firmware_smoke_failure(
            &args,
            FirmwareSmokeFailureInput {
                firmware: Some(firmware),
                adapter: None,
                endpoints: None,
                steps,
                counters,
                stats,
                error: DiagnosticErrorReport {
                    code: "firmware_too_many_pages",
                    message: format!(
                        "firmware requires {} 4 KiB pages, but RTL8812A page selector exposes {} pages",
                        firmware_page_count(firmware_payload.bytes.len()),
                        MAX_FIRMWARE_DOWNLOAD_PAGES
                    ),
                },
            },
        );
    }

    let selected = match select_supported_adapter(selector) {
        Ok(device) => device,
        Err(error) => {
            return firmware_smoke_failure(
                &args,
                FirmwareSmokeFailureInput {
                    firmware: Some(firmware),
                    adapter: None,
                    endpoints: None,
                    steps,
                    counters,
                    stats,
                    error,
                },
            );
        }
    };

    let claimed = match radio_core::usb::claim_usb_device(&selected) {
        Ok(claimed) => claimed,
        Err(error) => {
            return firmware_smoke_failure(
                &args,
                FirmwareSmokeFailureInput {
                    firmware: Some(firmware),
                    adapter: Some(selected),
                    endpoints: None,
                    steps,
                    counters,
                    stats,
                    error: DiagnosticErrorReport {
                        code: "usb_claim_failed",
                        message: error.to_string(),
                    },
                },
            );
        }
    };

    let adapter = claimed.info.clone();
    let endpoints = claimed.endpoints.clone();
    let registers =
        Rtl8812auRegisterAccess::new(&claimed).with_timeout(Duration::from_millis(args.timeout_ms));

    if let Err(error) = run_firmware_sequence(
        &registers,
        &args,
        firmware_payload.bytes,
        &mut counters,
        &mut steps,
        &mut stats,
    ) {
        return firmware_smoke_failure(
            &args,
            FirmwareSmokeFailureInput {
                firmware: Some(firmware),
                adapter: Some(adapter),
                endpoints: Some(endpoints),
                steps,
                counters,
                stats,
                error,
            },
        );
    }

    FirmwareSmokeReport {
        schema_version: 1,
        command: "firmware-smoke",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        firmware_path: args.firmware,
        firmware: Some(firmware),
        timeout_ms: args.timeout_ms,
        download_attempts: args.download_attempts,
        checksum_min_attempts: args.checksum_min_attempts,
        checksum_timeout_ms: args.checksum_timeout_ms,
        ready_min_attempts: args.ready_min_attempts,
        ready_timeout_ms: args.ready_timeout_ms,
        poll_delay_us: args.poll_delay_us,
        firmware_payload_offset: stats.firmware_payload_offset,
        firmware_payload_len: stats.firmware_payload_len,
        firmware_signature_hex: stats.firmware_signature.map(|value| format_value(value, 4)),
        result: DiagnosticResult::Pass,
        adapter: Some(adapter),
        endpoints: Some(endpoints),
        steps,
        firmware_bytes_written: stats.firmware_bytes_written,
        firmware_control_writes: stats.firmware_control_writes,
        checksum_poll_attempts: stats.checksum_poll_attempts,
        ready_poll_attempts: stats.ready_poll_attempts,
        final_mcu_status_hex: stats.final_mcu_status.map(|value| format_value(value, 8)),
        counters,
        error: None,
        notes: vec![
            "guarded firmware smoke test: RTL8812A firmware was written through vendor control transfers",
            "no bulk traffic, channel tuning, RX loop, or TX operation was issued",
        ],
    }
}

