fn queue_rmw16_step<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
    spec: QueueRmw16Spec,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let before = read16_with_counter(registers, counters, spec.address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{} read before write failed: {error}", spec.register_name),
        }
    })?;
    let written = (before & spec.preserve_mask) | (spec.value & spec.value_mask);
    write16_with_counter(registers, counters, spec.address, written).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_write_failed",
            message: format!("{} write failed: {error}", spec.register_name),
        }
    })?;
    let after = read16_with_counter(registers, counters, spec.address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{} read after write failed: {error}", spec.register_name),
        }
    })?;
    let expected = spec.value & spec.value_mask;
    let passed = (after & spec.value_mask) == expected;
    steps.push(QueueDmaStepReport {
        phase: spec.phase,
        operation: "rmw16",
        description: spec.description,
        source: spec.source,
        register_name: spec.register_name,
        address: spec.address,
        address_hex: format_address(spec.address),
        width: "u16",
        mask_hex: Some(format_value(spec.value_mask, 4)),
        value_hex: Some(format_value(spec.value, 4)),
        before_hex: Some(format_value(before, 4)),
        written_hex: Some(format_value(written, 4)),
        after_hex: Some(format_value(after, 4)),
        expected_hex: Some(format_value(expected, 4)),
        passed,
    });
    if passed {
        Ok(())
    } else {
        Err(queue_readback_error(
            spec.register_name,
            format_value(spec.value_mask, 4),
            format_value(expected, 4),
            format_value(after & spec.value_mask, 4),
        ))
    }
}

fn queue_read_report8(spec: QueueRead8Spec) -> QueueDmaStepReport {
    QueueDmaStepReport {
        phase: spec.phase,
        operation: "read8",
        description: spec.description,
        source: POWER_SOURCE_USB_HALINIT,
        register_name: spec.register_name,
        address: spec.address,
        address_hex: format_address(spec.address),
        width: "u8",
        mask_hex: spec.mask.map(|mask| format_value(mask, 2)),
        value_hex: None,
        before_hex: None,
        written_hex: None,
        after_hex: Some(format_value(spec.value, 2)),
        expected_hex: spec.expected.map(|expected| format_value(expected, 2)),
        passed: spec.passed,
    }
}

fn queue_read_report16(spec: QueueRead16Spec) -> QueueDmaStepReport {
    QueueDmaStepReport {
        phase: spec.phase,
        operation: "read16",
        description: spec.description,
        source: POWER_SOURCE_USB_HALINIT,
        register_name: spec.register_name,
        address: spec.address,
        address_hex: format_address(spec.address),
        width: "u16",
        mask_hex: spec.mask.map(|mask| format_value(mask, 4)),
        value_hex: None,
        before_hex: None,
        written_hex: None,
        after_hex: Some(format_value(spec.value, 4)),
        expected_hex: spec.expected.map(|expected| format_value(expected, 4)),
        passed: spec.passed,
    }
}

fn queue_layout_from_endpoints(
    endpoints: &UsbEndpoints,
) -> std::result::Result<QueueLayout, DiagnosticErrorReport> {
    queue_layout_from_bulk_out_endpoint_count(endpoints.bulk_out_all.len())
}

fn queue_layout_from_bulk_out_endpoint_count(
    bulk_out_endpoint_count: usize,
) -> std::result::Result<QueueLayout, DiagnosticErrorReport> {
    let out_ep_queue_sel = match bulk_out_endpoint_count {
        2 => TX_SELE_HQ | TX_SELE_NQ,
        3 => TX_SELE_HQ | TX_SELE_LQ | TX_SELE_NQ,
        4 => TX_SELE_HQ | TX_SELE_LQ | TX_SELE_NQ | TX_SELE_EQ,
        other => {
            return Err(DiagnosticErrorReport {
                code: "unsupported_bulk_out_endpoint_count",
                message: format!(
                    "queue/DMA smoke supports 2, 3, or 4 bulk OUT endpoints, observed {other}"
                ),
            });
        }
    };

    let hpq = if out_ep_queue_sel & TX_SELE_HQ != 0 {
        NORMAL_PAGE_NUM_HPQ_8812
    } else {
        0
    };
    let lpq = if out_ep_queue_sel & TX_SELE_LQ != 0 {
        NORMAL_PAGE_NUM_LPQ_8812
    } else {
        0
    };
    let npq = if out_ep_queue_sel & TX_SELE_NQ != 0 {
        NORMAL_PAGE_NUM_NPQ_8812
    } else {
        0
    };
    let pubq = TX_TOTAL_PAGE_NUMBER_8812
        .checked_sub(hpq)
        .and_then(|value| value.checked_sub(lpq))
        .and_then(|value| value.checked_sub(npq))
        .ok_or_else(|| DiagnosticErrorReport {
            code: "invalid_queue_page_layout",
            message: "queue reserved-page layout underflowed public queue pages".to_string(),
        })?;
    let rqpn_npq = npq;
    let rqpn = u32::from(hpq) | (u32::from(lpq) << 8) | (u32::from(pubq) << 16) | LD_RQPN;
    let queue_map = queue_map_for_endpoint_count(bulk_out_endpoint_count);

    Ok(QueueLayout {
        bulk_out_endpoint_count,
        out_ep_queue_sel,
        hpq,
        lpq,
        npq,
        pubq,
        rqpn_npq,
        rqpn,
        queue_map,
    })
}

fn macos_usbhost_config(args: &MacosUsbHostArgs) -> MacosUsbHostConfig {
    MacosUsbHostConfig {
        configuration_value: args.configuration_value,
        interface_number: args.interface_number,
        bulk_in_endpoint: args.bulk_in_endpoint,
        bulk_out_endpoint: args.bulk_out_endpoint,
        bulk_out_endpoint_count: args.bulk_out_endpoint_count,
        poll_attempts: args.poll_attempts,
        poll_delay: Duration::from_millis(args.poll_delay_ms),
    }
}

fn runtime_transport_error(error: RuntimeTransportError) -> DiagnosticErrorReport {
    DiagnosticErrorReport {
        code: error.code,
        message: error.message,
    }
}

struct LiveUsbTransportOpen {
    transport: RuntimeUsbTransport,
    adapter: UsbDeviceInfo,
    endpoints: UsbEndpoints,
    counters: DiagnosticCounters,
}

fn open_runtime_transport(
    config: RuntimeUsbOpenConfig,
) -> std::result::Result<LiveUsbTransportOpen, DiagnosticErrorReport> {
    let session = RuntimeRadioSession::open(config).map_err(runtime_transport_error)?;
    let counters = diagnostic_counters_from_runtime(session.counters);

    Ok(LiveUsbTransportOpen {
        transport: session.transport,
        adapter: session.adapter,
        endpoints: session.endpoints,
        counters,
    })
}

fn open_libusb_transport(
    selector: DeviceSelector,
) -> std::result::Result<LiveUsbTransportOpen, DiagnosticErrorReport> {
    open_runtime_transport(RuntimeUsbOpenConfig::libusb(selector))
}

fn open_macos_usbhost_transport(
    args: &MacosUsbHostArgs,
    selector: DeviceSelector,
) -> std::result::Result<LiveUsbTransportOpen, DiagnosticErrorReport> {
    let config = macos_usbhost_config(args);
    open_runtime_transport(RuntimeUsbOpenConfig::macos_usbhost(selector, config))
}

fn queue_map_for_endpoint_count(bulk_out_endpoint_count: usize) -> u16 {
    match bulk_out_endpoint_count {
        2 => queue_map(
            QUEUE_NORMAL,
            QUEUE_NORMAL,
            QUEUE_HIGH,
            QUEUE_HIGH,
            QUEUE_HIGH,
            QUEUE_HIGH,
        ),
        3 => queue_map(
            QUEUE_LOW,
            QUEUE_LOW,
            QUEUE_NORMAL,
            QUEUE_HIGH,
            QUEUE_HIGH,
            QUEUE_HIGH,
        ),
        4 => queue_map(
            QUEUE_LOW,
            QUEUE_LOW,
            QUEUE_NORMAL,
            QUEUE_NORMAL,
            QUEUE_EXTRA,
            QUEUE_HIGH,
        ),
        _ => 0,
    }
}

fn queue_map(beq: u16, bkq: u16, viq: u16, voq: u16, mgq: u16, hiq: u16) -> u16 {
    ((hiq & 0x3) << 14)
        | ((mgq & 0x3) << 12)
        | ((bkq & 0x3) << 10)
        | ((beq & 0x3) << 8)
        | ((viq & 0x3) << 6)
        | ((voq & 0x3) << 4)
}

fn queue_page_report(layout: QueueLayout) -> QueuePageReport {
    QueuePageReport {
        hpq: layout.hpq,
        lpq: layout.lpq,
        npq: layout.npq,
        pubq: layout.pubq,
        rqpn_npq_hex: format_value(layout.rqpn_npq, 2),
        rqpn_hex: format_value(layout.rqpn, 8),
    }
}

fn queue_readback_error(
    register_name: &'static str,
    mask_hex: String,
    expected_hex: String,
    actual_hex: String,
) -> DiagnosticErrorReport {
    DiagnosticErrorReport {
        code: "register_readback_mismatch",
        message: format!(
            "{register_name} expected mask {mask_hex} to equal {expected_hex}, got {actual_hex}"
        ),
    }
}

fn mac_smoke_report(args: MacSmokeArgs) -> MacSmokeReport {
    let selector = args.adapter.selector();
    let mut steps = Vec::new();
    let mut counters = DiagnosticCounters::default();

    if !args.i_understand_this_writes_registers {
        return mac_smoke_failure(
            &args,
            None,
            None,
            steps,
            counters,
            DiagnosticErrorReport {
                code: "missing_write_authorization",
                message: "MAC smoke writes hardware registers and requires --i-understand-this-writes-registers".to_string(),
            },
        );
    }

    let selected = match select_supported_adapter(selector) {
        Ok(device) => device,
        Err(error) => {
            return mac_smoke_failure(&args, None, None, steps, counters, error);
        }
    };

    let claimed = match radio_core::usb::claim_usb_device(&selected) {
        Ok(claimed) => claimed,
        Err(error) => {
            return mac_smoke_failure(
                &args,
                Some(selected),
                None,
                steps,
                counters,
                DiagnosticErrorReport {
                    code: "usb_claim_failed",
                    message: error.to_string(),
                },
            );
        }
    };

    let adapter = claimed.info.clone();
    let endpoints = claimed.endpoints.clone();
    let registers =
        Rtl8812auRegisterAccess::new(&claimed).with_timeout(Duration::from_millis(args.timeout_ms));

    if let Err(error) = run_mac_sequence(&registers, &mut counters, &mut steps) {
        return mac_smoke_failure(
            &args,
            Some(adapter),
            Some(endpoints),
            steps,
            counters,
            error,
        );
    }

    MacSmokeReport {
        schema_version: 1,
        command: "mac-smoke",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        timeout_ms: args.timeout_ms,
        result: DiagnosticResult::Pass,
        adapter: Some(adapter),
        endpoints: Some(endpoints),
        receive_config_hex: format_value(MAC_RECEIVE_CONFIG, 8),
        retry_limit_hex: format_value(RETRY_LIMIT_STA, 4),
        steps,
        counters,
        error: None,
        notes: vec![
            "guarded MAC smoke test: RTL8812A driver-info, network-type, WMAC filter, rate/retry, EDCA, HW sequence, BAR, and MAC TX/RX enable registers were written",
            "no BB/RF table programming, channel tuning, bulk traffic, RX loop, or TX operation was issued",
        ],
    }
}

fn mac_smoke_failure(
    args: &MacSmokeArgs,
    adapter: Option<UsbDeviceInfo>,
    endpoints: Option<UsbEndpoints>,
    steps: Vec<QueueDmaStepReport>,
    counters: DiagnosticCounters,
    error: DiagnosticErrorReport,
) -> MacSmokeReport {
    mac_smoke_failure_with_command(
        "mac-smoke",
        args,
        adapter,
        endpoints,
        steps,
        counters,
        error,
    )
}

fn macos_mac_smoke_report(args: MacSmokeArgs) -> MacSmokeReport {
    let selector = args.adapter.selector();
    let mut steps = Vec::new();
    let mut counters = DiagnosticCounters::default();

    if !args.i_understand_this_writes_registers {
        return mac_smoke_failure_with_command(
            "macos-mac-smoke",
            &args,
            None,
            None,
            steps,
            counters,
            DiagnosticErrorReport {
                code: "missing_write_authorization",
                message: "macOS IOUSBHost MAC smoke writes hardware registers and requires --i-understand-this-writes-registers".to_string(),
            },
        );
    }

    #[cfg(not(target_os = "macos"))]
    {
        return mac_smoke_failure_with_command(
            "macos-mac-smoke",
            &args,
            None,
            None,
            steps,
            counters,
            DiagnosticErrorReport {
                code: "unsupported_platform",
                message: "macos-mac-smoke requires macOS IOUSBHost".to_string(),
            },
        );
    }

    #[cfg(target_os = "macos")]
    {
        let Some(vid) = selector.vid else {
            return mac_smoke_failure_with_command(
                "macos-mac-smoke",
                &args,
                None,
                None,
                steps,
                counters,
                DiagnosticErrorReport {
                    code: "missing_vid",
                    message:
                        "macos-mac-smoke requires --vid because IOUSBHost matching is VID/PID based"
                            .to_string(),
                },
            );
        };
        let Some(pid) = selector.pid else {
            return mac_smoke_failure_with_command(
                "macos-mac-smoke",
                &args,
                None,
                None,
                steps,
                counters,
                DiagnosticErrorReport {
                    code: "missing_pid",
                    message:
                        "macos-mac-smoke requires --pid because IOUSBHost matching is VID/PID based"
                            .to_string(),
                },
            );
        };

        let device = match macos_usbhost::MacosUsbHostDevice::open(vid, pid) {
            Ok(device) => device,
            Err(error) => {
                return mac_smoke_failure_with_command(
                    "macos-mac-smoke",
                    &args,
                    None,
                    None,
                    steps,
                    counters,
                    DiagnosticErrorReport {
                        code: "macos_usbhost_open_failed",
                        message: error,
                    },
                );
            }
        };

        let registers = Rtl8812auRegisterAccess::new(&device)
            .with_timeout(Duration::from_millis(args.timeout_ms));
        if let Err(error) = run_mac_sequence(&registers, &mut counters, &mut steps) {
            return mac_smoke_failure_with_command(
                "macos-mac-smoke",
                &args,
                None,
                None,
                steps,
                counters,
                error,
            );
        }

        MacSmokeReport {
            schema_version: 1,
            command: "macos-mac-smoke",
            started_at_unix_ms: started_at_unix_ms(),
            platform: platform_info(),
            selector,
            timeout_ms: args.timeout_ms,
            result: DiagnosticResult::Pass,
            adapter: None,
            endpoints: None,
            receive_config_hex: format_value(MAC_RECEIVE_CONFIG, 8),
            retry_limit_hex: format_value(RETRY_LIMIT_STA, 4),
            steps,
            counters,
            error: None,
            notes: vec![
                "macOS IOUSBHost guarded MAC smoke test: RTL8812A driver-info, network-type, WMAC filter, rate/retry, EDCA, HW sequence, BAR, and MAC TX/RX enable registers were written through default-control transfers",
                "no libusb enumeration, USB interface claim, BB/RF table programming, channel tuning, bulk traffic, RX loop, or TX operation was issued",
            ],
        }
    }
}

fn mac_smoke_failure_with_command(
    command: &'static str,
    args: &MacSmokeArgs,
    adapter: Option<UsbDeviceInfo>,
    endpoints: Option<UsbEndpoints>,
    steps: Vec<QueueDmaStepReport>,
    counters: DiagnosticCounters,
    error: DiagnosticErrorReport,
) -> MacSmokeReport {
    MacSmokeReport {
        schema_version: 1,
        command,
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector: args.adapter.selector(),
        timeout_ms: args.timeout_ms,
        result: DiagnosticResult::Fail,
        adapter,
        endpoints,
        receive_config_hex: format_value(MAC_RECEIVE_CONFIG, 8),
        retry_limit_hex: format_value(RETRY_LIMIT_STA, 4),
        steps,
        counters,
        error: Some(error),
        notes: vec![
            "guarded MAC smoke test stopped before BB/RF table programming, channel tuning, bulk traffic, RX loop, or TX operation",
        ],
    }
}

fn run_mac_sequence<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    mac_preflight(registers, counters, steps)?;

    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "driver_info",
            register_name: "REG_RX_DRVINFO_SZ",
            address: REG_RX_DRVINFO_SZ,
            value: DRVINFO_SZ,
            verify_mask: u8::MAX,
            verify_value: DRVINFO_SZ,
            description: "set RX driver-info size to include PHY status",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    mac_rmw32_step(
        registers,
        counters,
        steps,
        MacRmw32Spec {
            phase: "network_type",
            register_name: "REG_CR",
            address: REG_CR,
            preserve_mask: !MASK_NETTYPE,
            value_mask: MASK_NETTYPE,
            value: NETTYPE_LINK_AP,
            description: "set MAC network type to AP-style raw frame mode",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write32_step(
        registers,
        counters,
        steps,
        QueueWrite32Spec {
            phase: "wmac_filter",
            register_name: "REG_RCR",
            address: REG_RCR,
            value: MAC_RECEIVE_CONFIG,
            verify_mask: u32::MAX,
            verify_value: MAC_RECEIVE_CONFIG,
            description: "program WMAC receive configuration",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    for (register_name, address) in [("REG_MAR", REG_MAR), ("REG_MAR + 4", REG_MAR + 4)] {
        queue_write32_step(
            registers,
            counters,
            steps,
            QueueWrite32Spec {
                phase: "wmac_filter",
                register_name,
                address,
                value: u32::MAX,
                verify_mask: u32::MAX,
                verify_value: u32::MAX,
                description: "accept all multicast addresses",
                source: POWER_SOURCE_USB_HALINIT,
            },
        )?;
    }
    queue_write16_step(
        registers,
        counters,
        steps,
        QueueWrite16Spec {
            phase: "wmac_filter",
            register_name: "REG_RXFLTMAP1",
            address: REG_RXFLTMAP1,
            value: 1 << 10,
            verify_mask: u16::MAX,
            verify_value: 1 << 10,
            description: "allow PS-Poll control subtype in RX filter map",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    mac_rmw32_step(
        registers,
        counters,
        steps,
        MacRmw32Spec {
            phase: "adaptive_control",
            register_name: "REG_RRSR",
            address: REG_RRSR,
            preserve_mask: !RATE_BITMAP_ALL,
            value_mask: RATE_BITMAP_ALL,
            value: RATE_RRSR_CCK_ONLY_1M,
            description: "program response-rate set used by MAC acknowledgements",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write16_step(
        registers,
        counters,
        steps,
        QueueWrite16Spec {
            phase: "adaptive_control",
            register_name: "REG_SPEC_SIFS",
            address: REG_SPEC_SIFS,
            value: 0x1010,
            verify_mask: u16::MAX,
            verify_value: 0x1010,
            description: "set initial SIFS timing used in NAV",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write16_step(
        registers,
        counters,
        steps,
        QueueWrite16Spec {
            phase: "adaptive_control",
            register_name: "REG_RETRY_LIMIT",
            address: REG_RETRY_LIMIT,
            value: RETRY_LIMIT_STA,
            verify_mask: u16::MAX,
            verify_value: RETRY_LIMIT_STA,
            description: "set short and long retry limits",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;

    for (register_name, address) in [
        ("REG_SPEC_SIFS", REG_SPEC_SIFS),
        ("REG_MAC_SPEC_SIFS", REG_MAC_SPEC_SIFS),
        ("REG_SIFS_CTX", REG_SIFS_CTX),
        ("REG_SIFS_TRX", REG_SIFS_TRX),
    ] {
        queue_write16_step(
            registers,
            counters,
            steps,
            QueueWrite16Spec {
                phase: "edca",
                register_name,
                address,
                value: 0x100a,
                verify_mask: u16::MAX,
                verify_value: 0x100a,
                description: "set EDCA SIFS timing",
                source: POWER_SOURCE_USB_HALINIT,
            },
        )?;
    }
    for (register_name, address, value) in [
        ("REG_EDCA_BE_PARAM", REG_EDCA_BE_PARAM, 0x005e_a42b),
        ("REG_EDCA_BK_PARAM", REG_EDCA_BK_PARAM, 0x0000_a44f),
        ("REG_EDCA_VI_PARAM", REG_EDCA_VI_PARAM, 0x005e_a324),
        ("REG_EDCA_VO_PARAM", REG_EDCA_VO_PARAM, 0x002f_a226),
    ] {
        queue_write32_step(
            registers,
            counters,
            steps,
            QueueWrite32Spec {
                phase: "edca",
                register_name,
                address,
                value,
                verify_mask: u32::MAX,
                verify_value: value,
                description: "set EDCA TXOP and contention parameters",
                source: POWER_SOURCE_USB_HALINIT,
            },
        )?;
    }
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "tx_scheduler",
            register_name: "REG_TXPAUSE",
            address: REG_TXPAUSE,
            value: 0x00,
            verify_mask: u8::MAX,
            verify_value: 0x00,
            description: "release all MAC TX queues after reset",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    for (register_name, address) in [
        ("REG_USTIME_TSF", REG_USTIME_TSF),
        ("REG_USTIME_EDCA", REG_USTIME_EDCA),
    ] {
        queue_write8_step(
            registers,
            counters,
            steps,
            QueueWrite8Spec {
                phase: "edca",
                register_name,
                address,
                value: 0x50,
                verify_mask: u8::MAX,
                verify_value: 0x50,
                description: "set 80 MHz-clock microsecond timing",
                source: POWER_SOURCE_USB_HALINIT,
            },
        )?;
    }
    mac_rmw8_step(
        registers,
        counters,
        steps,
        MacRmw8Spec {
            phase: "retry_function",
            register_name: "REG_FWHW_TXQ_CTRL",
            address: REG_FWHW_TXQ_CTRL,
            preserve_mask: !EN_AMPDU_RTY_NEW,
            value_mask: EN_AMPDU_RTY_NEW,
            value: EN_AMPDU_RTY_NEW,
            description: "enable new AMPDU retry behavior",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "retry_function",
            register_name: "REG_ACKTO",
            address: REG_ACKTO,
            value: 0x80,
            verify_mask: u8::MAX,
            verify_value: 0x80,
            description: "set MAC ACK timeout",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    run_beacon_parameters_sequence(registers, counters, steps)?;
    run_usb_burst_packet_sequence(registers, counters, steps)?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "hw_sequence",
            register_name: "REG_HWSEQ_CTRL",
            address: REG_HWSEQ_CTRL,
            value: 0xff,
            verify_mask: u8::MAX,
            verify_value: 0xff,
            description: "enable hardware sequence number control",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write32_step(
        registers,
        counters,
        steps,
        QueueWrite32Spec {
            phase: "bar_control",
            register_name: "REG_BAR_MODE_CTRL",
            address: REG_BAR_MODE_CTRL,
            value: BAR_MODE_CTRL_VALUE,
            verify_mask: BAR_MODE_CTRL_READBACK_MASK,
            verify_value: BAR_MODE_CTRL_VALUE,
            description: "disable BAR mode as in upstream init",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    mac_rmw8_step(
        registers,
        counters,
        steps,
        MacRmw8Spec {
            phase: "mac_enable",
            register_name: "REG_CR",
            address: REG_CR,
            preserve_mask: !MAC_TX_RX_ENABLE_MASK,
            value_mask: MAC_TX_RX_ENABLE_MASK,
            value: MAC_TX_RX_ENABLE_MASK,
            description: "enable MAC TX and RX blocks after queue and boundary setup",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )
}

fn run_usb_burst_packet_sequence<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "usb_burst",
            register_name: "0xf050",
            address: 0xf050,
            value: 0x01,
            verify_mask: 0x00,
            verify_value: 0x00,
            description: "set USB3 RX interval register used by upstream burst setup",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write16_step(
        registers,
        counters,
        steps,
        QueueWrite16Spec {
            phase: "usb_burst",
            register_name: "REG_RXDMA_STATUS",
            address: REG_RXDMA_STATUS,
            value: 0x7400,
            verify_mask: 0x0000,
            verify_value: 0x0000,
            description: "set RXDMA burst length baseline",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "usb_burst",
            register_name: "REG_RXDMA_STATUS + 1",
            address: REG_RXDMA_STATUS + 1,
            value: 0xf5,
            verify_mask: 0x00,
            verify_value: 0x00,
            description: "set RXDMA control byte as in upstream burst setup",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "ampdu_limits",
            register_name: "REG_AMPDU_MAX_TIME_8812",
            address: REG_AMPDU_MAX_TIME_8812,
            value: 0x70,
            verify_mask: u8::MAX,
            verify_value: 0x70,
            description: "set AMPDU maximum time for RTL8812AU",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write32_step(
        registers,
        counters,
        steps,
        QueueWrite32Spec {
            phase: "ampdu_limits",
            register_name: "REG_AMPDU_MAX_LENGTH_8812",
            address: REG_AMPDU_MAX_LENGTH_8812,
            value: u32::MAX,
            verify_mask: u32::MAX,
            verify_value: u32::MAX,
            description: "allow maximum AMPDU length table entries",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;

    let speed_value =
        read8_with_counter(registers, counters, 0x00ff).map_err(|error| DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("USB speed probe register 0x00ff read failed: {error}"),
        })?;
    let rxdma_pro =
        read8_with_counter(registers, counters, REG_RXDMA_PRO_8812).map_err(|error| {
            DiagnosticErrorReport {
                code: "register_read_failed",
                message: format!("REG_RXDMA_PRO_8812 read failed: {error}"),
            }
        })?;
    let rxdma_pro_value = if speed_value & BIT7 != 0 {
        let phy_speed = read8_with_counter(registers, counters, 0xfe17).map_err(|error| {
            DiagnosticErrorReport {
                code: "register_read_failed",
                message: format!("USB PHY speed register 0xfe17 read failed: {error}"),
            }
        })?;
        if ((phy_speed >> 4) & 0x03) == 0 {
            (rxdma_pro | BIT4 | BIT3 | BIT2 | BIT1) & !BIT5
        } else {
            (rxdma_pro | BIT5 | BIT3 | BIT2 | BIT1) & !BIT4
        }
    } else {
        (rxdma_pro | BIT3 | BIT2 | BIT1) & !(BIT5 | BIT4)
    };
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "usb_burst",
            register_name: "REG_RXDMA_PRO_8812",
            address: REG_RXDMA_PRO_8812,
            value: rxdma_pro_value,
            verify_mask: u8::MAX,
            verify_value: rxdma_pro_value,
            description: "set USB burst packet length according to probed link speed",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "usb_burst",
            register_name: "REG_TDECTRL",
            address: REG_TDECTRL,
            value: 0x10,
            verify_mask: u8::MAX,
            verify_value: 0x10,
            description: "disable USB TX aggregation descriptor mode",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    mac_rmw8_step(
        registers,
        counters,
        steps,
        MacRmw8Spec {
            phase: "ampdu_limits",
            register_name: "REG_HT_SINGLE_AMPDU_8812",
            address: REG_HT_SINGLE_AMPDU_8812,
            preserve_mask: !BIT7,
            value_mask: BIT7,
            value: BIT7,
            description: "enable single-packet AMPDU handling",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "ampdu_limits",
            register_name: "REG_RX_PKT_LIMIT",
            address: REG_RX_PKT_LIMIT,
            value: 0x18,
            verify_mask: u8::MAX,
            verify_value: 0x18,
            description: "set VHT RX packet length limit",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "edca",
            register_name: "REG_PIFS",
            address: REG_PIFS,
            value: 0x00,
            verify_mask: u8::MAX,
            verify_value: 0x00,
            description: "clear PIFS timing register",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write16_step(
        registers,
        counters,
        steps,
        QueueWrite16Spec {
            phase: "ampdu_limits",
            register_name: "REG_MAX_AGGR_NUM",
            address: REG_MAX_AGGR_NUM,
            value: 0x1f1f,
            verify_mask: u16::MAX,
            verify_value: 0x1f1f,
            description: "set maximum aggregation count table entries",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    mac_rmw8_step(
        registers,
        counters,
        steps,
        MacRmw8Spec {
            phase: "retry_function",
            register_name: "REG_FWHW_TXQ_CTRL",
            address: REG_FWHW_TXQ_CTRL,
            preserve_mask: !EN_AMPDU_RTY_NEW,
            value_mask: EN_AMPDU_RTY_NEW,
            value: 0x00,
            description: "clear new AMPDU retry behavior after burst setup for RTL8812AU",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    mac_rmw8_step_with_verify_mask(
        registers,
        counters,
        steps,
        MacRmw8Spec {
            phase: "usb_burst",
            register_name: "REG_RSV_CTRL",
            address: REG_RSV_CTRL,
            preserve_mask: !(BIT5 | BIT6),
            value_mask: BIT5 | BIT6,
            value: BIT5 | BIT6,
            description: "preserve MAC state across bus reset as in upstream burst setup",
            source: POWER_SOURCE_USB_HALINIT,
        },
        BIT5,
    )?;

    for (register_name, address, low, high) in [
        ("REG_ARFR0_8812", REG_ARFR0_8812, 0x0000_0010, 0xffff_f000),
        ("REG_ARFR1_8812", REG_ARFR1_8812, 0x0000_0010, 0x003f_f000),
        ("REG_ARFR2_8812", REG_ARFR2_8812, 0x0000_0015, 0x003f_f000),
        ("REG_ARFR3_8812", REG_ARFR3_8812, 0x0000_0015, 0xffcf_f000),
    ] {
        queue_write32_step(
            registers,
            counters,
            steps,
            QueueWrite32Spec {
                phase: "arfr_table",
                register_name,
                address,
                value: low,
                verify_mask: u32::MAX,
                verify_value: low,
                description: "program adaptive rate fallback table low word",
                source: POWER_SOURCE_USB_HALINIT,
            },
        )?;
        queue_write32_step(
            registers,
            counters,
            steps,
            QueueWrite32Spec {
                phase: "arfr_table",
                register_name,
                address: address + 4,
                value: high,
                verify_mask: u32::MAX,
                verify_value: high,
                description: "program adaptive rate fallback table high word",
                source: POWER_SOURCE_USB_HALINIT,
            },
        )?;
    }

    Ok(())
}

fn run_beacon_parameters_sequence<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let bcn_ctrl = u16::from(DIS_TSF_UDT) | (u16::from(DIS_TSF_UDT) << 8);
    queue_write16_step(
        registers,
        counters,
        steps,
        QueueWrite16Spec {
            phase: "beacon_parameters",
            register_name: "REG_BCN_CTRL",
            address: REG_BCN_CTRL,
            value: bcn_ctrl,
            verify_mask: u16::MAX,
            verify_value: bcn_ctrl,
            description: "disable TSF update on both ports before beacon timing setup",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "beacon_parameters",
            register_name: "REG_TBTT_PROHIBIT",
            address: REG_TBTT_PROHIBIT,
            value: TBTT_PROHIBIT_SETUP_TIME,
            verify_mask: u8::MAX,
            verify_value: TBTT_PROHIBIT_SETUP_TIME,
            description: "set TBTT prohibit setup time",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "beacon_parameters",
            register_name: "REG_TBTT_PROHIBIT + 1",
            address: REG_TBTT_PROHIBIT + 1,
            value: (TBTT_PROHIBIT_HOLD_TIME_STOP_BCN & 0x00ff) as u8,
            verify_mask: u8::MAX,
            verify_value: (TBTT_PROHIBIT_HOLD_TIME_STOP_BCN & 0x00ff) as u8,
            description: "set low byte of TBTT prohibit hold time",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    mac_rmw8_step(
        registers,
        counters,
        steps,
        MacRmw8Spec {
            phase: "beacon_parameters",
            register_name: "REG_TBTT_PROHIBIT + 2",
            address: REG_TBTT_PROHIBIT + 2,
            preserve_mask: 0xf0,
            value_mask: 0x0f,
            value: (TBTT_PROHIBIT_HOLD_TIME_STOP_BCN >> 8) as u8,
            description: "set high nibble of TBTT prohibit hold time",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "beacon_parameters",
            register_name: "REG_DRVERLYINT",
            address: REG_DRVERLYINT,
            value: DRIVER_EARLY_INT_TIME_8812,
            verify_mask: u8::MAX,
            verify_value: DRIVER_EARLY_INT_TIME_8812,
            description: "set driver early interrupt time",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "beacon_parameters",
            register_name: "REG_BCNDMATIM",
            address: REG_BCNDMATIM,
            value: BCN_DMA_ATIME_INT_TIME_8812,
            verify_mask: u8::MAX,
            verify_value: BCN_DMA_ATIME_INT_TIME_8812,
            description: "set beacon DMA timing",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )?;
    queue_write16_step(
        registers,
        counters,
        steps,
        QueueWrite16Spec {
            phase: "beacon_parameters",
            register_name: "REG_BCNTCFG",
            address: REG_BCNTCFG,
            value: 0x4413,
            verify_mask: u16::MAX,
            verify_value: 0x4413,
            description: "set beacon contention parameters",
            source: POWER_SOURCE_USB_HALINIT,
        },
    )
}

fn mac_preflight<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let cr = read16_with_counter(registers, counters, REG_CR).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("REG_CR preflight read failed: {error}"),
        }
    })?;
    let cr_passed = (cr & CR_ENABLE_BITS) == CR_ENABLE_BITS;
    steps.push(queue_read_report16(QueueRead16Spec {
        phase: "preflight",
        description: "verify command register block enables before MAC programming",
        register_name: "REG_CR",
        address: REG_CR,
        value: cr,
        mask: Some(CR_ENABLE_BITS),
        expected: Some(CR_ENABLE_BITS),
        passed: cr_passed,
    }));
    if !cr_passed {
        return Err(DiagnosticErrorReport {
            code: "mac_not_powered_on",
            message: format!(
                "REG_CR expected block-enable mask {} to be set before MAC programming, got {}",
                format_value(CR_ENABLE_BITS, 4),
                format_value(cr, 4)
            ),
        });
    }

    let mcu = read8_with_counter(registers, counters, REG_MCUFWDL).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("REG_MCUFWDL preflight read failed: {error}"),
        }
    })?;
    let firmware_ready_mask = RAM_DL_SEL | BIT6 | BIT1;
    let firmware_passed = (mcu & firmware_ready_mask) == firmware_ready_mask;
    steps.push(queue_read_report8(QueueRead8Spec {
        phase: "preflight",
        description: "verify firmware is running before MAC programming",
        register_name: "REG_MCUFWDL",
        address: REG_MCUFWDL,
        value: mcu,
        mask: Some(firmware_ready_mask),
        expected: Some(firmware_ready_mask),
        passed: firmware_passed,
    }));
    if !firmware_passed {
        return Err(DiagnosticErrorReport {
            code: "firmware_not_ready",
            message: format!(
                "REG_MCUFWDL expected firmware-ready mask {} before MAC programming, got {}",
                format_value(firmware_ready_mask, 2),
                format_value(mcu, 2)
            ),
        });
    }

    Ok(())
}

#[derive(Debug, Clone, Copy)]
struct MacRmw8Spec {
    phase: &'static str,
    register_name: &'static str,
    address: u16,
    preserve_mask: u8,
    value_mask: u8,
    value: u8,
    description: &'static str,
    source: &'static str,
}

#[derive(Debug, Clone, Copy)]
struct MacRmw32Spec {
    phase: &'static str,
    register_name: &'static str,
    address: u16,
    preserve_mask: u32,
    value_mask: u32,
    value: u32,
    description: &'static str,
    source: &'static str,
}

fn mac_rmw8_step<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
    spec: MacRmw8Spec,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    mac_rmw8_step_with_verify_mask(registers, counters, steps, spec, spec.value_mask)
}

fn mac_rmw8_step_with_verify_mask<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
    spec: MacRmw8Spec,
    verify_mask: u8,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let before = read8_with_counter(registers, counters, spec.address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{} read before write failed: {error}", spec.register_name),
        }
    })?;
    let written = (before & spec.preserve_mask) | (spec.value & spec.value_mask);
    write8_with_counter(registers, counters, spec.address, written).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_write_failed",
            message: format!("{} write failed: {error}", spec.register_name),
        }
    })?;
    let after = read8_with_counter(registers, counters, spec.address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{} read after write failed: {error}", spec.register_name),
        }
    })?;
    let expected = spec.value & verify_mask;
    let passed = (after & verify_mask) == expected;
    steps.push(QueueDmaStepReport {
        phase: spec.phase,
        operation: "rmw8",
        description: spec.description,
        source: spec.source,
        register_name: spec.register_name,
        address: spec.address,
        address_hex: format_address(spec.address),
        width: "u8",
        mask_hex: Some(format_value(verify_mask, 2)),
        value_hex: Some(format_value(spec.value, 2)),
        before_hex: Some(format_value(before, 2)),
        written_hex: Some(format_value(written, 2)),
        after_hex: Some(format_value(after, 2)),
        expected_hex: Some(format_value(expected, 2)),
        passed,
    });
    if passed {
        Ok(())
    } else {
        Err(queue_readback_error(
            spec.register_name,
            format_value(verify_mask, 2),
            format_value(expected, 2),
            format_value(after & verify_mask, 2),
        ))
    }
}

fn mac_rmw32_step<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
    spec: MacRmw32Spec,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let before = read32_with_counter(registers, counters, spec.address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{} read before write failed: {error}", spec.register_name),
        }
    })?;
    let written = (before & spec.preserve_mask) | (spec.value & spec.value_mask);
    write32_with_counter(registers, counters, spec.address, written).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_write_failed",
            message: format!("{} write failed: {error}", spec.register_name),
        }
    })?;
    let after = read32_with_counter(registers, counters, spec.address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{} read after write failed: {error}", spec.register_name),
        }
    })?;
    let expected = spec.value & spec.value_mask;
    let passed = (after & spec.value_mask) == expected;
    steps.push(QueueDmaStepReport {
        phase: spec.phase,
        operation: "rmw32",
        description: spec.description,
        source: spec.source,
        register_name: spec.register_name,
        address: spec.address,
        address_hex: format_address(spec.address),
        width: "u32",
        mask_hex: Some(format_value(spec.value_mask, 8)),
        value_hex: Some(format_value(spec.value, 8)),
        before_hex: Some(format_value(before, 8)),
        written_hex: Some(format_value(written, 8)),
        after_hex: Some(format_value(after, 8)),
        expected_hex: Some(format_value(expected, 8)),
        passed,
    });
    if passed {
        Ok(())
    } else {
        Err(queue_readback_error(
            spec.register_name,
            format_value(spec.value_mask, 8),
            format_value(expected, 8),
            format_value(after & spec.value_mask, 8),
        ))
    }
}

fn bb_smoke_report(args: BbSmokeArgs) -> BbSmokeReport {
    let selector = args.adapter.selector();
    let condition_env = args.condition_env();
    let mut setup_steps = Vec::new();
    let mut counters = DiagnosticCounters::default();
    let mut stats = BbSmokeStats::default();

    let (phy_plan, agc_plan) = match load_bb_table_plans(&args.bb_source, condition_env) {
        Ok(plans) => plans,
        Err(error) => {
            return bb_smoke_failure(
                &args,
                BbSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    phy_plan: None,
                    agc_plan: None,
                    stats,
                    counters,
                    error,
                },
            );
        }
    };

    if !args.i_understand_this_writes_registers {
        return bb_smoke_failure(
            &args,
            BbSmokeFailureInput {
                condition_env,
                adapter: None,
                endpoints: None,
                setup_steps,
                phy_plan: Some(phy_plan),
                agc_plan: Some(agc_plan),
                stats,
                counters,
                error: DiagnosticErrorReport {
                    code: "missing_write_authorization",
                    message: "BB smoke writes hardware registers and requires --i-understand-this-writes-registers".to_string(),
                },
            },
        );
    }

    let selected = match select_supported_adapter(selector) {
        Ok(device) => device,
        Err(error) => {
            return bb_smoke_failure(
                &args,
                BbSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    phy_plan: Some(phy_plan),
                    agc_plan: Some(agc_plan),
                    stats,
                    counters,
                    error,
                },
            );
        }
    };

    let claimed = match radio_core::usb::claim_usb_device(&selected) {
        Ok(claimed) => claimed,
        Err(error) => {
            return bb_smoke_failure(
                &args,
                BbSmokeFailureInput {
                    condition_env,
                    adapter: Some(selected),
                    endpoints: None,
                    setup_steps,
                    phy_plan: Some(phy_plan),
                    agc_plan: Some(agc_plan),
                    stats,
                    counters,
                    error: DiagnosticErrorReport {
                        code: "usb_claim_failed",
                        message: error.to_string(),
                    },
                },
            );
        }
    };

    let adapter = claimed.info.clone();
    let endpoints = claimed.endpoints.clone();
    let registers =
        Rtl8812auRegisterAccess::new(&claimed).with_timeout(Duration::from_millis(args.timeout_ms));

    if let Err(error) = run_bb_sequence(
        &registers,
        &args,
        &phy_plan,
        &agc_plan,
        &mut counters,
        &mut setup_steps,
        &mut stats,
    ) {
        return bb_smoke_failure(
            &args,
            BbSmokeFailureInput {
                condition_env,
                adapter: Some(adapter),
                endpoints: Some(endpoints),
                setup_steps,
                phy_plan: Some(phy_plan),
                agc_plan: Some(agc_plan),
                stats,
                counters,
                error,
            },
        );
    }

    BbSmokeReport {
        schema_version: 1,
        command: "bb-smoke",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        bb_source: args.bb_source,
        condition_env,
        crystal_cap_hex: format_value(args.crystal_cap, 2),
        timeout_ms: args.timeout_ms,
        result: DiagnosticResult::Pass,
        adapter: Some(adapter),
        endpoints: Some(endpoints),
        setup_steps,
        phy_plan: Some(phy_plan),
        agc_plan: Some(agc_plan),
        phy_writes_applied: stats.phy_writes_applied,
        agc_writes_applied: stats.agc_writes_applied,
        delays_applied: stats.delays_applied,
        counters,
        error: None,
        notes: vec![
            "guarded BB smoke test: RTL8812A PHY_REG and AGC_TAB tables were parsed from external Realtek source and written through vendor control transfers",
            "no RF radio table programming, channel tuning, bulk traffic, RX loop, or TX operation was issued",
        ],
    }
}

fn bb_smoke_failure(args: &BbSmokeArgs, input: BbSmokeFailureInput) -> BbSmokeReport {
    bb_smoke_failure_with_command("bb-smoke", args, input)
}

fn bb_smoke_failure_with_command(
    command: &'static str,
    args: &BbSmokeArgs,
    input: BbSmokeFailureInput,
) -> BbSmokeReport {
    BbSmokeReport {
        schema_version: 1,
        command,
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector: args.adapter.selector(),
        bb_source: args.bb_source.clone(),
        condition_env: input.condition_env,
        crystal_cap_hex: format_value(args.crystal_cap, 2),
        timeout_ms: args.timeout_ms,
        result: DiagnosticResult::Fail,
        adapter: input.adapter,
        endpoints: input.endpoints,
        setup_steps: input.setup_steps,
        phy_plan: input.phy_plan,
        agc_plan: input.agc_plan,
        phy_writes_applied: input.stats.phy_writes_applied,
        agc_writes_applied: input.stats.agc_writes_applied,
        delays_applied: input.stats.delays_applied,
        counters: input.counters,
        error: Some(input.error),
        notes: vec![
            "guarded BB smoke test stopped before RF radio table programming, channel tuning, bulk traffic, RX loop, or TX operation",
        ],
    }
}

fn macos_bb_smoke_report(args: BbSmokeArgs) -> BbSmokeReport {
    let selector = args.adapter.selector();
    let condition_env = args.condition_env();
    let mut setup_steps = Vec::new();
    let mut counters = DiagnosticCounters::default();
    let mut stats = BbSmokeStats::default();

    let (phy_plan, agc_plan) = match load_bb_table_plans(&args.bb_source, condition_env) {
        Ok(plans) => plans,
        Err(error) => {
            return bb_smoke_failure_with_command(
                "macos-bb-smoke",
                &args,
                BbSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    phy_plan: None,
                    agc_plan: None,
                    stats,
                    counters,
                    error,
                },
            );
        }
    };

    if !args.i_understand_this_writes_registers {
        return bb_smoke_failure_with_command(
            "macos-bb-smoke",
            &args,
            BbSmokeFailureInput {
                condition_env,
                adapter: None,
                endpoints: None,
                setup_steps,
                phy_plan: Some(phy_plan),
                agc_plan: Some(agc_plan),
                stats,
                counters,
                error: DiagnosticErrorReport {
                    code: "missing_write_authorization",
                    message: "macOS IOUSBHost BB smoke writes hardware registers and requires --i-understand-this-writes-registers".to_string(),
                },
            },
        );
    }

    #[cfg(not(target_os = "macos"))]
    {
        return bb_smoke_failure_with_command(
            "macos-bb-smoke",
            &args,
            BbSmokeFailureInput {
                condition_env,
                adapter: None,
                endpoints: None,
                setup_steps,
                phy_plan: Some(phy_plan),
                agc_plan: Some(agc_plan),
                stats,
                counters,
                error: DiagnosticErrorReport {
                    code: "unsupported_platform",
                    message: "macos-bb-smoke requires macOS IOUSBHost".to_string(),
                },
            },
        );
    }

    #[cfg(target_os = "macos")]
    {
        let Some(vid) = selector.vid else {
            return bb_smoke_failure_with_command(
                "macos-bb-smoke",
                &args,
                BbSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    phy_plan: Some(phy_plan),
                    agc_plan: Some(agc_plan),
                    stats,
                    counters,
                    error: DiagnosticErrorReport {
                        code: "missing_vid",
                        message: "macos-bb-smoke requires --vid because IOUSBHost matching is VID/PID based".to_string(),
                    },
                },
            );
        };
        let Some(pid) = selector.pid else {
            return bb_smoke_failure_with_command(
                "macos-bb-smoke",
                &args,
                BbSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    phy_plan: Some(phy_plan),
                    agc_plan: Some(agc_plan),
                    stats,
                    counters,
                    error: DiagnosticErrorReport {
                        code: "missing_pid",
                        message: "macos-bb-smoke requires --pid because IOUSBHost matching is VID/PID based".to_string(),
                    },
                },
            );
        };

        let device = match macos_usbhost::MacosUsbHostDevice::open(vid, pid) {
            Ok(device) => device,
            Err(error) => {
                return bb_smoke_failure_with_command(
                    "macos-bb-smoke",
                    &args,
                    BbSmokeFailureInput {
                        condition_env,
                        adapter: None,
                        endpoints: None,
                        setup_steps,
                        phy_plan: Some(phy_plan),
                        agc_plan: Some(agc_plan),
                        stats,
                        counters,
                        error: DiagnosticErrorReport {
                            code: "macos_usbhost_open_failed",
                            message: error,
                        },
                    },
                );
            }
        };

        let registers = Rtl8812auRegisterAccess::new(&device)
            .with_timeout(Duration::from_millis(args.timeout_ms));
        if let Err(error) = run_bb_sequence(
            &registers,
            &args,
            &phy_plan,
            &agc_plan,
            &mut counters,
            &mut setup_steps,
            &mut stats,
        ) {
            return bb_smoke_failure_with_command(
                "macos-bb-smoke",
                &args,
                BbSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    phy_plan: Some(phy_plan),
                    agc_plan: Some(agc_plan),
                    stats,
                    counters,
                    error,
                },
            );
        }

        BbSmokeReport {
            schema_version: 1,
            command: "macos-bb-smoke",
            started_at_unix_ms: started_at_unix_ms(),
            platform: platform_info(),
            selector,
            bb_source: args.bb_source,
            condition_env,
            crystal_cap_hex: format_value(args.crystal_cap, 2),
            timeout_ms: args.timeout_ms,
            result: DiagnosticResult::Pass,
            adapter: None,
            endpoints: None,
            setup_steps,
            phy_plan: Some(phy_plan),
            agc_plan: Some(agc_plan),
            phy_writes_applied: stats.phy_writes_applied,
            agc_writes_applied: stats.agc_writes_applied,
            delays_applied: stats.delays_applied,
            counters,
            error: None,
            notes: vec![
                "macOS IOUSBHost guarded BB smoke test: RTL8812A PHY_REG and AGC_TAB tables were parsed from external Realtek source and written through default-control transfers",
                "no libusb enumeration, USB interface claim, RF radio table programming, channel tuning, bulk traffic, RX loop, or TX operation was issued",
            ],
        }
    }
}

fn load_bb_table_plans(
    source_path: &Path,
    condition_env: RealtekConditionEnv,
) -> std::result::Result<(RealtekTablePlan, RealtekTablePlan), DiagnosticErrorReport> {
    let source = fs::read_to_string(source_path).map_err(|error| DiagnosticErrorReport {
        code: "bb_source_read_failed",
        message: format!("failed to read {}: {error}", source_path.display()),
    })?;

    let phy_values =
        parse_realtek_u32_array(&source, BB_PHY_ARRAY).map_err(|error| DiagnosticErrorReport {
            code: "bb_phy_table_parse_failed",
            message: error.to_string(),
        })?;
    let agc_values =
        parse_realtek_u32_array(&source, BB_AGC_ARRAY).map_err(|error| DiagnosticErrorReport {
            code: "bb_agc_table_parse_failed",
            message: error.to_string(),
        })?;
    let phy_plan = plan_realtek_table(
        BB_PHY_ARRAY,
        RealtekTableKind::BbPhy,
        &phy_values,
        condition_env,
    )
    .map_err(|error| DiagnosticErrorReport {
        code: "bb_phy_table_plan_failed",
        message: error.to_string(),
    })?;
    let agc_plan = plan_realtek_table(
        BB_AGC_ARRAY,
        RealtekTableKind::BbAgc,
        &agc_values,
        condition_env,
    )
    .map_err(|error| DiagnosticErrorReport {
        code: "bb_agc_table_plan_failed",
        message: error.to_string(),
    })?;

    Ok((phy_plan, agc_plan))
}

fn load_mac_table_plan(
    source_path: &Path,
    condition_env: RealtekConditionEnv,
) -> std::result::Result<RealtekTablePlan, DiagnosticErrorReport> {
    let source = fs::read_to_string(source_path).map_err(|error| DiagnosticErrorReport {
        code: "mac_source_read_failed",
        message: format!("failed to read {}: {error}", source_path.display()),
    })?;

    let values =
        parse_realtek_u32_array(&source, MAC_REG_ARRAY).map_err(|error| DiagnosticErrorReport {
            code: "mac_table_parse_failed",
            message: error.to_string(),
        })?;
    plan_realtek_table(MAC_REG_ARRAY, RealtekTableKind::Mac, &values, condition_env).map_err(
        |error| DiagnosticErrorReport {
            code: "mac_table_plan_failed",
            message: error.to_string(),
        },
    )
}

fn run_mac_table_plan<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    plan: &RealtekTablePlan,
) -> std::result::Result<usize, DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let mut writes = 0usize;
    for action in &plan.actions {
        match action.kind {
            RealtekTableActionKind::Delay => {
                let delay_us = action.delay_us.unwrap_or_default();
                if delay_us > 0 {
                    std::thread::sleep(Duration::from_micros(delay_us));
                }
            }
            RealtekTableActionKind::Write => {
                let address = u16::try_from(action.address).map_err(|_| DiagnosticErrorReport {
                    code: "mac_table_address_out_of_range",
                    message: format!(
                        "{} pair {} address {} does not fit a USB register address",
                        plan.array_name, action.pair_index, action.address_hex
                    ),
                })?;
                let data = action.data.ok_or_else(|| DiagnosticErrorReport {
                    code: "mac_table_write_missing_data",
                    message: format!(
                        "{} pair {} is a write action with no data",
                        plan.array_name, action.pair_index
                    ),
                })?;
                write8_with_counter(registers, counters, address, data as u8).map_err(|error| {
                    DiagnosticErrorReport {
                        code: "mac_table_write_failed",
                        message: format!(
                            "{} pair {} write addr={} data={} failed: {error}",
                            plan.array_name,
                            action.pair_index,
                            action.address_hex,
                            action.data_hex.as_deref().unwrap_or("<missing>")
                        ),
                    }
                })?;
                writes += 1;
                std::thread::sleep(Duration::from_micros(1));
            }
        }
    }
    Ok(writes)
}

fn run_bb_sequence<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    args: &BbSmokeArgs,
    phy_plan: &RealtekTablePlan,
    agc_plan: &RealtekTablePlan,
    counters: &mut DiagnosticCounters,
    setup_steps: &mut Vec<QueueDmaStepReport>,
    stats: &mut BbSmokeStats,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    bb_preflight(registers, counters, setup_steps)?;
    mac_rmw8_step(
        registers,
        counters,
        setup_steps,
        MacRmw8Spec {
            phase: "bb_power",
            register_name: "REG_SYS_FUNC_EN",
            address: REG_SYS_FUNC_EN,
            preserve_mask: !FEN_USBA,
            value_mask: FEN_USBA,
            value: FEN_USBA,
            description: "enable USB analog path before BB/RF configuration",
            source: BB_SOURCE_PHYCFG,
        },
    )?;
    mac_rmw8_step(
        registers,
        counters,
        setup_steps,
        MacRmw8Spec {
            phase: "bb_power",
            register_name: "REG_SYS_FUNC_EN",
            address: REG_SYS_FUNC_EN,
            preserve_mask: !(FEN_USBA | FEN_BB_GLB_RSTN | FEN_BBRSTB),
            value_mask: FEN_USBA | FEN_BB_GLB_RSTN | FEN_BBRSTB,
            value: FEN_USBA | FEN_BB_GLB_RSTN | FEN_BBRSTB,
            description: "release BB global reset and BB reset before table programming",
            source: BB_SOURCE_PHYCFG,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        setup_steps,
        QueueWrite8Spec {
            phase: "bb_power",
            register_name: "REG_RF_CTRL",
            address: REG_RF_CTRL,
            value: 0x07,
            verify_mask: u8::MAX,
            verify_value: 0x07,
            description: "power on RF path A gate before BB table programming",
            source: BB_SOURCE_PHYCFG,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        setup_steps,
        QueueWrite8Spec {
            phase: "bb_power",
            register_name: "REG_RF_B_CTRL_8812",
            address: REG_RF_B_CTRL_8812,
            value: 0x07,
            verify_mask: u8::MAX,
            verify_value: 0x07,
            description: "power on RF path B gate before BB table programming",
            source: BB_SOURCE_PHYCFG,
        },
    )?;

    run_bb_table_plan(registers, counters, stats, phy_plan)?;
    run_bb_table_plan(registers, counters, stats, agc_plan)?;
    bb_masked_write32_step(
        registers,
        counters,
        setup_steps,
        BbMaskedWrite32Spec {
            phase: "bb_crystal_cap",
            register_name: "REG_MAC_PHY_CTRL",
            address: REG_MAC_PHY_CTRL,
            bitmask: RTL8812_CRYSTAL_CAP_MASK,
            data: u32::from((args.crystal_cap & 0x3f) | ((args.crystal_cap & 0x3f) << 6)),
            description: "set RTL8812A crystal-cap bits after BB and AGC table programming",
            source: "aircrack-ng/rtl8812au@7344855:hal/hal_com.c",
        },
    )
}

fn bb_preflight<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let cr = read16_with_counter(registers, counters, REG_CR).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("REG_CR preflight read failed: {error}"),
        }
    })?;
    let cr_passed = (cr & CR_ENABLE_BITS) == CR_ENABLE_BITS;
    steps.push(queue_read_report16(QueueRead16Spec {
        phase: "preflight",
        description: "verify command register block enables before BB programming",
        register_name: "REG_CR",
        address: REG_CR,
        value: cr,
        mask: Some(CR_ENABLE_BITS),
        expected: Some(CR_ENABLE_BITS),
        passed: cr_passed,
    }));
    if !cr_passed {
        return Err(DiagnosticErrorReport {
            code: "mac_not_powered_on",
            message: format!(
                "REG_CR expected block-enable mask {} to be set before BB programming, got {}",
                format_value(CR_ENABLE_BITS, 4),
                format_value(cr, 4)
            ),
        });
    }

    let mcu = read8_with_counter(registers, counters, REG_MCUFWDL).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("REG_MCUFWDL preflight read failed: {error}"),
        }
    })?;
    let firmware_ready_mask = RAM_DL_SEL | BIT6 | BIT1;
    let firmware_passed = (mcu & firmware_ready_mask) == firmware_ready_mask;
    steps.push(queue_read_report8(QueueRead8Spec {
        phase: "preflight",
        description: "verify firmware is running before BB programming",
        register_name: "REG_MCUFWDL",
        address: REG_MCUFWDL,
        value: mcu,
        mask: Some(firmware_ready_mask),
        expected: Some(firmware_ready_mask),
        passed: firmware_passed,
    }));
    if !firmware_passed {
        return Err(DiagnosticErrorReport {
            code: "firmware_not_ready",
            message: format!(
                "REG_MCUFWDL expected firmware-ready mask {} before BB programming, got {}",
                format_value(firmware_ready_mask, 2),
                format_value(mcu, 2)
            ),
        });
    }

    Ok(())
}

fn run_bb_table_plan<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    stats: &mut BbSmokeStats,
    plan: &RealtekTablePlan,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    for action in &plan.actions {
        match action.kind {
            RealtekTableActionKind::Delay => {
                let delay_us = action.delay_us.unwrap_or_default();
                if delay_us > 0 {
                    std::thread::sleep(Duration::from_micros(delay_us));
                }
                stats.delays_applied += 1;
            }
            RealtekTableActionKind::Write => {
                let address = u16::try_from(action.address).map_err(|_| DiagnosticErrorReport {
                    code: "bb_table_address_out_of_range",
                    message: format!(
                        "{} pair {} address {} does not fit a USB register address",
                        plan.array_name, action.pair_index, action.address_hex
                    ),
                })?;
                let bitmask = action.bitmask.unwrap_or(u32::MAX);
                let data = action.data.ok_or_else(|| DiagnosticErrorReport {
                    code: "bb_table_write_missing_data",
                    message: format!(
                        "{} pair {} is a write action with no data",
                        plan.array_name, action.pair_index
                    ),
                })?;
                bb_set_bb_reg(registers, counters, address, bitmask, data).map_err(|error| {
                    DiagnosticErrorReport {
                        code: "bb_table_write_failed",
                        message: format!(
                            "{} pair {} write addr={} data={} failed: {error}",
                            plan.array_name,
                            action.pair_index,
                            action.address_hex,
                            action.data_hex.as_deref().unwrap_or("<missing>")
                        ),
                    }
                })?;
                match plan.kind {
                    RealtekTableKind::Mac => {}
                    RealtekTableKind::BbPhy => stats.phy_writes_applied += 1,
                    RealtekTableKind::BbAgc => stats.agc_writes_applied += 1,
                    RealtekTableKind::RfRadioA | RealtekTableKind::RfRadioB => {}
                }
                std::thread::sleep(Duration::from_micros(1));
            }
        }
    }
    Ok(())
}

fn bb_set_bb_reg<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    address: u16,
    bitmask: u32,
    data: u32,
) -> std::result::Result<(), radio_core::Rtl8812auRegisterError>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    if bitmask == u32::MAX {
        return write32_with_counter(registers, counters, address, data);
    }

    if bitmask == 0 {
        return Ok(());
    }

    let original = read32_with_counter(registers, counters, address)?;
    let bitshift = bitmask.trailing_zeros();
    let written = (original & !bitmask) | ((data << bitshift) & bitmask);
    write32_with_counter(registers, counters, address, written)
}

#[derive(Debug, Clone, Copy)]
struct BbMaskedWrite32Spec {
    phase: &'static str,
    register_name: &'static str,
    address: u16,
    bitmask: u32,
    data: u32,
    description: &'static str,
    source: &'static str,
}

fn bb_masked_write32_step<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
    spec: BbMaskedWrite32Spec,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let before = read32_with_counter(registers, counters, spec.address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{} read before write failed: {error}", spec.register_name),
        }
    })?;
    let bitshift = spec.bitmask.trailing_zeros();
    let written = (before & !spec.bitmask) | ((spec.data << bitshift) & spec.bitmask);
    write32_with_counter(registers, counters, spec.address, written).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_write_failed",
            message: format!("{} write failed: {error}", spec.register_name),
        }
    })?;
    let after = read32_with_counter(registers, counters, spec.address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{} read after write failed: {error}", spec.register_name),
        }
    })?;
    let expected = (spec.data << bitshift) & spec.bitmask;
    let passed = (after & spec.bitmask) == expected;
    steps.push(QueueDmaStepReport {
        phase: spec.phase,
        operation: "masked_write32",
        description: spec.description,
        source: spec.source,
        register_name: spec.register_name,
        address: spec.address,
        address_hex: format_address(spec.address),
        width: "u32",
        mask_hex: Some(format_value(spec.bitmask, 8)),
        value_hex: Some(format_value(spec.data, 8)),
        before_hex: Some(format_value(before, 8)),
        written_hex: Some(format_value(written, 8)),
        after_hex: Some(format_value(after, 8)),
        expected_hex: Some(format_value(expected, 8)),
        passed,
    });

    if passed {
        Ok(())
    } else {
        Err(queue_readback_error(
            spec.register_name,
            format_value(spec.bitmask, 8),
            format_value(expected, 8),
            format_value(after & spec.bitmask, 8),
        ))
    }
}

fn rf_smoke_report(args: RfSmokeArgs) -> RfSmokeReport {
    let selector = args.adapter.selector();
    let condition_env = args.condition_env();
    let mut setup_steps = Vec::new();
    let mut counters = DiagnosticCounters::default();
    let mut stats = RfSmokeStats::default();

    let (radioa_plan, radiob_plan) = match load_rf_table_plans(&args.rf_source, condition_env) {
        Ok(plans) => plans,
        Err(error) => {
            return rf_smoke_failure(
                &args,
                RfSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    radioa_plan: None,
                    radiob_plan: None,
                    stats,
                    counters,
                    error,
                },
            );
        }
    };

    if !args.i_understand_this_writes_registers {
        return rf_smoke_failure(
            &args,
            RfSmokeFailureInput {
                condition_env,
                adapter: None,
                endpoints: None,
                setup_steps,
                radioa_plan: Some(radioa_plan),
                radiob_plan: Some(radiob_plan),
                stats,
                counters,
                error: DiagnosticErrorReport {
                    code: "missing_write_authorization",
                    message: "RF smoke writes hardware registers and requires --i-understand-this-writes-registers".to_string(),
                },
            },
        );
    }

    let selected = match select_supported_adapter(selector) {
        Ok(device) => device,
        Err(error) => {
            return rf_smoke_failure(
                &args,
                RfSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    radioa_plan: Some(radioa_plan),
                    radiob_plan: Some(radiob_plan),
                    stats,
                    counters,
                    error,
                },
            );
        }
    };

    let claimed = match radio_core::usb::claim_usb_device(&selected) {
        Ok(claimed) => claimed,
        Err(error) => {
            return rf_smoke_failure(
                &args,
                RfSmokeFailureInput {
                    condition_env,
                    adapter: Some(selected),
                    endpoints: None,
                    setup_steps,
                    radioa_plan: Some(radioa_plan),
                    radiob_plan: Some(radiob_plan),
                    stats,
                    counters,
                    error: DiagnosticErrorReport {
                        code: "usb_claim_failed",
                        message: error.to_string(),
                    },
                },
            );
        }
    };

    let adapter = claimed.info.clone();
    let endpoints = claimed.endpoints.clone();
    let registers =
        Rtl8812auRegisterAccess::new(&claimed).with_timeout(Duration::from_millis(args.timeout_ms));

    if let Err(error) = run_rf_sequence(
        &registers,
        &radioa_plan,
        &radiob_plan,
        &mut counters,
        &mut setup_steps,
        &mut stats,
    ) {
        return rf_smoke_failure(
            &args,
            RfSmokeFailureInput {
                condition_env,
                adapter: Some(adapter),
                endpoints: Some(endpoints),
                setup_steps,
                radioa_plan: Some(radioa_plan),
                radiob_plan: Some(radiob_plan),
                stats,
                counters,
                error,
            },
        );
    }

    RfSmokeReport {
        schema_version: 1,
        command: "rf-smoke",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        rf_source: args.rf_source,
        condition_env,
        timeout_ms: args.timeout_ms,
        result: DiagnosticResult::Pass,
        adapter: Some(adapter),
        endpoints: Some(endpoints),
        setup_steps,
        radioa_plan: Some(radioa_plan),
        radiob_plan: Some(radiob_plan),
        radioa_writes_applied: stats.radioa_writes_applied,
        radiob_writes_applied: stats.radiob_writes_applied,
        delays_applied: stats.delays_applied,
        counters,
        error: None,
        notes: vec![
            "guarded RF smoke test: RTL8812A radioA/radioB tables were parsed from external Realtek source and written through RF 3-wire BB registers",
            "no channel tuning, bulk traffic, RX loop, or TX operation was issued",
        ],
    }
}

fn rf_smoke_failure(args: &RfSmokeArgs, input: RfSmokeFailureInput) -> RfSmokeReport {
    rf_smoke_failure_with_command("rf-smoke", args, input)
}

fn rf_smoke_failure_with_command(
    command: &'static str,
    args: &RfSmokeArgs,
    input: RfSmokeFailureInput,
) -> RfSmokeReport {
    RfSmokeReport {
        schema_version: 1,
        command,
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector: args.adapter.selector(),
        rf_source: args.rf_source.clone(),
        condition_env: input.condition_env,
        timeout_ms: args.timeout_ms,
        result: DiagnosticResult::Fail,
        adapter: input.adapter,
        endpoints: input.endpoints,
        setup_steps: input.setup_steps,
        radioa_plan: input.radioa_plan,
        radiob_plan: input.radiob_plan,
        radioa_writes_applied: input.stats.radioa_writes_applied,
        radiob_writes_applied: input.stats.radiob_writes_applied,
        delays_applied: input.stats.delays_applied,
        counters: input.counters,
        error: Some(input.error),
        notes: vec![
            "guarded RF smoke test stopped before channel tuning, bulk traffic, RX loop, or TX operation",
        ],
    }
}

fn macos_rf_smoke_report(args: RfSmokeArgs) -> RfSmokeReport {
    let selector = args.adapter.selector();
    let condition_env = args.condition_env();
    let mut setup_steps = Vec::new();
    let mut counters = DiagnosticCounters::default();
    let mut stats = RfSmokeStats::default();

    let (radioa_plan, radiob_plan) = match load_rf_table_plans(&args.rf_source, condition_env) {
        Ok(plans) => plans,
        Err(error) => {
            return rf_smoke_failure_with_command(
                "macos-rf-smoke",
                &args,
                RfSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    radioa_plan: None,
                    radiob_plan: None,
                    stats,
                    counters,
                    error,
                },
            );
        }
    };

    if !args.i_understand_this_writes_registers {
        return rf_smoke_failure_with_command(
            "macos-rf-smoke",
            &args,
            RfSmokeFailureInput {
                condition_env,
                adapter: None,
                endpoints: None,
                setup_steps,
                radioa_plan: Some(radioa_plan),
                radiob_plan: Some(radiob_plan),
                stats,
                counters,
                error: DiagnosticErrorReport {
                    code: "missing_write_authorization",
                    message: "macOS IOUSBHost RF smoke writes hardware registers and requires --i-understand-this-writes-registers".to_string(),
                },
            },
        );
    }

    #[cfg(not(target_os = "macos"))]
    {
        return rf_smoke_failure_with_command(
            "macos-rf-smoke",
            &args,
            RfSmokeFailureInput {
                condition_env,
                adapter: None,
                endpoints: None,
                setup_steps,
                radioa_plan: Some(radioa_plan),
                radiob_plan: Some(radiob_plan),
                stats,
                counters,
                error: DiagnosticErrorReport {
                    code: "unsupported_platform",
                    message: "macos-rf-smoke requires macOS IOUSBHost".to_string(),
                },
            },
        );
    }

    #[cfg(target_os = "macos")]
    {
        let Some(vid) = selector.vid else {
            return rf_smoke_failure_with_command(
                "macos-rf-smoke",
                &args,
                RfSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    radioa_plan: Some(radioa_plan),
                    radiob_plan: Some(radiob_plan),
                    stats,
                    counters,
                    error: DiagnosticErrorReport {
                        code: "missing_vid",
                        message: "macos-rf-smoke requires --vid because IOUSBHost matching is VID/PID based".to_string(),
                    },
                },
            );
        };
        let Some(pid) = selector.pid else {
            return rf_smoke_failure_with_command(
                "macos-rf-smoke",
                &args,
                RfSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    radioa_plan: Some(radioa_plan),
                    radiob_plan: Some(radiob_plan),
                    stats,
                    counters,
                    error: DiagnosticErrorReport {
                        code: "missing_pid",
                        message: "macos-rf-smoke requires --pid because IOUSBHost matching is VID/PID based".to_string(),
                    },
                },
            );
        };

        let device = match macos_usbhost::MacosUsbHostDevice::open(vid, pid) {
            Ok(device) => device,
            Err(error) => {
                return rf_smoke_failure_with_command(
                    "macos-rf-smoke",
                    &args,
                    RfSmokeFailureInput {
                        condition_env,
                        adapter: None,
                        endpoints: None,
                        setup_steps,
                        radioa_plan: Some(radioa_plan),
                        radiob_plan: Some(radiob_plan),
                        stats,
                        counters,
                        error: DiagnosticErrorReport {
                            code: "macos_usbhost_open_failed",
                            message: error,
                        },
                    },
                );
            }
        };

        let registers = Rtl8812auRegisterAccess::new(&device)
            .with_timeout(Duration::from_millis(args.timeout_ms));
        if let Err(error) = run_rf_sequence(
            &registers,
            &radioa_plan,
            &radiob_plan,
            &mut counters,
            &mut setup_steps,
            &mut stats,
        ) {
            return rf_smoke_failure_with_command(
                "macos-rf-smoke",
                &args,
                RfSmokeFailureInput {
                    condition_env,
                    adapter: None,
                    endpoints: None,
                    setup_steps,
                    radioa_plan: Some(radioa_plan),
                    radiob_plan: Some(radiob_plan),
                    stats,
                    counters,
                    error,
                },
            );
        }

        RfSmokeReport {
            schema_version: 1,
            command: "macos-rf-smoke",
            started_at_unix_ms: started_at_unix_ms(),
            platform: platform_info(),
            selector,
            rf_source: args.rf_source,
            condition_env,
            timeout_ms: args.timeout_ms,
            result: DiagnosticResult::Pass,
            adapter: None,
            endpoints: None,
            setup_steps,
            radioa_plan: Some(radioa_plan),
            radiob_plan: Some(radiob_plan),
            radioa_writes_applied: stats.radioa_writes_applied,
            radiob_writes_applied: stats.radiob_writes_applied,
            delays_applied: stats.delays_applied,
            counters,
            error: None,
            notes: vec![
                "macOS IOUSBHost guarded RF smoke test: RTL8812A radioA/radioB tables were parsed from external Realtek source and written through default-control transfers",
                "no libusb enumeration, USB interface claim, channel tuning, bulk traffic, RX loop, or TX operation was issued",
            ],
        }
    }
}

fn load_rf_table_plans(
    source_path: &Path,
    condition_env: RealtekConditionEnv,
) -> std::result::Result<(RealtekTablePlan, RealtekTablePlan), DiagnosticErrorReport> {
    let source = fs::read_to_string(source_path).map_err(|error| DiagnosticErrorReport {
        code: "rf_source_read_failed",
        message: format!("failed to read {}: {error}", source_path.display()),
    })?;

    let radioa_values = parse_realtek_u32_array(&source, RF_RADIOA_ARRAY).map_err(|error| {
        DiagnosticErrorReport {
            code: "rf_radioa_table_parse_failed",
            message: error.to_string(),
        }
    })?;
    let radiob_values = parse_realtek_u32_array(&source, RF_RADIOB_ARRAY).map_err(|error| {
        DiagnosticErrorReport {
            code: "rf_radiob_table_parse_failed",
            message: error.to_string(),
        }
    })?;
    let radioa_plan = plan_realtek_table(
        RF_RADIOA_ARRAY,
        RealtekTableKind::RfRadioA,
        &radioa_values,
        condition_env,
    )
    .map_err(|error| DiagnosticErrorReport {
        code: "rf_radioa_table_plan_failed",
        message: error.to_string(),
    })?;
    let radiob_plan = plan_realtek_table(
        RF_RADIOB_ARRAY,
        RealtekTableKind::RfRadioB,
        &radiob_values,
        condition_env,
    )
    .map_err(|error| DiagnosticErrorReport {
        code: "rf_radiob_table_plan_failed",
        message: error.to_string(),
    })?;

    Ok((radioa_plan, radiob_plan))
}

fn run_rf_sequence<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    radioa_plan: &RealtekTablePlan,
    radiob_plan: &RealtekTablePlan,
    counters: &mut DiagnosticCounters,
    setup_steps: &mut Vec<QueueDmaStepReport>,
    stats: &mut RfSmokeStats,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    rf_preflight(registers, counters, setup_steps)?;
    run_rf_table_plan(registers, counters, stats, radioa_plan)?;
    run_rf_table_plan(registers, counters, stats, radiob_plan)
}

fn rf_preflight<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    bb_preflight(registers, counters, steps)?;
    let sys = read8_with_counter(registers, counters, REG_SYS_FUNC_EN).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("REG_SYS_FUNC_EN RF preflight read failed: {error}"),
        }
    })?;
    let expected = FEN_USBA | FEN_BB_GLB_RSTN | FEN_BBRSTB;
    let passed = (sys & expected) == expected;
    steps.push(QueueDmaStepReport {
        phase: "preflight",
        operation: "read8",
        description: "verify BB reset and USB analog path are enabled before RF 3-wire writes",
        source: RF_SOURCE_PHYCFG,
        register_name: "REG_SYS_FUNC_EN",
        address: REG_SYS_FUNC_EN,
        address_hex: format_address(REG_SYS_FUNC_EN),
        width: "u8",
        mask_hex: Some(format_value(expected, 2)),
        value_hex: None,
        before_hex: None,
        written_hex: None,
        after_hex: Some(format_value(sys, 2)),
        expected_hex: Some(format_value(expected, 2)),
        passed,
    });
    if !passed {
        return Err(DiagnosticErrorReport {
            code: "bb_not_ready",
            message: format!(
                "REG_SYS_FUNC_EN expected BB-ready mask {} before RF programming, got {}",
                format_value(expected, 2),
                format_value(sys, 2)
            ),
        });
    }
    Ok(())
}

fn run_rf_table_plan<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    counters: &mut DiagnosticCounters,
    stats: &mut RfSmokeStats,
    plan: &RealtekTablePlan,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let rf_3wire_register = match plan.kind {
        RealtekTableKind::RfRadioA => REG_RF_PATH_A_3WIRE,
        RealtekTableKind::RfRadioB => REG_RF_PATH_B_3WIRE,
        other => {
            return Err(DiagnosticErrorReport {
                code: "invalid_rf_table_kind",
                message: format!("{} has non-RF table kind {other:?}", plan.array_name),
            });
        }
    };

    for action in &plan.actions {
        match action.kind {
            RealtekTableActionKind::Delay => {
                let delay_us = action.delay_us.unwrap_or_default();
                if delay_us > 0 {
                    std::thread::sleep(Duration::from_micros(delay_us));
                }
                stats.delays_applied += 1;
            }
            RealtekTableActionKind::Write => {
                let data = action.data.ok_or_else(|| DiagnosticErrorReport {
                    code: "rf_table_write_missing_data",
                    message: format!(
                        "{} pair {} is a write action with no data",
                        plan.array_name, action.pair_index
                    ),
                })?;
                let encoded = encode_rf_serial_write(action.address, data);
                write32_with_counter(registers, counters, rf_3wire_register, encoded).map_err(
                    |error| DiagnosticErrorReport {
                        code: "rf_table_write_failed",
                        message: format!(
                            "{} pair {} RF addr={} data={} via {} failed: {error}",
                            plan.array_name,
                            action.pair_index,
                            action.address_hex,
                            action.data_hex.as_deref().unwrap_or("<missing>"),
                            format_address(rf_3wire_register)
                        ),
                    },
                )?;
                match plan.kind {
                    RealtekTableKind::RfRadioA => stats.radioa_writes_applied += 1,
                    RealtekTableKind::RfRadioB => stats.radiob_writes_applied += 1,
                    RealtekTableKind::Mac | RealtekTableKind::BbPhy | RealtekTableKind::BbAgc => {}
                }
                std::thread::sleep(Duration::from_micros(1));
            }
        }
    }

    Ok(())
}

fn encode_rf_serial_write(rf_offset: u32, data: u32) -> u32 {
    (((rf_offset & 0xff) << 20) | (data & 0x000f_ffff)) & 0x0fff_ffff
}

fn run_channel_sequence<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    channel: Channel,
    bandwidth: Bandwidth,
    rfe_type: u8,
    radioa_plan: &RealtekTablePlan,
    radiob_plan: &RealtekTablePlan,
    counters: &mut DiagnosticCounters,
    steps: &mut Vec<QueueDmaStepReport>,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let programming_channel_number = channel_programming_number(channel, bandwidth)?;
    let data_sc = data_secondary_channel_setting(channel, bandwidth)?;

    rf_preflight(registers, counters, steps)?;

    let mut rf_path_a = last_rf_register_data(radioa_plan, RF_CHNLBW_JAGUAR)?;
    let mut rf_path_b = last_rf_register_data(radiob_plan, RF_CHNLBW_JAGUAR)?;

    switch_wireless_band_8812(registers, counters, steps, channel.band, rfe_type)?;
    ensure_ofdmccken_tx_8812(registers, counters, steps)?;

    bb_masked_write32_step(
        registers,
        counters,
        steps,
        BbMaskedWrite32Spec {
            phase: "channel",
            register_name: "rFc_area_Jaguar",
            address: REG_FC_AREA_JAGUAR,
            bitmask: 0x1ffe_0000,
            data: fc_area_data(programming_channel_number),
            description: "program RTL8812A fc_area for the selected channel group",
            source: RF_SOURCE_PHYCFG,
        },
    )?;

    rf_path_a = apply_rf_mask(
        rf_path_a,
        RF_CHNLBW_MOD_AG_MASK,
        rf_mod_ag_data(programming_channel_number),
    );
    rf_serial_write_step(
        registers,
        counters,
        steps,
        RfSerialWriteSpec {
            phase: "channel",
            path: "A",
            bb_register_name: "rA_LSSIWrite_Jaguar",
            bb_register: REG_RF_PATH_A_3WIRE,
            rf_register_name: "RF_CHNLBW_Jaguar",
            rf_offset: RF_CHNLBW_JAGUAR,
            value: rf_path_a,
            description: "set RF path A MOD_AG bits for the selected channel group",
            source: RF_SOURCE_PHYCFG,
        },
    )?;
    fix_spur_8812a(
        registers,
        counters,
        steps,
        programming_channel_number,
        bandwidth,
    )?;
    rf_path_a = apply_rf_mask(
        rf_path_a,
        RF_CHNLBW_CHANNEL_MASK,
        u32::from(programming_channel_number),
    );
    rf_serial_write_step(
        registers,
        counters,
        steps,
        RfSerialWriteSpec {
            phase: "channel",
            path: "A",
            bb_register_name: "rA_LSSIWrite_Jaguar",
            bb_register: REG_RF_PATH_A_3WIRE,
            rf_register_name: "RF_CHNLBW_Jaguar",
            rf_offset: RF_CHNLBW_JAGUAR,
            value: rf_path_a,
            description: "set RF path A channel byte",
            source: RF_SOURCE_PHYCFG,
        },
    )?;

    rf_path_b = apply_rf_mask(
        rf_path_b,
        RF_CHNLBW_MOD_AG_MASK,
        rf_mod_ag_data(programming_channel_number),
    );
    rf_serial_write_step(
        registers,
        counters,
        steps,
        RfSerialWriteSpec {
            phase: "channel",
            path: "B",
            bb_register_name: "rB_LSSIWrite_Jaguar",
            bb_register: REG_RF_PATH_B_3WIRE,
            rf_register_name: "RF_CHNLBW_Jaguar",
            rf_offset: RF_CHNLBW_JAGUAR,
            value: rf_path_b,
            description: "set RF path B MOD_AG bits for the selected channel group",
            source: RF_SOURCE_PHYCFG,
        },
    )?;
    fix_spur_8812a(
        registers,
        counters,
        steps,
        programming_channel_number,
        bandwidth,
    )?;
    rf_path_b = apply_rf_mask(
        rf_path_b,
        RF_CHNLBW_CHANNEL_MASK,
        u32::from(programming_channel_number),
    );
    rf_serial_write_step(
        registers,
        counters,
        steps,
        RfSerialWriteSpec {
            phase: "channel",
            path: "B",
            bb_register_name: "rB_LSSIWrite_Jaguar",
            bb_register: REG_RF_PATH_B_3WIRE,
            rf_register_name: "RF_CHNLBW_Jaguar",
            rf_offset: RF_CHNLBW_JAGUAR,
            value: rf_path_b,
            description: "set RF path B channel byte",
            source: RF_SOURCE_PHYCFG,
        },
    )?;

    let wmac_bandwidth_bits = match bandwidth {
        Bandwidth::Mhz20 => 0x0000,
        Bandwidth::Mhz40 => 0x0080,
        Bandwidth::Mhz80 => 0x0100,
    };

    queue_rmw16_step(
        registers,
        counters,
        steps,
        QueueRmw16Spec {
            phase: "bandwidth",
            register_name: "REG_WMAC_TRXPTCL_CTL",
            address: REG_WMAC_TRXPTCL_CTL,
            preserve_mask: 0xfe7f,
            value_mask: 0x0180,
            value: wmac_bandwidth_bits,
            description: match bandwidth {
                Bandwidth::Mhz20 => "clear WMAC 40/80 MHz bandwidth bits for 20 MHz operation",
                Bandwidth::Mhz40 => "set WMAC 40 MHz bandwidth bit and clear 80 MHz bit",
                Bandwidth::Mhz80 => "set WMAC 80 MHz bandwidth bit and clear 40 MHz bit",
            },
            source: RF_SOURCE_PHYCFG,
        },
    )?;
    queue_write8_step(
        registers,
        counters,
        steps,
        QueueWrite8Spec {
            phase: "bandwidth",
            register_name: "REG_DATA_SC_8812",
            address: REG_DATA_SC_8812,
            value: data_sc,
            verify_mask: u8::MAX,
            verify_value: data_sc,
            description: match bandwidth {
                Bandwidth::Mhz20 => "clear secondary-channel data mapping for 20 MHz operation",
                Bandwidth::Mhz40 => {
                    "program primary 20 MHz subchannel mapping for 40 MHz operation"
                }
                Bandwidth::Mhz80 => {
                    "program primary 40/20 MHz subchannel mapping for 80 MHz operation"
                }
            },
            source: RF_SOURCE_PHYCFG,
        },
    )?;

    let bw_indication = read8_with_counter(registers, counters, REG_BW_INDICATION_JAGUAR + 3)
        .map_err(|error| DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("rBWIndication_Jaguar + 3 read failed: {error}"),
        })?;
    steps.push(QueueDmaStepReport {
        phase: "bandwidth",
        operation: "read8",
        description: "sample rBWIndication_Jaguar + 3, matching upstream post-bandwidth flow",
        source: RF_SOURCE_PHYCFG,
        register_name: "rBWIndication_Jaguar + 3",
        address: REG_BW_INDICATION_JAGUAR + 3,
        address_hex: format_address(REG_BW_INDICATION_JAGUAR + 3),
        width: "u8",
        mask_hex: None,
        value_hex: None,
        before_hex: None,
        written_hex: None,
        after_hex: Some(format_value(bw_indication, 2)),
        expected_hex: None,
        passed: true,
    });

    let rf_mode_data = match bandwidth {
        Bandwidth::Mhz20 => 0x0030_0200,
        Bandwidth::Mhz40 => 0x0030_0201,
        Bandwidth::Mhz80 => 0x0030_0202,
    };
    bb_masked_write32_step(
        registers,
        counters,
        steps,
        BbMaskedWrite32Spec {
            phase: "bandwidth",
            register_name: "rRFMOD_Jaguar",
            address: REG_RF_MOD_JAGUAR,
            bitmask: 0x0030_03c3,
            data: rf_mode_data,
            description: match bandwidth {
                Bandwidth::Mhz20 => "program BB RF mode fields for 20 MHz operation",
                Bandwidth::Mhz40 => "program BB RF mode fields for 40 MHz operation",
                Bandwidth::Mhz80 => "program BB RF mode fields for 80 MHz operation",
            },
            source: RF_SOURCE_PHYCFG,
        },
    )?;
    bb_masked_write32_step(
        registers,
        counters,
        steps,
        BbMaskedWrite32Spec {
            phase: "bandwidth",
            register_name: "rADC_Buf_Clk_Jaguar",
            address: REG_ADC_BUF_CLK_JAGUAR,
            bitmask: 1 << 30,
            data: if bandwidth == Bandwidth::Mhz80 { 1 } else { 0 },
            description: match bandwidth {
                Bandwidth::Mhz20 => "select the default ADC buffer clock for 20 MHz operation",
                Bandwidth::Mhz40 => "select the default ADC buffer clock for 40 MHz operation",
                Bandwidth::Mhz80 => "select the 80 MHz ADC buffer clock",
            },
            source: RF_SOURCE_PHYCFG,
        },
    )?;
    if matches!(bandwidth, Bandwidth::Mhz40 | Bandwidth::Mhz80) {
        bb_masked_write32_step(
            registers,
            counters,
            steps,
            BbMaskedWrite32Spec {
                phase: "bandwidth",
                register_name: "rRFMOD_Jaguar",
                address: REG_RF_MOD_JAGUAR,
                bitmask: 0x0000_003c,
                data: u32::from(data_sc),
                description: match bandwidth {
                    Bandwidth::Mhz40 => "mirror 40 MHz primary subchannel mapping into BB RF mode",
                    Bandwidth::Mhz80 => "mirror 80 MHz primary subchannel mapping into BB RF mode",
                    Bandwidth::Mhz20 => unreachable!("guarded by bandwidth match"),
                },
                source: RF_SOURCE_PHYCFG,
            },
        )?;
        bb_masked_write32_step(
            registers,
            counters,
            steps,
            BbMaskedWrite32Spec {
                phase: "bandwidth",
                register_name: "rCCAonSec_Jaguar",
                address: REG_CCA_ON_SEC_JAGUAR,
                bitmask: 0xf000_0000,
                data: u32::from(data_sc),
                description: match bandwidth {
                    Bandwidth::Mhz40 => "program CCA-on-secondary mapping for 40 MHz operation",
                    Bandwidth::Mhz80 => "program CCA-on-secondary mapping for 80 MHz operation",
                    Bandwidth::Mhz20 => unreachable!("guarded by bandwidth match"),
                },
                source: RF_SOURCE_PHYCFG,
            },
        )?;
    }

    let l1_peak = match bandwidth {
        Bandwidth::Mhz20 => 7,
        Bandwidth::Mhz40 if (bw_indication & BIT2) != 0 => 6,
        Bandwidth::Mhz40 => 7,
        Bandwidth::Mhz80 if (bw_indication & BIT2) != 0 => 5,
        Bandwidth::Mhz80 => 6,
    };
    bb_masked_write32_step(
        registers,
        counters,
        steps,
        BbMaskedWrite32Spec {
            phase: "bandwidth",
            register_name: "rL1PeakTH_Jaguar",
            address: REG_L1_PEAK_TH_JAGUAR,
            bitmask: 0x03c0_0000,
            data: l1_peak,
            description: match bandwidth {
                Bandwidth::Mhz20 => "set 2T2R L1 peak threshold for 20 MHz operation",
                Bandwidth::Mhz40 => "set 2T2R L1 peak threshold for 40 MHz operation",
                Bandwidth::Mhz80 => "set 2T2R L1 peak threshold for 80 MHz operation",
            },
            source: RF_SOURCE_PHYCFG,
        },
    )?;
    if bandwidth == Bandwidth::Mhz40 {
        bb_masked_write32_step(
            registers,
            counters,
            steps,
            BbMaskedWrite32Spec {
                phase: "bandwidth",
                register_name: "rCCK_System_Jaguar",
                address: REG_CCK_SYSTEM_JAGUAR,
                bitmask: 0x10,
                data: if data_sc == VHT_DATA_SC_20_UPPER_OF_80MHZ {
                    1
                } else {
                    0
                },
                description: "program CCK sideband selection for 40 MHz operation",
                source: RF_SOURCE_PHYCFG,
            },
        )?;
    }
    fix_spur_8812a(
        registers,
        counters,
        steps,
        programming_channel_number,
        bandwidth,
    )?;

    let rf_bandwidth_bits = match bandwidth {
        Bandwidth::Mhz20 => 3,
        Bandwidth::Mhz40 => 1,
        Bandwidth::Mhz80 => 0,
    };
    rf_path_a = apply_rf_mask(rf_path_a, RF_CHNLBW_BW_MASK, rf_bandwidth_bits);
    rf_serial_write_step(
        registers,
        counters,
        steps,
        RfSerialWriteSpec {
            phase: "bandwidth",
            path: "A",
            bb_register_name: "rA_LSSIWrite_Jaguar",
            bb_register: REG_RF_PATH_A_3WIRE,
            rf_register_name: "RF_CHNLBW_Jaguar",
            rf_offset: RF_CHNLBW_JAGUAR,
            value: rf_path_a,
            description: match bandwidth {
                Bandwidth::Mhz20 => "set RF path A bandwidth bits to 20 MHz",
                Bandwidth::Mhz40 => "set RF path A bandwidth bits to 40 MHz",
                Bandwidth::Mhz80 => "set RF path A bandwidth bits to 80 MHz",
            },
            source: RF_SOURCE_RF6052,
        },
    )?;
    rf_path_b = apply_rf_mask(rf_path_b, RF_CHNLBW_BW_MASK, rf_bandwidth_bits);
    rf_serial_write_step(
        registers,
        counters,
        steps,
        RfSerialWriteSpec {
            phase: "bandwidth",
            path: "B",
            bb_register_name: "rB_LSSIWrite_Jaguar",
            bb_register: REG_RF_PATH_B_3WIRE,
            rf_register_name: "RF_CHNLBW_Jaguar",
            rf_offset: RF_CHNLBW_JAGUAR,
            value: rf_path_b,
            description: match bandwidth {
                Bandwidth::Mhz20 => "set RF path B bandwidth bits to 20 MHz",
                Bandwidth::Mhz40 => "set RF path B bandwidth bits to 40 MHz",
                Bandwidth::Mhz80 => "set RF path B bandwidth bits to 80 MHz",
            },
            source: RF_SOURCE_RF6052,
        },
    )?;

    if should_apply_captured_tx_bringup_tail(channel, bandwidth) {
        apply_captured_tx_bringup_tail_8812a(registers, counters, steps, bandwidth)?;
    }

    Ok(())
}

fn should_apply_captured_tx_bringup_tail(channel: Channel, bandwidth: Bandwidth) -> bool {
    channel.band == Band::Ghz5 && matches!(bandwidth, Bandwidth::Mhz20 | Bandwidth::Mhz40)
}

