fn add_counters(left: &mut DiagnosticCounters, right: DiagnosticCounters) {
    left.usb_control_reads += right.usb_control_reads;
    left.usb_control_writes += right.usb_control_writes;
    left.usb_bulk_in_reads += right.usb_bulk_in_reads;
    left.usb_bulk_out_writes += right.usb_bulk_out_writes;
    left.rx_frames += right.rx_frames;
    left.tx_frames += right.tx_frames;
    left.dropped_frames += right.dropped_frames;
}

fn rx_scan_wfb_forward_config(
    args: &RxScanArgs,
) -> std::result::Result<Option<RxScanWfbForwardConfig>, DiagnosticErrorReport> {
    wfb_forward_config_from_parts(
        args.wfb_link_id,
        args.wfb_radio_port,
        args.rx_aggregator,
        args.rx_wlan_idx,
        args.rx_mcs_index,
        args.bandwidth,
    )
}

fn bridge_run_wfb_forward_config(
    args: &BridgeRunArgs,
) -> std::result::Result<Option<RxScanWfbForwardConfig>, DiagnosticErrorReport> {
    wfb_forward_config_from_parts(
        args.wfb_link_id,
        args.wfb_radio_port,
        args.rx_aggregator,
        args.rx_wlan_idx,
        args.rx_mcs_index,
        args.tx.bandwidth,
    )
}

fn bridge_run_wfb_forward_configs(
    args: &BridgeRunArgs,
) -> std::result::Result<Vec<RxScanWfbForwardConfig>, DiagnosticErrorReport> {
    let mut configs = Vec::new();
    if let Some(config) = bridge_run_wfb_forward_config(args)? {
        configs.push(config);
    }
    for forward in &args.rx_forwards {
        let link_id = match forward.link_id.or(args.wfb_link_id) {
            Some(link_id) => link_id,
            None => {
                return Err(DiagnosticErrorReport {
                    code: "missing_wfb_rx_forward_link_id",
                    message: "--rx-forward RADIO_PORT=HOST:PORT requires --wfb-link-id; use LINK_ID:RADIO_PORT=HOST:PORT to make it self-contained".to_string(),
                });
            }
        };
        let channel_id = WfbChannelId::new(link_id, forward.radio_port).map_err(|error| {
            DiagnosticErrorReport {
                code: "invalid_wfb_rx_channel_id",
                message: error.to_string(),
            }
        })?;
        configs.push(RxScanWfbForwardConfig {
            config: RxForwardConfig {
                channel_id,
                wlan_idx: args.rx_wlan_idx,
                mcs_index: args.rx_mcs_index,
                bandwidth_mhz: args.tx.bandwidth.mhz() as u8,
            },
            aggregator: Some(forward.aggregator),
        });
    }
    Ok(configs)
}

fn wfb_forward_config_from_parts(
    wfb_link_id: Option<u32>,
    wfb_radio_port: Option<u8>,
    rx_aggregator: Option<SocketAddr>,
    rx_wlan_idx: u8,
    rx_mcs_index: u8,
    bandwidth: Bandwidth,
) -> std::result::Result<Option<RxScanWfbForwardConfig>, DiagnosticErrorReport> {
    match (wfb_link_id, wfb_radio_port) {
        (None, None) if rx_aggregator.is_none() => Ok(None),
        (None, None) => Err(DiagnosticErrorReport {
            code: "missing_wfb_rx_filter",
            message: "--rx-aggregator requires --wfb-link-id and --wfb-radio-port".to_string(),
        }),
        (Some(_), None) | (None, Some(_)) => Err(DiagnosticErrorReport {
            code: "incomplete_wfb_rx_filter",
            message: "--wfb-link-id and --wfb-radio-port must be supplied together".to_string(),
        }),
        (Some(link_id), Some(radio_port)) => {
            let channel_id =
                WfbChannelId::new(link_id, radio_port).map_err(|error| DiagnosticErrorReport {
                    code: "invalid_wfb_rx_channel_id",
                    message: error.to_string(),
                })?;
            Ok(Some(RxScanWfbForwardConfig {
                config: RxForwardConfig {
                    channel_id,
                    wlan_idx: rx_wlan_idx,
                    mcs_index: rx_mcs_index,
                    bandwidth_mhz: bandwidth.mhz() as u8,
                },
                aggregator: rx_aggregator,
            }))
        }
    }
}

fn rx_scan_report(args: RxScanArgs) -> PendingDiagnosticReport {
    let (channel, result, error) = resolve_report_channel(args.channel, args.bandwidth);
    if !args.fixture_bulk_in.is_empty() && result != DiagnosticResult::Fail {
        return rx_scan_fixture_report(args, channel.expect("channel resolved"));
    }

    if result == DiagnosticResult::Fail {
        return pending_report(PendingReportInput {
            command: "rx-scan",
            selector: args.adapter.selector(),
            adapter: None,
            endpoints: None,
            channel,
            bandwidth: Some(args.bandwidth),
            firmware_path: None,
            firmware: None,
            init_dry_run: None,
            init_live: None,
            duration_ms: Some(args.duration_ms),
            pcap_path: args.pcap,
            tx_frame_len: None,
            tx_frame_source: None,
            tx_dry_run: None,
            tx_live: None,
            rx_fixture: None,
            repeat_tx: None,
            counters: DiagnosticCounters::default(),
            result,
            phases: vec![DiagnosticPhase {
                id: "argument_validation",
                status: DiagnosticPhaseStatus::Blocked,
                detail: "channel or bandwidth arguments are not supported",
            }],
            error,
            notes: vec!["live RX aborted before claiming USB"],
        });
    }

    let wfb_forward_config = match rx_scan_wfb_forward_config(&args) {
        Ok(config) => config,
        Err(error) => {
            return pending_report(PendingReportInput {
                command: "rx-scan",
                selector: args.adapter.selector(),
                adapter: None,
                endpoints: None,
                channel,
                bandwidth: Some(args.bandwidth),
                firmware_path: None,
                firmware: None,
                init_dry_run: None,
                init_live: None,
                duration_ms: Some(args.duration_ms),
                pcap_path: args.pcap,
                tx_frame_len: None,
                tx_frame_source: None,
                tx_dry_run: None,
                tx_live: None,
                rx_fixture: None,
                repeat_tx: None,
                counters: DiagnosticCounters::default(),
                result: DiagnosticResult::Fail,
                phases: vec![DiagnosticPhase {
                    id: "argument_validation",
                    status: DiagnosticPhaseStatus::Blocked,
                    detail: "WFB RX forwarding arguments are invalid",
                }],
                error: Some(error),
                notes: vec!["live RX aborted before claiming USB"],
            });
        }
    };

    let init_assets = match load_rx_scan_init_assets(&args) {
        Ok(init_assets) => init_assets,
        Err(error) => {
            return pending_report(PendingReportInput {
                command: "rx-scan",
                selector: args.adapter.selector(),
                adapter: None,
                endpoints: None,
                channel,
                bandwidth: Some(args.bandwidth),
                firmware_path: args.firmware.clone(),
                firmware: None,
                init_dry_run: None,
                init_live: None,
                duration_ms: Some(args.duration_ms),
                pcap_path: args.pcap,
                tx_frame_len: None,
                tx_frame_source: None,
                tx_dry_run: None,
                tx_live: None,
                rx_fixture: None,
                repeat_tx: None,
                counters: DiagnosticCounters::default(),
                result: DiagnosticResult::Fail,
                phases: vec![DiagnosticPhase {
                    id: "argument_validation",
                    status: DiagnosticPhaseStatus::Blocked,
                    detail: "rx-scan same-session init arguments did not pass local validation",
                }],
                error: Some(error),
                notes: vec!["live RX aborted before claiming USB or writing hardware registers"],
            });
        }
    };
    let init_bridge_args = args.init_before_rx.then(|| rx_scan_init_bridge_args(&args));
    let init_firmware_path = init_assets
        .as_ref()
        .map(|assets| assets.firmware_path.clone());
    let init_firmware = init_assets.as_ref().map(|assets| assets.firmware.clone());
    let selector = args.adapter.selector();
    let (mut session, claim_detail) = if args.macos_usbhost.enabled {
        match open_macos_usbhost_transport(&args.macos_usbhost, selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "opened retained macOS IOUSBHost session for live RX",
            ),
            Err(error) => {
                return pending_report(PendingReportInput {
                    command: "rx-scan",
                    selector,
                    adapter: None,
                    endpoints: None,
                    channel,
                    bandwidth: Some(args.bandwidth),
                    firmware_path: None,
                    firmware: None,
                    init_dry_run: None,
                    init_live: None,
                    duration_ms: Some(args.duration_ms),
                    pcap_path: args.pcap,
                    tx_frame_len: None,
                    tx_frame_source: None,
                    tx_dry_run: None,
                    tx_live: None,
                    rx_fixture: None,
                    repeat_tx: None,
                    counters: DiagnosticCounters::default(),
                    result: DiagnosticResult::Fail,
                    phases: vec![DiagnosticPhase {
                        id: "usb_claim",
                        status: DiagnosticPhaseStatus::Blocked,
                        detail: "macOS IOUSBHost retained-session open failed",
                    }],
                    error: Some(error),
                    notes: vec!["live RX stopped before bulk IN reads"],
                });
            }
        }
    } else {
        match open_libusb_transport(selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "claimed initialized adapter for live RX",
            ),
            Err(error) => {
                return pending_report(PendingReportInput {
                    command: "rx-scan",
                    selector,
                    adapter: None,
                    endpoints: None,
                    channel,
                    bandwidth: Some(args.bandwidth),
                    firmware_path: None,
                    firmware: None,
                    init_dry_run: None,
                    init_live: None,
                    duration_ms: Some(args.duration_ms),
                    pcap_path: args.pcap,
                    tx_frame_len: None,
                    tx_frame_source: None,
                    tx_dry_run: None,
                    tx_live: None,
                    rx_fixture: None,
                    repeat_tx: None,
                    counters: DiagnosticCounters::default(),
                    result: DiagnosticResult::Fail,
                    phases: vec![DiagnosticPhase {
                        id: "usb_claim",
                        status: DiagnosticPhaseStatus::Blocked,
                        detail: "runtime USB transport open failed",
                    }],
                    error: Some(error),
                    notes: vec!["live RX stopped before bulk IN reads"],
                });
            }
        }
    };
    match session.selected_bulk_in_endpoint() {
        Some(_) => {}
        None => {
            return pending_report(PendingReportInput {
                command: "rx-scan",
                selector,
                adapter: Some(session.adapter.clone()),
                endpoints: Some(session.endpoints.clone()),
                channel,
                bandwidth: Some(args.bandwidth),
                firmware_path: None,
                firmware: None,
                init_dry_run: None,
                init_live: None,
                duration_ms: Some(args.duration_ms),
                pcap_path: args.pcap,
                tx_frame_len: None,
                tx_frame_source: None,
                tx_dry_run: None,
                tx_live: None,
                rx_fixture: None,
                repeat_tx: None,
                counters: diagnostic_counters_from_runtime(session.counters),
                result: DiagnosticResult::Fail,
                phases: vec![DiagnosticPhase {
                    id: "bulk_in_loop",
                    status: DiagnosticPhaseStatus::Blocked,
                    detail: "claimed interface has no bulk IN endpoint",
                }],
                error: Some(DiagnosticErrorReport {
                    code: "missing_bulk_in_endpoint",
                    message: "claimed interface has no bulk IN endpoint".to_string(),
                }),
                notes: vec!["live RX stopped before bulk IN reads"],
            });
        }
    };

    let channel = channel.expect("channel resolved before live RX");
    let mut pre_rx_counters = diagnostic_counters_from_runtime(session.counters);
    let mut init_live = None;
    if let (Some(init_assets), Some(init_bridge_args)) =
        (init_assets.as_ref(), init_bridge_args.as_ref())
    {
        match run_bridge_tx_bench_same_session_init(
            &mut session,
            init_bridge_args,
            channel,
            init_assets,
        ) {
            Ok(init_report) => {
                pre_rx_counters = diagnostic_counters_from_runtime(session.counters);
                init_live = Some(same_session_init_into_init_live(init_report));
            }
            Err((init_report, error)) => {
                pre_rx_counters = diagnostic_counters_from_runtime(session.counters);
                init_live = Some(same_session_init_into_init_live(init_report));
                return pending_report(PendingReportInput {
                    command: "rx-scan",
                    selector,
                    adapter: Some(session.adapter.clone()),
                    endpoints: Some(session.endpoints.clone()),
                    channel: Some(channel),
                    bandwidth: Some(args.bandwidth),
                    firmware_path: init_firmware_path,
                    firmware: init_firmware,
                    init_dry_run: None,
                    init_live,
                    duration_ms: Some(args.duration_ms),
                    pcap_path: args.pcap,
                    tx_frame_len: None,
                    tx_frame_source: None,
                    tx_dry_run: None,
                    tx_live: None,
                    rx_fixture: None,
                    repeat_tx: None,
                    counters: pre_rx_counters,
                    result: DiagnosticResult::Fail,
                    phases: vec![
                        DiagnosticPhase {
                            id: "usb_claim",
                            status: DiagnosticPhaseStatus::Completed,
                            detail: claim_detail,
                        },
                        DiagnosticPhase {
                            id: "init_before_rx",
                            status: DiagnosticPhaseStatus::Blocked,
                            detail: "rx-scan same-session init failed before the bulk IN loop",
                        },
                    ],
                    error: Some(error),
                    notes: vec![
                        "live RX stopped before bulk IN capture because same-session init failed",
                    ],
                });
            }
        }
    }

    if args.monitor_opmode_before_rx {
        let registers = Rtl8812auRegisterAccess::new(&session.transport)
            .with_timeout(Duration::from_millis(args.init_timeout_ms));
        if let Err(error) = bridge_tx_bench_set_monitor_opmode(&registers, &mut pre_rx_counters) {
            return pending_report(PendingReportInput {
                command: "rx-scan",
                selector,
                adapter: Some(session.adapter.clone()),
                endpoints: Some(session.endpoints.clone()),
                channel: Some(channel),
                bandwidth: Some(args.bandwidth),
                firmware_path: init_firmware_path,
                firmware: init_firmware,
                init_dry_run: None,
                init_live,
                duration_ms: Some(args.duration_ms),
                pcap_path: args.pcap,
                tx_frame_len: None,
                tx_frame_source: None,
                tx_dry_run: None,
                tx_live: None,
                rx_fixture: None,
                repeat_tx: None,
                counters: pre_rx_counters,
                result: DiagnosticResult::Fail,
                phases: vec![
                    DiagnosticPhase {
                        id: "usb_claim",
                        status: DiagnosticPhaseStatus::Completed,
                        detail: claim_detail,
                    },
                    DiagnosticPhase {
                        id: "monitor_opmode",
                        status: DiagnosticPhaseStatus::Blocked,
                        detail: "rx-scan monitor/no-link receive filter setup failed before the bulk IN loop",
                    },
                ],
                error: Some(error),
                notes: vec![
                    "live RX stopped before bulk IN capture because monitor receive setup failed",
                ],
            });
        }
    }

    let pcap_path = args.pcap.clone();
    let frame_jsonl_path = args.frame_jsonl.clone();
    match run_rx_bulk_in_capture(
        &mut session,
        channel,
        args.duration_ms,
        args.timeout_ms,
        pcap_path.as_deref(),
        frame_jsonl_path.as_deref(),
        wfb_forward_config,
    ) {
        Ok((rx_fixture, mut counters)) => {
            add_counters(&mut counters, pre_rx_counters);
            let mut phases = vec![DiagnosticPhase {
                id: "usb_claim",
                status: DiagnosticPhaseStatus::Completed,
                detail: claim_detail,
            }];
            if args.init_before_rx {
                phases.push(DiagnosticPhase {
                    id: "init_before_rx",
                    status: DiagnosticPhaseStatus::Completed,
                    detail: "completed full RTL8812AU init inside the retained RX USB session",
                });
            }
            if args.monitor_opmode_before_rx {
                phases.push(DiagnosticPhase {
                    id: "monitor_opmode",
                    status: DiagnosticPhaseStatus::Completed,
                    detail: "set Linux-style monitor/no-link receive filtering before capture",
                });
            }
            phases.push(DiagnosticPhase {
                id: "bulk_in_loop",
                status: DiagnosticPhaseStatus::Completed,
                detail: "read bounded buffers from the RTL8812AU bulk IN endpoint",
            });
            phases.push(DiagnosticPhase {
                id: "pcap",
                status: DiagnosticPhaseStatus::Completed,
                detail: "optional PCAP output completed",
            });
            let notes = if args.init_before_rx && args.monitor_opmode_before_rx {
                vec![
                    "live RX initialized the adapter, set monitor/no-link receive filtering, and captured bulk-IN traffic over one retained USB session",
                    "no bulk OUT frame submissions or TX operations were issued",
                ]
            } else if args.init_before_rx {
                vec![
                    "live RX initialized the adapter and captured bulk-IN traffic over one retained USB session",
                    "no bulk OUT frame submissions or TX operations were issued",
                ]
            } else if args.monitor_opmode_before_rx {
                vec![
                    "live RX set monitor/no-link receive filtering on an already-initialized adapter before capture",
                    "no bulk OUT frame submissions or TX operations were issued",
                ]
            } else {
                vec![
                    "live RX assumes the adapter has already completed init on the requested channel",
                    "no control writes, bulk OUT frame submissions, or TX operations were issued",
                ]
            };
            pending_report(PendingReportInput {
                command: "rx-scan",
                selector,
                adapter: Some(session.adapter.clone()),
                endpoints: Some(session.endpoints.clone()),
                channel: Some(channel),
                bandwidth: Some(args.bandwidth),
                firmware_path: init_firmware_path,
                firmware: init_firmware,
                init_dry_run: None,
                init_live,
                duration_ms: Some(args.duration_ms),
                pcap_path,
                tx_frame_len: None,
                tx_frame_source: None,
                tx_dry_run: None,
                tx_live: None,
                rx_fixture: Some(rx_fixture),
                repeat_tx: None,
                counters,
                result: DiagnosticResult::Pass,
                phases,
                error: None,
                notes,
            })
        }
        Err(error) => pending_report(PendingReportInput {
            command: "rx-scan",
            selector,
            adapter: Some(session.adapter.clone()),
            endpoints: Some(session.endpoints.clone()),
            channel: Some(channel),
            bandwidth: Some(args.bandwidth),
            firmware_path: init_firmware_path,
            firmware: init_firmware,
            init_dry_run: None,
            init_live,
            duration_ms: Some(args.duration_ms),
            pcap_path,
            tx_frame_len: None,
            tx_frame_source: None,
            tx_dry_run: None,
            tx_live: None,
            rx_fixture: None,
            repeat_tx: None,
            counters: pre_rx_counters,
            result: DiagnosticResult::Fail,
            phases: vec![DiagnosticPhase {
                id: "bulk_in_loop",
                status: DiagnosticPhaseStatus::Blocked,
                detail: "bulk IN capture failed",
            }],
            error: Some(error),
            notes: vec!["live RX stopped during bulk IN capture"],
        }),
    }
}

fn run_rx_bulk_in_capture(
    session: &mut RuntimeRadioSession<RuntimeUsbTransport>,
    channel: Channel,
    duration_ms: u64,
    timeout_ms: u64,
    pcap_path: Option<&Path>,
    frame_jsonl_path: Option<&Path>,
    wfb_forward_config: Option<RxScanWfbForwardConfig>,
) -> std::result::Result<(RxFixtureReport, DiagnosticCounters), DiagnosticErrorReport> {
    let bulk_in_endpoint =
        session
            .selected_bulk_in_endpoint()
            .ok_or_else(|| DiagnosticErrorReport {
                code: "missing_bulk_in_endpoint",
                message: "runtime radio session has no selected bulk IN endpoint".to_string(),
            })?;
    let mut report = RxFixtureReport {
        frame_jsonl_path: frame_jsonl_path.map(Path::to_path_buf),
        ..RxFixtureReport::default()
    };
    let mut pcap = create_optional_pcap(pcap_path)?;
    let mut frame_jsonl = create_optional_frame_jsonl(frame_jsonl_path)?;
    let mut wfb_forwards = create_wfb_forwards(wfb_forward_config.into_iter().collect())?;
    let timeout_ms = timeout_ms.clamp(1, duration_ms.max(1));
    let per_read_timeout = Duration::from_millis(timeout_ms);
    let deadline = Instant::now() + Duration::from_millis(duration_ms);
    let mut buf = vec![0u8; 16 * 1024];

    while Instant::now() < deadline {
        let remaining = deadline.saturating_duration_since(Instant::now());
        if remaining.is_zero() {
            break;
        }
        let timeout = per_read_timeout.min(remaining);
        match session.read_rx_packets(channel, &mut buf, timeout) {
            Ok(read) if read.bytes_read == 0 => {
                report.buffers_read += 1;
            }
            Ok(read) => {
                report.buffers_read += 1;
                report.bulk_bytes += read.bytes_read as u64;
                debug_assert_eq!(read.endpoint, bulk_in_endpoint);
                process_rx_packet_outcomes(
                    &mut report,
                    &mut pcap,
                    &mut frame_jsonl,
                    &mut wfb_forwards,
                    channel,
                    &read.packets,
                )?;
            }
            Err(error) if error.timeout => {
                report.read_timeouts += 1;
            }
            Err(error) => {
                return Err(DiagnosticErrorReport {
                    code: "bulk_in_read_failed",
                    message: format!(
                        "bulk IN read from endpoint 0x{bulk_in_endpoint:02x} failed: {error}"
                    ),
                });
            }
        }
    }

    flush_optional_pcap(&mut pcap)?;
    flush_optional_frame_jsonl(&mut frame_jsonl)?;
    set_rx_wfb_forward_reports(&mut report, wfb_forwards);
    let counters = DiagnosticCounters {
        usb_bulk_in_reads: report.buffers_read + report.read_timeouts,
        rx_frames: report.parsed_frames,
        dropped_frames: report.dropped_packets,
        ..DiagnosticCounters::default()
    };
    Ok((report, counters))
}

fn create_optional_pcap(
    pcap_path: Option<&Path>,
) -> std::result::Result<Option<PcapWriter<File>>, DiagnosticErrorReport> {
    match pcap_path {
        Some(path) => Ok(Some(
            PcapWriter::new(File::create(path).map_err(|error| DiagnosticErrorReport {
                code: "pcap_create_failed",
                message: format!("failed to create {}: {error}", path.display()),
            })?)
            .map_err(|error| DiagnosticErrorReport {
                code: "pcap_header_write_failed",
                message: format!("failed to write PCAP header: {error}"),
            })?,
        )),
        None => Ok(None),
    }
}

fn create_optional_frame_jsonl(
    frame_jsonl_path: Option<&Path>,
) -> std::result::Result<Option<File>, DiagnosticErrorReport> {
    match frame_jsonl_path {
        Some(path) => File::create(path)
            .map(Some)
            .map_err(|error| DiagnosticErrorReport {
                code: "frame_jsonl_create_failed",
                message: format!("failed to create {}: {error}", path.display()),
            }),
        None => Ok(None),
    }
}

fn create_wfb_forwards(
    configs: Vec<RxScanWfbForwardConfig>,
) -> std::result::Result<Vec<RxWfbForwardRuntime>, DiagnosticErrorReport> {
    configs.into_iter().map(create_wfb_forward).collect()
}

fn create_wfb_forward(
    config: RxScanWfbForwardConfig,
) -> std::result::Result<RxWfbForwardRuntime, DiagnosticErrorReport> {
    let socket = match config.aggregator {
        Some(_) => Some(
            UdpSocket::bind("0.0.0.0:0").map_err(|error| DiagnosticErrorReport {
                code: "rx_forward_socket_bind_failed",
                message: format!("failed to bind WFB RX forwarding UDP socket: {error}"),
            })?,
        ),
        None => None,
    };
    let channel_id = config.config.channel_id;
    Ok(RxWfbForwardRuntime {
        config: config.config,
        socket,
        aggregator: config.aggregator,
        report: RxWfbForwardReport {
            link_id: channel_id.link_id,
            link_id_hex: format_value(channel_id.link_id, 6),
            radio_port: channel_id.radio_port,
            radio_port_hex: format_value(channel_id.radio_port, 2),
            aggregator: config.aggregator,
            wlan_idx: config.config.wlan_idx,
            mcs_index: config.config.mcs_index,
            bandwidth_mhz: config.config.bandwidth_mhz,
            forwarded_bytes: 0,
            counters: RxCounters::default(),
        },
    })
}

fn set_rx_wfb_forward_reports(report: &mut RxFixtureReport, runtimes: Vec<RxWfbForwardRuntime>) {
    let reports: Vec<RxWfbForwardReport> =
        runtimes.into_iter().map(|runtime| runtime.report).collect();
    report.wfb_forward = reports.first().cloned();
    report.wfb_forwards = reports;
}

fn set_rx_wfb_forward_reports_from_runtime(
    report: &mut RxFixtureReport,
    snapshots: Vec<ProductionRuntimeRxForwardSnapshot>,
) {
    let reports: Vec<RxWfbForwardReport> = snapshots
        .into_iter()
        .map(|snapshot| {
            let channel_id = snapshot.config.channel_id;
            RxWfbForwardReport {
                link_id: channel_id.link_id,
                link_id_hex: format_value(channel_id.link_id, 6),
                radio_port: channel_id.radio_port,
                radio_port_hex: format_value(channel_id.radio_port, 2),
                aggregator: snapshot.aggregator,
                wlan_idx: snapshot.config.wlan_idx,
                mcs_index: snapshot.config.mcs_index,
                bandwidth_mhz: snapshot.config.bandwidth_mhz,
                forwarded_bytes: snapshot.forwarded_bytes,
                counters: snapshot.counters,
            }
        })
        .collect();
    report.wfb_forward = reports.first().cloned();
    report.wfb_forwards = reports;
}

fn bridge_run_runtime_forward_plans(
    configs: &[RxScanWfbForwardConfig],
) -> Vec<ProductionRuntimeRxForwardPlan> {
    configs
        .iter()
        .map(|config| ProductionRuntimeRxForwardPlan {
            config: config.config,
            aggregator: config.aggregator,
        })
        .collect()
}

fn process_rx_buffer(
    report: &mut RxFixtureReport,
    pcap: &mut Option<PcapWriter<File>>,
    frame_jsonl: &mut Option<File>,
    wfb_forwards: &mut [RxWfbForwardRuntime],
    channel: Channel,
    buf: &[u8],
) -> std::result::Result<(), DiagnosticErrorReport> {
    let mut offset = 0usize;
    while offset < buf.len() {
        let parsed = parse_rx_packet(&buf[offset..], channel);
        match parsed.outcome {
            RxParseOutcome::Frame => {
                let frame = parsed.frame.expect("frame outcome includes frame");
                report.parsed_frames += 1;
                count_rx_metadata(report, &frame);
                count_rx_frame_type(report, &frame.data);
                process_wfb_rx_forwards(wfb_forwards, &frame)?;
                if let Some(writer) = pcap.as_mut() {
                    writer
                        .write_frame(SystemTime::now(), &frame.data)
                        .map_err(|error| DiagnosticErrorReport {
                            code: "pcap_packet_write_failed",
                            message: format!("failed to write PCAP packet: {error}"),
                        })?;
                    report.pcap_frames_written += 1;
                }
                if let Some(writer) = frame_jsonl.as_mut() {
                    write_rx_frame_record(writer, channel, &frame)?;
                    report.frame_records_written += 1;
                }
                advance_fixture_offset(&mut offset, parsed.consumed, buf.len(), report);
            }
            RxParseOutcome::Drop => {
                report.dropped_packets += 1;
                advance_fixture_offset(&mut offset, parsed.consumed, buf.len(), report);
            }
            RxParseOutcome::NeedMoreData => {
                report.need_more_data += 1;
                break;
            }
        }
    }
    Ok(())
}

fn process_rx_packet_outcomes(
    report: &mut RxFixtureReport,
    pcap: &mut Option<PcapWriter<File>>,
    frame_jsonl: &mut Option<File>,
    wfb_forwards: &mut [RxWfbForwardRuntime],
    channel: Channel,
    packets: &[radio_core::ParsedRxPacket],
) -> std::result::Result<(), DiagnosticErrorReport> {
    for parsed in packets {
        match parsed.outcome {
            RxParseOutcome::Frame => {
                let frame = parsed.frame.as_ref().expect("frame outcome includes frame");
                report.parsed_frames += 1;
                count_rx_metadata(report, frame);
                count_rx_frame_type(report, &frame.data);
                process_wfb_rx_forwards(wfb_forwards, frame)?;
                if let Some(writer) = pcap.as_mut() {
                    writer
                        .write_frame(SystemTime::now(), &frame.data)
                        .map_err(|error| DiagnosticErrorReport {
                            code: "pcap_packet_write_failed",
                            message: format!("failed to write PCAP packet: {error}"),
                        })?;
                    report.pcap_frames_written += 1;
                }
                if let Some(writer) = frame_jsonl.as_mut() {
                    write_rx_frame_record(writer, channel, frame)?;
                    report.frame_records_written += 1;
                }
            }
            RxParseOutcome::Drop => {
                report.dropped_packets += 1;
            }
            RxParseOutcome::NeedMoreData => {
                report.need_more_data += 1;
            }
        }
    }
    Ok(())
}

fn apply_runtime_rx_packet_telemetry(
    report: &mut RxFixtureReport,
    telemetry: wfb_radio_runtime::ProductionRuntimeRxPacketTelemetry,
) {
    report.parsed_frames = report.parsed_frames.saturating_add(telemetry.parsed_frames);
    report.phy_status_frames = report
        .phy_status_frames
        .saturating_add(telemetry.phy_status_frames);
    report.rssi_valid_frames = report
        .rssi_valid_frames
        .saturating_add(telemetry.rssi_valid_frames);
    report.snr_frames = report.snr_frames.saturating_add(telemetry.snr_frames);
    report.noise_frames = report.noise_frames.saturating_add(telemetry.noise_frames);
    report.dropped_packets = report
        .dropped_packets
        .saturating_add(telemetry.dropped_packets);
    report.need_more_data = report
        .need_more_data
        .saturating_add(telemetry.need_more_data);
    report.management_frames = report
        .management_frames
        .saturating_add(telemetry.management_frames);
    report.control_frames = report
        .control_frames
        .saturating_add(telemetry.control_frames);
    report.data_frames = report.data_frames.saturating_add(telemetry.data_frames);
    report.extension_frames = report
        .extension_frames
        .saturating_add(telemetry.extension_frames);
}

fn write_rx_packet_side_outputs(
    report: &mut RxFixtureReport,
    pcap: &mut Option<PcapWriter<File>>,
    frame_jsonl: &mut Option<File>,
    channel: Channel,
    packets: &[radio_core::ParsedRxPacket],
) -> std::result::Result<(), DiagnosticErrorReport> {
    for parsed in packets {
        if parsed.outcome != RxParseOutcome::Frame {
            continue;
        }
        let frame = parsed.frame.as_ref().expect("frame outcome includes frame");
        if let Some(writer) = pcap.as_mut() {
            writer
                .write_frame(SystemTime::now(), &frame.data)
                .map_err(|error| DiagnosticErrorReport {
                    code: "pcap_packet_write_failed",
                    message: format!("failed to write PCAP packet: {error}"),
                })?;
            report.pcap_frames_written += 1;
        }
        if let Some(writer) = frame_jsonl.as_mut() {
            write_rx_frame_record(writer, channel, frame)?;
            report.frame_records_written += 1;
        }
    }
    Ok(())
}

fn count_rx_metadata(report: &mut RxFixtureReport, frame: &radio_core::RxFrame) {
    if frame.phy_status {
        report.phy_status_frames += 1;
    }
    if frame.rssi_dbm_valid {
        report.rssi_valid_frames += 1;
    }
    if frame.snr_db.is_some() {
        report.snr_frames += 1;
    }
    if frame.noise_dbm.is_some() {
        report.noise_frames += 1;
    }
}

fn process_wfb_rx_forwards(
    wfb_forwards: &mut [RxWfbForwardRuntime],
    frame: &radio_core::RxFrame,
) -> std::result::Result<(), DiagnosticErrorReport> {
    for runtime in wfb_forwards {
        process_wfb_rx_forward(runtime, frame)?;
    }
    Ok(())
}

fn process_wfb_rx_forward(
    runtime: &mut RxWfbForwardRuntime,
    frame: &radio_core::RxFrame,
) -> std::result::Result<(), DiagnosticErrorReport> {
    let Some(packet) =
        build_rx_forward_datagram(frame, runtime.config, &mut runtime.report.counters)
    else {
        return Ok(());
    };
    if let (Some(socket), Some(aggregator)) = (runtime.socket.as_ref(), runtime.aggregator) {
        let bytes = socket.send_to(&packet, aggregator).map_err(|error| {
            runtime.report.counters.send_failed += 1;
            DiagnosticErrorReport {
                code: "rx_forward_send_failed",
                message: format!("failed to send WFB RX datagram to {aggregator}: {error}"),
            }
        })?;
        runtime.report.counters.forwarded += 1;
        runtime.report.forwarded_bytes += bytes as u64;
    }
    Ok(())
}

fn flush_optional_pcap(
    pcap: &mut Option<PcapWriter<File>>,
) -> std::result::Result<(), DiagnosticErrorReport> {
    if let Some(writer) = pcap.as_mut() {
        writer.flush().map_err(|error| DiagnosticErrorReport {
            code: "pcap_flush_failed",
            message: format!("failed to flush PCAP: {error}"),
        })?;
    }
    Ok(())
}

fn flush_optional_frame_jsonl(
    frame_jsonl: &mut Option<File>,
) -> std::result::Result<(), DiagnosticErrorReport> {
    if let Some(writer) = frame_jsonl.as_mut() {
        writer.flush().map_err(|error| DiagnosticErrorReport {
            code: "frame_jsonl_flush_failed",
            message: format!("failed to flush frame JSONL: {error}"),
        })?;
    }
    Ok(())
}

fn write_rx_frame_record(
    writer: &mut File,
    channel: Channel,
    frame: &radio_core::RxFrame,
) -> std::result::Result<(), DiagnosticErrorReport> {
    let frame_type = frame_type(&frame.data)
        .map(|kind| format!("{kind:?}"))
        .unwrap_or_else(|_| "Malformed".to_string());
    let record = RxFrameJsonRecord {
        timestamp_unix_ms: started_at_unix_ms(),
        frame_len: frame.data.len(),
        rssi_dbm: frame.rssi_dbm,
        rssi_dbm_valid: frame.rssi_dbm_valid,
        rssi_dbm_source: frame.rssi_dbm_source,
        noise_dbm: frame.noise_dbm,
        snr_db: frame.snr_db,
        snr_db_source: frame.snr_db_source,
        channel,
        frequency_mhz: channel.frequency_mhz,
        band: channel.band,
        phy_status: frame.phy_status,
        driver_info_size: frame.driver_info_size,
        rx_shift: frame.rx_shift,
        raw_phy_status_len: frame.raw_phy_status.len(),
        raw_phy_status_hex: encode_hex(&frame.raw_phy_status),
        rx_rate_raw: frame.rx_rate_raw,
        rx_rate_raw_hex: format!("0x{:02x}", frame.rx_rate_raw),
        rx_rate: frame.rx_rate,
        rx_bandwidth_raw: frame.rx_bandwidth_raw,
        rx_bandwidth_mhz: frame.rx_bandwidth.map(|bandwidth| bandwidth.mhz()),
        short_gi: frame.short_gi,
        ldpc: frame.ldpc,
        stbc: frame.stbc,
        frame_type,
        frame_hex: encode_hex(&frame.data),
    };
    serde_json::to_writer(&mut *writer, &record).map_err(|error| DiagnosticErrorReport {
        code: "frame_jsonl_write_failed",
        message: format!("failed to encode frame JSONL record: {error}"),
    })?;
    writer
        .write_all(b"\n")
        .map_err(|error| DiagnosticErrorReport {
            code: "frame_jsonl_write_failed",
            message: format!("failed to write frame JSONL newline: {error}"),
        })
}

fn rx_scan_fixture_report(args: RxScanArgs, channel: Channel) -> PendingDiagnosticReport {
    let pcap_path = args.pcap.clone();
    let frame_jsonl_path = args.frame_jsonl.clone();
    let (result, rx_fixture, counters, error, phases, notes) = match parse_rx_fixture_files(
        &args.fixture_bulk_in,
        channel,
        pcap_path.as_deref(),
        frame_jsonl_path.as_deref(),
    ) {
        Ok((fixture, counters)) => (
            DiagnosticResult::Pass,
            Some(fixture),
            counters,
            None,
            vec![
                DiagnosticPhase {
                    id: "fixture_bulk_in",
                    status: DiagnosticPhaseStatus::Completed,
                    detail: "parsed raw RTL8812AU bulk-IN fixture buffers",
                },
                DiagnosticPhase {
                    id: "pcap",
                    status: DiagnosticPhaseStatus::Completed,
                    detail: "optional PCAP output completed",
                },
            ],
            vec!["fixture mode only: no USB bulk IN reads were issued"],
        ),
        Err(error) => (
            DiagnosticResult::Fail,
            None,
            DiagnosticCounters::default(),
            Some(error),
            vec![DiagnosticPhase {
                id: "fixture_bulk_in",
                status: DiagnosticPhaseStatus::Blocked,
                detail: "fixture parsing failed before live RX was attempted",
            }],
            vec!["fixture mode only: no USB bulk IN reads were issued"],
        ),
    };

    pending_report(PendingReportInput {
        command: "rx-scan",
        selector: args.adapter.selector(),
        adapter: None,
        endpoints: None,
        channel: Some(channel),
        bandwidth: Some(args.bandwidth),
        firmware_path: None,
        firmware: None,
        init_dry_run: None,
        init_live: None,
        duration_ms: Some(args.duration_ms),
        pcap_path,
        tx_frame_len: None,
        tx_frame_source: None,
        tx_dry_run: None,
        tx_live: None,
        rx_fixture,
        repeat_tx: None,
        counters,
        result,
        phases,
        error,
        notes,
    })
}

fn parse_rx_fixture_files(
    paths: &[PathBuf],
    channel: Channel,
    pcap_path: Option<&Path>,
    frame_jsonl_path: Option<&Path>,
) -> std::result::Result<(RxFixtureReport, DiagnosticCounters), DiagnosticErrorReport> {
    let mut report = RxFixtureReport {
        fixture_paths: paths.to_vec(),
        frame_jsonl_path: frame_jsonl_path.map(Path::to_path_buf),
        ..RxFixtureReport::default()
    };
    let mut pcap = create_optional_pcap(pcap_path)?;
    let mut frame_jsonl = create_optional_frame_jsonl(frame_jsonl_path)?;
    let mut wfb_forwards = Vec::new();

    for path in paths {
        let buf = fs::read(path).map_err(|error| DiagnosticErrorReport {
            code: "fixture_read_failed",
            message: format!("failed to read {}: {error}", path.display()),
        })?;
        report.buffers_read += 1;
        report.bulk_bytes += buf.len() as u64;
        process_rx_buffer(
            &mut report,
            &mut pcap,
            &mut frame_jsonl,
            &mut wfb_forwards,
            channel,
            &buf,
        )?;
    }

    flush_optional_pcap(&mut pcap)?;
    flush_optional_frame_jsonl(&mut frame_jsonl)?;

    let counters = DiagnosticCounters {
        usb_bulk_in_reads: report.buffers_read + report.read_timeouts,
        rx_frames: report.parsed_frames,
        dropped_frames: report.dropped_packets,
        ..DiagnosticCounters::default()
    };
    Ok((report, counters))
}

fn advance_fixture_offset(
    offset: &mut usize,
    consumed: usize,
    buf_len: usize,
    report: &mut RxFixtureReport,
) {
    if consumed == 0 {
        report.need_more_data += 1;
        *offset = buf_len;
        return;
    }
    let remaining = buf_len.saturating_sub(*offset);
    report.bytes_consumed += consumed.min(remaining) as u64;
    *offset = (*offset + consumed).min(buf_len);
}

fn count_rx_frame_type(report: &mut RxFixtureReport, frame: &[u8]) {
    match frame_type(frame) {
        Ok(FrameType::Management) => report.management_frames += 1,
        Ok(FrameType::Control) => report.control_frames += 1,
        Ok(FrameType::Data) => report.data_frames += 1,
        Ok(FrameType::Extension) => report.extension_frames += 1,
        Err(_) => report.dropped_packets += 1,
    }
}

fn tx_once_report(args: TxOnceArgs) -> PendingDiagnosticReport {
    let (channel, mut result, mut error) = resolve_report_channel(args.channel, args.bandwidth);
    let mut tx_dry_run = None;
    let (tx_frame_len, tx_frame_source) =
        validate_tx_frame_arg(args.frame_hex.as_deref(), &mut result, &mut error);

    if args.packet_out.is_some() && !args.dry_run && result != DiagnosticResult::Fail {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "packet_out_requires_dry_run",
            message: "--packet-out is only valid with --dry-run".to_string(),
        });
    }
    if args.tx_led.tx_led && args.dry_run && result != DiagnosticResult::Fail {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "tx_led_requires_live_tx",
            message: "--tx-led is only valid for live TX commands".to_string(),
        });
    }
    if tx_status_enabled(&args.tx_status) && args.dry_run && result != DiagnosticResult::Fail {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "tx_status_requires_live_tx",
            message: "--tx-status is only valid for live TX commands".to_string(),
        });
    }
    if args.tx_led.tx_led
        && args.tx_led.tx_led_hold_ms > MAX_TX_LED_HOLD_MS
        && result != DiagnosticResult::Fail
    {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_tx_led_hold",
            message: format!("--tx-led-hold-ms must be <= {MAX_TX_LED_HOLD_MS}"),
        });
    }
    if tx_status_enabled(&args.tx_status)
        && args.tx_status.tx_status_delay_ms > MAX_TX_STATUS_DELAY_MS
        && result != DiagnosticResult::Fail
    {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_tx_status_delay",
            message: format!("--tx-status-delay-ms must be <= {MAX_TX_STATUS_DELAY_MS}"),
        });
    }
    if tx_status_enabled(&args.tx_status)
        && args.tx_status.tx_status_poll_count > MAX_TX_STATUS_POLL_COUNT
        && result != DiagnosticResult::Fail
    {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_tx_status_poll_count",
            message: format!("--tx-status-poll-count must be <= {MAX_TX_STATUS_POLL_COUNT}"),
        });
    }
    if tx_status_enabled(&args.tx_status)
        && tx_status_total_poll_ms(&args.tx_status) > MAX_TX_STATUS_TOTAL_POLL_MS
        && result != DiagnosticResult::Fail
    {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_tx_status_poll_total",
            message: format!(
                "--tx-status-poll-ms multiplied by --tx-status-poll-count must be <= {MAX_TX_STATUS_TOTAL_POLL_MS}"
            ),
        });
    }

    if args.dry_run && result != DiagnosticResult::Fail {
        match args.frame_hex.as_deref() {
            Some(hex) => match build_tx_dry_run_report(
                hex,
                channel.expect("channel resolved before dry run"),
                args.bandwidth,
                &args.tx_options,
                args.packet_out.clone(),
            ) {
                Ok(report) => {
                    result = DiagnosticResult::Pass;
                    tx_dry_run = Some(report);
                }
                Err(report_error) => {
                    result = DiagnosticResult::Fail;
                    error = Some(report_error);
                }
            },
            None => {
                result = DiagnosticResult::Fail;
                error = Some(DiagnosticErrorReport {
                    code: "missing_frame_hex",
                    message: "--dry-run requires --frame-hex so no test frame is invented"
                        .to_string(),
                });
            }
        }
    }

    if !args.dry_run && result != DiagnosticResult::Fail {
        if args.frame_hex.is_none() {
            result = DiagnosticResult::Fail;
            error = Some(DiagnosticErrorReport {
                code: "missing_frame_hex",
                message: "live tx-once requires --frame-hex so no test frame is invented"
                    .to_string(),
            });
        } else if !args.i_understand_this_transmits {
            result = DiagnosticResult::Fail;
            error = Some(DiagnosticErrorReport {
                code: "missing_tx_authorization",
                message: "live tx-once requires --i-understand-this-transmits".to_string(),
            });
        }
    }

    if !args.dry_run && result != DiagnosticResult::Fail {
        return tx_once_live_report(
            args,
            channel.expect("channel resolved before live tx"),
            tx_frame_len,
            tx_frame_source,
        );
    }

    let phases = if result == DiagnosticResult::Fail {
        vec![DiagnosticPhase {
            id: "argument_validation",
            status: DiagnosticPhaseStatus::Blocked,
            detail: "TX arguments did not pass local validation",
        }]
    } else if args.dry_run {
        vec![DiagnosticPhase {
            id: "tx_descriptor",
            status: DiagnosticPhaseStatus::Completed,
            detail: "built descriptor-prefixed packet without touching USB",
        }]
    } else {
        vec![
            DiagnosticPhase {
                id: "init",
                status: DiagnosticPhaseStatus::Pending,
                detail: "requires completed radio initialization",
            },
            DiagnosticPhase {
                id: "tx_descriptor",
                status: DiagnosticPhaseStatus::Pending,
                detail: "build RTL8812AU descriptor for one validated IEEE 802.11 frame",
            },
            DiagnosticPhase {
                id: "bulk_out",
                status: DiagnosticPhaseStatus::Pending,
                detail: "write one descriptor-prefixed frame to the bulk OUT endpoint",
            },
        ]
    };

    pending_report(PendingReportInput {
        command: "tx-once",
        selector: args.adapter.selector(),
        adapter: None,
        endpoints: None,
        channel,
        bandwidth: Some(args.bandwidth),
        firmware_path: None,
        firmware: None,
        init_dry_run: None,
        init_live: None,
        duration_ms: None,
        pcap_path: None,
        tx_frame_len,
        tx_frame_source,
        tx_dry_run,
        tx_live: None,
        rx_fixture: None,
        repeat_tx: None,
        counters: DiagnosticCounters::default(),
        result,
        phases,
        error,
        notes: if args.dry_run {
            vec!["dry run only: no USB bulk OUT write was issued"]
        } else {
            vec!["live TX requires --frame-hex and --i-understand-this-transmits"]
        },
    })
}

fn tx_once_live_report(
    args: TxOnceArgs,
    channel: Channel,
    tx_frame_len: Option<usize>,
    tx_frame_source: Option<&'static str>,
) -> PendingDiagnosticReport {
    let selector = args.adapter.selector();
    let bandwidth = args.bandwidth;
    let frame_hex = args
        .frame_hex
        .as_deref()
        .expect("live tx frame hex was validated");
    let frame = match parse_hex_bytes(frame_hex) {
        Ok(frame) => frame,
        Err(error) => {
            return tx_once_live_failure(TxOnceLiveFailureInput {
                selector,
                adapter: None,
                endpoints: None,
                channel,
                bandwidth,
                tx_frame_len,
                tx_frame_source,
                counters: DiagnosticCounters::default(),
                phase_id: "argument_validation",
                phase_detail: "TX frame hex could not be parsed",
                error: DiagnosticErrorReport {
                    code: "invalid_frame_hex",
                    message: error,
                },
            });
        }
    };
    let opts = tx_options_from_args(bandwidth, &args.tx_options);
    let packet_len = match build_tx_packet(&frame, channel, opts) {
        Ok(packet) => packet.len(),
        Err(error) => {
            return tx_once_live_failure(TxOnceLiveFailureInput {
                selector,
                adapter: None,
                endpoints: None,
                channel,
                bandwidth,
                tx_frame_len,
                tx_frame_source,
                counters: DiagnosticCounters::default(),
                phase_id: "tx_descriptor",
                phase_detail: "TX descriptor construction failed",
                error: DiagnosticErrorReport {
                    code: "tx_descriptor_failed",
                    message: error.to_string(),
                },
            });
        }
    };

    let (mut session, claim_detail) = if args.macos_usbhost.enabled {
        match open_macos_usbhost_transport(&args.macos_usbhost, selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "opened retained macOS IOUSBHost session for live TX",
            ),
            Err(error) => {
                return tx_once_live_failure(TxOnceLiveFailureInput {
                    selector,
                    adapter: None,
                    endpoints: None,
                    channel,
                    bandwidth,
                    tx_frame_len,
                    tx_frame_source,
                    counters: DiagnosticCounters::default(),
                    phase_id: "usb_claim",
                    phase_detail: "macOS IOUSBHost retained-session open failed",
                    error,
                });
            }
        }
    } else {
        match open_libusb_transport(selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "claimed initialized adapter for live TX",
            ),
            Err(error) => {
                return tx_once_live_failure(TxOnceLiveFailureInput {
                    selector,
                    adapter: None,
                    endpoints: None,
                    channel,
                    bandwidth,
                    tx_frame_len,
                    tx_frame_source,
                    counters: DiagnosticCounters::default(),
                    phase_id: "usb_claim",
                    phase_detail: "runtime USB transport open failed",
                    error,
                });
            }
        }
    };
    let bulk_out = match session.selected_bulk_out_endpoint() {
        Some(endpoint) => endpoint,
        None => {
            return tx_once_live_failure(TxOnceLiveFailureInput {
                selector,
                adapter: Some(session.adapter.clone()),
                endpoints: Some(session.endpoints.clone()),
                channel,
                bandwidth,
                tx_frame_len,
                tx_frame_source,
                counters: diagnostic_counters_from_runtime(session.counters),
                phase_id: "bulk_out",
                phase_detail: "claimed interface has no bulk OUT endpoint",
                error: DiagnosticErrorReport {
                    code: "missing_bulk_out_endpoint",
                    message: "claimed interface has no bulk OUT endpoint".to_string(),
                },
            });
        }
    };

    let mut submit_counters = TxSubmitCounters::default();
    let mut tx_activity_led = tx_activity_led_report(&args.tx_led);
    let mut tx_status = tx_status_probe_report(&args.tx_status);
    if tx_activity_led.is_some() || tx_status.is_some() {
        let registers = Rtl8812auRegisterAccess::new(&session.transport);
        tx_activity_led_step(&registers, &mut tx_activity_led, LedAction::On);
        tx_status_probe_pre(&registers, &mut tx_status);
    }
    match session.submit_80211_frame(&frame, channel, opts, &mut submit_counters) {
        Ok(bytes_written) => {
            if tx_status.is_some() {
                let registers = Rtl8812auRegisterAccess::new(&session.transport);
                tx_status_probe_post(&registers, &mut tx_status);
                tx_status_attach_rf_summary(&mut tx_status, &submit_counters);
            }
            tx_activity_led_hold(&tx_activity_led);
            if tx_activity_led.is_some() {
                let registers = Rtl8812auRegisterAccess::new(&session.transport);
                tx_activity_led_step(&registers, &mut tx_activity_led, LedAction::Off);
            }
            let mut counters = DiagnosticCounters {
                usb_control_writes: session.counters.usb_control_writes,
                usb_bulk_out_writes: submit_counters.submitted,
                tx_frames: submit_counters.submitted,
                ..DiagnosticCounters::default()
            };
            add_tx_activity_led_counters(&mut counters, &tx_activity_led);
            add_tx_status_probe_counters(&mut counters, &tx_status);
            pending_report(PendingReportInput {
                command: "tx-once",
                selector,
                adapter: Some(session.adapter.clone()),
                endpoints: Some(session.endpoints.clone()),
                channel: Some(channel),
                bandwidth: Some(bandwidth),
                firmware_path: None,
                firmware: None,
                init_dry_run: None,
                init_live: None,
                duration_ms: None,
                pcap_path: None,
                tx_frame_len,
                tx_frame_source,
                tx_dry_run: None,
                tx_live: Some(TxLiveReport {
                    bulk_out_endpoint: bulk_out,
                    bulk_out_endpoint_hex: format_value(bulk_out, 2),
                    frame_len: frame.len(),
                    packet_len,
                    bytes_written,
                    tx_options: opts,
                    tx_activity_led,
                    tx_status,
                    submit_counters,
                }),
                rx_fixture: None,
                repeat_tx: None,
                counters,
                result: DiagnosticResult::Pass,
                phases: vec![
                    DiagnosticPhase {
                        id: "usb_claim",
                        status: DiagnosticPhaseStatus::Completed,
                        detail: claim_detail,
                    },
                    DiagnosticPhase {
                        id: "tx_descriptor",
                        status: DiagnosticPhaseStatus::Completed,
                        detail: "built RTL8812AU descriptor for one validated IEEE 802.11 frame",
                    },
                    DiagnosticPhase {
                        id: "bulk_out",
                        status: DiagnosticPhaseStatus::Completed,
                        detail: "wrote one descriptor-prefixed frame to the bulk OUT endpoint",
                    },
                ],
                error: None,
                notes: vec![
                    "live TX assumes the adapter has already completed init on the requested channel",
                    "one descriptor-prefixed frame was submitted; no RX loop was started",
                ],
            })
        }
        Err(error) => {
            if tx_status.is_some() {
                let registers = Rtl8812auRegisterAccess::new(&session.transport);
                tx_status_probe_post(&registers, &mut tx_status);
                tx_status_attach_rf_summary(&mut tx_status, &submit_counters);
            }
            tx_activity_led_hold(&tx_activity_led);
            if tx_activity_led.is_some() {
                let registers = Rtl8812auRegisterAccess::new(&session.transport);
                tx_activity_led_step(&registers, &mut tx_activity_led, LedAction::Off);
            }
            let mut counters = DiagnosticCounters {
                usb_control_writes: session.counters.usb_control_writes,
                usb_bulk_out_writes: submit_counters.submitted + submit_counters.failed,
                tx_frames: submit_counters.submitted,
                ..DiagnosticCounters::default()
            };
            add_tx_activity_led_counters(&mut counters, &tx_activity_led);
            add_tx_status_probe_counters(&mut counters, &tx_status);
            tx_once_live_failure(TxOnceLiveFailureInput {
                selector,
                adapter: Some(session.adapter.clone()),
                endpoints: Some(session.endpoints.clone()),
                channel,
                bandwidth,
                tx_frame_len,
                tx_frame_source,
                counters,
                phase_id: "bulk_out",
                phase_detail: "bulk OUT frame submission failed",
                error: DiagnosticErrorReport {
                    code: "tx_submit_failed",
                    message: error.to_string(),
                },
            })
        }
    }
}

struct TxOnceLiveFailureInput {
    selector: DeviceSelector,
    adapter: Option<UsbDeviceInfo>,
    endpoints: Option<UsbEndpoints>,
    channel: Channel,
    bandwidth: Bandwidth,
    tx_frame_len: Option<usize>,
    tx_frame_source: Option<&'static str>,
    counters: DiagnosticCounters,
    phase_id: &'static str,
    phase_detail: &'static str,
    error: DiagnosticErrorReport,
}

fn tx_once_live_failure(input: TxOnceLiveFailureInput) -> PendingDiagnosticReport {
    pending_report(PendingReportInput {
        command: "tx-once",
        selector: input.selector,
        adapter: input.adapter,
        endpoints: input.endpoints,
        channel: Some(input.channel),
        bandwidth: Some(input.bandwidth),
        firmware_path: None,
        firmware: None,
        init_dry_run: None,
        init_live: None,
        duration_ms: None,
        pcap_path: None,
        tx_frame_len: input.tx_frame_len,
        tx_frame_source: input.tx_frame_source,
        tx_dry_run: None,
        tx_live: None,
        rx_fixture: None,
        repeat_tx: None,
        counters: input.counters,
        result: DiagnosticResult::Fail,
        phases: vec![DiagnosticPhase {
            id: input.phase_id,
            status: DiagnosticPhaseStatus::Blocked,
            detail: input.phase_detail,
        }],
        error: Some(input.error),
        notes: vec!["live TX stopped before a verified single-frame submission"],
    })
}

fn tx_repeat_report(args: TxRepeatArgs) -> PendingDiagnosticReport {
    let (channel, mut result, mut error) = resolve_report_channel(args.channel, args.bandwidth);
    let (tx_frame_len, tx_frame_source) =
        validate_tx_frame_arg(args.frame_hex.as_deref(), &mut result, &mut error);

    if args.frame_hex.is_none() && result != DiagnosticResult::Fail {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "missing_frame_hex",
            message: "live tx-repeat requires --frame-hex so no test frame is invented".to_string(),
        });
    }
    if !args.i_understand_this_transmits && result != DiagnosticResult::Fail {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "missing_tx_authorization",
            message: "repeated TX requires --i-understand-this-transmits".to_string(),
        });
    }
    if args.count == 0 && result != DiagnosticResult::Fail {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_repeat_count",
            message: "--count must be greater than zero".to_string(),
        });
    }
    if args.interval_ms == 0 && result != DiagnosticResult::Fail {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_repeat_interval",
            message: "--interval-ms must be greater than zero".to_string(),
        });
    }
    if args.tx_led.tx_led
        && args.tx_led.tx_led_hold_ms > MAX_TX_LED_HOLD_MS
        && result != DiagnosticResult::Fail
    {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_tx_led_hold",
            message: format!("--tx-led-hold-ms must be <= {MAX_TX_LED_HOLD_MS}"),
        });
    }
    if tx_status_enabled(&args.tx_status)
        && args.tx_status.tx_status_delay_ms > MAX_TX_STATUS_DELAY_MS
        && result != DiagnosticResult::Fail
    {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_tx_status_delay",
            message: format!("--tx-status-delay-ms must be <= {MAX_TX_STATUS_DELAY_MS}"),
        });
    }
    if tx_status_enabled(&args.tx_status)
        && args.tx_status.tx_status_poll_count > MAX_TX_STATUS_POLL_COUNT
        && result != DiagnosticResult::Fail
    {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_tx_status_poll_count",
            message: format!("--tx-status-poll-count must be <= {MAX_TX_STATUS_POLL_COUNT}"),
        });
    }
    if tx_status_enabled(&args.tx_status)
        && tx_status_total_poll_ms(&args.tx_status) > MAX_TX_STATUS_TOTAL_POLL_MS
        && result != DiagnosticResult::Fail
    {
        result = DiagnosticResult::Fail;
        error = Some(DiagnosticErrorReport {
            code: "invalid_tx_status_poll_total",
            message: format!(
                "--tx-status-poll-ms multiplied by --tx-status-poll-count must be <= {MAX_TX_STATUS_TOTAL_POLL_MS}"
            ),
        });
    }

    if result != DiagnosticResult::Fail {
        return tx_repeat_live_report(
            args,
            channel.expect("channel resolved before live repeated tx"),
            tx_frame_len,
            tx_frame_source,
        );
    }

    let phases = if result == DiagnosticResult::Fail {
        vec![DiagnosticPhase {
            id: "argument_validation",
            status: DiagnosticPhaseStatus::Blocked,
            detail: "repeated TX arguments did not pass local validation",
        }]
    } else {
        vec![
            DiagnosticPhase {
                id: "init",
                status: DiagnosticPhaseStatus::Pending,
                detail: "requires completed radio initialization",
            },
            DiagnosticPhase {
                id: "repeat_gate",
                status: DiagnosticPhaseStatus::Pending,
                detail: "operator supplied explicit count, interval, channel, and authorization",
            },
            DiagnosticPhase {
                id: "bulk_out_loop",
                status: DiagnosticPhaseStatus::Pending,
                detail: "write descriptor-prefixed frame count times with the requested interval",
            },
        ]
    };

    pending_report(PendingReportInput {
        command: "tx-repeat",
        selector: args.adapter.selector(),
        adapter: None,
        endpoints: None,
        channel,
        bandwidth: Some(args.bandwidth),
        firmware_path: None,
        firmware: None,
        init_dry_run: None,
        init_live: None,
        duration_ms: None,
        pcap_path: None,
        tx_frame_len,
        tx_frame_source,
        tx_dry_run: None,
        tx_live: None,
        rx_fixture: None,
        repeat_tx: Some(RepeatTxReport {
            count: args.count,
            interval_ms: args.interval_ms,
            authorized: args.i_understand_this_transmits,
            bulk_out_endpoint: None,
            bulk_out_endpoint_hex: None,
            frame_len: tx_frame_len,
            packet_len: None,
            elapsed_ms: None,
            submitted_per_second: None,
            usb_bytes_per_second: None,
            cpu: None,
            tx_options: None,
            tx_activity_led: None,
            tx_status: None,
            submit_counters: TxSubmitCounters::default(),
        }),
        counters: DiagnosticCounters::default(),
        result,
        phases,
        error,
        notes: vec!["live repeated TX stopped before USB bulk OUT writes"],
    })
}

fn tx_repeat_live_report(
    args: TxRepeatArgs,
    channel: Channel,
    tx_frame_len: Option<usize>,
    tx_frame_source: Option<&'static str>,
) -> PendingDiagnosticReport {
    let selector = args.adapter.selector();
    let bandwidth = args.bandwidth;
    let frame_hex = args
        .frame_hex
        .as_deref()
        .expect("live repeated tx frame hex was validated");
    let frame = match parse_hex_bytes(frame_hex) {
        Ok(frame) => frame,
        Err(error) => {
            return tx_repeat_live_failure(TxRepeatLiveFailureInput {
                selector,
                adapter: None,
                endpoints: None,
                channel,
                bandwidth,
                tx_frame_len,
                tx_frame_source,
                repeat: repeat_tx_report_base(&args, tx_frame_len, None, None, None, None),
                counters: DiagnosticCounters::default(),
                phase_id: "argument_validation",
                phase_detail: "TX frame hex could not be parsed",
                error: DiagnosticErrorReport {
                    code: "invalid_frame_hex",
                    message: error,
                },
            });
        }
    };
    let opts = tx_options_from_args(bandwidth, &args.tx_options);
    let packet_len = match build_tx_packet(&frame, channel, opts) {
        Ok(packet) => packet.len(),
        Err(error) => {
            return tx_repeat_live_failure(TxRepeatLiveFailureInput {
                selector,
                adapter: None,
                endpoints: None,
                channel,
                bandwidth,
                tx_frame_len,
                tx_frame_source,
                repeat: repeat_tx_report_base(
                    &args,
                    Some(frame.len()),
                    None,
                    None,
                    None,
                    Some(opts),
                ),
                counters: DiagnosticCounters::default(),
                phase_id: "tx_descriptor",
                phase_detail: "TX descriptor construction failed",
                error: DiagnosticErrorReport {
                    code: "tx_descriptor_failed",
                    message: error.to_string(),
                },
            });
        }
    };

    let (mut session, claim_detail) = if args.macos_usbhost.enabled {
        match open_macos_usbhost_transport(&args.macos_usbhost, selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "opened retained macOS IOUSBHost session for live repeated TX",
            ),
            Err(error) => {
                return tx_repeat_live_failure(TxRepeatLiveFailureInput {
                    selector,
                    adapter: None,
                    endpoints: None,
                    channel,
                    bandwidth,
                    tx_frame_len,
                    tx_frame_source,
                    repeat: repeat_tx_report_base(
                        &args,
                        Some(frame.len()),
                        Some(packet_len),
                        None,
                        None,
                        Some(opts),
                    ),
                    counters: DiagnosticCounters::default(),
                    phase_id: "usb_claim",
                    phase_detail: "macOS IOUSBHost retained-session open failed",
                    error,
                });
            }
        }
    } else {
        match open_libusb_transport(selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "claimed initialized adapter for live repeated TX",
            ),
            Err(error) => {
                return tx_repeat_live_failure(TxRepeatLiveFailureInput {
                    selector,
                    adapter: None,
                    endpoints: None,
                    channel,
                    bandwidth,
                    tx_frame_len,
                    tx_frame_source,
                    repeat: repeat_tx_report_base(
                        &args,
                        Some(frame.len()),
                        Some(packet_len),
                        None,
                        None,
                        Some(opts),
                    ),
                    counters: DiagnosticCounters::default(),
                    phase_id: "usb_claim",
                    phase_detail: "runtime USB transport open failed",
                    error,
                });
            }
        }
    };
    let bulk_out = match session.selected_bulk_out_endpoint() {
        Some(endpoint) => endpoint,
        None => {
            return tx_repeat_live_failure(TxRepeatLiveFailureInput {
                selector,
                adapter: Some(session.adapter.clone()),
                endpoints: Some(session.endpoints.clone()),
                channel,
                bandwidth,
                tx_frame_len,
                tx_frame_source,
                repeat: repeat_tx_report_base(
                    &args,
                    Some(frame.len()),
                    Some(packet_len),
                    None,
                    None,
                    Some(opts),
                ),
                counters: diagnostic_counters_from_runtime(session.counters),
                phase_id: "bulk_out_loop",
                phase_detail: "claimed interface has no bulk OUT endpoint",
                error: DiagnosticErrorReport {
                    code: "missing_bulk_out_endpoint",
                    message: "claimed interface has no bulk OUT endpoint".to_string(),
                },
            });
        }
    };

    let mut submit_counters = TxSubmitCounters::default();
    let mut tx_activity_led = tx_activity_led_report(&args.tx_led);
    let mut tx_status = tx_status_probe_report(&args.tx_status);
    if tx_activity_led.is_some() || tx_status.is_some() {
        let registers = Rtl8812auRegisterAccess::new(&session.transport);
        tx_activity_led_step(&registers, &mut tx_activity_led, LedAction::On);
        tx_status_probe_pre(&registers, &mut tx_status);
    }
    let cpu_started = process_cpu_usage();
    let started = Instant::now();
    for index in 0..args.count {
        if let Err(error) = session.submit_80211_frame(&frame, channel, opts, &mut submit_counters)
        {
            if tx_status.is_some() {
                let registers = Rtl8812auRegisterAccess::new(&session.transport);
                tx_status_probe_post(&registers, &mut tx_status);
                tx_status_attach_rf_summary(&mut tx_status, &submit_counters);
            }
            tx_activity_led_hold(&tx_activity_led);
            if tx_activity_led.is_some() {
                let registers = Rtl8812auRegisterAccess::new(&session.transport);
                tx_activity_led_step(&registers, &mut tx_activity_led, LedAction::Off);
            }
            let mut counters = DiagnosticCounters {
                usb_control_writes: session.counters.usb_control_writes,
                usb_bulk_out_writes: submit_counters.submitted + submit_counters.failed,
                tx_frames: submit_counters.submitted,
                dropped_frames: submit_counters.failed + submit_counters.rejected,
                ..DiagnosticCounters::default()
            };
            add_tx_activity_led_counters(&mut counters, &tx_activity_led);
            add_tx_status_probe_counters(&mut counters, &tx_status);
            let elapsed_ms = elapsed_ms_u64(started);
            let cpu = cpu_usage_delta(cpu_started, process_cpu_usage(), elapsed_ms);
            let mut repeat = repeat_tx_report_with_submit(
                &args,
                Some(frame.len()),
                Some(packet_len),
                Some(bulk_out),
                Some(elapsed_ms),
                Some(opts),
                submit_counters,
            );
            repeat.cpu = cpu;
            repeat.tx_activity_led = tx_activity_led;
            repeat.tx_status = tx_status;
            return tx_repeat_live_failure(TxRepeatLiveFailureInput {
                selector,
                adapter: Some(session.adapter.clone()),
                endpoints: Some(session.endpoints.clone()),
                channel,
                bandwidth,
                tx_frame_len,
                tx_frame_source,
                repeat,
                counters,
                phase_id: "bulk_out_loop",
                phase_detail: "bulk OUT frame submission failed during repeated TX",
                error: DiagnosticErrorReport {
                    code: "tx_submit_failed",
                    message: format!("frame {}: {error}", index + 1),
                },
            });
        }

        if index + 1 < args.count {
            std::thread::sleep(Duration::from_millis(args.interval_ms));
        }
    }
    if tx_status.is_some() {
        let registers = Rtl8812auRegisterAccess::new(&session.transport);
        tx_status_probe_post(&registers, &mut tx_status);
        tx_status_attach_rf_summary(&mut tx_status, &submit_counters);
    }
    tx_activity_led_hold(&tx_activity_led);
    if tx_activity_led.is_some() {
        let registers = Rtl8812auRegisterAccess::new(&session.transport);
        tx_activity_led_step(&registers, &mut tx_activity_led, LedAction::Off);
    }
    let elapsed_ms = elapsed_ms_u64(started);
    let mut counters = DiagnosticCounters {
        usb_control_writes: session.counters.usb_control_writes,
        usb_bulk_out_writes: submit_counters.submitted,
        tx_frames: submit_counters.submitted,
        ..DiagnosticCounters::default()
    };
    add_tx_activity_led_counters(&mut counters, &tx_activity_led);
    add_tx_status_probe_counters(&mut counters, &tx_status);
    let cpu = cpu_usage_delta(cpu_started, process_cpu_usage(), elapsed_ms);
    let mut repeat = repeat_tx_report_with_submit(
        &args,
        Some(frame.len()),
        Some(packet_len),
        Some(bulk_out),
        Some(elapsed_ms),
        Some(opts),
        submit_counters,
    );
    repeat.cpu = cpu;
    repeat.tx_activity_led = tx_activity_led;
    repeat.tx_status = tx_status;

    pending_report(PendingReportInput {
        command: "tx-repeat",
        selector,
        adapter: Some(session.adapter.clone()),
        endpoints: Some(session.endpoints.clone()),
        channel: Some(channel),
        bandwidth: Some(bandwidth),
        firmware_path: None,
        firmware: None,
        init_dry_run: None,
        init_live: None,
        duration_ms: Some(elapsed_ms),
        pcap_path: None,
        tx_frame_len,
        tx_frame_source,
        tx_dry_run: None,
        tx_live: None,
        rx_fixture: None,
        repeat_tx: Some(repeat),
        counters,
        result: DiagnosticResult::Pass,
        phases: vec![
            DiagnosticPhase {
                id: "usb_claim",
                status: DiagnosticPhaseStatus::Completed,
                detail: claim_detail,
            },
            DiagnosticPhase {
                id: "repeat_gate",
                status: DiagnosticPhaseStatus::Completed,
                detail: "operator supplied explicit count, interval, channel, frame, and authorization",
            },
            DiagnosticPhase {
                id: "bulk_out_loop",
                status: DiagnosticPhaseStatus::Completed,
                detail: "submitted descriptor-prefixed frames to bulk OUT with requested pacing",
            },
        ],
        error: None,
        notes: vec![
            "live repeated TX assumes the adapter has already completed init on the requested channel",
            "no RX loop or independent over-the-air verification was started",
        ],
    })
}

struct TxRepeatLiveFailureInput {
    selector: DeviceSelector,
    adapter: Option<UsbDeviceInfo>,
    endpoints: Option<UsbEndpoints>,
    channel: Channel,
    bandwidth: Bandwidth,
    tx_frame_len: Option<usize>,
    tx_frame_source: Option<&'static str>,
    repeat: RepeatTxReport,
    counters: DiagnosticCounters,
    phase_id: &'static str,
    phase_detail: &'static str,
    error: DiagnosticErrorReport,
}

fn tx_repeat_live_failure(input: TxRepeatLiveFailureInput) -> PendingDiagnosticReport {
    pending_report(PendingReportInput {
        command: "tx-repeat",
        selector: input.selector,
        adapter: input.adapter,
        endpoints: input.endpoints,
        channel: Some(input.channel),
        bandwidth: Some(input.bandwidth),
        firmware_path: None,
        firmware: None,
        init_dry_run: None,
        init_live: None,
        duration_ms: input.repeat.elapsed_ms,
        pcap_path: None,
        tx_frame_len: input.tx_frame_len,
        tx_frame_source: input.tx_frame_source,
        tx_dry_run: None,
        tx_live: None,
        rx_fixture: None,
        repeat_tx: Some(input.repeat),
        counters: input.counters,
        result: DiagnosticResult::Fail,
        phases: vec![DiagnosticPhase {
            id: input.phase_id,
            status: DiagnosticPhaseStatus::Blocked,
            detail: input.phase_detail,
        }],
        error: Some(input.error),
        notes: vec!["live repeated TX stopped before completing the requested frame count"],
    })
}

fn repeat_tx_report_base(
    args: &TxRepeatArgs,
    frame_len: Option<usize>,
    packet_len: Option<usize>,
    bulk_out_endpoint: Option<u8>,
    elapsed_ms: Option<u64>,
    tx_options: Option<TxOptions>,
) -> RepeatTxReport {
    repeat_tx_report_with_submit(
        args,
        frame_len,
        packet_len,
        bulk_out_endpoint,
        elapsed_ms,
        tx_options,
        TxSubmitCounters::default(),
    )
}

fn repeat_tx_report_with_submit(
    args: &TxRepeatArgs,
    frame_len: Option<usize>,
    packet_len: Option<usize>,
    bulk_out_endpoint: Option<u8>,
    elapsed_ms: Option<u64>,
    tx_options: Option<TxOptions>,
    submit_counters: TxSubmitCounters,
) -> RepeatTxReport {
    RepeatTxReport {
        count: args.count,
        interval_ms: args.interval_ms,
        authorized: args.i_understand_this_transmits,
        bulk_out_endpoint,
        bulk_out_endpoint_hex: bulk_out_endpoint.map(|endpoint| format_value(endpoint, 2)),
        frame_len,
        packet_len,
        elapsed_ms,
        submitted_per_second: rate_per_second(submit_counters.submitted, elapsed_ms),
        usb_bytes_per_second: rate_per_second(submit_counters.bytes_written, elapsed_ms),
        cpu: None,
        tx_options,
        tx_activity_led: None,
        tx_status: None,
        submit_counters,
    }
}

fn bridge_tx_once_report(args: BridgeTxOnceArgs) -> BridgeTxOnceReport {
    let selector = args.adapter.selector();
    let (channel, result, error) = resolve_report_channel(args.channel, args.bandwidth);
    let mut report = bridge_tx_once_base_report(selector, channel, args.bandwidth);
    if result == DiagnosticResult::Fail {
        return bridge_tx_once_failure(
            report,
            "argument_validation",
            "bridge TX arguments did not pass local validation",
            error.expect("unsupported channel error"),
        );
    }
    let channel = channel.expect("channel resolved before bridge TX");

    let (datagram, datagram_source) = match bridge_tx_datagram_from_args(&args) {
        Ok(datagram) => datagram,
        Err(error) => {
            return bridge_tx_once_failure(
                report,
                "argument_validation",
                "bridge TX datagram arguments did not pass local validation",
                error,
            );
        }
    };

    let parsed = match parse_tx_datagram(&datagram) {
        Ok(parsed) => parsed,
        Err(error) => {
            report.bridge_counters = bridge_tx_parse_error_counters(&error);
            return bridge_tx_once_failure(
                report,
                "bridge_parse",
                "WFB distributor datagram could not be parsed",
                DiagnosticErrorReport {
                    code: "invalid_bridge_tx_datagram",
                    message: error.to_string(),
                },
            );
        }
    };

    let frame_len = parsed.ieee80211_frame.len();
    let tx_options =
        apply_bridge_tx_overrides(&args.tx_overrides, args.bandwidth, parsed.tx_options);
    let (packet_len, tx_descriptor_hex) =
        match build_tx_packet(parsed.ieee80211_frame, channel, tx_options) {
            Ok(packet) => (
                packet.len(),
                Some(encode_hex(&packet[..TX_DESC_SIZE.min(packet.len())])),
            ),
            Err(error) => {
                return bridge_tx_once_failure(
                    report,
                    "tx_descriptor",
                    "bridge TX descriptor construction failed before USB submission",
                    DiagnosticErrorReport {
                        code: "tx_descriptor_failed",
                        message: error.to_string(),
                    },
                );
            }
        };
    report.datagram = Some(BridgeTxDatagramReport {
        source: datagram_source,
        datagram_len: datagram.len(),
        fwmark: parsed.fwmark,
        fwmark_hex: format_value(parsed.fwmark, 8),
        radiotap_len: parsed.radiotap_len,
        frame_len,
        packet_len: Some(packet_len),
        tx_descriptor_hex,
        tx_profile: args.tx_overrides.tx_profile,
        tx_options,
    });

    if let Some(datagram_report) = &mut report.datagram {
        datagram_report.packet_len = Some(packet_len);
    }

    if !args.i_understand_this_transmits {
        return bridge_tx_once_failure(
            report,
            "argument_validation",
            "bridge TX requires explicit operator authorization",
            DiagnosticErrorReport {
                code: "missing_tx_authorization",
                message: "bridge-tx-once requires --i-understand-this-transmits".to_string(),
            },
        );
    }

    let (mut session, claim_detail) = if args.macos_usbhost.enabled {
        match open_macos_usbhost_transport(&args.macos_usbhost, selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "opened retained macOS IOUSBHost session for live bridge TX",
            ),
            Err(error) => {
                return bridge_tx_once_failure(
                    report,
                    "usb_claim",
                    "macOS IOUSBHost retained-session open failed",
                    error,
                );
            }
        }
    } else {
        match open_libusb_transport(selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "claimed initialized adapter for live bridge TX",
            ),
            Err(error) => {
                return bridge_tx_once_failure(
                    report,
                    "usb_claim",
                    "runtime USB transport open failed",
                    error,
                );
            }
        }
    };

    let bulk_out = match session.selected_bulk_out_endpoint() {
        Some(endpoint) => endpoint,
        None => {
            report.adapter = Some(session.adapter.clone());
            report.endpoints = Some(session.endpoints.clone());
            report.counters = diagnostic_counters_from_runtime(session.counters);
            return bridge_tx_once_failure(
                report,
                "bulk_out",
                "claimed interface has no bulk OUT endpoint",
                DiagnosticErrorReport {
                    code: "missing_bulk_out_endpoint",
                    message: "claimed interface has no bulk OUT endpoint".to_string(),
                },
            );
        }
    };

    let mut bridge_counters = TxCounters::default();
    let mut submit_counters = TxSubmitCounters::default();
    let submit_result = {
        let mut radio = BridgeTxSessionRadio {
            session: &mut session,
            channel,
            channel_bandwidth: args.bandwidth,
            overrides: &args.tx_overrides,
            submit_counters: &mut submit_counters,
        };
        submit_tx_datagram(&datagram, &mut radio, &mut bridge_counters)
    };

    let mut counters = diagnostic_counters_from_runtime(session.counters);
    counters.dropped_frames = counters.dropped_frames.max(bridge_counters.dropped);
    report.adapter = Some(session.adapter.clone());
    report.endpoints = Some(session.endpoints.clone());
    report.bulk_out_endpoint = Some(bulk_out);
    report.bulk_out_endpoint_hex = Some(format_value(bulk_out, 2));
    report.bridge_counters = bridge_counters;
    report.submit_counters = submit_counters;
    report.counters = counters;

    match submit_result {
        Ok(_) => {
            report.result = DiagnosticResult::Pass;
            report.phases = vec![
                DiagnosticPhase {
                    id: "argument_validation",
                    status: DiagnosticPhaseStatus::Completed,
                    detail: "operator supplied a datagram, channel, and live TX authorization",
                },
                DiagnosticPhase {
                    id: "bridge_parse",
                    status: DiagnosticPhaseStatus::Completed,
                    detail: "parsed WFB firmware mark, radiotap metadata, and IEEE 802.11 frame",
                },
                DiagnosticPhase {
                    id: "usb_claim",
                    status: DiagnosticPhaseStatus::Completed,
                    detail: claim_detail,
                },
                DiagnosticPhase {
                    id: "bridge_submit",
                    status: DiagnosticPhaseStatus::Completed,
                    detail: "submitted parsed bridge frame through the live radio TX backend",
                },
            ];
            report.notes = vec![
                "live bridge TX assumes the adapter has already completed init on the requested channel",
                "one parsed WFB distributor-style datagram was submitted; no RX peer confirmation was attempted",
            ];
            report
        }
        Err(error) => bridge_tx_once_failure(
            report,
            "bridge_submit",
            "bridge TX submission failed",
            DiagnosticErrorReport {
                code: "bridge_tx_submit_failed",
                message: error.to_string(),
            },
        ),
    }
}

struct BridgeTxSessionRadio<'a> {
    session: &'a mut RuntimeRadioSession<RuntimeUsbTransport>,
    channel: Channel,
    channel_bandwidth: Bandwidth,
    overrides: &'a BridgeTxOverrideArgs,
    submit_counters: &'a mut TxSubmitCounters,
}

struct BridgeTxBenchSessionRadio<'a> {
    session: &'a mut RuntimeRadioSession<RuntimeUsbTransport>,
    channel: Channel,
    args: &'a BridgeTxBenchArgs,
    submit_counters: &'a mut TxSubmitCounters,
}

fn production_bridge_tx_overrides(
    overrides: &BridgeTxOverrideArgs,
) -> ProductionRuntimeBridgeTxOverrides {
    ProductionRuntimeBridgeTxOverrides {
        tx_profile: match overrides.tx_profile {
            BridgeTxProfileArg::LinuxMonitor => ProductionRuntimeBridgeTxProfile::LinuxMonitor,
            BridgeTxProfileArg::RadiotapDirect => ProductionRuntimeBridgeTxProfile::RadiotapDirect,
        },
        tx_rate: overrides.tx_rate,
        tx_bandwidth: overrides.tx_bandwidth,
        tx_channel_bandwidth: overrides.tx_channel_bandwidth,
        tx_queue: match overrides.tx_queue {
            TxQueueArg::Auto => None,
            queue => Some(queue.into()),
        },
        mac_id: overrides.mac_id,
        tx_rate_id: overrides.tx_rate_id,
        tx_retries: overrides.tx_retries,
        tx_fallback_limit: overrides.tx_fallback_limit,
        enable_rate_fallback: overrides.enable_rate_fallback,
        no_agg_break: overrides.no_agg_break,
    }
}

fn apply_bridge_tx_overrides(
    overrides: &BridgeTxOverrideArgs,
    channel_bandwidth: Bandwidth,
    mut options: TxOptions,
) -> TxOptions {
    options.channel_bandwidth = Some(overrides.tx_channel_bandwidth.unwrap_or(channel_bandwidth));
    if let Some(rate) = overrides.tx_rate {
        options.rate = rate;
    }
    if let Some(bandwidth) = overrides.tx_bandwidth {
        options.bandwidth = bandwidth;
    }
    options = apply_bridge_tx_profile(overrides.tx_profile, options);
    if overrides.tx_queue != TxQueueArg::Auto {
        options.queue = overrides.tx_queue.into();
    }
    if let Some(mac_id) = overrides.mac_id {
        options.mac_id = mac_id;
    }
    if let Some(rate_id) = overrides.tx_rate_id {
        options.rate_id = Some(rate_id);
    }
    if let Some(retries) = overrides.tx_retries {
        options.retries = retries;
    }
    if let Some(fallback_limit) = overrides.tx_fallback_limit {
        options.rate_fallback_limit = fallback_limit;
    }
    if overrides.enable_rate_fallback {
        options.disable_rate_fallback = false;
    }
    if overrides.no_agg_break {
        options.aggregate_break = false;
    }
    options
}

fn apply_wfb_monitor_tx_defaults(mut options: TxOptions) -> TxOptions {
    if matches!(options.rate, TxRate::Mcs(_) | TxRate::Vht { .. }) {
        options.queue = TxQueue::Mgnt;
        options.mac_id = 1;
        if matches!(options.rate, TxRate::Mcs(_)) {
            options.rate_id = Some(7);
        }
        options.disable_rate_fallback = false;
        options.rate_fallback_limit = 0;
        options.aggregate_break = false;
        if options.no_retry {
            options.retries = 0;
        }
    }

    options
}

fn apply_bridge_tx_profile(profile: BridgeTxProfileArg, options: TxOptions) -> TxOptions {
    match profile {
        BridgeTxProfileArg::LinuxMonitor => apply_wfb_monitor_tx_defaults(options),
        BridgeTxProfileArg::RadiotapDirect => options,
    }
}

impl RadioTx for BridgeTxSessionRadio<'_> {
    fn submit_80211(
        &mut self,
        frame: &[u8],
        options: TxOptions,
    ) -> std::result::Result<(), String> {
        let options = apply_bridge_tx_overrides(self.overrides, self.channel_bandwidth, options);
        self.session
            .submit_80211_frame(frame, self.channel, options, self.submit_counters)
            .map(|_| ())
            .map_err(|error| error.to_string())
    }
}

impl RadioTx for BridgeTxBenchSessionRadio<'_> {
    fn submit_80211(
        &mut self,
        frame: &[u8],
        options: TxOptions,
    ) -> std::result::Result<(), String> {
        let options = bridge_tx_bench_tx_options(self.args, options);
        self.session
            .submit_80211_frame(frame, self.channel, options, self.submit_counters)
            .map(|_| ())
            .map_err(|error| error.to_string())
    }
}

fn bridge_tx_once_base_report(
    selector: DeviceSelector,
    channel: Option<Channel>,
    bandwidth: Bandwidth,
) -> BridgeTxOnceReport {
    BridgeTxOnceReport {
        schema_version: 1,
        command: "bridge-tx-once",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        adapter: None,
        endpoints: None,
        channel,
        bandwidth,
        datagram: None,
        bulk_out_endpoint: None,
        bulk_out_endpoint_hex: None,
        bridge_counters: TxCounters::default(),
        submit_counters: TxSubmitCounters::default(),
        counters: DiagnosticCounters::default(),
        result: DiagnosticResult::NotImplemented,
        phases: Vec::new(),
        error: None,
        notes: vec!["live bridge TX stopped before USB bulk OUT submission"],
    }
}

fn bridge_tx_once_failure(
    mut report: BridgeTxOnceReport,
    phase_id: &'static str,
    phase_detail: &'static str,
    error: DiagnosticErrorReport,
) -> BridgeTxOnceReport {
    report.result = DiagnosticResult::Fail;
    report.phases = vec![DiagnosticPhase {
        id: phase_id,
        status: DiagnosticPhaseStatus::Blocked,
        detail: phase_detail,
    }];
    report.error = Some(error);
    if report.notes.is_empty() {
        report
            .notes
            .push("live bridge TX stopped before USB bulk OUT submission");
    }
    report
}

fn bridge_tx_listen_report(args: BridgeTxListenArgs) -> BridgeTxListenReport {
    let selector = args.adapter.selector();
    let (channel, result, error) = resolve_report_channel(args.channel, args.bandwidth);
    let mut report = bridge_tx_listen_base_report(&args, selector, channel);
    if result == DiagnosticResult::Fail {
        return bridge_tx_listen_failure(
            report,
            "argument_validation",
            "bridge TX listen arguments did not pass local validation",
            error.expect("unsupported channel error"),
        );
    }
    let channel = channel.expect("channel resolved before bridge TX listen");

    if !args.i_understand_this_transmits {
        return bridge_tx_listen_failure(
            report,
            "argument_validation",
            "bridge TX listen requires explicit operator authorization",
            DiagnosticErrorReport {
                code: "missing_tx_authorization",
                message: "bridge-tx-listen requires --i-understand-this-transmits".to_string(),
            },
        );
    }
    if let Err(error) = validate_tx_calibration_profile_write_authorization(
        args.tx_calibration.tx_calibration_profile,
        args.i_understand_this_writes_registers,
    ) {
        return bridge_tx_listen_failure(
            report,
            "argument_validation",
            "bridge TX listener calibration profile write authorization is missing",
            error,
        );
    }
    if args.max_datagrams == 0 {
        return bridge_tx_listen_failure(
            report,
            "argument_validation",
            "bridge TX listen requires at least one datagram",
            DiagnosticErrorReport {
                code: "invalid_max_datagrams",
                message: "--max-datagrams must be greater than zero".to_string(),
            },
        );
    }
    if args.idle_timeout_ms == 0 {
        return bridge_tx_listen_failure(
            report,
            "argument_validation",
            "bridge TX listen requires a nonzero idle timeout",
            DiagnosticErrorReport {
                code: "invalid_idle_timeout",
                message: "--idle-timeout-ms must be greater than zero".to_string(),
            },
        );
    }
    if tx_status_enabled(&args.tx_status)
        && args.tx_status.tx_status_delay_ms > MAX_TX_STATUS_DELAY_MS
    {
        return bridge_tx_listen_failure(
            report,
            "argument_validation",
            "bridge TX listener TX status delay is outside the guarded range",
            DiagnosticErrorReport {
                code: "invalid_tx_status_delay",
                message: format!("--tx-status-delay-ms must be <= {MAX_TX_STATUS_DELAY_MS}"),
            },
        );
    }
    if tx_status_enabled(&args.tx_status)
        && args.tx_status.tx_status_poll_count > MAX_TX_STATUS_POLL_COUNT
    {
        return bridge_tx_listen_failure(
            report,
            "argument_validation",
            "bridge TX listener TX status poll count is outside the guarded range",
            DiagnosticErrorReport {
                code: "invalid_tx_status_poll_count",
                message: format!("--tx-status-poll-count must be <= {MAX_TX_STATUS_POLL_COUNT}"),
            },
        );
    }
    if tx_status_enabled(&args.tx_status)
        && tx_status_total_poll_ms(&args.tx_status) > MAX_TX_STATUS_TOTAL_POLL_MS
    {
        return bridge_tx_listen_failure(
            report,
            "argument_validation",
            "bridge TX listener TX status poll total is outside the guarded range",
            DiagnosticErrorReport {
                code: "invalid_tx_status_poll_total",
                message: format!(
                    "--tx-status-poll-ms multiplied by --tx-status-poll-count must be <= {MAX_TX_STATUS_TOTAL_POLL_MS}"
                ),
            },
        );
    }

    let init_bridge_args = bridge_tx_listen_init_bridge_args(&args);
    let init_assets = match load_bridge_tx_bench_init_assets(&init_bridge_args) {
        Ok(init_assets) => init_assets,
        Err(error) => {
            return bridge_tx_listen_failure(
                report,
                "argument_validation",
                "bridge TX listener same-session init arguments did not pass local validation",
                error,
            );
        }
    };

    let socket = match UdpSocket::bind(args.bind) {
        Ok(socket) => socket,
        Err(error) => {
            return bridge_tx_listen_failure(
                report,
                "socket_bind",
                "failed to bind bridge TX UDP listener",
                DiagnosticErrorReport {
                    code: "udp_bind_failed",
                    message: format!("failed to bind {}: {error}", args.bind),
                },
            );
        }
    };
    if let Err(error) = configure_bridge_tx_socket(&socket, args.bind) {
        return bridge_tx_listen_failure(
            report,
            "socket_bind",
            "failed to configure bridge TX UDP listener receive buffer",
            error,
        );
    }
    if let Err(error) = socket.set_read_timeout(Some(Duration::from_millis(args.idle_timeout_ms))) {
        return bridge_tx_listen_failure(
            report,
            "socket_bind",
            "failed to configure bridge TX UDP listener timeout",
            DiagnosticErrorReport {
                code: "udp_timeout_config_failed",
                message: error.to_string(),
            },
        );
    }

    let (mut session, claim_detail) = if args.macos_usbhost.enabled {
        match open_macos_usbhost_transport(&args.macos_usbhost, selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "opened retained macOS IOUSBHost session for live bridge TX listener",
            ),
            Err(error) => {
                return bridge_tx_listen_failure(
                    report,
                    "usb_claim",
                    "macOS IOUSBHost retained-session open failed",
                    error,
                );
            }
        }
    } else {
        match open_libusb_transport(selector) {
            Ok(open) => (
                RuntimeRadioSession::new(
                    open.transport,
                    open.adapter,
                    open.endpoints,
                    runtime_radio_counters_from_diagnostic(open.counters),
                ),
                "claimed initialized adapter for live bridge TX listener",
            ),
            Err(error) => {
                return bridge_tx_listen_failure(
                    report,
                    "usb_claim",
                    "runtime USB transport open failed",
                    error,
                );
            }
        }
    };

    let bulk_out = match session.selected_bulk_out_endpoint() {
        Some(endpoint) => endpoint,
        None => {
            report.adapter = Some(session.adapter.clone());
            report.endpoints = Some(session.endpoints.clone());
            report.counters = diagnostic_counters_from_runtime(session.counters);
            return bridge_tx_listen_failure(
                report,
                "bulk_out",
                "claimed interface has no bulk OUT endpoint",
                DiagnosticErrorReport {
                    code: "missing_bulk_out_endpoint",
                    message: "claimed interface has no bulk OUT endpoint".to_string(),
                },
            );
        }
    };
    report.adapter = Some(session.adapter.clone());
    report.endpoints = Some(session.endpoints.clone());
    report.bulk_out_endpoint = Some(bulk_out);
    report.bulk_out_endpoint_hex = Some(format_value(bulk_out, 2));
    let mut pre_tx_counters = diagnostic_counters_from_runtime(session.counters);

    if let Some(init_assets) = init_assets.as_ref() {
        match run_bridge_tx_bench_same_session_init(
            &mut session,
            &init_bridge_args,
            channel,
            init_assets,
        ) {
            Ok(init_report) => {
                pre_tx_counters = diagnostic_counters_from_runtime(session.counters);
                report.same_session_init = Some(init_report);
            }
            Err((init_report, error)) => {
                pre_tx_counters = diagnostic_counters_from_runtime(session.counters);
                report.same_session_init = Some(init_report);
                report.counters = pre_tx_counters;
                return bridge_tx_listen_failure(
                    report,
                    "init_before_tx",
                    "bridge TX listener same-session init failed before the TX loop",
                    error,
                );
            }
        }
    }

    if args.clear_txdma_status_before_tx {
        let registers = Rtl8812auRegisterAccess::new(&session.transport)
            .with_timeout(Duration::from_millis(args.init_timeout_ms));
        match bridge_tx_bench_clear_txdma_status(
            &registers,
            args.txdma_status_clear_value,
            &mut pre_tx_counters,
        ) {
            Ok(clear_report) => {
                report.txdma_status_clear = Some(clear_report);
            }
            Err(error) => {
                report.counters = pre_tx_counters;
                return bridge_tx_listen_failure(
                    report,
                    "clear_txdma_status",
                    "bridge TX listener TXDMA status clear failed before the TX loop",
                    error,
                );
            }
        }
    }

    if !args.pre_tx_rf_write.is_empty() {
        let registers = Rtl8812auRegisterAccess::new(&session.transport)
            .with_timeout(Duration::from_millis(args.init_timeout_ms));
        for write in &args.pre_tx_rf_write {
            match bridge_tx_bench_write_rf_serial_register(&registers, write, &mut pre_tx_counters)
            {
                Ok(mut write_reports) => report.pre_tx_rf_writes.append(&mut write_reports),
                Err(error) => {
                    report.counters = pre_tx_counters;
                    return bridge_tx_listen_failure(
                        report,
                        "pre_tx_rf_write",
                        "bridge TX listener RF 3-wire write failed before the TX loop",
                        error,
                    );
                }
            }
        }
    }

    if !args.pre_tx_write8.is_empty()
        || !args.pre_tx_write16.is_empty()
        || !args.pre_tx_write32.is_empty()
        || !args.pre_tx_rmw32.is_empty()
    {
        let registers = Rtl8812auRegisterAccess::new(&session.transport)
            .with_timeout(Duration::from_millis(args.init_timeout_ms));
        for write in &args.pre_tx_write8 {
            match bridge_tx_bench_write8_register(
                &registers,
                "pre_tx_write8",
                write.address,
                write.value as u8,
                &mut pre_tx_counters,
            ) {
                Ok(write_report) => report.pre_tx_register_writes.push(write_report),
                Err(error) => {
                    report.counters = pre_tx_counters;
                    return bridge_tx_listen_failure(
                        report,
                        "pre_tx_register_write",
                        "bridge TX listener generic u8 register write failed before the TX loop",
                        error,
                    );
                }
            }
        }
        for write in &args.pre_tx_write16 {
            match bridge_tx_bench_write16_register(
                &registers,
                "pre_tx_write16",
                write.address,
                write.value as u16,
                &mut pre_tx_counters,
            ) {
                Ok(write_report) => report.pre_tx_register_writes.push(write_report),
                Err(error) => {
                    report.counters = pre_tx_counters;
                    return bridge_tx_listen_failure(
                        report,
                        "pre_tx_register_write",
                        "bridge TX listener generic u16 register write failed before the TX loop",
                        error,
                    );
                }
            }
        }
        for write in &args.pre_tx_write32 {
            match bridge_tx_bench_write32_register(
                &registers,
                "pre_tx_write32",
                write.address,
                write.value,
                &mut pre_tx_counters,
            ) {
                Ok(write_report) => report.pre_tx_register_writes.push(write_report),
                Err(error) => {
                    report.counters = pre_tx_counters;
                    return bridge_tx_listen_failure(
                        report,
                        "pre_tx_register_write",
                        "bridge TX listener generic u32 register write failed before the TX loop",
                        error,
                    );
                }
            }
        }
        for write in &args.pre_tx_rmw32 {
            match bridge_tx_bench_rmw32_register(
                &registers,
                "pre_tx_rmw32",
                write.address,
                write.mask,
                write.value,
                &mut pre_tx_counters,
            ) {
                Ok(write_report) => report.pre_tx_register_masked_writes.push(write_report),
                Err(error) => {
                    report.counters = pre_tx_counters;
                    return bridge_tx_listen_failure(
                        report,
                        "pre_tx_register_write",
                        "bridge TX listener generic masked u32 register write failed before the TX loop",
                        error,
                    );
                }
            }
        }
    }

    if tx_calibration_profile_requested(&args.tx_calibration) {
        let registers = Rtl8812auRegisterAccess::new(&session.transport)
            .with_timeout(Duration::from_millis(args.init_timeout_ms));
        match apply_tx_calibration_profile(
            &registers,
            &args.tx_calibration,
            channel,
            args.bandwidth,
            args.rfe_type,
            &mut pre_tx_counters,
        ) {
            Ok(profile_report) => {
                report.tx_calibration_profile = profile_report;
            }
            Err(error) => {
                report.counters = pre_tx_counters;
                return bridge_tx_listen_failure(
                    report,
                    "tx_calibration_profile",
                    "bridge TX listener calibration profile failed before the TX loop",
                    error,
                );
            }
        }
    }

    if tx_power_control_requested(&args.tx_power) {
        let registers = Rtl8812auRegisterAccess::new(&session.transport)
            .with_timeout(Duration::from_millis(args.init_timeout_ms));
        match apply_tx_power_control(
            &registers,
            &args.tx_power,
            channel,
            args.bandwidth,
            &mut pre_tx_counters,
        ) {
            Ok(tx_power_report) => {
                report.tx_power_control = tx_power_report;
            }
            Err(error) => {
                report.counters = pre_tx_counters;
                return bridge_tx_listen_failure(
                    report,
                    "tx_power_control",
                    "bridge TX listener TXAGC power control failed before the TX loop",
                    error,
                );
            }
        }
    }

    if report.same_session_init.is_some()
        || tx_power_control_requested(&args.tx_power)
        || tx_calibration_profile_requested(&args.tx_calibration)
    {
        let registers = Rtl8812auRegisterAccess::new(&session.transport)
            .with_timeout(Duration::from_millis(args.init_timeout_ms));
        match tx_pre_calibration_probe(
            &registers,
            report.same_session_init.is_some(),
            channel,
            args.bandwidth,
            args.tx_calibration.tx_calibration_profile,
            &mut pre_tx_counters,
        ) {
            Ok(probe) => {
                report.rf_calibration_pre_tx = Some(probe);
            }
            Err(error) => {
                report.counters = pre_tx_counters;
                return bridge_tx_listen_failure(
                    report,
                    "rf_calibration_probe",
                    "bridge TX listener RF calibration probe failed before the TX loop",
                    error,
                );
            }
        }
    }

    let mut bridge_counters = TxCounters::default();
    let mut submit_counters = TxSubmitCounters::default();
    let mut tx_status = tx_status_probe_report(&args.tx_status);
    if tx_status.is_some() {
        let registers = Rtl8812auRegisterAccess::new(&session.transport);
        tx_status_probe_pre(&registers, &mut tx_status);
    }
    if let Err(error) = bridge_tx_listen_write_ready_file(&args, &report) {
        report.counters = pre_tx_counters;
        return bridge_tx_listen_failure(
            report,
            "bridge_ready",
            "bridge TX listener failed to write the ready marker before the TX loop",
            error,
        );
    }
    let cpu_started = process_cpu_usage();
    let started = Instant::now();
    let mut datagram_bytes = 0u64;
    let mut frame_bytes = 0u64;
    let mut buf = vec![0u8; u16::MAX as usize];
    for _ in 0..args.max_datagrams {
        let (len, peer) = match socket.recv_from(&mut buf) {
            Ok(received) => received,
            Err(error)
                if matches!(
                    error.kind(),
                    std::io::ErrorKind::WouldBlock | std::io::ErrorKind::TimedOut
                ) =>
            {
                bridge_tx_listen_update_counters(
                    &mut report,
                    pre_tx_counters,
                    bridge_counters,
                    submit_counters,
                );
                bridge_tx_listen_set_runtime_metrics(
                    &mut report,
                    started,
                    cpu_started,
                    datagram_bytes,
                    frame_bytes,
                );
                let (code, message) = if report.datagrams_received == 0 {
                    (
                        "bridge_tx_listen_timeout",
                        "timed out before receiving any bridge TX datagrams".to_string(),
                    )
                } else {
                    (
                        "bridge_tx_listen_idle",
                        format!(
                            "stopped after {} received datagram(s) and an idle timeout",
                            report.datagrams_received
                        ),
                    )
                };
                return bridge_tx_listen_failure(
                    report,
                    "bridge_listen",
                    "bridge TX listener timed out",
                    DiagnosticErrorReport { code, message },
                );
            }
            Err(error) => {
                bridge_tx_listen_update_counters(
                    &mut report,
                    pre_tx_counters,
                    bridge_counters,
                    submit_counters,
                );
                bridge_tx_listen_set_runtime_metrics(
                    &mut report,
                    started,
                    cpu_started,
                    datagram_bytes,
                    frame_bytes,
                );
                return bridge_tx_listen_failure(
                    report,
                    "bridge_listen",
                    "bridge TX UDP receive failed",
                    DiagnosticErrorReport {
                        code: "udp_receive_failed",
                        message: error.to_string(),
                    },
                );
            }
        };

        report.datagrams_received += 1;
        report.last_peer = Some(peer.to_string());
        let datagram = &buf[..len];
        datagram_bytes = datagram_bytes.saturating_add(len as u64);
        let parsed = match parse_tx_datagram(datagram) {
            Ok(parsed) => parsed,
            Err(error) => {
                bridge_counters = bridge_tx_parse_error_counters(&error);
                bridge_tx_listen_update_counters(
                    &mut report,
                    pre_tx_counters,
                    bridge_counters,
                    submit_counters,
                );
                bridge_tx_listen_set_runtime_metrics(
                    &mut report,
                    started,
                    cpu_started,
                    datagram_bytes,
                    frame_bytes,
                );
                return bridge_tx_listen_failure(
                    report,
                    "bridge_parse",
                    "received WFB distributor datagram could not be parsed",
                    DiagnosticErrorReport {
                        code: "invalid_bridge_tx_datagram",
                        message: error.to_string(),
                    },
                );
            }
        };
        frame_bytes = frame_bytes.saturating_add(parsed.ieee80211_frame.len() as u64);
        let tx_options =
            apply_bridge_tx_overrides(&args.tx_overrides, args.bandwidth, parsed.tx_options);
        let (packet_len, tx_descriptor_hex) =
            match build_tx_packet(parsed.ieee80211_frame, channel, tx_options) {
                Ok(packet) => (
                    packet.len(),
                    Some(encode_hex(&packet[..TX_DESC_SIZE.min(packet.len())])),
                ),
                Err(error) => {
                    bridge_tx_listen_update_counters(
                        &mut report,
                        pre_tx_counters,
                        bridge_counters,
                        submit_counters,
                    );
                    bridge_tx_listen_set_runtime_metrics(
                        &mut report,
                        started,
                        cpu_started,
                        datagram_bytes,
                        frame_bytes,
                    );
                    return bridge_tx_listen_failure(
                        report,
                        "tx_descriptor",
                        "received bridge TX datagram could not build a TX descriptor",
                        DiagnosticErrorReport {
                            code: "tx_descriptor_failed",
                            message: error.to_string(),
                        },
                    );
                }
            };
        report.last_datagram = Some(BridgeTxDatagramReport {
            source: "udp",
            datagram_len: len,
            fwmark: parsed.fwmark,
            fwmark_hex: format_value(parsed.fwmark, 8),
            radiotap_len: parsed.radiotap_len,
            frame_len: parsed.ieee80211_frame.len(),
            packet_len: Some(packet_len),
            tx_descriptor_hex,
            tx_profile: args.tx_overrides.tx_profile,
            tx_options,
        });

        let submit_result = {
            let mut radio = BridgeTxSessionRadio {
                session: &mut session,
                channel,
                channel_bandwidth: args.bandwidth,
                overrides: &args.tx_overrides,
                submit_counters: &mut submit_counters,
            };
            submit_tx_datagram(datagram, &mut radio, &mut bridge_counters)
        };
        if let Err(error) = submit_result {
            if tx_status.is_some() {
                let registers = Rtl8812auRegisterAccess::new(&session.transport);
                tx_status_probe_post(&registers, &mut tx_status);
                tx_status_attach_rf_summary(&mut tx_status, &submit_counters);
                report.tx_status = tx_status;
            }
            bridge_tx_listen_update_counters(
                &mut report,
                pre_tx_counters,
                bridge_counters,
                submit_counters,
            );
            bridge_tx_listen_set_runtime_metrics(
                &mut report,
                started,
                cpu_started,
                datagram_bytes,
                frame_bytes,
            );
            return bridge_tx_listen_failure(
                report,
                "bridge_submit",
                "bridge TX listener submission failed",
                DiagnosticErrorReport {
                    code: "bridge_tx_submit_failed",
                    message: error.to_string(),
                },
            );
        }
    }

    if tx_status.is_some() {
        let registers = Rtl8812auRegisterAccess::new(&session.transport);
        tx_status_probe_post(&registers, &mut tx_status);
        tx_status_attach_rf_summary(&mut tx_status, &submit_counters);
        report.tx_status = tx_status;
    }
    bridge_tx_listen_update_counters(
        &mut report,
        pre_tx_counters,
        bridge_counters,
        submit_counters,
    );
    bridge_tx_listen_set_runtime_metrics(
        &mut report,
        started,
        cpu_started,
        datagram_bytes,
        frame_bytes,
    );
    report.result = DiagnosticResult::Pass;
    let mut phases = vec![
        DiagnosticPhase {
            id: "argument_validation",
            status: DiagnosticPhaseStatus::Completed,
            detail: "operator supplied channel, socket bounds, and live TX authorization",
        },
        DiagnosticPhase {
            id: "socket_bind",
            status: DiagnosticPhaseStatus::Completed,
            detail: "bound UDP socket for WFB distributor-style TX datagrams",
        },
        DiagnosticPhase {
            id: "usb_claim",
            status: DiagnosticPhaseStatus::Completed,
            detail: claim_detail,
        },
    ];
    if args.init_before_tx {
        phases.push(DiagnosticPhase {
            id: "init_before_tx",
            status: DiagnosticPhaseStatus::Completed,
            detail:
                "completed full RTL8812AU init inside the retained bridge TX listener USB session",
        });
    }
    if args.clear_txdma_status_before_tx {
        phases.push(DiagnosticPhase {
            id: "clear_txdma_status",
            status: DiagnosticPhaseStatus::Completed,
            detail: "wrote REG_TXDMA_STATUS before the TX loop as a guarded TXDMA-clear experiment",
        });
    }
    if !report.pre_tx_register_writes.is_empty() || !report.pre_tx_register_masked_writes.is_empty()
    {
        phases.push(DiagnosticPhase {
            id: "pre_tx_register_write",
            status: DiagnosticPhaseStatus::Completed,
            detail: "applied generic pre-TX register writes as guarded experiments",
        });
    }
    if !report.pre_tx_rf_writes.is_empty() {
        phases.push(DiagnosticPhase {
            id: "pre_tx_rf_write",
            status: DiagnosticPhaseStatus::Completed,
            detail: "applied RF 3-wire pre-TX writes as guarded experiments",
        });
    }
    if report.tx_power_control.is_some() {
        phases.push(DiagnosticPhase {
            id: "tx_power_control",
            status: DiagnosticPhaseStatus::Completed,
            detail: "applied explicit TXAGC power control before the TX loop",
        });
    }
    if report.tx_calibration_profile.is_some() {
        phases.push(DiagnosticPhase {
            id: "tx_calibration_profile",
            status: DiagnosticPhaseStatus::Completed,
            detail: "applied explicit targeted calibration profile before the TX loop",
        });
    }
    if report.rf_calibration_pre_tx.is_some() {
        phases.push(DiagnosticPhase {
            id: "rf_calibration_probe",
            status: DiagnosticPhaseStatus::Completed,
            detail: "sampled RF calibration state before the TX loop",
        });
    }
    phases.push(DiagnosticPhase {
        id: "bridge_listen",
        status: DiagnosticPhaseStatus::Completed,
        detail: "received bounded UDP datagrams and submitted them through live radio TX",
    });
    report.phases = phases;
    report.notes = if args.init_before_tx {
        vec![
            "live bridge TX listener ran same-session RTL8812AU init before accepting datagrams",
            "UDP datagrams were submitted through the radio backend; no receiver confirmation was attempted",
        ]
    } else {
        vec![
            "live bridge TX listener assumes the adapter has already completed init on the requested channel",
            "UDP datagrams were submitted through the radio backend; no receiver confirmation was attempted",
        ]
    };
    report
}

fn bridge_tx_listen_base_report(
    args: &BridgeTxListenArgs,
    selector: DeviceSelector,
    channel: Option<Channel>,
) -> BridgeTxListenReport {
    BridgeTxListenReport {
        schema_version: 1,
        command: "bridge-tx-listen",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        adapter: None,
        endpoints: None,
        channel,
        bandwidth: args.bandwidth,
        bind_addr: args.bind.to_string(),
        ready_file: args.ready_file.clone(),
        max_datagrams: args.max_datagrams,
        idle_timeout_ms: args.idle_timeout_ms,
        datagrams_received: 0,
        last_peer: None,
        last_datagram: None,
        bulk_out_endpoint: None,
        bulk_out_endpoint_hex: None,
        same_session_init: None,
        txdma_status_clear: None,
        tx_power_control: None,
        tx_calibration_profile: None,
        rf_calibration_pre_tx: None,
        pre_tx_register_writes: Vec::new(),
        pre_tx_register_masked_writes: Vec::new(),
        pre_tx_rf_writes: Vec::new(),
        tx_status: None,
        bridge_counters: TxCounters::default(),
        submit_counters: TxSubmitCounters::default(),
        throughput: None,
        cpu: None,
        counters: DiagnosticCounters::default(),
        result: DiagnosticResult::NotImplemented,
        phases: Vec::new(),
        error: None,
        notes: vec!["live bridge TX listener stopped before completing bounded submission"],
    }
}

fn bridge_tx_listen_write_ready_file(
    args: &BridgeTxListenArgs,
    report: &BridgeTxListenReport,
) -> std::result::Result<(), DiagnosticErrorReport> {
    let Some(path) = args.ready_file.as_ref() else {
        return Ok(());
    };
    let marker = serde_json::json!({
        "source": "bridge-tx-listen",
        "ready_at_unix_ms": started_at_unix_ms(),
        "bind_addr": report.bind_addr,
        "channel": report.channel.as_ref().map(|channel| channel.number),
        "channel_frequency_mhz": report.channel.as_ref().map(|channel| channel.frequency_mhz),
        "bandwidth_mhz": args.bandwidth.mhz(),
        "max_datagrams": args.max_datagrams,
        "idle_timeout_ms": args.idle_timeout_ms,
        "init_before_tx": args.init_before_tx,
        "same_session_init_result": report.same_session_init.as_ref().map(|init| init.result.as_str()),
        "tx_power_control_applied": report.tx_power_control.is_some(),
        "tx_calibration_profile_applied": report.tx_calibration_profile.is_some(),
    });
    let mut bytes = serde_json::to_vec_pretty(&marker).map_err(|error| DiagnosticErrorReport {
        code: "bridge_ready_marker_serialize_failed",
        message: error.to_string(),
    })?;
    bytes.push(b'\n');
    fs::write(path, bytes).map_err(|error| DiagnosticErrorReport {
        code: "bridge_ready_marker_write_failed",
        message: format!("{}: {error}", path.display()),
    })
}

fn bridge_tx_listen_set_runtime_metrics(
    report: &mut BridgeTxListenReport,
    started: Instant,
    cpu_started: Option<CpuUsageSnapshot>,
    datagram_bytes: u64,
    frame_bytes: u64,
) {
    let elapsed = started.elapsed();
    let elapsed_us = elapsed.as_micros().try_into().unwrap_or(u64::MAX);
    let elapsed_ms = elapsed.as_millis().try_into().unwrap_or(u64::MAX);
    report.throughput = Some(BridgeTxListenThroughputReport {
        elapsed_us,
        received_per_second: rate_per_second_us(report.datagrams_received, elapsed_us),
        submitted_per_second: rate_per_second_us(report.submit_counters.submitted, elapsed_us),
        datagram_bytes,
        frame_bytes,
        usb_bytes: report.submit_counters.bytes_written,
        datagram_bytes_per_second: rate_per_second_us(datagram_bytes, elapsed_us),
        frame_bytes_per_second: rate_per_second_us(frame_bytes, elapsed_us),
        usb_bytes_per_second: rate_per_second_us(report.submit_counters.bytes_written, elapsed_us),
    });
    report.cpu = cpu_usage_delta(cpu_started, process_cpu_usage(), elapsed_ms);
}

fn bridge_tx_listen_failure(
    mut report: BridgeTxListenReport,
    phase_id: &'static str,
    phase_detail: &'static str,
    error: DiagnosticErrorReport,
) -> BridgeTxListenReport {
    report.result = DiagnosticResult::Fail;
    report.phases = vec![DiagnosticPhase {
        id: phase_id,
        status: DiagnosticPhaseStatus::Blocked,
        detail: phase_detail,
    }];
    report.error = Some(error);
    report
}

#[cfg(unix)]
extern "C" fn bridge_run_signal_handler(_signal: libc::c_int) {
    BRIDGE_RUN_STOP_REQUESTED.store(true, Ordering::SeqCst);
}

#[cfg(unix)]
fn install_bridge_run_signal_handlers() -> std::io::Result<()> {
    unsafe {
        let mut action: libc::sigaction = std::mem::zeroed();
        action.sa_sigaction = bridge_run_signal_handler as *const () as libc::sighandler_t;
        action.sa_flags = 0;
        libc::sigemptyset(&mut action.sa_mask);
        for signal in [libc::SIGINT, libc::SIGTERM] {
            if libc::sigaction(signal, &action, std::ptr::null_mut()) != 0 {
                return Err(std::io::Error::last_os_error());
            }
        }
    }
    Ok(())
}

#[cfg(not(unix))]
fn install_bridge_run_signal_handlers() -> std::io::Result<()> {
    Ok(())
}

fn configure_bridge_tx_socket(
    socket: &UdpSocket,
    bind_addr: SocketAddr,
) -> std::result::Result<(), DiagnosticErrorReport> {
    configure_production_tx_ingress_socket(socket, bind_addr, PRODUCTION_TX_SOCKET_RCVBUF_BYTES)
        .map_err(runtime_radio_error)
}

fn bridge_run_bind_addrs(args: &BridgeRunArgs) -> Vec<SocketAddr> {
    let mut bind_addrs = Vec::with_capacity(args.tx_binds.len() + 1);
    bind_addrs.push(args.tx.bind);
    bind_addrs.extend(args.tx_binds.iter().copied());
    bind_addrs
}

fn bridge_run_bind_tx_sockets(
    args: &BridgeRunArgs,
) -> std::result::Result<Vec<ProductionRuntimeTxIngressSocket>, DiagnosticErrorReport> {
    let bind_addrs = bridge_run_bind_addrs(args);
    bind_production_tx_ingress_sockets(&bind_addrs, PRODUCTION_TX_SOCKET_RCVBUF_BYTES)
        .map_err(runtime_radio_error)
}

fn bridge_run_spawn_tx_receivers(
    sockets: Vec<ProductionRuntimeTxIngressSocket>,
) -> std::result::Result<ProductionRuntimeTxIngressReceiver, DiagnosticErrorReport> {
    spawn_production_tx_ingress_receivers(sockets, PRODUCTION_TX_RECEIVE_TIMEOUT)
        .map_err(runtime_radio_error)
}

fn runtime_calibration_evidence_source_label(
    source: RuntimeTxCalibrationEvidenceSource,
) -> &'static str {
    match source {
        RuntimeTxCalibrationEvidenceSource::Default => "default",
        RuntimeTxCalibrationEvidenceSource::CapturedLinuxTail => "captured_linux_tail",
        RuntimeTxCalibrationEvidenceSource::TargetedLinuxParityCapture => {
            "targeted_linux_parity_capture"
        }
        RuntimeTxCalibrationEvidenceSource::RuntimeLck => "runtime_lck",
        RuntimeTxCalibrationEvidenceSource::ReadOnlyIqkProbe => "read_only_iqk_probe",
        RuntimeTxCalibrationEvidenceSource::RuntimeIqk => "runtime_iqk",
    }
}

