type RfSerialWriteTarget = (TxPowerPathArg, &'static str, &'static str, u16);
type RfSerialReadTarget = (
    TxPowerPathArg,
    &'static str,
    &'static str,
    u16,
    &'static str,
    u16,
    &'static str,
    u16,
);

const RF_SERIAL_TARGET_A: [RfSerialWriteTarget; 1] = [(
    TxPowerPathArg::A,
    "A",
    "rA_LSSIWrite_Jaguar",
    REG_RF_PATH_A_3WIRE,
)];
const RF_SERIAL_TARGET_B: [RfSerialWriteTarget; 1] = [(
    TxPowerPathArg::B,
    "B",
    "rB_LSSIWrite_Jaguar",
    REG_RF_PATH_B_3WIRE,
)];
const RF_SERIAL_TARGET_BOTH: [RfSerialWriteTarget; 2] = [
    (
        TxPowerPathArg::A,
        "A",
        "rA_LSSIWrite_Jaguar",
        REG_RF_PATH_A_3WIRE,
    ),
    (
        TxPowerPathArg::B,
        "B",
        "rB_LSSIWrite_Jaguar",
        REG_RF_PATH_B_3WIRE,
    ),
];
const RF_SERIAL_READ_TARGET_A: RfSerialReadTarget = (
    TxPowerPathArg::A,
    "A",
    "rA_PI_Mode_Jaguar",
    REG_RF_PI_MODE_A_JAGUAR,
    "rA_PIRead_Jaguar",
    REG_RF_PI_READ_A_JAGUAR,
    "rA_SIRead_Jaguar",
    REG_RF_SI_READ_A_JAGUAR,
);
const RF_SERIAL_READ_TARGET_B: RfSerialReadTarget = (
    TxPowerPathArg::B,
    "B",
    "rB_PI_Mode_Jaguar",
    REG_RF_PI_MODE_B_JAGUAR,
    "rB_PIRead_Jaguar",
    REG_RF_PI_READ_B_JAGUAR,
    "rB_SIRead_Jaguar",
    REG_RF_SI_READ_B_JAGUAR,
);

fn rf_serial_write_targets(path: TxPowerPathArg) -> &'static [RfSerialWriteTarget] {
    match path {
        TxPowerPathArg::A => &RF_SERIAL_TARGET_A,
        TxPowerPathArg::B => &RF_SERIAL_TARGET_B,
        TxPowerPathArg::Both => &RF_SERIAL_TARGET_BOTH,
    }
}

fn rf_register_display_name(rf_offset: u32) -> &'static str {
    match rf_offset {
        0x00 => "RF_0x00",
        RF_IQK_LOK_READBACK_JAGUAR => "RF_0x08_LOK_readback",
        RF_IQK_TX_0X30_JAGUAR => "RF_0x30_IQK",
        RF_IQK_TX_0X31_JAGUAR => "RF_0x31_IQK",
        RF_IQK_TX_0X32_JAGUAR => "RF_0x32_IQK",
        RF_IQK_LOK_LOAD_JAGUAR => "RF_0x58_LOK_load",
        0x65 => "RF_0x65_IQK_backup",
        0x8f => "RF_0x8f_IQK_backup",
        RF_IQK_MODE_JAGUAR => "RF_0xef_IQK_mode",
        RF_CHNLBW_JAGUAR => "RF_CHNLBW_Jaguar",
        RF_LCK_JAGUAR => "RF_LCK",
        _ => "RF register",
    }
}

fn rf_serial_read_target(path: TxPowerPathArg) -> Option<RfSerialReadTarget> {
    match path {
        TxPowerPathArg::A => Some(RF_SERIAL_READ_TARGET_A),
        TxPowerPathArg::B => Some(RF_SERIAL_READ_TARGET_B),
        TxPowerPathArg::Both => None,
    }
}

fn rf_serial_read_register<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    path: TxPowerPathArg,
    rf_offset: u32,
    counters: &mut DiagnosticCounters,
) -> std::result::Result<RfSerialReadReport, DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let (
        path,
        path_name,
        pi_mode_register_name,
        pi_mode_register,
        pi_readback_register_name,
        pi_readback_register,
        si_readback_register_name,
        si_readback_register,
    ) = rf_serial_read_target(path).ok_or_else(|| DiagnosticErrorReport {
        code: "rf_serial_read_path_unsupported",
        message: "RF serial read requires path A or path B, not both".to_string(),
    })?;
    let before = *counters;
    let rf_offset = rf_offset & 0xff;

    let pi_mode_value =
        read32_with_counter(registers, counters, pi_mode_register).map_err(|error| {
            DiagnosticErrorReport {
                code: "rf_serial_read_failed",
                message: format!(
                    "RF path {path_name} PI/SI mode read from {} failed: {error}",
                    format_address(pi_mode_register)
                ),
            }
        })?;
    let pi_mode = pi_mode_value & 0x4 != 0;

    bb_set_bb_reg(
        registers,
        counters,
        REG_HSSI_READ_JAGUAR,
        0x0000_00ff,
        rf_offset,
    )
    .map_err(|error| DiagnosticErrorReport {
        code: "rf_serial_read_failed",
        message: format!(
            "RF path {path_name} read-address select offset 0x{rf_offset:02x} through {} failed: {error}",
            format_address(REG_HSSI_READ_JAGUAR)
        ),
    })?;
    std::thread::sleep(Duration::from_micros(20));

    let (readback_register_name, readback_register) = if pi_mode {
        (pi_readback_register_name, pi_readback_register)
    } else {
        (si_readback_register_name, si_readback_register)
    };
    let value = read32_with_counter(registers, counters, readback_register).map_err(|error| {
        DiagnosticErrorReport {
            code: "rf_serial_read_failed",
            message: format!(
                "RF path {path_name} offset 0x{rf_offset:02x} readback from {} failed: {error}",
                format_address(readback_register)
            ),
        }
    })? & RF_REGISTER_OFFSET_MASK;

    Ok(RfSerialReadReport {
        register_name: rf_register_display_name(rf_offset),
        path,
        path_name,
        rf_offset,
        rf_offset_hex: format_value(rf_offset, 2),
        hssi_register_name: "rHSSIRead_Jaguar",
        hssi_register: REG_HSSI_READ_JAGUAR,
        hssi_register_hex: format_address(REG_HSSI_READ_JAGUAR),
        hssi_mask_hex: format_value(0x0000_00ff_u32, 8),
        pi_mode_register_name,
        pi_mode_register,
        pi_mode_register_hex: format_address(pi_mode_register),
        pi_mode_value,
        pi_mode_value_hex: format_value(pi_mode_value, 8),
        pi_mode,
        readback_register_name,
        readback_register,
        readback_register_hex: format_address(readback_register),
        readback_mask_hex: format_value(RF_REGISTER_OFFSET_MASK, 5),
        value,
        value_hex: format_value(value, 5),
        counters: diagnostic_counters_delta(before, *counters),
    })
}

fn bridge_tx_bench_write_rf_serial_register<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    write: &PreTxRfWriteArg,
    counters: &mut DiagnosticCounters,
) -> std::result::Result<Vec<BridgeTxBenchRfSerialWriteReport>, DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let mut reports = Vec::new();
    for &(path, path_name, bb_register_name, bb_register) in rf_serial_write_targets(write.path) {
        let encoded = encode_rf_serial_write(write.rf_offset, write.value);
        write32_with_counter(registers, counters, bb_register, encoded).map_err(|error| {
            DiagnosticErrorReport {
                code: "rf_serial_write_failed",
                message: format!(
                    "pre-TX RF path {path_name} offset 0x{:02x} value {} via {} failed: {error}",
                    write.rf_offset,
                    format_value(write.value, 5),
                    format_address(bb_register)
                ),
            }
        })?;
        reports.push(BridgeTxBenchRfSerialWriteReport {
            register_name: rf_register_display_name(write.rf_offset),
            path,
            path_name,
            bb_register_name,
            bb_register,
            bb_register_hex: format_value(bb_register, 4),
            rf_offset: write.rf_offset,
            rf_offset_hex: format_value(write.rf_offset, 2),
            value: write.value,
            value_hex: format_value(write.value, 5),
            encoded,
            encoded_hex: format_value(encoded, 8),
            counters: DiagnosticCounters {
                usb_control_writes: 1,
                ..DiagnosticCounters::default()
            },
        });
        std::thread::sleep(Duration::from_micros(1));
    }
    Ok(reports)
}

fn bridge_tx_bench_trace_apply_plan(
    source_path: &Path,
    input: &str,
    min_address: u16,
    max_address: u16,
) -> std::result::Result<
    (
        BridgeTxBenchTraceApplyReport,
        Vec<BridgeTxBenchTraceApplyWrite>,
    ),
    DiagnosticErrorReport,
> {
    let final_writes =
        parse_trace_register_final_writes_json(input).map_err(|error| DiagnosticErrorReport {
            code: "pre_tx_trace_register_parse_failed",
            message: format!("parse {}: {error}", source_path.display()),
        })?;
    let mut report = BridgeTxBenchTraceApplyReport {
        source_path: source_path.to_path_buf(),
        mode: "final-map",
        min_address,
        min_address_hex: format_address(min_address),
        max_address,
        max_address_hex: format_address(max_address),
        min_event_index: None,
        max_event_index: None,
        first_applied_event_index: None,
        last_applied_event_index: None,
        writes_loaded: final_writes.len(),
        writes_selected: 0,
        writes_applied: 0,
        skipped_out_of_range: 0,
        skipped_out_of_event_range: 0,
        skipped_unsupported_width: 0,
    };
    let mut writes = Vec::new();
    for final_write in final_writes {
        let Some(width) = tx_status_width_from_trace_width(final_write.width) else {
            report.skipped_unsupported_width += 1;
            continue;
        };
        if final_write.address < min_address || final_write.address > max_address {
            report.skipped_out_of_range += 1;
            continue;
        }
        let value = parse_trace_value_hex(&final_write.value_le_hex).map_err(|error| {
            DiagnosticErrorReport {
                code: "pre_tx_trace_register_value_failed",
                message: format!("parse {}: {error}", source_path.display()),
            }
        })?;
        report.writes_selected += 1;
        writes.push(BridgeTxBenchTraceApplyWrite {
            event_index: Some(final_write.last_event_index),
            address: final_write.address,
            width,
            value,
        });
    }

    Ok((report, writes))
}

fn parse_trace_register_writes_json(
    input: &str,
) -> std::result::Result<Vec<TraceRegisterWriteReport>, String> {
    #[derive(Deserialize)]
    struct TraceRegisterWritesEnvelope {
        writes: Option<Vec<TraceRegisterWriteReport>>,
    }

    if let Ok(writes) = serde_json::from_str::<Vec<TraceRegisterWriteReport>>(input) {
        return Ok(writes);
    }

    let envelope = serde_json::from_str::<TraceRegisterWritesEnvelope>(input)
        .map_err(|error| error.to_string())?;
    envelope.writes.ok_or_else(|| {
        "JSON does not contain a trace-registers writes array; run trace-registers with --include-writes and save the full report with global --report".to_string()
    })
}

fn bridge_tx_bench_trace_sequence_apply_plan(
    source_path: &Path,
    input: &str,
    min_address: u16,
    max_address: u16,
    min_event_index: Option<usize>,
    max_event_index: Option<usize>,
) -> std::result::Result<
    (
        BridgeTxBenchTraceApplyReport,
        Vec<BridgeTxBenchTraceApplyWrite>,
    ),
    DiagnosticErrorReport,
> {
    let trace_writes =
        parse_trace_register_writes_json(input).map_err(|error| DiagnosticErrorReport {
            code: "pre_tx_trace_register_sequence_parse_failed",
            message: format!("parse {}: {error}", source_path.display()),
        })?;
    let mut report = BridgeTxBenchTraceApplyReport {
        source_path: source_path.to_path_buf(),
        mode: "ordered-sequence",
        min_address,
        min_address_hex: format_address(min_address),
        max_address,
        max_address_hex: format_address(max_address),
        min_event_index,
        max_event_index,
        first_applied_event_index: None,
        last_applied_event_index: None,
        writes_loaded: trace_writes.len(),
        writes_selected: 0,
        writes_applied: 0,
        skipped_out_of_range: 0,
        skipped_out_of_event_range: 0,
        skipped_unsupported_width: 0,
    };
    let mut writes = Vec::new();
    for trace_write in trace_writes {
        let Some(width) = tx_status_width_from_trace_width(trace_write.width) else {
            report.skipped_unsupported_width += 1;
            continue;
        };
        if trace_write.address < min_address || trace_write.address > max_address {
            report.skipped_out_of_range += 1;
            continue;
        }
        if min_event_index.is_some_and(|min_event_index| trace_write.event_index < min_event_index)
            || max_event_index
                .is_some_and(|max_event_index| trace_write.event_index > max_event_index)
        {
            report.skipped_out_of_event_range += 1;
            continue;
        }
        let value = parse_trace_value_hex(&trace_write.value_le_hex).map_err(|error| {
            DiagnosticErrorReport {
                code: "pre_tx_trace_register_sequence_value_failed",
                message: format!("parse {}: {error}", source_path.display()),
            }
        })?;
        report.writes_selected += 1;
        report.first_applied_event_index = report
            .first_applied_event_index
            .or(Some(trace_write.event_index));
        report.last_applied_event_index = Some(trace_write.event_index);
        writes.push(BridgeTxBenchTraceApplyWrite {
            event_index: Some(trace_write.event_index),
            address: trace_write.address,
            width,
            value,
        });
    }

    Ok((report, writes))
}

fn bridge_tx_bench_write_trace_register<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    write: &BridgeTxBenchTraceApplyWrite,
    counters: &mut DiagnosticCounters,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    match write.width {
        TxStatusRegisterWidth::U8 => {
            write8_with_counter(registers, counters, write.address, write.value as u8)
        }
        TxStatusRegisterWidth::U16 => {
            write16_with_counter(registers, counters, write.address, write.value as u16)
        }
        TxStatusRegisterWidth::U32 => {
            write32_with_counter(registers, counters, write.address, write.value)
        }
    }
    .map_err(|error| DiagnosticErrorReport {
        code: "pre_tx_trace_register_sequence_write_failed",
        message: format!(
            "event={} address={} width={} write failed: {error}",
            write
                .event_index
                .map(|event_index| event_index.to_string())
                .unwrap_or_else(|| "unknown".to_string()),
            format_address(write.address),
            match write.width {
                TxStatusRegisterWidth::U8 => 1,
                TxStatusRegisterWidth::U16 => 2,
                TxStatusRegisterWidth::U32 => 4,
            }
        ),
    })
}

fn bridge_tx_bench_apply_trace_registers<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    args: &BridgeTxBenchArgs,
    report: &mut BridgeTxBenchReport,
    counters: &mut DiagnosticCounters,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    if args.pre_tx_apply_min_address > args.pre_tx_apply_max_address {
        return Err(DiagnosticErrorReport {
            code: "invalid_pre_tx_trace_register_range",
            message: format!(
                "--pre-tx-apply-min-address {} is greater than --pre-tx-apply-max-address {}",
                format_address(args.pre_tx_apply_min_address),
                format_address(args.pre_tx_apply_max_address)
            ),
        });
    }

    for source_path in &args.pre_tx_apply_registers_from {
        let input = fs::read_to_string(source_path).map_err(|error| DiagnosticErrorReport {
            code: "pre_tx_trace_register_read_failed",
            message: format!("read {}: {error}", source_path.display()),
        })?;
        let (mut apply_report, writes) = bridge_tx_bench_trace_apply_plan(
            source_path,
            &input,
            args.pre_tx_apply_min_address,
            args.pre_tx_apply_max_address,
        )?;
        for write in writes {
            let write_report = match write.width {
                TxStatusRegisterWidth::U8 => bridge_tx_bench_write8_register(
                    registers,
                    "pre_tx_trace_apply",
                    write.address,
                    write.value as u8,
                    counters,
                ),
                TxStatusRegisterWidth::U16 => bridge_tx_bench_write16_register(
                    registers,
                    "pre_tx_trace_apply",
                    write.address,
                    write.value as u16,
                    counters,
                ),
                TxStatusRegisterWidth::U32 => bridge_tx_bench_write32_register(
                    registers,
                    "pre_tx_trace_apply",
                    write.address,
                    write.value,
                    counters,
                ),
            }?;
            apply_report.writes_applied += 1;
            report.pre_tx_register_writes.push(write_report);
        }
        report.pre_tx_register_apply.push(apply_report);
    }

    Ok(())
}

fn bridge_tx_bench_apply_trace_register_sequences<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    args: &BridgeTxBenchArgs,
    report: &mut BridgeTxBenchReport,
    counters: &mut DiagnosticCounters,
) -> std::result::Result<(), DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    if args.pre_tx_apply_min_address > args.pre_tx_apply_max_address {
        return Err(DiagnosticErrorReport {
            code: "invalid_pre_tx_trace_register_range",
            message: format!(
                "--pre-tx-apply-min-address {} is greater than --pre-tx-apply-max-address {}",
                format_address(args.pre_tx_apply_min_address),
                format_address(args.pre_tx_apply_max_address)
            ),
        });
    }
    if args
        .pre_tx_apply_min_event
        .zip(args.pre_tx_apply_max_event)
        .is_some_and(|(min_event, max_event)| min_event > max_event)
    {
        return Err(DiagnosticErrorReport {
            code: "invalid_pre_tx_trace_register_event_range",
            message: format!(
                "--pre-tx-apply-min-event {} is greater than --pre-tx-apply-max-event {}",
                args.pre_tx_apply_min_event.unwrap_or_default(),
                args.pre_tx_apply_max_event.unwrap_or_default()
            ),
        });
    }

    for source_path in &args.pre_tx_apply_register_sequence_from {
        let input = fs::read_to_string(source_path).map_err(|error| DiagnosticErrorReport {
            code: "pre_tx_trace_register_sequence_read_failed",
            message: format!("read {}: {error}", source_path.display()),
        })?;
        let (mut apply_report, writes) = bridge_tx_bench_trace_sequence_apply_plan(
            source_path,
            &input,
            args.pre_tx_apply_min_address,
            args.pre_tx_apply_max_address,
            args.pre_tx_apply_min_event,
            args.pre_tx_apply_max_event,
        )?;
        for write in writes {
            bridge_tx_bench_write_trace_register(registers, &write, counters)?;
            apply_report.writes_applied += 1;
        }
        report.pre_tx_register_apply.push(apply_report);
    }

    Ok(())
}

fn bridge_tx_bench_rmw32_register<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    register_name: &'static str,
    address: u16,
    mask: u32,
    value: u32,
    counters: &mut DiagnosticCounters,
) -> std::result::Result<BridgeTxBenchRegisterMaskedWriteReport, DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let before = read32_with_counter(registers, counters, address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{register_name} pre-rmw read failed: {error}"),
        }
    })?;
    let written = (before & !mask) | (value & mask);
    write32_with_counter(registers, counters, address, written).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_write_failed",
            message: format!("{register_name} masked write failed: {error}"),
        }
    })?;
    let after = read32_with_counter(registers, counters, address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{register_name} post-rmw read failed: {error}"),
        }
    })?;

    Ok(BridgeTxBenchRegisterMaskedWriteReport {
        register_name,
        address,
        address_hex: format_value(address, 4),
        width: "u32",
        mask,
        mask_hex: format_value(mask, 8),
        before,
        before_hex: format_value(before, 8),
        written,
        written_hex: format_value(written, 8),
        after,
        after_hex: format_value(after, 8),
        changed: before != after,
        counters: DiagnosticCounters {
            usb_control_reads: 2,
            usb_control_writes: 1,
            ..DiagnosticCounters::default()
        },
    })
}

fn bridge_tx_bench_set8_register<T>(
    registers: &Rtl8812auRegisterAccess<T>,
    register_name: &'static str,
    address: u16,
    mask: u8,
    counters: &mut DiagnosticCounters,
) -> std::result::Result<BridgeTxBenchRegisterClearReport, DiagnosticErrorReport>
where
    T: radio_core::rtl8812au::Rtl8812auUsbTransport,
{
    let before = read8_with_counter(registers, counters, address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{register_name} pre-set read failed: {error}"),
        }
    })?;
    let value = before | mask;
    write8_with_counter(registers, counters, address, value).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_write_failed",
            message: format!("{register_name} set write failed: {error}"),
        }
    })?;
    let after = read8_with_counter(registers, counters, address).map_err(|error| {
        DiagnosticErrorReport {
            code: "register_read_failed",
            message: format!("{register_name} post-set read failed: {error}"),
        }
    })?;

    Ok(BridgeTxBenchRegisterClearReport {
        register_name,
        address,
        address_hex: format_value(address, 4),
        width: "u8",
        before: u32::from(before),
        before_hex: format_value(before, 2),
        written: u32::from(value),
        written_hex: format_value(value, 2),
        after: u32::from(after),
        after_hex: format_value(after, 2),
        changed: before != after,
        counters: DiagnosticCounters {
            usb_control_reads: 2,
            usb_control_writes: 1,
            ..DiagnosticCounters::default()
        },
    })
}

