fn bridge_tx_bench_failure(
    mut report: BridgeTxBenchReport,
    phase_id: &'static str,
    phase_detail: &'static str,
    error: DiagnosticErrorReport,
) -> BridgeTxBenchReport {
    report.result = DiagnosticResult::Fail;
    report.phases = vec![DiagnosticPhase {
        id: phase_id,
        status: DiagnosticPhaseStatus::Blocked,
        detail: phase_detail,
    }];
    report.error = Some(error);
    report
}

fn bridge_tx_bench_update_metrics(
    report: &mut BridgeTxBenchReport,
    pre_tx_counters: DiagnosticCounters,
    bridge_counters: TxCounters,
    submit_counters: TxSubmitCounters,
    elapsed_us: u64,
    cpu: Option<CpuUsageReport>,
) {
    report.bridge_counters = bridge_counters;
    report.submit_counters = submit_counters;
    report.counters = DiagnosticCounters {
        usb_control_reads: pre_tx_counters.usb_control_reads,
        usb_control_writes: pre_tx_counters.usb_control_writes,
        usb_bulk_in_reads: pre_tx_counters.usb_bulk_in_reads,
        usb_bulk_out_writes: report.submit_counters.submitted + report.submit_counters.failed,
        tx_frames: report.submit_counters.submitted,
        dropped_frames: report.bridge_counters.dropped,
        ..DiagnosticCounters::default()
    };
    report.throughput = Some(BridgeTxBenchThroughputReport {
        elapsed_us,
        submitted_per_second: rate_per_second_us(report.submit_counters.submitted, elapsed_us),
        usb_bytes_per_second: rate_per_second_us(report.submit_counters.bytes_written, elapsed_us),
        payload_bytes_per_second: rate_per_second_us(
            report
                .submit_counters
                .submitted
                .saturating_mul(report.payload_len as u64),
            elapsed_us,
        ),
        datagram_bytes_per_second: rate_per_second_us(
            report
                .submit_counters
                .submitted
                .saturating_mul(report.datagram_len.unwrap_or_default() as u64),
            elapsed_us,
        ),
    });
    report.cpu = cpu;
}

fn rf_quality_report(args: RfQualityReportArgs) -> RfQualityReport {
    let selector = args.adapter.selector();
    let (channel, channel_result, channel_error) =
        resolve_report_channel(args.channel, args.bandwidth);
    let mut result = if channel_result == DiagnosticResult::Fail {
        DiagnosticResult::Fail
    } else {
        DiagnosticResult::Pass
    };
    let mut error = channel_error;
    let mut phases = vec![DiagnosticPhase {
        id: "argument_validation",
        status: if result == DiagnosticResult::Fail {
            DiagnosticPhaseStatus::Blocked
        } else {
            DiagnosticPhaseStatus::Completed
        },
        detail: "validated RF-quality profile channel, bandwidth, descriptor profile, and WFB comparison parameters",
    }];

    let mac_report_json = match args.mac_report.as_deref() {
        Some(path) if result != DiagnosticResult::Fail => {
            match rf_quality_load_json(path, "mac_report_read_failed", "mac_report_parse_failed") {
                Ok(value) => {
                    phases.push(DiagnosticPhase {
                        id: "macos_artifact",
                        status: DiagnosticPhaseStatus::Completed,
                        detail: "loaded macOS bridge or benchmark JSON artifact",
                    });
                    Some(value)
                }
                Err(load_error) => {
                    result = DiagnosticResult::Fail;
                    error = Some(load_error);
                    phases.push(DiagnosticPhase {
                        id: "macos_artifact",
                        status: DiagnosticPhaseStatus::Blocked,
                        detail: "failed to load macOS RF-quality input artifact",
                    });
                    None
                }
            }
        }
        Some(_) => None,
        None => {
            phases.push(DiagnosticPhase {
                id: "macos_artifact",
                status: DiagnosticPhaseStatus::Pending,
                detail: "no macOS bridge or benchmark artifact was supplied",
            });
            None
        }
    };

    let efuse_report_json = match args.efuse_report.as_deref() {
        Some(path) if result != DiagnosticResult::Fail => {
            match rf_quality_load_json(
                path,
                "efuse_report_read_failed",
                "efuse_report_parse_failed",
            ) {
                Ok(value) => {
                    phases.push(DiagnosticPhase {
                        id: "efuse_artifact",
                        status: DiagnosticPhaseStatus::Completed,
                        detail: "loaded EFUSE JSON artifact for adapter and TX-power context",
                    });
                    Some(value)
                }
                Err(load_error) => {
                    result = DiagnosticResult::Fail;
                    error = Some(load_error);
                    phases.push(DiagnosticPhase {
                        id: "efuse_artifact",
                        status: DiagnosticPhaseStatus::Blocked,
                        detail: "failed to load EFUSE RF-quality input artifact",
                    });
                    None
                }
            }
        }
        Some(_) => None,
        None => None,
    };

    let linux_baseline = match args.linux_baseline.as_deref() {
        Some(path) if result != DiagnosticResult::Fail => {
            match rf_quality_load_json(
                path,
                "linux_baseline_read_failed",
                "linux_baseline_parse_failed",
            )
            .and_then(|value| rf_quality_linux_baseline_report(path, &value))
            {
                Ok(baseline) => {
                    phases.push(DiagnosticPhase {
                        id: "linux_baseline",
                        status: DiagnosticPhaseStatus::Completed,
                        detail: "loaded Linux baseline artifact and extracted comparable profile parameters",
                    });
                    Some(baseline)
                }
                Err(load_error) => {
                    result = DiagnosticResult::Fail;
                    error = Some(load_error);
                    phases.push(DiagnosticPhase {
                        id: "linux_baseline",
                        status: DiagnosticPhaseStatus::Blocked,
                        detail: "failed to load Linux baseline RF-quality artifact",
                    });
                    None
                }
            }
        }
        Some(_) => None,
        None => {
            phases.push(DiagnosticPhase {
                id: "linux_baseline",
                status: DiagnosticPhaseStatus::Pending,
                detail: "no Linux baseline was supplied; comparison and range acceptance remain unevaluated",
            });
            None
        }
    };

    let profile = rf_quality_profile_report(&args, channel);
    let close_range_report_json = match args.close_range_report.as_deref() {
        Some(path) if result != DiagnosticResult::Fail => {
            match rf_quality_load_json(
                path,
                "close_range_report_read_failed",
                "close_range_report_parse_failed",
            ) {
                Ok(value) => {
                    phases.push(DiagnosticPhase {
                        id: "close_range_gate_artifact",
                        status: DiagnosticPhaseStatus::Completed,
                        detail: "loaded close-range RF-quality gate report",
                    });
                    Some(value)
                }
                Err(load_error) => {
                    result = DiagnosticResult::Fail;
                    error = Some(load_error);
                    phases.push(DiagnosticPhase {
                        id: "close_range_gate_artifact",
                        status: DiagnosticPhaseStatus::Blocked,
                        detail: "failed to load close-range RF-quality gate report",
                    });
                    None
                }
            }
        }
        Some(_) => None,
        None => None,
    };
    let profile_gate =
        rf_quality_profile_gate_report(&args, &profile, close_range_report_json.as_ref());
    if rf_quality_profile_gate_blocks(&profile_gate) {
        result = DiagnosticResult::Fail;
        error.get_or_insert_with(|| DiagnosticErrorReport {
            code: "close_range_gate_failed",
            message: profile_gate.reason.to_string(),
        });
        phases.push(DiagnosticPhase {
            id: "close_range_gate",
            status: DiagnosticPhaseStatus::Blocked,
            detail: "outdoor long-distance profile is blocked by the close-range gate",
        });
    } else {
        phases.push(DiagnosticPhase {
            id: "close_range_gate",
            status: DiagnosticPhaseStatus::Completed,
            detail: "close-range gate validation completed",
        });
    }

    let receiver_evidence = rf_quality_receiver_evidence_from_artifacts(&args.receiver_artifacts);
    let macos = rf_quality_macos_report(
        &args,
        mac_report_json.as_ref(),
        efuse_report_json.as_ref(),
        receiver_evidence.as_ref(),
    );
    let comparison =
        rf_quality_compare_profile_to_baseline(&profile, &macos, linux_baseline.as_ref());
    let acceptance = rf_quality_acceptance(result, &comparison, &profile_gate);

    RfQualityReport {
        schema_version: 1,
        command: "rf-quality-report",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        bandwidth_evidence: rf_quality_bandwidth_evidence_report(&args),
        companion_notes: rf_quality_companion_notes_report(&args),
        profile,
        macos,
        linux_baseline,
        comparison,
        profile_gate,
        acceptance,
        result,
        phases,
        error,
        notes: vec![
            "RF-quality reports are evidence envelopes; USB submission alone is not range acceptance",
            "this command does not initialize the adapter, transmit frames, or alter existing bridge defaults",
        ],
    }
}

fn rf_quality_bandwidth_evidence_report(
    args: &RfQualityReportArgs,
) -> RfQualityBandwidthEvidenceReport {
    let observed_frame_bandwidth_mhz = args
        .observed_ppdu_bandwidth
        .map(|bandwidth| bandwidth.mhz());
    let status = match observed_frame_bandwidth_mhz {
        None => RfQualityBandwidthEvidenceStatus::NotSupplied,
        Some(observed) if observed == args.bandwidth.mhz() => {
            RfQualityBandwidthEvidenceStatus::MatchesChannelContext
        }
        Some(observed) if observed < args.bandwidth.mhz() => {
            RfQualityBandwidthEvidenceStatus::ContextOnlyNarrowerObserved
        }
        Some(_) => RfQualityBandwidthEvidenceStatus::ObservedWiderThanContext,
    };
    RfQualityBandwidthEvidenceReport {
        channel_context_bandwidth: args.bandwidth,
        channel_context_bandwidth_mhz: args.bandwidth.mhz(),
        observed_frame_bandwidth: args.observed_ppdu_bandwidth,
        observed_frame_bandwidth_mhz,
        status,
        source: args.observed_ppdu_source.clone(),
        artifacts: args.observed_ppdu_artifacts.clone(),
    }
}

fn rf_quality_companion_notes_report(args: &RfQualityReportArgs) -> RfQualityCompanionNotesReport {
    let complete_for_field_run = args.distance_or_geometry.is_some()
        && args.antenna_orientation.is_some()
        && args.adapter_placement.is_some()
        && !args.environment_notes.is_empty()
        && !args.companion_artifacts.is_empty();
    RfQualityCompanionNotesReport {
        distance_or_geometry: args.distance_or_geometry.clone(),
        antenna_orientation: args.antenna_orientation.clone(),
        adapter_placement: args.adapter_placement.clone(),
        environment_notes: args.environment_notes.clone(),
        artifacts: args.companion_artifacts.clone(),
        complete_for_field_run,
    }
}

fn rf_quality_profile_report(
    args: &RfQualityReportArgs,
    channel: Option<Channel>,
) -> RfQualityProfileReport {
    RfQualityProfileReport {
        name: args.profile_name.clone(),
        kind: args.profile_kind,
        channel: args.channel,
        channel_frequency_mhz: channel.map(|channel| channel.frequency_mhz),
        bandwidth: args.bandwidth,
        bandwidth_mhz: args.bandwidth.mhz(),
        tx_rate: args.tx_rate.clone(),
        tx_descriptor_profile: args.tx_profile,
        tx_power_mode: args.tx_power_mode,
        calibration_mode: args.calibration_mode,
        wfb: RfQualityWfbSettingsReport {
            link_id: args.wfb_link_id,
            link_id_hex: format_value(args.wfb_link_id, 6),
            radio_port: args.wfb_radio_port,
            radio_port_hex: format_value(args.wfb_radio_port, 2),
            fec_k: args.fec_k,
            fec_n: args.fec_n,
        },
        payload_len: args.payload_len,
        expected_payloads: args.expected_payloads,
        receiver_artifacts: args.receiver_artifacts.clone(),
    }
}

fn rf_quality_macos_report(
    args: &RfQualityReportArgs,
    mac_report: Option<&serde_json::Value>,
    efuse_report: Option<&serde_json::Value>,
    receiver_evidence: Option<&serde_json::Value>,
) -> RfQualityMacosReport {
    let command = mac_report.and_then(|value| rf_quality_json_string(value, &["command"]));
    let result = mac_report.and_then(|value| rf_quality_json_string(value, &["result"]));
    let adapter = mac_report.and_then(|value| rf_quality_json_clone(value, &["adapter"]));
    let endpoints = mac_report.and_then(|value| rf_quality_json_clone(value, &["endpoints"]));
    let efuse_summary = efuse_report
        .and_then(|value| rf_quality_json_clone(value, &["efuse", "summary"]))
        .or_else(|| {
            mac_report.and_then(|value| rf_quality_json_clone(value, &["efuse", "summary"]))
        })
        .or_else(|| mac_report.and_then(|value| rf_quality_json_clone(value, &["efuse_summary"])));
    let rfe_type = mac_report
        .and_then(|value| rf_quality_json_u8(value, &["same_session_init", "rfe_type"]))
        .or_else(|| mac_report.and_then(|value| rf_quality_json_u8(value, &["rfe_type"])));
    let channel = mac_report
        .and_then(|value| rf_quality_json_u8(value, &["channel", "number"]))
        .or_else(|| mac_report.and_then(|value| rf_quality_json_u8(value, &["channel"])));
    let bandwidth_mhz = mac_report
        .and_then(|value| rf_quality_json_bandwidth_mhz(value, &["bandwidth"]))
        .or_else(|| {
            mac_report.and_then(|value| {
                rf_quality_json_bandwidth_mhz(value, &["same_session_init", "effective_bandwidth"])
            })
        });
    let tx_descriptor_profile = mac_report
        .and_then(|value| rf_quality_json_string(value, &["last_datagram", "tx_profile"]))
        .or_else(|| mac_report.and_then(|value| rf_quality_json_string(value, &["tx_profile"])));
    let tx_descriptor_hex = mac_report
        .and_then(|value| rf_quality_json_string(value, &["last_datagram", "tx_descriptor_hex"]))
        .or_else(|| {
            mac_report.and_then(|value| rf_quality_json_string(value, &["tx_descriptor_hex"]))
        });
    let tx_options =
        mac_report.and_then(|value| rf_quality_json_clone(value, &["last_datagram", "tx_options"]));
    let mut receiver_artifacts = args.receiver_artifacts.clone();
    if let Some(value) = mac_report {
        receiver_artifacts.extend(rf_quality_json_pathbufs(value, &["receiver_artifacts"]));
        receiver_artifacts.extend(rf_quality_json_pathbufs(value, &["rx_pcap_path"]));
        receiver_artifacts.extend(rf_quality_json_pathbufs(value, &["rx_frame_jsonl_path"]));
    }

    RfQualityMacosReport {
        source_report: args.mac_report.clone(),
        efuse_report: args.efuse_report.clone(),
        command,
        result,
        adapter,
        endpoints,
        efuse_summary,
        rfe_type,
        rfe_type_hex: rfe_type.map(|value| format_value(value, 2)),
        channel,
        bandwidth_mhz,
        tx_descriptor_profile,
        tx_descriptor_hex,
        tx_options,
        tx_power: RfQualityTxPowerReport {
            mode: args.tx_power_mode,
            control_report: mac_report
                .and_then(|value| rf_quality_json_clone(value, &["tx_power_control"])),
            register_evidence: mac_report
                .and_then(|value| {
                    rf_quality_json_array_clone(
                        value,
                        &["tx_status", "rf_summary", "activity_registers"],
                    )
                })
                .unwrap_or_default(),
        },
        calibration: rf_quality_calibration_report(args, mac_report, efuse_report),
        wfb_outcome: rf_quality_wfb_outcome(args, mac_report, receiver_evidence),
        receiver_artifacts,
    }
}

fn rf_quality_calibration_report(
    args: &RfQualityReportArgs,
    mac_report: Option<&serde_json::Value>,
    efuse_report: Option<&serde_json::Value>,
) -> RfQualityCalibrationReport {
    let probes = rf_quality_calibration_probes_from_mac(mac_report);
    let final_probe = rf_quality_calibration_final_probe(&probes);
    let probe_stop_gap = probes
        .iter()
        .any(|probe| rf_quality_json_bool(probe, &["stop_gap"]).unwrap_or(false));
    let mode_stop_gap = matches!(
        args.calibration_mode,
        RfQualityCalibrationMode::StopGapCaptured
            | RfQualityCalibrationMode::Static
            | RfQualityCalibrationMode::TargetedLinuxParity
    );
    let stop_gap = mode_stop_gap || probe_stop_gap;
    let mut stop_gap_sources = Vec::new();
    if mode_stop_gap {
        stop_gap_sources.push("operator-selected calibration mode is stop-gap/static");
    }
    if probe_stop_gap {
        stop_gap_sources.push("macOS report contains stop-gap calibration probe evidence");
    }

    let thermal_probe = final_probe.and_then(|value| rf_quality_json_clone(value, &["thermal"]));
    let efuse_thermal_meter = efuse_report
        .and_then(|value| rf_quality_efuse_named_byte(value, "EEPROM_THERMAL_METER_8812"));
    let efuse_iqk_lck =
        efuse_report.and_then(|value| rf_quality_efuse_named_byte(value, "EEPROM_IQK_LCK_8812"));
    let thermal = (thermal_probe.is_some()
        || efuse_thermal_meter.is_some()
        || efuse_iqk_lck.is_some())
    .then(|| {
        serde_json::json!({
            "probe": thermal_probe,
            "efuse_thermal_meter": efuse_thermal_meter,
            "efuse_iqk_lck": efuse_iqk_lck,
        })
    });
    let runtime_iqk = mac_report
        .and_then(|value| rf_quality_json_clone(value, &["tx_calibration_profile", "runtime_iqk"]))
        .filter(|value| !value.is_null());
    let runtime_iqk_summary = rf_quality_runtime_iqk_summary(runtime_iqk.as_ref());

    RfQualityCalibrationReport {
        mode: args.calibration_mode,
        stop_gap,
        label: rf_quality_calibration_label(args.calibration_mode),
        stop_gap_sources,
        profile_report: mac_report
            .and_then(|value| rf_quality_json_clone(value, &["tx_calibration_profile"])),
        rfe_pinmux: final_probe
            .and_then(|value| rf_quality_json_clone(value, &["rfe_pinmux"]))
            .or_else(|| mac_report.and_then(|value| rf_quality_json_clone(value, &["rfe_pinmux"]))),
        rfe_inversion: final_probe
            .and_then(|value| rf_quality_json_clone(value, &["rfe_inversion"])),
        rfe_timing: final_probe.and_then(|value| rf_quality_json_clone(value, &["rfe_timing"])),
        rf_path: final_probe.and_then(|value| rf_quality_json_clone(value, &["rf_path"])),
        iqk: final_probe
            .and_then(|value| rf_quality_json_clone(value, &["iqk"]))
            .or_else(|| {
                mac_report.and_then(|value| {
                    rf_quality_json_clone(value, &["tx_calibration_profile", "iqk"])
                })
            })
            .or_else(|| mac_report.and_then(|value| rf_quality_json_clone(value, &["iqk"]))),
        runtime_iqk,
        runtime_iqk_summary,
        lck: final_probe
            .and_then(|value| rf_quality_json_clone(value, &["lck"]))
            .or_else(|| {
                mac_report.and_then(|value| {
                    rf_quality_json_clone(value, &["tx_calibration_profile", "lck"])
                })
            })
            .or_else(|| mac_report.and_then(|value| rf_quality_json_clone(value, &["lck"]))),
        thermal: thermal
            .or_else(|| mac_report.and_then(|value| rf_quality_json_clone(value, &["thermal"]))),
        probes,
    }
}

fn rf_quality_runtime_iqk_summary(
    runtime_iqk: Option<&serde_json::Value>,
) -> Option<RfQualityRuntimeIqkSummaryReport> {
    let runtime_iqk = runtime_iqk?;
    if !runtime_iqk.is_object() {
        return None;
    }
    let status = rf_quality_json_string(runtime_iqk, &["status"]);
    let cleanup_status = rf_quality_json_string(runtime_iqk, &["cleanup_status"]);
    let sweep_index = rf_quality_json_u64(runtime_iqk, &["sweep_index"]);
    let sweep_count = rf_quality_json_u64(runtime_iqk, &["sweep_count"]);
    let max_sweeps = rf_quality_json_u64(runtime_iqk, &["max_sweeps"]);
    let cleanup_restored = cleanup_status.as_deref() == Some("restored");
    let mut fallback_stages = Vec::new();

    if let Some(paths) =
        rf_quality_json_get(runtime_iqk, &["paths"]).and_then(|value| value.as_array())
    {
        for path in paths {
            let path_name = rf_quality_json_string(path, &["path_name"])
                .or_else(|| rf_quality_json_string(path, &["path"]));
            for stage_name in ["tx", "rx"] {
                let Some(stage) = rf_quality_json_get(path, &[stage_name]) else {
                    continue;
                };
                let stage_status = rf_quality_json_string(stage, &["status"]);
                let fallback_used =
                    rf_quality_json_bool(stage, &["fallback_used"]).unwrap_or(false);
                let stage_failed = stage_status
                    .as_deref()
                    .is_some_and(|status| status != "success" && status != "skipped");
                if fallback_used || stage_failed {
                    fallback_stages.push(RfQualityRuntimeIqkFallbackStageReport {
                        path: path_name.clone(),
                        stage: Some(stage_name.to_string()),
                        status: stage_status,
                        fallback_used,
                        failure_label: rf_quality_json_string(stage, &["failure_label"]),
                        selected_iqc: rf_quality_json_clone(stage, &["selected_iqc"]),
                    });
                }
            }
        }
    }

    let risk = if !cleanup_restored {
        RfQualityRuntimeIqkRiskStatus::CleanupNotRestored
    } else if !fallback_stages.is_empty() || status.as_deref() == Some("fallback_applied") {
        RfQualityRuntimeIqkRiskStatus::FallbackApplied
    } else if status.as_deref() == Some("completed") {
        RfQualityRuntimeIqkRiskStatus::Completed
    } else {
        RfQualityRuntimeIqkRiskStatus::UnknownStatus
    };
    let completed = risk == RfQualityRuntimeIqkRiskStatus::Completed;

    Some(RfQualityRuntimeIqkSummaryReport {
        status,
        cleanup_status,
        sweep_index,
        sweep_count,
        max_sweeps,
        completed,
        cleanup_restored,
        fallback_stage_count: fallback_stages.len(),
        fallback_stages,
        risk,
    })
}

fn rf_quality_calibration_probes_from_mac(
    mac_report: Option<&serde_json::Value>,
) -> Vec<serde_json::Value> {
    let Some(value) = mac_report else {
        return Vec::new();
    };
    let mut probes =
        rf_quality_json_array_clone(value, &["same_session_init", "calibration_state"])
            .unwrap_or_default();
    if let Some(pre_tx) = rf_quality_json_clone(value, &["rf_calibration_pre_tx"]) {
        probes.push(pre_tx);
    }
    probes
}

fn rf_quality_calibration_final_probe(probes: &[serde_json::Value]) -> Option<&serde_json::Value> {
    probes
        .iter()
        .rev()
        .find(|probe| rf_quality_json_string(probe, &["stage"]).as_deref() == Some("before_tx"))
        .or_else(|| probes.last())
}

fn rf_quality_wfb_outcome(
    args: &RfQualityReportArgs,
    mac_report: Option<&serde_json::Value>,
    receiver_evidence: Option<&serde_json::Value>,
) -> RfQualityWfbOutcomeReport {
    let expected_datagrams = args.expected_payloads.and_then(|payloads| {
        (args.fec_k > 0).then(|| {
            (payloads
                .saturating_mul(u64::from(args.fec_n))
                .saturating_add(u64::from(args.fec_k).saturating_sub(1)))
                / u64::from(args.fec_k)
        })
    });
    let Some(value) = mac_report else {
        return RfQualityWfbOutcomeReport {
            expected_datagrams,
            observed_datagrams: None,
            datagram_shortfall: None,
            short_run_datagram_tolerance: Some(RF_QUALITY_SHORT_RUN_DATAGRAM_TOLERANCE),
            short_run_datagram_tolerance_applied: false,
            receiver_status: receiver_evidence
                .and_then(|value| rf_quality_json_string(value, &["receiver_status"]))
                .or_else(|| {
                    receiver_evidence.and_then(|value| {
                        rf_quality_json_string(value, &["receiver_health", "status"])
                    })
                }),
            receiver_session_observed: receiver_evidence
                .and_then(|value| rf_quality_json_bool(value, &["receiver_session_observed"]))
                .or_else(|| {
                    receiver_evidence.and_then(|value| {
                        rf_quality_json_bool(value, &["receiver_health", "session_observed"])
                    })
                }),
            receiver_unable_decrypt_count: receiver_evidence
                .and_then(|value| rf_quality_json_u64(value, &["receiver_unable_decrypt_count"]))
                .or_else(|| {
                    receiver_evidence.and_then(|value| {
                        rf_quality_json_u64(value, &["receiver_health", "unable_decrypt_count"])
                    })
                }),
            receiver_total_datagrams: receiver_evidence.and_then(|value| {
                rf_quality_json_u64(value, &["receiver_health", "counter", "total_datagrams"])
            }),
            receiver_evidence: receiver_evidence.cloned(),
            receiver_telemetry: rf_quality_receiver_telemetry(receiver_evidence),
            receiver_signal: rf_quality_receiver_signal(receiver_evidence),
            channel_state: rf_quality_channel_state(receiver_evidence),
            recovered_payloads: args.recovered_payloads,
            ..RfQualityWfbOutcomeReport::default()
        };
    };
    let submitted_datagrams = rf_quality_json_u64(value, &["submit_counters", "submitted"])
        .or_else(|| rf_quality_json_u64(value, &["bridge_counters", "injected"]));
    let observed_datagrams =
        rf_quality_json_u64(value, &["datagrams_received"]).or(submitted_datagrams);
    let datagram_shortfall = expected_datagrams
        .zip(observed_datagrams)
        .map(|(expected, observed)| expected as i64 - observed as i64);
    let short_run_datagram_tolerance_applied = datagram_shortfall
        .map(|shortfall| {
            shortfall > 0
                && shortfall <= RF_QUALITY_SHORT_RUN_DATAGRAM_TOLERANCE as i64
                && args
                    .expected_payloads
                    .zip(args.recovered_payloads)
                    .map(|(expected, recovered)| recovered >= expected)
                    .unwrap_or(false)
        })
        .unwrap_or(false);
    RfQualityWfbOutcomeReport {
        expected_datagrams,
        observed_datagrams,
        datagram_shortfall,
        short_run_datagram_tolerance: Some(RF_QUALITY_SHORT_RUN_DATAGRAM_TOLERANCE),
        short_run_datagram_tolerance_applied,
        receiver_status: receiver_evidence
            .and_then(|value| rf_quality_json_string(value, &["receiver_status"]))
            .or_else(|| {
                receiver_evidence
                    .and_then(|value| rf_quality_json_string(value, &["receiver_health", "status"]))
            }),
        receiver_session_observed: receiver_evidence
            .and_then(|value| rf_quality_json_bool(value, &["receiver_session_observed"]))
            .or_else(|| {
                receiver_evidence.and_then(|value| {
                    rf_quality_json_bool(value, &["receiver_health", "session_observed"])
                })
            }),
        receiver_unable_decrypt_count: receiver_evidence
            .and_then(|value| rf_quality_json_u64(value, &["receiver_unable_decrypt_count"]))
            .or_else(|| {
                receiver_evidence.and_then(|value| {
                    rf_quality_json_u64(value, &["receiver_health", "unable_decrypt_count"])
                })
            }),
        receiver_total_datagrams: receiver_evidence.and_then(|value| {
            rf_quality_json_u64(value, &["receiver_health", "counter", "total_datagrams"])
        }),
        submitted_datagrams,
        recovered_payloads: args
            .recovered_payloads
            .or_else(|| rf_quality_json_u64(value, &["rx", "wfb_forward", "counters", "forwarded"]))
            .or_else(|| {
                rf_quality_json_u64(value, &["rx", "wfb_forwards", "0", "counters", "forwarded"])
            })
            .or_else(|| rf_quality_json_u64(value, &["recovered_payloads"])),
        dropped_datagrams: rf_quality_json_u64(value, &["bridge_counters", "dropped"])
            .or_else(|| rf_quality_json_u64(value, &["rx", "dropped_packets"])),
        malformed_datagrams: rf_quality_json_u64(value, &["bridge_counters", "malformed"]).or_else(
            || rf_quality_json_u64(value, &["rx", "wfb_forward", "counters", "malformed"]),
        ),
        receiver_evidence: receiver_evidence.cloned(),
        receiver_telemetry: rf_quality_receiver_telemetry(receiver_evidence),
        receiver_signal: rf_quality_receiver_signal(receiver_evidence),
        channel_state: rf_quality_channel_state(receiver_evidence),
        throughput: rf_quality_json_clone(value, &["throughput"]),
        cpu: rf_quality_json_clone(value, &["cpu"]),
    }
}

fn rf_quality_channel_state(
    receiver_evidence: Option<&serde_json::Value>,
) -> Option<serde_json::Value> {
    receiver_evidence.and_then(|value| rf_quality_json_clone(value, &["channel_state"]))
}

fn rf_quality_receiver_telemetry(
    receiver_evidence: Option<&serde_json::Value>,
) -> Option<serde_json::Value> {
    let receiver_evidence = receiver_evidence?;
    let summary = rf_quality_json_clone(
        receiver_evidence,
        &["receiver_health", "rx_antenna_summary"],
    )
    .or_else(|| rf_quality_json_clone(receiver_evidence, &["rx_antenna_summary"]))?;
    Some(serde_json::json!({
        "source": "linux_wfb_rx_rx_ant",
        "rx_antenna_summary": summary,
        "rx_antenna_report_count": rf_quality_json_u64(receiver_evidence, &["receiver_health", "rx_antenna_report_count"])
            .or_else(|| rf_quality_json_u64(receiver_evidence, &["rx_antenna_report_count"])),
    }))
}

fn rf_quality_receiver_signal(
    receiver_evidence: Option<&serde_json::Value>,
) -> Option<RfQualityReceiverSignalReport> {
    let receiver_evidence = receiver_evidence?;
    let summary = rf_quality_json_get(
        receiver_evidence,
        &["receiver_health", "rx_antenna_summary"],
    )
    .or_else(|| rf_quality_json_get(receiver_evidence, &["rx_antenna_summary"]))?;
    let samples = rf_quality_receiver_signal_samples(receiver_evidence);
    if samples.is_empty() {
        return None;
    }
    let all_samples = {
        let all_samples = rf_quality_receiver_signal_all_samples(receiver_evidence);
        if all_samples.is_empty() {
            samples.clone()
        } else {
            all_samples
        }
    };

    let mut antenna_ids = BTreeMap::new();
    let mut tuple_values = BTreeMap::new();
    for sample in &samples {
        if let Some(antenna_id) = rf_quality_json_u64(sample, &["antenna_id"]) {
            antenna_ids.insert(antenna_id, ());
        }
        let tuple = (
            rf_quality_json_u64(sample, &["freq_mhz"])
                .or_else(|| rf_quality_json_u64(sample, &["frequency_mhz"]))
                .or_else(|| rf_quality_json_u64(sample, &["freq"])),
            rf_quality_json_u64(sample, &["mcs_index"])
                .or_else(|| rf_quality_json_u64(sample, &["mcs"])),
            rf_quality_json_u64(sample, &["bandwidth_mhz"])
                .or_else(|| rf_quality_json_u64(sample, &["bw_mhz"]))
                .or_else(|| rf_quality_json_u64(sample, &["bandwidth"])),
        );
        if tuple.0.is_some() || tuple.1.is_some() || tuple.2.is_some() {
            tuple_values.insert(tuple, ());
        }
    }

    let tuples = tuple_values
        .keys()
        .map(
            |(freq_mhz, mcs_index, bandwidth_mhz)| RfQualityReceiverSignalTupleReport {
                freq_mhz: *freq_mhz,
                mcs_index: *mcs_index,
                bandwidth_mhz: *bandwidth_mhz,
            },
        )
        .collect::<Vec<_>>();
    let (rssi_avg_dbm_min, rssi_avg_dbm_max) = rf_quality_receiver_signal_i64_range(
        summary,
        &samples,
        "rssi_avg_dbm_min",
        "rssi_avg_dbm_max",
        "rssi_avg_dbm",
    );
    let (snr_avg_db_min, snr_avg_db_max) = rf_quality_receiver_signal_i64_range(
        summary,
        &samples,
        "snr_avg_db_min",
        "snr_avg_db_max",
        "snr_avg_db",
    );
    let snr_avg_values = rf_quality_receiver_signal_i64_values(&all_samples, "snr_avg_db");
    let snr_avg_nonzero_count = snr_avg_values.iter().filter(|value| **value != 0).count();
    let snr_status = rf_quality_receiver_signal_snr_status(
        snr_avg_db_min,
        snr_avg_db_max,
        snr_avg_values.len(),
        snr_avg_nonzero_count,
    );
    let snr_confidence = match snr_status {
        RfQualityReceiverSignalSnrStatus::Available => {
            RfQualityReceiverSignalSnrConfidence::ReceiverReportedNonzero
        }
        RfQualityReceiverSignalSnrStatus::AllZero => {
            RfQualityReceiverSignalSnrConfidence::ReceiverReportedZeroOnly
        }
        RfQualityReceiverSignalSnrStatus::Missing => RfQualityReceiverSignalSnrConfidence::Missing,
    };
    let snr_usable = snr_status == RfQualityReceiverSignalSnrStatus::Available;
    let report_count = rf_quality_json_u64(summary, &["report_count"])
        .or_else(|| {
            rf_quality_json_u64(
                receiver_evidence,
                &["receiver_health", "rx_antenna_report_count"],
            )
        })
        .or_else(|| rf_quality_json_u64(receiver_evidence, &["rx_antenna_report_count"]));
    let antenna_count = antenna_ids.len();
    let tuple_count = tuples.len();
    let tuple_consistent = (!tuples.is_empty()).then_some(tuples.len() == 1);
    let rssi_present = rssi_avg_dbm_min.is_some() && rssi_avg_dbm_max.is_some();
    let mut issues = Vec::new();
    if report_count.is_some_and(|count| count == 0) {
        issues.push("zero_rx_antenna_reports");
    }
    if antenna_count == 0 {
        issues.push("missing_antenna_id");
    }
    if tuple_count == 0 {
        issues.push("missing_rx_tuple");
    } else if tuple_consistent == Some(false) {
        issues.push("inconsistent_rx_tuple");
    }
    if !rssi_present {
        issues.push("missing_rssi_avg");
    }
    match snr_status {
        RfQualityReceiverSignalSnrStatus::Available => {}
        RfQualityReceiverSignalSnrStatus::AllZero => issues.push("snr_all_zero"),
        RfQualityReceiverSignalSnrStatus::Missing => issues.push("missing_snr_avg"),
    }
    let degraded =
        antenna_count == 0 || tuple_count != 1 || tuple_consistent != Some(true) || !rssi_present;
    let status = if degraded {
        RfQualityReceiverSignalStatus::Degraded
    } else if snr_status == RfQualityReceiverSignalSnrStatus::Available {
        RfQualityReceiverSignalStatus::Complete
    } else {
        RfQualityReceiverSignalStatus::Usable
    };
    let issue_count = issues.len();

    Some(RfQualityReceiverSignalReport {
        source: "linux_wfb_rx_rx_ant",
        status,
        issue_count,
        issues,
        report_count,
        antenna_count,
        tuple_count,
        tuple_consistent,
        tuples,
        rssi_avg_dbm_min,
        rssi_avg_dbm_max,
        rssi_avg_spread_db: rssi_avg_dbm_min
            .zip(rssi_avg_dbm_max)
            .map(|(min, max)| max - min),
        snr_avg_db_min,
        snr_avg_db_max,
        snr_avg_spread_db: snr_avg_db_min
            .zip(snr_avg_db_max)
            .map(|(min, max)| max - min),
        snr_status,
        snr_confidence,
        snr_usable,
        snr_avg_sample_count: snr_avg_values.len(),
        snr_avg_nonzero_count,
    })
}

fn rf_quality_receiver_signal_snr_status(
    snr_avg_db_min: Option<i64>,
    snr_avg_db_max: Option<i64>,
    snr_avg_sample_count: usize,
    snr_avg_nonzero_count: usize,
) -> RfQualityReceiverSignalSnrStatus {
    if snr_avg_nonzero_count > 0 {
        return RfQualityReceiverSignalSnrStatus::Available;
    }
    if snr_avg_sample_count > 0 {
        return RfQualityReceiverSignalSnrStatus::AllZero;
    }
    match snr_avg_db_min.zip(snr_avg_db_max) {
        Some((0, 0)) => RfQualityReceiverSignalSnrStatus::AllZero,
        Some(_) => RfQualityReceiverSignalSnrStatus::Available,
        None => RfQualityReceiverSignalSnrStatus::Missing,
    }
}

fn rf_quality_receiver_signal_samples(
    receiver_evidence: &serde_json::Value,
) -> Vec<&serde_json::Value> {
    for path in [
        &["receiver_health", "rx_antenna_summary", "latest_by_antenna"][..],
        &["rx_antenna_summary", "latest_by_antenna"],
        &["receiver_health", "rx_antenna_reports"],
        &["rx_antenna_reports"],
    ] {
        if let Some(values) =
            rf_quality_json_get(receiver_evidence, path).and_then(|value| value.as_array())
        {
            if !values.is_empty() {
                return values.iter().collect();
            }
        }
    }
    Vec::new()
}

fn rf_quality_receiver_signal_all_samples(
    receiver_evidence: &serde_json::Value,
) -> Vec<&serde_json::Value> {
    for path in [
        &["receiver_health", "rx_antenna_reports"][..],
        &["rx_antenna_reports"],
    ] {
        if let Some(values) =
            rf_quality_json_get(receiver_evidence, path).and_then(|value| value.as_array())
        {
            if !values.is_empty() {
                return values.iter().collect();
            }
        }
    }
    Vec::new()
}

fn rf_quality_receiver_signal_i64_range(
    summary: &serde_json::Value,
    samples: &[&serde_json::Value],
    min_key: &str,
    max_key: &str,
    sample_key: &str,
) -> (Option<i64>, Option<i64>) {
    let min_value = rf_quality_json_i64(summary, &[min_key]);
    let max_value = rf_quality_json_i64(summary, &[max_key]);
    if min_value.is_some() || max_value.is_some() {
        return (min_value, max_value);
    }

    let values = rf_quality_receiver_signal_i64_values(samples, sample_key);
    (values.iter().min().copied(), values.iter().max().copied())
}

fn rf_quality_receiver_signal_i64_values(samples: &[&serde_json::Value], key: &str) -> Vec<i64> {
    samples
        .iter()
        .filter_map(|sample| rf_quality_json_i64(sample, &[key]))
        .collect()
}

fn rf_quality_receiver_evidence_from_artifacts(paths: &[PathBuf]) -> Option<serde_json::Value> {
    paths.iter().find_map(|path| {
        let file_name = path.file_name()?.to_str()?;
        if file_name != "datagram-evidence.json" {
            return None;
        }
        rf_quality_load_json(
            path,
            "receiver_evidence_read_failed",
            "receiver_evidence_parse_failed",
        )
        .ok()
    })
}

fn rf_quality_linux_baseline_report(
    path: &Path,
    value: &serde_json::Value,
) -> std::result::Result<RfQualityLinuxBaselineReport, DiagnosticErrorReport> {
    let channel = rf_quality_json_u8(value, &["profile", "channel"])
        .or_else(|| rf_quality_json_u8(value, &["channel", "number"]))
        .or_else(|| rf_quality_json_u8(value, &["channel"]));
    let bandwidth_mhz = rf_quality_json_bandwidth_mhz(value, &["profile", "bandwidth"])
        .or_else(|| rf_quality_json_bandwidth_mhz(value, &["bandwidth"]))
        .or_else(|| rf_quality_json_bandwidth_mhz(value, &["bandwidth_mhz"]));
    let tx_rate = rf_quality_json_string(value, &["profile", "tx_rate"])
        .or_else(|| rf_quality_json_string(value, &["tx_rate"]));
    let tx_descriptor_profile =
        rf_quality_json_string(value, &["profile", "tx_descriptor_profile"])
            .or_else(|| rf_quality_json_string(value, &["tx_profile"]))
            .or_else(|| rf_quality_json_string(value, &["tx_descriptor_profile"]));
    let link_id = rf_quality_json_u32(value, &["profile", "wfb", "link_id"])
        .or_else(|| rf_quality_json_u32(value, &["wfb", "link_id"]))
        .or_else(|| rf_quality_json_u32(value, &["wfb_link_id"]))
        .or_else(|| rf_quality_json_u32(value, &["link_id"]));
    let radio_port = rf_quality_json_u8(value, &["profile", "wfb", "radio_port"])
        .or_else(|| rf_quality_json_u8(value, &["wfb", "radio_port"]))
        .or_else(|| rf_quality_json_u8(value, &["wfb_radio_port"]))
        .or_else(|| rf_quality_json_u8(value, &["radio_port"]));
    let fec_k = rf_quality_json_u8(value, &["profile", "wfb", "fec_k"])
        .or_else(|| rf_quality_json_u8(value, &["wfb", "fec_k"]))
        .or_else(|| rf_quality_json_u8(value, &["fec_k"]));
    let fec_n = rf_quality_json_u8(value, &["profile", "wfb", "fec_n"])
        .or_else(|| rf_quality_json_u8(value, &["wfb", "fec_n"]))
        .or_else(|| rf_quality_json_u8(value, &["fec_n"]));

    Ok(RfQualityLinuxBaselineReport {
        source_report: path.to_path_buf(),
        command: rf_quality_json_string(value, &["command"]),
        adapter: rf_quality_json_clone(value, &["adapter"]),
        channel,
        bandwidth_mhz,
        tx_rate,
        tx_descriptor_profile,
        wfb: RfQualityBaselineWfbReport {
            link_id,
            link_id_hex: link_id.map(|value| format_value(value, 6)),
            radio_port,
            radio_port_hex: radio_port.map(|value| format_value(value, 2)),
            fec_k,
            fec_n,
        },
        payload_len: rf_quality_json_usize(value, &["profile", "payload_len"])
            .or_else(|| rf_quality_json_usize(value, &["payload_len"])),
        source_payloads: rf_quality_json_u64(value, &["profile", "expected_payloads"])
            .or_else(|| rf_quality_json_u64(value, &["profile", "source_payloads"]))
            .or_else(|| rf_quality_json_u64(value, &["metrics", "source_payloads"]))
            .or_else(|| rf_quality_json_u64(value, &["source_payloads"])),
        recovered_payloads: rf_quality_json_u64(value, &["metrics", "recovered_payloads"])
            .or_else(|| rf_quality_json_u64(value, &["recovered_payloads"])),
        submitted_datagrams: rf_quality_json_u64(value, &["metrics", "submitted_datagrams"])
            .or_else(|| rf_quality_json_u64(value, &["submitted_datagrams"]))
            .or_else(|| rf_quality_json_u64(value, &["submit_counters", "submitted"])),
        throughput_mbps: rf_quality_json_f64(value, &["metrics", "throughput_mbps"])
            .or_else(|| rf_quality_json_f64(value, &["throughput_mbps"])),
        receiver_artifacts: rf_quality_json_pathbufs(value, &["receiver_artifacts"])
            .into_iter()
            .chain(rf_quality_json_pathbufs(value, &["artifacts", "receiver"]))
            .collect(),
        calibration_registers: rf_quality_linux_calibration_registers(value),
    })
}

fn rf_quality_compare_profile_to_baseline(
    profile: &RfQualityProfileReport,
    macos: &RfQualityMacosReport,
    baseline: Option<&RfQualityLinuxBaselineReport>,
) -> RfQualityComparisonReport {
    let Some(baseline) = baseline else {
        return RfQualityComparisonReport {
            status: RfQualityComparisonStatus::NoBaseline,
            mismatch_count: 0,
            invalidating_mismatch_count: 0,
            degraded_mismatch_count: 0,
            mismatches: Vec::new(),
            outcome: rf_quality_outcome_comparison(profile, macos, None),
            calibration: rf_quality_calibration_comparison(macos, None),
        };
    };

    let mut mismatches = Vec::new();
    rf_quality_compare_u64(
        &mut mismatches,
        "channel",
        u64::from(profile.channel),
        baseline.channel.map(u64::from),
        RfQualityMismatchSeverity::InvalidComparison,
        "channel mismatch makes RF and range comparison invalid",
    );
    rf_quality_compare_u64(
        &mut mismatches,
        "bandwidth_mhz",
        u64::from(profile.bandwidth_mhz),
        baseline.bandwidth_mhz.map(u64::from),
        RfQualityMismatchSeverity::InvalidComparison,
        "bandwidth mismatch makes RF and range comparison invalid",
    );
    rf_quality_compare_normalized_string(
        &mut mismatches,
        "tx_rate",
        &profile.tx_rate,
        baseline.tx_rate.as_deref(),
        RfQualityMismatchSeverity::InvalidComparison,
        "fixed TX rate mismatch makes payload recovery and range comparison invalid",
    );
    rf_quality_compare_normalized_string(
        &mut mismatches,
        "tx_descriptor_profile",
        bridge_tx_profile_label(profile.tx_descriptor_profile),
        baseline.tx_descriptor_profile.as_deref(),
        RfQualityMismatchSeverity::DegradedComparison,
        "descriptor profile mismatch can change RF behavior and degrades comparison confidence",
    );
    rf_quality_compare_u64(
        &mut mismatches,
        "wfb.link_id",
        u64::from(profile.wfb.link_id),
        baseline.wfb.link_id.map(u64::from),
        RfQualityMismatchSeverity::InvalidComparison,
        "WFB link ID mismatch means the receiver may be observing different traffic",
    );
    rf_quality_compare_u64(
        &mut mismatches,
        "wfb.radio_port",
        u64::from(profile.wfb.radio_port),
        baseline.wfb.radio_port.map(u64::from),
        RfQualityMismatchSeverity::InvalidComparison,
        "WFB radio port mismatch means the receiver may be observing different traffic",
    );
    rf_quality_compare_u64(
        &mut mismatches,
        "wfb.fec_k",
        u64::from(profile.wfb.fec_k),
        baseline.wfb.fec_k.map(u64::from),
        RfQualityMismatchSeverity::InvalidComparison,
        "FEC source packet mismatch changes recovery behavior",
    );
    rf_quality_compare_u64(
        &mut mismatches,
        "wfb.fec_n",
        u64::from(profile.wfb.fec_n),
        baseline.wfb.fec_n.map(u64::from),
        RfQualityMismatchSeverity::InvalidComparison,
        "FEC total packet mismatch changes recovery behavior",
    );
    if let Some(payload_len) = profile.payload_len {
        rf_quality_compare_u64(
            &mut mismatches,
            "payload_len",
            payload_len as u64,
            baseline.payload_len.map(|value| value as u64),
            RfQualityMismatchSeverity::InvalidComparison,
            "payload size mismatch changes airtime, FEC packing, and throughput comparison",
        );
    }
    if let Some(expected_payloads) = profile.expected_payloads {
        rf_quality_compare_u64(
            &mut mismatches,
            "expected_payloads",
            expected_payloads,
            baseline.source_payloads,
            RfQualityMismatchSeverity::InvalidComparison,
            "expected source payload count mismatch changes loss and recovery comparison",
        );
    }

    let invalidating_mismatch_count = mismatches
        .iter()
        .filter(|mismatch| mismatch.severity == RfQualityMismatchSeverity::InvalidComparison)
        .count();
    let degraded_mismatch_count = mismatches.len().saturating_sub(invalidating_mismatch_count);
    RfQualityComparisonReport {
        status: if mismatches.is_empty() {
            RfQualityComparisonStatus::Matched
        } else {
            RfQualityComparisonStatus::Mismatched
        },
        mismatch_count: mismatches.len(),
        invalidating_mismatch_count,
        degraded_mismatch_count,
        mismatches,
        outcome: rf_quality_outcome_comparison(profile, macos, Some(baseline)),
        calibration: rf_quality_calibration_comparison(macos, Some(baseline)),
    }
}

fn rf_quality_outcome_comparison(
    profile: &RfQualityProfileReport,
    macos: &RfQualityMacosReport,
    baseline: Option<&RfQualityLinuxBaselineReport>,
) -> RfQualityOutcomeComparisonReport {
    let macos_side = RfQualityOutcomeSideReport {
        submitted_datagrams: macos.wfb_outcome.submitted_datagrams,
        source_payloads: profile.expected_payloads,
        recovered_payloads: macos.wfb_outcome.recovered_payloads,
        loss_percent: rf_quality_loss_percent(
            profile.expected_payloads,
            macos.wfb_outcome.recovered_payloads,
        ),
        throughput_mbps: macos
            .wfb_outcome
            .throughput
            .as_ref()
            .and_then(rf_quality_throughput_mbps_from_json),
        receiver_artifacts: macos.receiver_artifacts.clone(),
    };
    let linux_side = baseline.map(|baseline| RfQualityOutcomeSideReport {
        submitted_datagrams: baseline.submitted_datagrams,
        source_payloads: baseline.source_payloads,
        recovered_payloads: baseline.recovered_payloads,
        loss_percent: rf_quality_loss_percent(
            baseline.source_payloads,
            baseline.recovered_payloads,
        ),
        throughput_mbps: baseline.throughput_mbps,
        receiver_artifacts: baseline.receiver_artifacts.clone(),
    });
    let recovered_payload_delta = macos_side
        .recovered_payloads
        .zip(linux_side.as_ref().and_then(|side| side.recovered_payloads))
        .map(|(macos, linux)| macos as i64 - linux as i64);
    let throughput_ratio_macos_to_linux = macos_side
        .throughput_mbps
        .zip(linux_side.as_ref().and_then(|side| side.throughput_mbps))
        .and_then(|(macos, linux)| (linux > 0.0).then_some(macos / linux));
    let receiver_metadata_status = rf_quality_receiver_metadata_status(&macos.wfb_outcome);
    let acceptance_margin = rf_quality_outcome_acceptance_margin(
        &macos_side,
        linux_side.as_ref(),
        throughput_ratio_macos_to_linux,
        receiver_metadata_status,
    );

    RfQualityOutcomeComparisonReport {
        macos: macos_side,
        linux_baseline: linux_side,
        recovered_payload_delta,
        throughput_ratio_macos_to_linux,
        acceptance_margin,
    }
}

fn rf_quality_outcome_acceptance_margin(
    macos: &RfQualityOutcomeSideReport,
    linux_baseline: Option<&RfQualityOutcomeSideReport>,
    throughput_ratio_macos_to_linux: Option<f64>,
    receiver_metadata_status: &'static str,
) -> RfQualityOutcomeAcceptanceMarginReport {
    let Some(linux_baseline) = linux_baseline else {
        return RfQualityOutcomeAcceptanceMarginReport {
            status: RfQualityOutcomeAcceptanceMarginStatus::NoBaseline,
            criteria_version: "rf-quality-margin-v1",
            max_loss_delta_percent_points: RF_QUALITY_MAX_LOSS_DELTA_PERCENT_POINTS,
            loss_delta_percent_points: None,
            min_throughput_ratio: RF_QUALITY_MIN_THROUGHPUT_RATIO,
            throughput_ratio_macos_to_linux,
            throughput_evaluated: false,
            receiver_metadata_status,
            failures: Vec::new(),
        };
    };

    let (Some(macos_loss), Some(linux_loss)) = (macos.loss_percent, linux_baseline.loss_percent)
    else {
        return RfQualityOutcomeAcceptanceMarginReport {
            status: RfQualityOutcomeAcceptanceMarginStatus::MissingOutcomeData,
            criteria_version: "rf-quality-margin-v1",
            max_loss_delta_percent_points: RF_QUALITY_MAX_LOSS_DELTA_PERCENT_POINTS,
            loss_delta_percent_points: None,
            min_throughput_ratio: RF_QUALITY_MIN_THROUGHPUT_RATIO,
            throughput_ratio_macos_to_linux,
            throughput_evaluated: false,
            receiver_metadata_status,
            failures: Vec::new(),
        };
    };

    let loss_delta_percent_points = macos_loss - linux_loss;
    let mut failures = Vec::new();
    if loss_delta_percent_points > RF_QUALITY_MAX_LOSS_DELTA_PERCENT_POINTS {
        failures.push("macOS payload loss exceeds Linux baseline by more than the allowed margin");
    }

    RfQualityOutcomeAcceptanceMarginReport {
        status: if failures.is_empty() {
            RfQualityOutcomeAcceptanceMarginStatus::WithinMargin
        } else {
            RfQualityOutcomeAcceptanceMarginStatus::OutsideMargin
        },
        criteria_version: "rf-quality-margin-v1",
        max_loss_delta_percent_points: RF_QUALITY_MAX_LOSS_DELTA_PERCENT_POINTS,
        loss_delta_percent_points: Some(loss_delta_percent_points),
        min_throughput_ratio: RF_QUALITY_MIN_THROUGHPUT_RATIO,
        throughput_ratio_macos_to_linux,
        throughput_evaluated: false,
        receiver_metadata_status,
        failures,
    }
}

fn rf_quality_receiver_metadata_status(wfb_outcome: &RfQualityWfbOutcomeReport) -> &'static str {
    let Some(evidence) = wfb_outcome.receiver_evidence.as_ref() else {
        return "not_available";
    };
    if rf_quality_json_u64(evidence, &["receiver_health", "rx_antenna_report_count"])
        .is_some_and(|count| count > 0)
        || rf_quality_json_array_nonempty(evidence, &["receiver_health", "rx_antenna_reports"])
        || rf_quality_json_array_nonempty(
            evidence,
            &["receiver_health", "rx_antenna_summary", "latest_by_antenna"],
        )
    {
        "available"
    } else {
        "not_available"
    }
}

fn rf_quality_calibration_comparison(
    macos: &RfQualityMacosReport,
    baseline: Option<&RfQualityLinuxBaselineReport>,
) -> RfQualityCalibrationComparisonReport {
    let macos_registers = rf_quality_macos_calibration_registers(&macos.calibration);
    let Some(baseline) = baseline else {
        return RfQualityCalibrationComparisonReport {
            status: RfQualityCalibrationComparisonStatus::NoBaseline,
            macos_register_count: macos_registers.len(),
            linux_register_count: 0,
            compared_register_count: 0,
            mismatches: Vec::new(),
        };
    };
    if baseline.calibration_registers.is_empty() {
        return RfQualityCalibrationComparisonReport {
            status: RfQualityCalibrationComparisonStatus::NoLinuxCalibrationRegisters,
            macos_register_count: macos_registers.len(),
            linux_register_count: 0,
            compared_register_count: 0,
            mismatches: Vec::new(),
        };
    }
    if macos_registers.is_empty() {
        return RfQualityCalibrationComparisonReport {
            status: RfQualityCalibrationComparisonStatus::NoMacosCalibrationRegisters,
            macos_register_count: 0,
            linux_register_count: baseline.calibration_registers.len(),
            compared_register_count: 0,
            mismatches: Vec::new(),
        };
    }

    let linux_by_address = baseline
        .calibration_registers
        .iter()
        .map(|register| (register.address, register))
        .collect::<BTreeMap<_, _>>();
    let mut compared_register_count = 0usize;
    let mut mismatches = Vec::new();
    for macos_register in &macos_registers {
        let Some(linux_register) = linux_by_address.get(&macos_register.address) else {
            continue;
        };
        compared_register_count += 1;
        if rf_quality_normalize_value_hex(&macos_register.value_hex)
            != rf_quality_normalize_value_hex(&linux_register.value_hex)
        {
            mismatches.push(RfQualityCalibrationRegisterMismatchReport {
                register_name: macos_register
                    .register_name
                    .clone()
                    .or_else(|| linux_register.register_name.clone()),
                address: macos_register.address,
                address_hex: macos_register.address_hex.clone(),
                macos_value_hex: macos_register.value_hex.clone(),
                linux_value_hex: linux_register.value_hex.clone(),
            });
        }
    }

    RfQualityCalibrationComparisonReport {
        status: if compared_register_count == 0 {
            RfQualityCalibrationComparisonStatus::NoOverlap
        } else if mismatches.is_empty() {
            RfQualityCalibrationComparisonStatus::Matched
        } else {
            RfQualityCalibrationComparisonStatus::Mismatched
        },
        macos_register_count: macos_registers.len(),
        linux_register_count: baseline.calibration_registers.len(),
        compared_register_count,
        mismatches,
    }
}

fn rf_quality_linux_calibration_registers(
    value: &serde_json::Value,
) -> Vec<RfQualityCalibrationRegisterValueReport> {
    let mut registers = BTreeMap::new();
    rf_quality_collect_calibration_registers_from_array(
        value.as_array(),
        "linux_final_register_map",
        &mut registers,
    );
    for path in [
        &["final_writes"][..],
        &["registers"][..],
        &["calibration_registers"][..],
    ] {
        rf_quality_collect_calibration_registers_from_array(
            rf_quality_json_get(value, path).and_then(|value| value.as_array()),
            "linux_final_register_map",
            &mut registers,
        );
    }
    registers.into_values().collect()
}

fn rf_quality_macos_calibration_registers(
    calibration: &RfQualityCalibrationReport,
) -> Vec<RfQualityCalibrationRegisterValueReport> {
    let mut registers = BTreeMap::new();
    for group in [
        calibration.rfe_pinmux.as_ref(),
        calibration.rfe_inversion.as_ref(),
        calibration.rfe_timing.as_ref(),
        calibration.rf_path.as_ref(),
        calibration.iqk.as_ref(),
        calibration.lck.as_ref(),
    ] {
        rf_quality_collect_calibration_registers_from_array(
            group.and_then(|value| value.as_array()),
            "macos_calibration_probe",
            &mut registers,
        );
    }
    registers.into_values().collect()
}

fn rf_quality_collect_calibration_registers_from_array(
    values: Option<&Vec<serde_json::Value>>,
    source: &'static str,
    registers: &mut BTreeMap<u16, RfQualityCalibrationRegisterValueReport>,
) {
    let Some(values) = values else {
        return;
    };
    for value in values {
        let Some(address) = rf_quality_json_register_address(value) else {
            continue;
        };
        if !rf_quality_is_calibration_register_address(address) {
            continue;
        }
        let Some(value_hex) = rf_quality_json_string(value, &["value_hex"])
            .or_else(|| rf_quality_json_string(value, &["value_le_hex"]))
            .or_else(|| rf_quality_json_string(value, &["after_hex"]))
        else {
            continue;
        };
        registers.insert(
            address,
            RfQualityCalibrationRegisterValueReport {
                register_name: rf_quality_json_string(value, &["register_name"])
                    .or_else(|| rf_quality_json_string(value, &["name"])),
                address,
                address_hex: format_address(address),
                value_hex: rf_quality_normalize_value_hex(&value_hex),
                source,
            },
        );
    }
}

fn rf_quality_json_register_address(value: &serde_json::Value) -> Option<u16> {
    rf_quality_json_u64(value, &["address"])
        .or_else(|| {
            rf_quality_json_string(value, &["address_hex"])
                .as_deref()
                .and_then(parse_u64_text)
        })
        .and_then(|value| u16::try_from(value).ok())
}

fn rf_quality_is_calibration_register_address(address: u16) -> bool {
    [
        RF_CALIBRATION_RFE_PINMUX_REGISTERS,
        RF_CALIBRATION_RFE_INVERSION_REGISTERS,
        RF_CALIBRATION_RFE_TIMING_REGISTERS,
        RF_CALIBRATION_IQK_REGISTERS,
        RF_CALIBRATION_LCK_RELATED_REGISTERS,
        RF_CALIBRATION_RF_PATH_REGISTERS,
    ]
    .into_iter()
    .flatten()
    .any(|(_, candidate)| *candidate == address)
}

fn rf_quality_normalize_value_hex(value: &str) -> String {
    parse_u64_text(value)
        .map(|value| format_value(value, 8))
        .unwrap_or_else(|| value.trim().to_ascii_lowercase())
}

fn rf_quality_loss_percent(
    source_payloads: Option<u64>,
    recovered_payloads: Option<u64>,
) -> Option<f64> {
    let source_payloads = source_payloads?;
    let recovered_payloads = recovered_payloads?;
    if source_payloads == 0 {
        return None;
    }
    let recovered_payloads = recovered_payloads.min(source_payloads);
    Some((source_payloads - recovered_payloads) as f64 * 100.0 / source_payloads as f64)
}

fn rf_quality_throughput_mbps_from_json(value: &serde_json::Value) -> Option<f64> {
    let bytes_per_second = rf_quality_json_f64(value, &["datagram_bytes_per_second"])
        .or_else(|| rf_quality_json_f64(value, &["payload_bytes_per_second"]))
        .or_else(|| rf_quality_json_f64(value, &["usb_bytes_per_second"]))?;
    Some(bytes_per_second * 8.0 / 1_000_000.0)
}

fn rf_quality_compare_u64(
    mismatches: &mut Vec<RfQualityMismatchReport>,
    field: &'static str,
    macos_value: u64,
    linux_value: Option<u64>,
    severity: RfQualityMismatchSeverity,
    impact: &'static str,
) {
    if let Some(linux_value) = linux_value {
        if macos_value != linux_value {
            mismatches.push(RfQualityMismatchReport {
                field,
                macos_value: macos_value.to_string(),
                linux_value: linux_value.to_string(),
                severity,
                impact,
            });
        }
    }
}

fn rf_quality_compare_normalized_string(
    mismatches: &mut Vec<RfQualityMismatchReport>,
    field: &'static str,
    macos_value: &str,
    linux_value: Option<&str>,
    severity: RfQualityMismatchSeverity,
    impact: &'static str,
) {
    if let Some(linux_value) = linux_value {
        if rf_quality_normalize_token(macos_value) != rf_quality_normalize_token(linux_value) {
            mismatches.push(RfQualityMismatchReport {
                field,
                macos_value: macos_value.to_string(),
                linux_value: linux_value.to_string(),
                severity,
                impact,
            });
        }
    }
}

fn rf_quality_profile_gate_report(
    args: &RfQualityReportArgs,
    profile: &RfQualityProfileReport,
    close_range_report: Option<&serde_json::Value>,
) -> RfQualityProfileGateReport {
    let required = matches!(profile.kind, RfQualityProfileKind::OutdoorLongDistance);
    let close_range_report_path = args.close_range_report.clone();
    if !required {
        return RfQualityProfileGateReport {
            required,
            status: RfQualityProfileGateStatus::NotRequired,
            close_range_report: close_range_report_path,
            mismatch_count: 0,
            mismatches: Vec::new(),
            reason: "close-range gate is required only for outdoor long-distance profiles",
        };
    }

    let Some(close_range_report_path) = close_range_report_path else {
        return RfQualityProfileGateReport {
            required,
            status: RfQualityProfileGateStatus::MissingCloseRangeReport,
            close_range_report: None,
            mismatch_count: 0,
            mismatches: Vec::new(),
            reason:
                "outdoor long-distance profiles require --close-range-report for the same RF-quality tuple",
        };
    };

    let Some(close_range_report) = close_range_report else {
        return RfQualityProfileGateReport {
            required,
            status: RfQualityProfileGateStatus::InvalidCloseRangeReport,
            close_range_report: Some(close_range_report_path),
            mismatch_count: 0,
            mismatches: Vec::new(),
            reason: "close-range gate report could not be loaded or parsed",
        };
    };

    let close_kind = rf_quality_json_string(close_range_report, &["profile", "kind"]);
    let close_result = rf_quality_json_string(close_range_report, &["result"]);
    let close_acceptance = rf_quality_json_string(close_range_report, &["acceptance", "status"]);
    if close_kind.as_deref() != Some("close_range")
        || close_result.as_deref() != Some("pass")
        || close_acceptance.as_deref() != Some("baseline_comparable")
    {
        return RfQualityProfileGateReport {
            required,
            status: RfQualityProfileGateStatus::CloseRangeNotPassed,
            close_range_report: Some(close_range_report_path),
            mismatch_count: 0,
            mismatches: Vec::new(),
            reason:
                "close-range gate report must be a passing close_range report with baseline_comparable acceptance",
        };
    }

    let mut mismatches = Vec::new();
    rf_quality_gate_compare_u64(
        &mut mismatches,
        "channel",
        u64::from(profile.channel),
        rf_quality_json_u64(close_range_report, &["profile", "channel"]),
        "channel mismatch means the outdoor run is not gated by the same RF profile",
    );
    rf_quality_gate_compare_u64(
        &mut mismatches,
        "bandwidth_mhz",
        u64::from(profile.bandwidth_mhz),
        rf_quality_json_u64(close_range_report, &["profile", "bandwidth_mhz"]),
        "bandwidth mismatch changes RF behavior and range interpretation",
    );
    rf_quality_gate_compare_string(
        &mut mismatches,
        "tx_rate",
        &profile.tx_rate,
        rf_quality_json_string(close_range_report, &["profile", "tx_rate"]).as_deref(),
        "fixed TX rate mismatch changes range and recovery behavior",
    );
    rf_quality_gate_compare_string(
        &mut mismatches,
        "tx_descriptor_profile",
        bridge_tx_profile_label(profile.tx_descriptor_profile),
        rf_quality_json_string(close_range_report, &["profile", "tx_descriptor_profile"])
            .as_deref(),
        "descriptor profile mismatch changes transmit behavior",
    );
    rf_quality_gate_compare_string(
        &mut mismatches,
        "tx_power_mode",
        rf_quality_tx_power_mode_label(profile.tx_power_mode),
        rf_quality_json_string(close_range_report, &["profile", "tx_power_mode"]).as_deref(),
        "TX power mode mismatch invalidates the close-range gate",
    );
    rf_quality_gate_compare_string(
        &mut mismatches,
        "calibration_mode",
        rf_quality_calibration_mode_label(profile.calibration_mode),
        rf_quality_json_string(close_range_report, &["profile", "calibration_mode"]).as_deref(),
        "calibration mode mismatch invalidates the close-range gate",
    );
    rf_quality_gate_compare_u64(
        &mut mismatches,
        "wfb.link_id",
        u64::from(profile.wfb.link_id),
        rf_quality_json_u64(close_range_report, &["profile", "wfb", "link_id"]),
        "WFB link ID mismatch means the receiver may observe different traffic",
    );
    rf_quality_gate_compare_u64(
        &mut mismatches,
        "wfb.radio_port",
        u64::from(profile.wfb.radio_port),
        rf_quality_json_u64(close_range_report, &["profile", "wfb", "radio_port"]),
        "WFB radio port mismatch means the receiver may observe different traffic",
    );
    rf_quality_gate_compare_u64(
        &mut mismatches,
        "wfb.fec_k",
        u64::from(profile.wfb.fec_k),
        rf_quality_json_u64(close_range_report, &["profile", "wfb", "fec_k"]),
        "FEC source packet mismatch changes recovery behavior",
    );
    rf_quality_gate_compare_u64(
        &mut mismatches,
        "wfb.fec_n",
        u64::from(profile.wfb.fec_n),
        rf_quality_json_u64(close_range_report, &["profile", "wfb", "fec_n"]),
        "FEC total packet mismatch changes recovery behavior",
    );
    if let Some(payload_len) = profile.payload_len {
        rf_quality_gate_compare_u64(
            &mut mismatches,
            "payload_len",
            payload_len as u64,
            rf_quality_json_u64(close_range_report, &["profile", "payload_len"]),
            "payload length mismatch changes airtime, FEC packing, and throughput",
        );
    }
    if let Some(expected_payloads) = profile.expected_payloads {
        rf_quality_gate_compare_u64(
            &mut mismatches,
            "expected_payloads",
            expected_payloads,
            rf_quality_json_u64(close_range_report, &["profile", "expected_payloads"]),
            "expected payload count mismatch changes loss and recovery comparison",
        );
    }
    if let Some(risk) = rf_quality_json_string(
        close_range_report,
        &["macos", "calibration", "runtime_iqk_summary", "risk"],
    ) {
        if risk != "completed" {
            mismatches.push(RfQualityProfileGateMismatchReport {
                field: "runtime_iqk_summary.risk",
                current_value: "completed".to_string(),
                close_range_value: risk,
                impact: "runtime IQK close-range gate must complete without cleanup failure or fallback before outdoor range promotion",
            });
        }
    }
    if !rf_quality_close_range_gate_receiver_telemetry_available(close_range_report) {
        mismatches.push(RfQualityProfileGateMismatchReport {
            field: "receiver_telemetry",
            current_value: "available".to_string(),
            close_range_value: "missing".to_string(),
            impact: "outdoor range promotion requires close-range RX_ANT receiver telemetry so MCS/RSSI/SNR health is part of the gate",
        });
    } else {
        rf_quality_close_range_gate_receiver_telemetry_matches(
            &mut mismatches,
            profile,
            close_range_report,
        );
        rf_quality_close_range_gate_receiver_signal_status_matches(
            &mut mismatches,
            close_range_report,
        );
        rf_quality_close_range_gate_channel_state_matches(
            &mut mismatches,
            profile,
            close_range_report,
        );
    }

    let mismatch_count = mismatches.len();
    RfQualityProfileGateReport {
        required,
        status: if mismatch_count == 0 {
            RfQualityProfileGateStatus::Passed
        } else {
            RfQualityProfileGateStatus::MismatchedProfile
        },
        close_range_report: Some(close_range_report_path),
        mismatch_count,
        mismatches,
        reason: if mismatch_count == 0 {
            "outdoor long-distance profile has a passing close-range gate for the same RF-quality tuple"
        } else {
            "close-range gate report does not match the outdoor long-distance RF-quality tuple"
        },
    }
}

fn rf_quality_close_range_gate_receiver_telemetry_available(
    close_range_report: &serde_json::Value,
) -> bool {
    rf_quality_json_string(
        close_range_report,
        &[
            "comparison",
            "outcome",
            "acceptance_margin",
            "receiver_metadata_status",
        ],
    )
    .is_some_and(|status| status == "available")
        || rf_quality_json_u64(
            close_range_report,
            &[
                "macos",
                "wfb_outcome",
                "receiver_telemetry",
                "rx_antenna_report_count",
            ],
        )
        .is_some_and(|count| count > 0)
        || rf_quality_json_array_nonempty(
            close_range_report,
            &[
                "macos",
                "wfb_outcome",
                "receiver_telemetry",
                "rx_antenna_summary",
                "latest_by_antenna",
            ],
        )
        || rf_quality_json_u64(
            close_range_report,
            &[
                "macos",
                "wfb_outcome",
                "receiver_evidence",
                "receiver_health",
                "rx_antenna_report_count",
            ],
        )
        .is_some_and(|count| count > 0)
        || rf_quality_json_array_nonempty(
            close_range_report,
            &[
                "macos",
                "wfb_outcome",
                "receiver_evidence",
                "receiver_health",
                "rx_antenna_reports",
            ],
        )
}

fn rf_quality_close_range_gate_receiver_telemetry_matches(
    mismatches: &mut Vec<RfQualityProfileGateMismatchReport>,
    profile: &RfQualityProfileReport,
    close_range_report: &serde_json::Value,
) {
    let samples = rf_quality_close_range_gate_receiver_telemetry_samples(close_range_report);
    if let Some(freq_mhz) = profile.channel_frequency_mhz {
        rf_quality_gate_compare_receiver_telemetry_u64(
            mismatches,
            "receiver_telemetry.freq_mhz",
            u64::from(freq_mhz),
            &samples,
            &["freq_mhz", "frequency_mhz", "freq"],
            "close-range RX_ANT frequency must match the outdoor profile channel before range promotion",
        );
    }
    rf_quality_gate_compare_receiver_telemetry_u64(
        mismatches,
        "receiver_telemetry.bandwidth_mhz",
        u64::from(profile.bandwidth_mhz),
        &samples,
        &["bandwidth_mhz", "bandwidth", "bw_mhz"],
        "close-range RX_ANT bandwidth must match the outdoor profile bandwidth before range promotion",
    );
    if let Some(mcs_index) = rf_quality_tx_rate_expected_mcs(&profile.tx_rate) {
        rf_quality_gate_compare_receiver_telemetry_u64(
            mismatches,
            "receiver_telemetry.mcs_index",
            mcs_index,
            &samples,
            &["mcs_index", "mcs"],
            "close-range RX_ANT MCS must match the fixed outdoor TX rate before range promotion",
        );
    }
}

fn rf_quality_close_range_gate_receiver_signal_status_matches(
    mismatches: &mut Vec<RfQualityProfileGateMismatchReport>,
    close_range_report: &serde_json::Value,
) {
    let Some(status) = rf_quality_json_string(
        close_range_report,
        &["macos", "wfb_outcome", "receiver_signal", "status"],
    ) else {
        return;
    };
    if status != "complete" && status != "usable" {
        mismatches.push(RfQualityProfileGateMismatchReport {
            field: "receiver_signal.status",
            current_value: "complete_or_usable".to_string(),
            close_range_value: status,
            impact: "outdoor range promotion requires close-range RX_ANT signal evidence with a consistent tuple and RSSI averages",
        });
    }
}

fn rf_quality_close_range_gate_channel_state_matches(
    mismatches: &mut Vec<RfQualityProfileGateMismatchReport>,
    profile: &RfQualityProfileReport,
    close_range_report: &serde_json::Value,
) {
    let Some(channel_state) = rf_quality_json_get(
        close_range_report,
        &["macos", "wfb_outcome", "channel_state"],
    )
    .or_else(|| {
        rf_quality_json_get(
            close_range_report,
            &["macos", "wfb_outcome", "receiver_evidence", "channel_state"],
        )
    }) else {
        return;
    };
    if let Some(status) = rf_quality_json_string(channel_state, &["verify_status"]) {
        if status != "verified" {
            mismatches.push(RfQualityProfileGateMismatchReport {
                field: "channel_state.verify_status",
                current_value: "verified".to_string(),
                close_range_value: status,
                impact: "outdoor range promotion requires close-range Linux peer channel verification to pass when channel-state evidence is present",
            });
        }
    }
    if let Some(freq_mhz) = profile.channel_frequency_mhz {
        rf_quality_gate_compare_u64(
            mismatches,
            "channel_state.observed_frequency_mhz",
            u64::from(freq_mhz),
            rf_quality_json_u64(channel_state, &["observed_frequency_mhz"]),
            "close-range Linux peer observed channel frequency must match the outdoor profile",
        );
    }
    rf_quality_gate_compare_u64(
        mismatches,
        "channel_state.observed_width_mhz",
        u64::from(profile.bandwidth_mhz),
        rf_quality_json_u64(channel_state, &["observed_width_mhz"]),
        "close-range Linux peer observed channel width must match the outdoor profile",
    );
}

fn rf_quality_close_range_gate_receiver_telemetry_samples(
    close_range_report: &serde_json::Value,
) -> Vec<&serde_json::Value> {
    for path in [
        &[
            "macos",
            "wfb_outcome",
            "receiver_telemetry",
            "rx_antenna_summary",
            "latest_by_antenna",
        ][..],
        &[
            "macos",
            "wfb_outcome",
            "receiver_evidence",
            "receiver_health",
            "rx_antenna_summary",
            "latest_by_antenna",
        ],
        &[
            "macos",
            "wfb_outcome",
            "receiver_evidence",
            "rx_antenna_summary",
            "latest_by_antenna",
        ],
        &[
            "macos",
            "wfb_outcome",
            "receiver_evidence",
            "receiver_health",
            "rx_antenna_reports",
        ],
        &[
            "macos",
            "wfb_outcome",
            "receiver_evidence",
            "rx_antenna_reports",
        ],
    ] {
        if let Some(values) =
            rf_quality_json_get(close_range_report, path).and_then(|value| value.as_array())
        {
            if !values.is_empty() {
                return values.iter().collect();
            }
        }
    }
    Vec::new()
}

fn rf_quality_profile_gate_blocks(gate: &RfQualityProfileGateReport) -> bool {
    matches!(
        gate.status,
        RfQualityProfileGateStatus::MissingCloseRangeReport
            | RfQualityProfileGateStatus::InvalidCloseRangeReport
            | RfQualityProfileGateStatus::CloseRangeNotPassed
            | RfQualityProfileGateStatus::MismatchedProfile
    )
}

fn rf_quality_gate_compare_u64(
    mismatches: &mut Vec<RfQualityProfileGateMismatchReport>,
    field: &'static str,
    current_value: u64,
    close_range_value: Option<u64>,
    impact: &'static str,
) {
    match close_range_value {
        Some(close_range_value) if close_range_value == current_value => {}
        Some(close_range_value) => mismatches.push(RfQualityProfileGateMismatchReport {
            field,
            current_value: current_value.to_string(),
            close_range_value: close_range_value.to_string(),
            impact,
        }),
        None => mismatches.push(RfQualityProfileGateMismatchReport {
            field,
            current_value: current_value.to_string(),
            close_range_value: "<missing>".to_string(),
            impact,
        }),
    }
}

fn rf_quality_gate_compare_string(
    mismatches: &mut Vec<RfQualityProfileGateMismatchReport>,
    field: &'static str,
    current_value: &str,
    close_range_value: Option<&str>,
    impact: &'static str,
) {
    match close_range_value {
        Some(close_range_value)
            if rf_quality_normalize_token(close_range_value)
                == rf_quality_normalize_token(current_value) => {}
        Some(close_range_value) => mismatches.push(RfQualityProfileGateMismatchReport {
            field,
            current_value: current_value.to_string(),
            close_range_value: close_range_value.to_string(),
            impact,
        }),
        None => mismatches.push(RfQualityProfileGateMismatchReport {
            field,
            current_value: current_value.to_string(),
            close_range_value: "<missing>".to_string(),
            impact,
        }),
    }
}

fn rf_quality_gate_compare_receiver_telemetry_u64(
    mismatches: &mut Vec<RfQualityProfileGateMismatchReport>,
    field: &'static str,
    current_value: u64,
    close_range_samples: &[&serde_json::Value],
    close_range_keys: &[&str],
    impact: &'static str,
) {
    if close_range_samples.is_empty() {
        mismatches.push(RfQualityProfileGateMismatchReport {
            field,
            current_value: current_value.to_string(),
            close_range_value: "<missing>".to_string(),
            impact,
        });
        return;
    }

    let mut close_range_values = Vec::with_capacity(close_range_samples.len());
    let mut matches_all = true;
    for (index, sample) in close_range_samples.iter().enumerate() {
        let value = close_range_keys
            .iter()
            .find_map(|key| rf_quality_json_u64(sample, &[*key]));
        if value != Some(current_value) {
            matches_all = false;
        }
        close_range_values.push(rf_quality_receiver_telemetry_value_label(
            sample, index, value,
        ));
    }

    if !matches_all {
        mismatches.push(RfQualityProfileGateMismatchReport {
            field,
            current_value: current_value.to_string(),
            close_range_value: close_range_values.join(", "),
            impact,
        });
    }
}

fn rf_quality_receiver_telemetry_value_label(
    sample: &serde_json::Value,
    index: usize,
    value: Option<u64>,
) -> String {
    let source = rf_quality_json_string(sample, &["antenna_id"])
        .map(|antenna| format!("ant{antenna}"))
        .or_else(|| {
            rf_quality_json_string(sample, &["antenna_id_hex"])
                .map(|antenna| format!("ant{antenna}"))
        })
        .unwrap_or_else(|| format!("sample{index}"));
    let value = value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "<missing>".to_string());
    format!("{source}={value}")
}

fn rf_quality_tx_rate_expected_mcs(tx_rate: &str) -> Option<u64> {
    match parse_tx_rate_arg(tx_rate).ok()? {
        TxRate::Mcs(mcs) | TxRate::Vht { mcs, .. } => Some(u64::from(mcs)),
        _ => None,
    }
}

fn rf_quality_acceptance(
    result: DiagnosticResult,
    comparison: &RfQualityComparisonReport,
    profile_gate: &RfQualityProfileGateReport,
) -> RfQualityAcceptanceReport {
    if rf_quality_profile_gate_blocks(profile_gate) {
        return RfQualityAcceptanceReport {
            status: RfQualityAcceptanceStatus::InvalidComparison,
            reason: "outdoor long-distance profile is blocked by the close-range gate",
            criteria_version: "rf-quality-v1",
            baseline_required_for_range_ready: true,
        };
    }

    if result == DiagnosticResult::Fail {
        return RfQualityAcceptanceReport {
            status: RfQualityAcceptanceStatus::ReportGenerationFailed,
            reason: "the RF-quality report could not be generated from the supplied inputs",
            criteria_version: "rf-quality-v1",
            baseline_required_for_range_ready: true,
        };
    }

    match comparison.status {
        RfQualityComparisonStatus::NoBaseline => RfQualityAcceptanceReport {
            status: RfQualityAcceptanceStatus::NotEvaluated,
            reason: "no Linux baseline was supplied, so range readiness is not evaluated",
            criteria_version: "rf-quality-v1",
            baseline_required_for_range_ready: true,
        },
        RfQualityComparisonStatus::Matched
            if comparison.outcome.acceptance_margin.status
                == RfQualityOutcomeAcceptanceMarginStatus::OutsideMargin =>
        {
            RfQualityAcceptanceReport {
                status: RfQualityAcceptanceStatus::DegradedComparison,
                reason:
                    "receiver-backed WFB outcome is outside the Linux-baseline acceptance margin",
                criteria_version: "rf-quality-v1",
                baseline_required_for_range_ready: true,
            }
        }
        RfQualityComparisonStatus::Matched => RfQualityAcceptanceReport {
            status: RfQualityAcceptanceStatus::BaselineComparable,
            reason:
                "macOS and Linux baseline parameters match for the fields present in the baseline",
            criteria_version: "rf-quality-v1",
            baseline_required_for_range_ready: true,
        },
        RfQualityComparisonStatus::Mismatched if comparison.invalidating_mismatch_count > 0 => {
            RfQualityAcceptanceReport {
                status: RfQualityAcceptanceStatus::InvalidComparison,
                reason: "one or more critical parameters differ from the Linux baseline",
                criteria_version: "rf-quality-v1",
                baseline_required_for_range_ready: true,
            }
        }
        RfQualityComparisonStatus::Mismatched => RfQualityAcceptanceReport {
            status: RfQualityAcceptanceStatus::DegradedComparison,
            reason: "only degraded-confidence parameter mismatches were found",
            criteria_version: "rf-quality-v1",
            baseline_required_for_range_ready: true,
        },
    }
}

fn rf_quality_load_json(
    path: &Path,
    read_code: &'static str,
    parse_code: &'static str,
) -> std::result::Result<serde_json::Value, DiagnosticErrorReport> {
    let text = fs::read_to_string(path).map_err(|error| DiagnosticErrorReport {
        code: read_code,
        message: format!("{}: {error}", path.display()),
    })?;
    serde_json::from_str(&text).map_err(|error| DiagnosticErrorReport {
        code: parse_code,
        message: format!("{}: {error}", path.display()),
    })
}

fn rf_quality_json_get<'a>(
    value: &'a serde_json::Value,
    path: &[&str],
) -> Option<&'a serde_json::Value> {
    let mut current = value;
    for key in path {
        match current {
            serde_json::Value::Object(map) => current = map.get(*key)?,
            serde_json::Value::Array(values) => {
                let index = key.parse::<usize>().ok()?;
                current = values.get(index)?;
            }
            _ => return None,
        }
    }
    Some(current)
}

fn rf_quality_json_clone(value: &serde_json::Value, path: &[&str]) -> Option<serde_json::Value> {
    rf_quality_json_get(value, path).cloned()
}

fn rf_quality_json_array_clone(
    value: &serde_json::Value,
    path: &[&str],
) -> Option<Vec<serde_json::Value>> {
    rf_quality_json_get(value, path)?
        .as_array()
        .map(|values| values.to_vec())
}

fn rf_quality_json_array_nonempty(value: &serde_json::Value, path: &[&str]) -> bool {
    rf_quality_json_get(value, path)
        .and_then(serde_json::Value::as_array)
        .is_some_and(|values| !values.is_empty())
}

fn rf_quality_json_string(value: &serde_json::Value, path: &[&str]) -> Option<String> {
    let value = rf_quality_json_get(value, path)?;
    match value {
        serde_json::Value::String(text) => Some(text.clone()),
        serde_json::Value::Number(number) => Some(number.to_string()),
        serde_json::Value::Bool(boolean) => Some(boolean.to_string()),
        _ => None,
    }
}

fn rf_quality_json_bool(value: &serde_json::Value, path: &[&str]) -> Option<bool> {
    let value = rf_quality_json_get(value, path)?;
    match value {
        serde_json::Value::Bool(boolean) => Some(*boolean),
        serde_json::Value::String(text) => match text.trim().to_ascii_lowercase().as_str() {
            "true" | "1" | "yes" => Some(true),
            "false" | "0" | "no" => Some(false),
            _ => None,
        },
        _ => None,
    }
}

fn rf_quality_json_u64(value: &serde_json::Value, path: &[&str]) -> Option<u64> {
    let value = rf_quality_json_get(value, path)?;
    match value {
        serde_json::Value::Number(number) => number.as_u64(),
        serde_json::Value::String(text) => parse_u64_text(text),
        _ => None,
    }
}

fn rf_quality_json_i64(value: &serde_json::Value, path: &[&str]) -> Option<i64> {
    let value = rf_quality_json_get(value, path)?;
    match value {
        serde_json::Value::Number(number) => number.as_i64(),
        serde_json::Value::String(text) => text.trim().parse::<i64>().ok(),
        _ => None,
    }
}

fn rf_quality_json_u32(value: &serde_json::Value, path: &[&str]) -> Option<u32> {
    rf_quality_json_u64(value, path).and_then(|value| u32::try_from(value).ok())
}

fn rf_quality_json_u8(value: &serde_json::Value, path: &[&str]) -> Option<u8> {
    rf_quality_json_u64(value, path).and_then(|value| u8::try_from(value).ok())
}

fn rf_quality_json_usize(value: &serde_json::Value, path: &[&str]) -> Option<usize> {
    rf_quality_json_u64(value, path).and_then(|value| usize::try_from(value).ok())
}

fn rf_quality_json_f64(value: &serde_json::Value, path: &[&str]) -> Option<f64> {
    let value = rf_quality_json_get(value, path)?;
    match value {
        serde_json::Value::Number(number) => number.as_f64(),
        serde_json::Value::String(text) => text.parse::<f64>().ok(),
        _ => None,
    }
}

fn rf_quality_json_bandwidth_mhz(value: &serde_json::Value, path: &[&str]) -> Option<u16> {
    let value = rf_quality_json_get(value, path)?;
    match value {
        serde_json::Value::Number(number) => {
            number.as_u64().and_then(|value| value.try_into().ok())
        }
        serde_json::Value::String(text) => rf_quality_bandwidth_mhz_from_text(text),
        serde_json::Value::Object(_) => rf_quality_json_bandwidth_mhz(value, &["mhz"])
            .or_else(|| rf_quality_json_bandwidth_mhz(value, &["bandwidth_mhz"])),
        _ => None,
    }
}

fn rf_quality_json_pathbufs(value: &serde_json::Value, path: &[&str]) -> Vec<PathBuf> {
    let Some(value) = rf_quality_json_get(value, path) else {
        return Vec::new();
    };
    match value {
        serde_json::Value::String(text) => vec![PathBuf::from(text)],
        serde_json::Value::Array(values) => values
            .iter()
            .filter_map(|value| value.as_str().map(PathBuf::from))
            .collect(),
        _ => Vec::new(),
    }
}

fn rf_quality_efuse_named_byte(value: &serde_json::Value, name: &str) -> Option<serde_json::Value> {
    for path in [
        &["efuse", "summary", "named_bytes"][..],
        &["efuse_summary", "named_bytes"][..],
        &["summary", "named_bytes"][..],
    ] {
        if let Some(bytes) = rf_quality_json_get(value, path).and_then(|value| value.as_array()) {
            if let Some(entry) = bytes
                .iter()
                .find(|entry| rf_quality_json_string(entry, &["name"]).as_deref() == Some(name))
            {
                return Some(entry.clone());
            }
        }
    }
    None
}

fn parse_u64_text(input: &str) -> Option<u64> {
    let trimmed = input.trim();
    if let Some(hex) = trimmed
        .strip_prefix("0x")
        .or_else(|| trimmed.strip_prefix("0X"))
    {
        u64::from_str_radix(hex, 16).ok()
    } else {
        trimmed.parse::<u64>().ok()
    }
}

fn rf_quality_bandwidth_mhz_from_text(input: &str) -> Option<u16> {
    let normalized = input
        .trim()
        .to_ascii_lowercase()
        .replace(['_', '-', ' '], "");
    match normalized.as_str() {
        "20" | "20mhz" | "mhz20" => Some(20),
        "40" | "40mhz" | "mhz40" => Some(40),
        "80" | "80mhz" | "mhz80" => Some(80),
        _ => None,
    }
}

fn rf_quality_calibration_label(mode: RfQualityCalibrationMode) -> &'static str {
    match mode {
        RfQualityCalibrationMode::StopGapCaptured => {
            "stop-gap calibration from captured or planted values"
        }
        RfQualityCalibrationMode::Static => "stop-gap static calibration values",
        RfQualityCalibrationMode::TargetedLinuxParity => {
            "targeted Linux-parity calibration register overrides"
        }
        RfQualityCalibrationMode::RuntimeApproximation => "runtime calibration approximation",
        RfQualityCalibrationMode::LinuxPorted => "ported Linux runtime calibration routine",
        RfQualityCalibrationMode::Unknown => "calibration state was not supplied",
    }
}

fn rf_quality_tx_power_mode_label(mode: RfQualityTxPowerMode) -> &'static str {
    match mode {
        RfQualityTxPowerMode::CurrentDefault => "current_default",
        RfQualityTxPowerMode::ManualIndex => "manual_index",
        RfQualityTxPowerMode::EfuseDerived => "efuse_derived",
        RfQualityTxPowerMode::LinuxCaptured => "linux_captured",
    }
}

fn rf_quality_calibration_mode_label(mode: RfQualityCalibrationMode) -> &'static str {
    match mode {
        RfQualityCalibrationMode::StopGapCaptured => "stop_gap_captured",
        RfQualityCalibrationMode::Static => "static",
        RfQualityCalibrationMode::TargetedLinuxParity => "targeted_linux_parity",
        RfQualityCalibrationMode::RuntimeApproximation => "runtime_approximation",
        RfQualityCalibrationMode::LinuxPorted => "linux_ported",
        RfQualityCalibrationMode::Unknown => "unknown",
    }
}

fn bridge_tx_profile_label(profile: BridgeTxProfileArg) -> &'static str {
    match profile {
        BridgeTxProfileArg::LinuxMonitor => "linux_monitor",
        BridgeTxProfileArg::RadiotapDirect => "radiotap_direct",
    }
}

fn rf_quality_normalize_token(input: &str) -> String {
    input
        .trim()
        .to_ascii_lowercase()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .collect()
}

fn build_bridge_tx_bench_datagram(
    args: &BridgeTxBenchArgs,
    channel_id: WfbChannelId,
    sequence: u16,
) -> std::result::Result<Vec<u8>, DiagnosticErrorReport> {
    let radiotap = bridge_tx_bench_ht_radiotap(args.bandwidth, args.mcs)?;
    let frame = build_bridge_tx_bench_frame(args, channel_id, sequence)?;
    let mut datagram = Vec::with_capacity(4 + radiotap.len() + frame.len());
    datagram.extend_from_slice(&args.fwmark.to_be_bytes());
    datagram.extend_from_slice(&radiotap);
    datagram.extend_from_slice(&frame);
    Ok(datagram)
}

fn build_bridge_tx_bench_frame(
    args: &BridgeTxBenchArgs,
    channel_id: WfbChannelId,
    sequence: u16,
) -> std::result::Result<Vec<u8>, DiagnosticErrorReport> {
    if let Some(frame_hex) = args.frame_hex.as_deref() {
        return parse_hex_bytes(frame_hex).map_err(|message| DiagnosticErrorReport {
            code: "invalid_bench_frame_hex",
            message,
        });
    }

    let payload = bridge_tx_bench_payload(args);
    let mut frame = match args.frame_kind {
        BridgeTxBenchFrameKind::WfbData => {
            let mut frame = Vec::with_capacity(24usize.saturating_add(payload.len()));
            frame.extend_from_slice(&build_wfb_data_header(channel_id, sequence));
            frame
        }
        BridgeTxBenchFrameKind::WfbDataNoDs => {
            let mut header = build_wfb_data_header(channel_id, sequence);
            header[1] &= !0x03;
            let mut frame = Vec::with_capacity(24usize.saturating_add(payload.len()));
            frame.extend_from_slice(&header);
            frame
        }
        BridgeTxBenchFrameKind::BroadcastData => {
            let mut frame = Vec::with_capacity(24usize.saturating_add(payload.len()));
            frame.extend_from_slice(&bridge_tx_bench_broadcast_data_header(0x08, sequence));
            frame
        }
        BridgeTxBenchFrameKind::BroadcastQosData => {
            let mut frame = Vec::with_capacity(26usize.saturating_add(payload.len()));
            frame.extend_from_slice(&bridge_tx_bench_broadcast_data_header(0x88, sequence));
            frame.extend_from_slice(&[0x00, 0x00]);
            frame
        }
    };
    frame.extend_from_slice(&payload);
    Ok(frame)
}

fn bridge_tx_bench_payload(args: &BridgeTxBenchArgs) -> Vec<u8> {
    let marker = args.payload_marker.as_deref().unwrap_or("").as_bytes();
    let mut payload = Vec::with_capacity(args.payload_len);
    payload.extend_from_slice(marker);
    for index in payload.len()..args.payload_len {
        payload.push((index % 251) as u8);
    }
    payload
}

fn bridge_tx_bench_broadcast_data_header(subtype: u8, sequence: u16) -> [u8; 24] {
    let mut header = [
        subtype, 0x00, 0x00, 0x00, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0x02, 0x11, 0x22, 0x33,
        0x44, 0x55, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0x00, 0x00,
    ];
    header[22..24].copy_from_slice(&sequence.to_le_bytes());
    header
}

fn bridge_tx_bench_ht_radiotap(
    bandwidth: Bandwidth,
    mcs: u8,
) -> std::result::Result<[u8; BRIDGE_TX_BENCH_RADIOTAP_LEN], DiagnosticErrorReport> {
    let bandwidth_flags = match bandwidth {
        Bandwidth::Mhz20 => 0x00,
        Bandwidth::Mhz40 => 0x01,
        Bandwidth::Mhz80 => {
            return Err(DiagnosticErrorReport {
                code: "unsupported_bench_bandwidth",
                message: "bridge-tx-bench synthetic HT datagrams support 20 or 40 MHz; use bridge-tx-listen for externally generated VHT/80 MHz datagrams".to_string(),
            });
        }
    };
    Ok([
        0x00,
        0x00,
        BRIDGE_TX_BENCH_RADIOTAP_LEN as u8,
        0x00,
        0x00,
        0x80,
        0x08,
        0x00,
        0x08,
        0x00,
        0x37,
        bandwidth_flags,
        mcs,
    ])
}

fn bridge_tx_bench_set_sequence(datagram: &mut [u8], sequence: u16) {
    datagram[BRIDGE_TX_BENCH_SEQUENCE_OFFSET..BRIDGE_TX_BENCH_SEQUENCE_OFFSET + 2]
        .copy_from_slice(&sequence.to_le_bytes());
}

fn bridge_tx_datagram_from_args(
    args: &BridgeTxOnceArgs,
) -> std::result::Result<(Vec<u8>, &'static str), DiagnosticErrorReport> {
    match (&args.datagram_hex, &args.datagram_file) {
        (Some(_), Some(_)) => Err(DiagnosticErrorReport {
            code: "multiple_datagram_sources",
            message: "use only one of --datagram-hex or --datagram-file".to_string(),
        }),
        (None, None) => Err(DiagnosticErrorReport {
            code: "missing_datagram",
            message: "bridge-tx-once requires --datagram-hex or --datagram-file".to_string(),
        }),
        (Some(hex), None) => parse_hex_bytes(hex)
            .map(|bytes| (bytes, "operator_hex"))
            .map_err(|message| DiagnosticErrorReport {
                code: "invalid_datagram_hex",
                message,
            }),
        (None, Some(path)) => fs::read(path)
            .map(|bytes| (bytes, "file"))
            .map_err(|error| DiagnosticErrorReport {
                code: "datagram_file_read_failed",
                message: format!("failed to read {}: {error}", path.display()),
            }),
    }
}

fn bridge_tx_parse_error_counters(error: &TxDatagramError) -> TxCounters {
    TxCounters {
        incoming: 1,
        dropped: 1,
        malformed: 1,
        unsupported_radiotap: u64::from(bridge_tx_is_unsupported_radiotap(error)),
        ..TxCounters::default()
    }
}

fn bridge_tx_is_unsupported_radiotap(error: &TxDatagramError) -> bool {
    matches!(
        error,
        TxDatagramError::Radiotap(
            RadiotapError::UnsupportedPresentFlags { .. }
                | RadiotapError::UnsupportedHtBandwidth { .. }
                | RadiotapError::UnsupportedVhtBandwidth { .. }
        )
    )
}

fn elapsed_ms_u64(started: Instant) -> u64 {
    started.elapsed().as_millis().try_into().unwrap_or(u64::MAX)
}

fn rate_per_second(count: u64, elapsed_ms: Option<u64>) -> Option<f64> {
    let elapsed_ms = elapsed_ms?;
    if elapsed_ms == 0 {
        return None;
    }
    Some(count as f64 * 1000.0 / elapsed_ms as f64)
}

fn rate_per_second_us(count: u64, elapsed_us: u64) -> Option<f64> {
    if elapsed_us == 0 {
        return None;
    }
    Some(count as f64 * 1_000_000.0 / elapsed_us as f64)
}

#[cfg(unix)]
fn process_cpu_usage() -> Option<CpuUsageSnapshot> {
    let mut usage = std::mem::MaybeUninit::<libc::rusage>::uninit();
    let rc = unsafe { libc::getrusage(libc::RUSAGE_SELF, usage.as_mut_ptr()) };
    if rc != 0 {
        return None;
    }
    let usage = unsafe { usage.assume_init() };
    Some(CpuUsageSnapshot {
        user_us: timeval_to_us(usage.ru_utime),
        system_us: timeval_to_us(usage.ru_stime),
    })
}

#[cfg(not(unix))]
fn process_cpu_usage() -> Option<CpuUsageSnapshot> {
    None
}

#[cfg(unix)]
fn timeval_to_us(value: libc::timeval) -> u64 {
    let seconds = value.tv_sec as i128;
    let micros = value.tv_usec as i128;
    if seconds < 0 || micros < 0 {
        0
    } else {
        (seconds * 1_000_000 + micros) as u64
    }
}

fn cpu_usage_delta(
    before: Option<CpuUsageSnapshot>,
    after: Option<CpuUsageSnapshot>,
    elapsed_ms: u64,
) -> Option<CpuUsageReport> {
    let before = before?;
    let after = after?;
    let user_us = after.user_us.saturating_sub(before.user_us);
    let system_us = after.system_us.saturating_sub(before.system_us);
    let total_us = user_us + system_us;
    Some(CpuUsageReport {
        user_us,
        system_us,
        total_us,
        percent_one_core: if elapsed_ms == 0 {
            None
        } else {
            Some(total_us as f64 * 100.0 / (elapsed_ms as f64 * 1000.0))
        },
    })
}

fn validate_tx_frame_arg(
    frame_hex: Option<&str>,
    result: &mut DiagnosticResult,
    error: &mut Option<DiagnosticErrorReport>,
) -> (Option<usize>, Option<&'static str>) {
    match frame_hex {
        Some(hex) if *result != DiagnosticResult::Fail => match parse_hex_bytes(hex) {
            Ok(frame) => match validate_ieee80211_frame(&frame) {
                Ok(()) => (Some(frame.len()), Some("operator_hex")),
                Err(frame_error) => {
                    *result = DiagnosticResult::Fail;
                    *error = Some(DiagnosticErrorReport {
                        code: "invalid_ieee80211_frame",
                        message: frame_error.to_string(),
                    });
                    (Some(frame.len()), Some("operator_hex"))
                }
            },
            Err(parse_error) => {
                *result = DiagnosticResult::Fail;
                *error = Some(DiagnosticErrorReport {
                    code: "invalid_frame_hex",
                    message: parse_error,
                });
                (None, Some("operator_hex"))
            }
        },
        Some(_) => (None, Some("operator_hex")),
        None => (None, None),
    }
}

fn tx_options_from_args(bandwidth: Bandwidth, args: &TxOptionArgs) -> TxOptions {
    TxOptions {
        rate: args.tx_rate,
        bandwidth,
        channel_bandwidth: Some(bandwidth),
        short_gi: args.short_gi,
        ldpc: args.ldpc,
        stbc: args.stbc,
        ..TxOptions::default()
    }
}

fn build_tx_dry_run_report(
    frame_hex: &str,
    channel: Channel,
    bandwidth: Bandwidth,
    tx_option_args: &TxOptionArgs,
    packet_out: Option<PathBuf>,
) -> std::result::Result<TxDryRunReport, DiagnosticErrorReport> {
    let frame = parse_hex_bytes(frame_hex).map_err(|message| DiagnosticErrorReport {
        code: "invalid_frame_hex",
        message,
    })?;
    let opts = tx_options_from_args(bandwidth, tx_option_args);
    let packet = build_tx_packet(&frame, channel, opts).map_err(|error| DiagnosticErrorReport {
        code: "tx_descriptor_build_failed",
        message: error.to_string(),
    })?;

    if let Some(path) = &packet_out {
        fs::write(path, &packet).map_err(|error| DiagnosticErrorReport {
            code: "packet_out_write_failed",
            message: format!("failed to write {}: {error}", path.display()),
        })?;
    }

    let descriptor_len = 40;
    Ok(TxDryRunReport {
        descriptor_len,
        frame_len: frame.len(),
        packet_len: packet.len(),
        packet_byte_sum: byte_sum(&packet),
        descriptor_hex: encode_hex(&packet[..descriptor_len]),
        packet_out,
        tx_options: opts,
    })
}

fn build_init_dry_run_report(
    firmware: &FirmwareImage,
    trace_out: Option<PathBuf>,
) -> std::result::Result<InitDryRunReport, DiagnosticErrorReport> {
    let plan = plan_rtl8812au_init(firmware).map_err(|error| DiagnosticErrorReport {
        code: "init_plan_failed",
        message: error.to_string(),
    })?;

    if let Some(path) = &trace_out {
        let events = plan.trace_events();
        let output =
            serde_json::to_string_pretty(&events).map_err(|error| DiagnosticErrorReport {
                code: "init_trace_encode_failed",
                message: error.to_string(),
            })?;
        fs::write(path, output).map_err(|error| DiagnosticErrorReport {
            code: "init_trace_write_failed",
            message: format!("failed to write {}: {error}", path.display()),
        })?;
    }

    Ok(init_dry_run_report_from_plan(plan, trace_out))
}

fn init_dry_run_report_from_plan(
    plan: InitDryRunPlan,
    trace_out: Option<PathBuf>,
) -> InitDryRunReport {
    let phase_counts = plan.phase_counts();
    let planned_transfers = plan.transfers.len();
    InitDryRunReport {
        firmware_len: plan.firmware_len,
        firmware_chunk_size: plan.firmware_chunk_size,
        source_repo: plan.source_repo,
        source_commit: plan.source_commit,
        planned_transfers,
        trace_out,
        phase_counts,
        transfers: plan.transfers,
    }
}

fn load_firmware_with_report(
    path: &Path,
) -> std::result::Result<(FirmwareImage, FirmwareReport), String> {
    let image = FirmwareImage::load_external(path).map_err(|error| error.to_string())?;
    let report = firmware_report_from_image(path, &image)?;
    Ok((image, report))
}

fn firmware_report_from_image(
    path: &Path,
    image: &FirmwareImage,
) -> std::result::Result<FirmwareReport, String> {
    let chunk_size = MAX_DLFW_PAGE_SIZE;
    let chunk_count = image
        .chunks(chunk_size)
        .map_err(|error| error.to_string())?
        .count();
    Ok(FirmwareReport {
        source: path.to_path_buf(),
        len: image.len,
        byte_sum: image.byte_sum,
        chunk_size,
        chunk_count,
    })
}

fn macos_descriptor_smoke_report(args: MacosDescriptorSmokeArgs) -> MacosDescriptorSmokeReport {
    let selector = args.adapter.selector();
    let counters = DiagnosticCounters::default();

    #[cfg(not(target_os = "macos"))]
    {
        return macos_descriptor_smoke_failure(
            &args,
            selector,
            counters,
            None,
            None,
            DiagnosticErrorReport {
                code: "unsupported_platform",
                message: "macos-descriptor-smoke requires macOS IOUSBHost".to_string(),
            },
        );
    }

    #[cfg(target_os = "macos")]
    {
        let Some(vid) = selector.vid else {
            return macos_descriptor_smoke_failure(
                &args,
                selector,
                counters,
                None,
                None,
                DiagnosticErrorReport {
                    code: "missing_vid",
                    message: "macos-descriptor-smoke requires --vid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };
        let Some(pid) = selector.pid else {
            return macos_descriptor_smoke_failure(
                &args,
                selector,
                counters,
                None,
                None,
                DiagnosticErrorReport {
                    code: "missing_pid",
                    message: "macos-descriptor-smoke requires --pid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };

        let device = match macos_usbhost::MacosUsbHostDevice::open(vid, pid) {
            Ok(device) => device,
            Err(error) => {
                return macos_descriptor_smoke_failure(
                    &args,
                    selector,
                    counters,
                    None,
                    None,
                    DiagnosticErrorReport {
                        code: "macos_usbhost_open_failed",
                        message: error,
                    },
                );
            }
        };

        let timeout = Duration::from_millis(args.timeout_ms);
        let mut counters = counters;
        let device_raw = match device.get_descriptor(
            USB_DESCRIPTOR_TYPE_DEVICE,
            0,
            USB_DEVICE_DESCRIPTOR_LEN,
            timeout,
        ) {
            Ok(raw) => {
                counters.usb_control_reads += 1;
                raw
            }
            Err(error) => {
                return macos_descriptor_smoke_failure(
                    &args,
                    selector,
                    counters,
                    None,
                    None,
                    DiagnosticErrorReport {
                        code: "device_descriptor_read_failed",
                        message: error,
                    },
                );
            }
        };
        let device_descriptor = match parse_usb_device_descriptor(&device_raw) {
            Ok(descriptor) => descriptor,
            Err(error) => {
                return macos_descriptor_smoke_failure(
                    &args, selector, counters, None, None, error,
                );
            }
        };

        let config_header = match device.get_descriptor(
            USB_DESCRIPTOR_TYPE_CONFIGURATION,
            args.configuration_index,
            USB_CONFIGURATION_DESCRIPTOR_LEN,
            timeout,
        ) {
            Ok(raw) => {
                counters.usb_control_reads += 1;
                raw
            }
            Err(error) => {
                return macos_descriptor_smoke_failure(
                    &args,
                    selector,
                    counters,
                    Some(device_descriptor),
                    None,
                    DiagnosticErrorReport {
                        code: "configuration_descriptor_header_read_failed",
                        message: error,
                    },
                );
            }
        };
        if config_header.len() < USB_CONFIGURATION_DESCRIPTOR_LEN {
            return macos_descriptor_smoke_failure(
                &args,
                selector,
                counters,
                Some(device_descriptor),
                None,
                DiagnosticErrorReport {
                    code: "short_configuration_descriptor_header",
                    message: format!(
                        "expected {USB_CONFIGURATION_DESCRIPTOR_LEN} bytes, got {}",
                        config_header.len()
                    ),
                },
            );
        }
        let total_len = le_u16(&config_header, 2).unwrap_or(0);
        if usize::from(total_len) < USB_CONFIGURATION_DESCRIPTOR_LEN {
            return macos_descriptor_smoke_failure(
                &args,
                selector,
                counters,
                Some(device_descriptor),
                None,
                DiagnosticErrorReport {
                    code: "invalid_configuration_descriptor_length",
                    message: format!(
                        "configuration descriptor total length {} is shorter than header",
                        total_len
                    ),
                },
            );
        }
        let config_raw = match device.get_descriptor(
            USB_DESCRIPTOR_TYPE_CONFIGURATION,
            args.configuration_index,
            usize::from(total_len),
            timeout,
        ) {
            Ok(raw) => {
                counters.usb_control_reads += 1;
                raw
            }
            Err(error) => {
                return macos_descriptor_smoke_failure(
                    &args,
                    selector,
                    counters,
                    Some(device_descriptor),
                    None,
                    DiagnosticErrorReport {
                        code: "configuration_descriptor_read_failed",
                        message: error,
                    },
                );
            }
        };
        let configuration = match parse_usb_configuration_descriptor(&config_raw) {
            Ok(configuration) => configuration,
            Err(error) => {
                return macos_descriptor_smoke_failure(
                    &args,
                    selector,
                    counters,
                    Some(device_descriptor),
                    None,
                    error,
                );
            }
        };

        MacosDescriptorSmokeReport {
            schema_version: 1,
            command: "macos-descriptor-smoke",
            started_at_unix_ms: started_at_unix_ms(),
            platform: platform_info(),
            selector,
            timeout_ms: args.timeout_ms,
            configuration_index: args.configuration_index,
            result: DiagnosticResult::Pass,
            device_descriptor: Some(device_descriptor),
            configuration: Some(configuration),
            counters,
            error: None,
            notes: vec![
                "macOS IOUSBHost descriptor smoke test: device and configuration descriptors were read through default-control transfers",
                "no libusb enumeration, USB interface claim, hardware register writes, bulk traffic, RX loop, or TX operation was issued",
            ],
        }
    }
}

fn macos_descriptor_smoke_failure(
    args: &MacosDescriptorSmokeArgs,
    selector: DeviceSelector,
    counters: DiagnosticCounters,
    device_descriptor: Option<UsbDeviceDescriptorReport>,
    configuration: Option<UsbConfigurationDescriptorReport>,
    error: DiagnosticErrorReport,
) -> MacosDescriptorSmokeReport {
    MacosDescriptorSmokeReport {
        schema_version: 1,
        command: "macos-descriptor-smoke",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        timeout_ms: args.timeout_ms,
        configuration_index: args.configuration_index,
        result: DiagnosticResult::Fail,
        device_descriptor,
        configuration,
        counters,
        error: Some(error),
        notes: vec![
            "macOS IOUSBHost descriptor smoke test stopped before hardware register writes, bulk traffic, RX loop, or TX operation",
        ],
    }
}

fn macos_interface_smoke_report(args: MacosInterfaceSmokeArgs) -> MacosInterfaceSmokeReport {
    let selector = args.adapter.selector();
    let endpoints = macos_interface_smoke_endpoints(&args);
    let endpoint_addresses = endpoints
        .iter()
        .copied()
        .map(|endpoint| format_value(endpoint, 2))
        .collect::<Vec<_>>();
    let counters = DiagnosticCounters::default();

    if !args.i_understand_this_may_reconfigure_usb {
        return macos_interface_smoke_failure(
            &args,
            selector,
            endpoint_addresses,
            None,
            counters,
            DiagnosticErrorReport {
                code: "missing_reconfigure_authorization",
                message: "macos-interface-smoke may issue SET_CONFIGURATION and requires --i-understand-this-may-reconfigure-usb".to_string(),
            },
        );
    }

    if endpoints.len() > 16 {
        return macos_interface_smoke_failure(
            &args,
            selector,
            endpoint_addresses,
            None,
            counters,
            DiagnosticErrorReport {
                code: "too_many_endpoints",
                message: format!(
                    "macos-interface-smoke supports at most 16 endpoint probes, got {}",
                    endpoints.len()
                ),
            },
        );
    }

    #[cfg(not(target_os = "macos"))]
    {
        return macos_interface_smoke_failure(
            &args,
            selector,
            endpoint_addresses,
            None,
            counters,
            DiagnosticErrorReport {
                code: "unsupported_platform",
                message: "macos-interface-smoke requires macOS IOUSBHost".to_string(),
            },
        );
    }

    #[cfg(target_os = "macos")]
    {
        let Some(vid) = selector.vid else {
            return macos_interface_smoke_failure(
                &args,
                selector,
                endpoint_addresses,
                None,
                counters,
                DiagnosticErrorReport {
                    code: "missing_vid",
                    message: "macos-interface-smoke requires --vid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };
        let Some(pid) = selector.pid else {
            return macos_interface_smoke_failure(
                &args,
                selector,
                endpoint_addresses,
                None,
                counters,
                DiagnosticErrorReport {
                    code: "missing_pid",
                    message: "macos-interface-smoke requires --pid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };

        let device = match macos_usbhost::MacosUsbHostDevice::open(vid, pid) {
            Ok(device) => device,
            Err(error) => {
                return macos_interface_smoke_failure(
                    &args,
                    selector,
                    endpoint_addresses,
                    None,
                    counters,
                    DiagnosticErrorReport {
                        code: "macos_usbhost_open_failed",
                        message: error,
                    },
                );
            }
        };

        let probe = match device.probe_interface(macos_usbhost::MacosUsbHostInterfaceProbeRequest {
            vid,
            pid,
            configuration_value: args.configuration_value,
            match_interfaces: args.match_interfaces,
            interface_number: args.interface_number,
            pipe_addresses: &endpoints,
            poll_attempts: args.poll_attempts,
            poll_delay: Duration::from_millis(args.poll_delay_ms),
        }) {
            Ok(probe) => probe,
            Err(error) => {
                return macos_interface_smoke_failure(
                    &args,
                    selector,
                    endpoint_addresses,
                    None,
                    counters,
                    DiagnosticErrorReport {
                        code: "macos_interface_probe_failed",
                        message: error,
                    },
                );
            }
        };

        let counters = DiagnosticCounters {
            usb_control_writes: u64::from(probe.configure_attempted),
            ..DiagnosticCounters::default()
        };
        let passed = probe.configure_ok
            && probe.interface_found
            && probe.interface_opened
            && probe.pipes.iter().all(|pipe| pipe.copied);
        let error = if passed {
            None
        } else {
            Some(DiagnosticErrorReport {
                code: macos_interface_probe_error_code(&probe),
                message: probe.error.clone().unwrap_or_else(|| {
                    "IOUSBHost interface or pipe probe did not satisfy all pass criteria"
                        .to_string()
                }),
            })
        };
        let interface_probe = macos_interface_probe_report_from_probe(&probe);

        MacosInterfaceSmokeReport {
            schema_version: 1,
            command: "macos-interface-smoke",
            started_at_unix_ms: started_at_unix_ms(),
            platform: platform_info(),
            selector,
            configuration_value: args.configuration_value,
            match_interfaces: args.match_interfaces,
            interface_number: args.interface_number,
            endpoint_addresses,
            poll_attempts: args.poll_attempts,
            poll_delay_ms: args.poll_delay_ms,
            result: if passed {
                DiagnosticResult::Pass
            } else {
                DiagnosticResult::Fail
            },
            interface_probe: Some(interface_probe),
            counters,
            error,
            notes: vec![
                "macOS IOUSBHost interface smoke test: SET_CONFIGURATION may be issued, then interface 0 and descriptor-confirmed pipes are probed",
                "no hardware register writes, firmware download, channel tuning, bulk IO request, RX loop, or TX operation was issued",
            ],
        }
    }
}

fn macos_interface_smoke_endpoints(args: &MacosInterfaceSmokeArgs) -> Vec<u8> {
    if args.endpoints.is_empty() {
        MACOS_DEFAULT_INTERFACE_PROBE_ENDPOINTS.to_vec()
    } else {
        args.endpoints.clone()
    }
}

fn macos_interface_smoke_failure(
    args: &MacosInterfaceSmokeArgs,
    selector: DeviceSelector,
    endpoint_addresses: Vec<String>,
    interface_probe: Option<MacosInterfaceProbeReport>,
    counters: DiagnosticCounters,
    error: DiagnosticErrorReport,
) -> MacosInterfaceSmokeReport {
    MacosInterfaceSmokeReport {
        schema_version: 1,
        command: "macos-interface-smoke",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        configuration_value: args.configuration_value,
        match_interfaces: args.match_interfaces,
        interface_number: args.interface_number,
        endpoint_addresses,
        poll_attempts: args.poll_attempts,
        poll_delay_ms: args.poll_delay_ms,
        result: DiagnosticResult::Fail,
        interface_probe,
        counters,
        error: Some(error),
        notes: vec![
            "macOS IOUSBHost interface smoke test stopped before any bulk IO request, RX loop, or TX operation",
        ],
    }
}

#[cfg(target_os = "macos")]
fn macos_interface_probe_error_code(
    probe: &macos_usbhost::MacosUsbHostInterfaceProbe,
) -> &'static str {
    if !probe.configure_ok {
        "macos_usb_configure_failed"
    } else if !probe.interface_found {
        "macos_interface_not_found"
    } else if !probe.interface_opened {
        "macos_interface_open_failed"
    } else if probe.pipes.iter().any(|pipe| !pipe.copied) {
        "macos_pipe_copy_failed"
    } else {
        "macos_interface_probe_failed"
    }
}

#[cfg(target_os = "macos")]
fn macos_interface_probe_report_from_probe(
    probe: &macos_usbhost::MacosUsbHostInterfaceProbe,
) -> MacosInterfaceProbeReport {
    MacosInterfaceProbeReport {
        configure_attempted: probe.configure_attempted,
        configure_ok: probe.configure_ok,
        match_interfaces: probe.match_interfaces,
        interface_found: probe.interface_found,
        interface_opened: probe.interface_opened,
        poll_attempts_observed: probe.poll_attempts_observed,
        matched_interface_count: probe.matched_interface_count,
        pipes: probe
            .pipes
            .iter()
            .map(|pipe| MacosPipeProbeReport {
                address: pipe.address,
                address_hex: format_value(pipe.address, 2),
                requested: pipe.requested,
                copied: pipe.copied,
                descriptor_available: pipe.descriptor_available,
                descriptor_address: pipe.descriptor_address,
                descriptor_address_hex: format_value(pipe.descriptor_address, 2),
                direction: if pipe.descriptor_address & USB_ENDPOINT_DIRECTION_IN != 0 {
                    "in"
                } else {
                    "out"
                },
                transfer_type: endpoint_transfer_type(pipe.attributes),
                attributes_hex: format_value(pipe.attributes, 2),
                max_packet_size: pipe.max_packet_size,
                interval: pipe.interval,
                error: pipe.error.clone(),
            })
            .collect(),
        error: probe.error.clone(),
    }
}

fn macos_bulk_in_smoke_report(args: MacosBulkInSmokeArgs) -> MacosBulkInSmokeReport {
    let selector = args.adapter.selector();
    let counters = DiagnosticCounters::default();

    if !args.i_understand_this_may_reconfigure_usb {
        return macos_bulk_in_smoke_failure(
            &args,
            selector,
            None,
            counters,
            DiagnosticErrorReport {
                code: "missing_reconfigure_authorization",
                message: "macos-bulk-in-smoke may issue SET_CONFIGURATION and requires --i-understand-this-may-reconfigure-usb".to_string(),
            },
        );
    }

    if args.length == 0 {
        return macos_bulk_in_smoke_failure(
            &args,
            selector,
            None,
            counters,
            DiagnosticErrorReport {
                code: "invalid_length",
                message: "--length must be nonzero".to_string(),
            },
        );
    }

    #[cfg(not(target_os = "macos"))]
    {
        return macos_bulk_in_smoke_failure(
            &args,
            selector,
            None,
            counters,
            DiagnosticErrorReport {
                code: "unsupported_platform",
                message: "macos-bulk-in-smoke requires macOS IOUSBHost".to_string(),
            },
        );
    }

    #[cfg(target_os = "macos")]
    {
        let Some(vid) = selector.vid else {
            return macos_bulk_in_smoke_failure(
                &args,
                selector,
                None,
                counters,
                DiagnosticErrorReport {
                    code: "missing_vid",
                    message: "macos-bulk-in-smoke requires --vid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };
        let Some(pid) = selector.pid else {
            return macos_bulk_in_smoke_failure(
                &args,
                selector,
                None,
                counters,
                DiagnosticErrorReport {
                    code: "missing_pid",
                    message: "macos-bulk-in-smoke requires --pid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };

        let device = match macos_usbhost::MacosUsbHostDevice::open(vid, pid) {
            Ok(device) => device,
            Err(error) => {
                return macos_bulk_in_smoke_failure(
                    &args,
                    selector,
                    None,
                    counters,
                    DiagnosticErrorReport {
                        code: "macos_usbhost_open_failed",
                        message: error,
                    },
                );
            }
        };

        let transfer = match device.bulk_read_once(macos_usbhost::MacosUsbHostBulkReadRequest {
            vid,
            pid,
            configuration_value: args.configuration_value,
            match_interfaces: args.match_interfaces,
            interface_number: args.interface_number,
            endpoint_address: args.endpoint,
            len: args.length,
            poll_attempts: args.poll_attempts,
            poll_delay: Duration::from_millis(args.poll_delay_ms),
            timeout: Duration::from_millis(args.timeout_ms),
        }) {
            Ok(transfer) => transfer,
            Err(error) => {
                return macos_bulk_in_smoke_failure(
                    &args,
                    selector,
                    None,
                    counters,
                    DiagnosticErrorReport {
                        code: "macos_bulk_read_failed",
                        message: error,
                    },
                );
            }
        };

        let counters = DiagnosticCounters {
            usb_control_writes: u64::from(transfer.configure_attempted),
            usb_bulk_in_reads: u64::from(transfer.pipe_copied),
            ..DiagnosticCounters::default()
        };
        let passed = transfer.configure_ok
            && transfer.interface_found
            && transfer.interface_opened
            && transfer.pipe_copied
            && (transfer.transfer_ok || transfer.timed_out);
        let error = if passed {
            None
        } else {
            Some(DiagnosticErrorReport {
                code: macos_bulk_in_error_code(&transfer),
                message: transfer.error.clone().unwrap_or_else(|| {
                    "IOUSBHost bulk-IN smoke did not satisfy all pass criteria".to_string()
                }),
            })
        };
        let transfer = macos_bulk_in_transfer_report_from_transfer(&transfer);

        MacosBulkInSmokeReport {
            schema_version: 1,
            command: "macos-bulk-in-smoke",
            started_at_unix_ms: started_at_unix_ms(),
            platform: platform_info(),
            selector,
            configuration_value: args.configuration_value,
            match_interfaces: args.match_interfaces,
            interface_number: args.interface_number,
            endpoint: args.endpoint,
            endpoint_hex: format_value(args.endpoint, 2),
            length: args.length,
            timeout_ms: args.timeout_ms,
            poll_attempts: args.poll_attempts,
            poll_delay_ms: args.poll_delay_ms,
            result: if passed {
                DiagnosticResult::Pass
            } else {
                DiagnosticResult::Fail
            },
            transfer: Some(transfer),
            counters,
            error,
            notes: vec![
                "macOS IOUSBHost bulk-IN smoke test: SET_CONFIGURATION may be issued, interface 0 and the selected pipe are opened, then one bounded bulk-IN request is submitted",
                "a timeout is accepted as a pass signal for this smoke test because it proves the pipe accepted a bulk transfer request without requiring RF traffic",
                "no hardware register writes, firmware download, channel tuning, bulk OUT request, RX loop, or TX operation was issued",
            ],
        }
    }
}

fn macos_bulk_in_smoke_failure(
    args: &MacosBulkInSmokeArgs,
    selector: DeviceSelector,
    transfer: Option<MacosBulkInTransferReport>,
    counters: DiagnosticCounters,
    error: DiagnosticErrorReport,
) -> MacosBulkInSmokeReport {
    MacosBulkInSmokeReport {
        schema_version: 1,
        command: "macos-bulk-in-smoke",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        configuration_value: args.configuration_value,
        match_interfaces: args.match_interfaces,
        interface_number: args.interface_number,
        endpoint: args.endpoint,
        endpoint_hex: format_value(args.endpoint, 2),
        length: args.length,
        timeout_ms: args.timeout_ms,
        poll_attempts: args.poll_attempts,
        poll_delay_ms: args.poll_delay_ms,
        result: DiagnosticResult::Fail,
        transfer,
        counters,
        error: Some(error),
        notes: vec![
            "macOS IOUSBHost bulk-IN smoke test stopped before bulk OUT, RX loop, or TX operation",
        ],
    }
}

#[cfg(target_os = "macos")]
fn macos_bulk_in_error_code(transfer: &macos_usbhost::MacosUsbHostBulkTransfer) -> &'static str {
    if !transfer.configure_ok {
        "macos_usb_configure_failed"
    } else if !transfer.interface_found {
        "macos_interface_not_found"
    } else if !transfer.interface_opened {
        "macos_interface_open_failed"
    } else if !transfer.pipe_copied {
        "macos_pipe_copy_failed"
    } else if !transfer.transfer_ok && !transfer.timed_out {
        "macos_bulk_in_request_failed"
    } else {
        "macos_bulk_in_smoke_failed"
    }
}

#[cfg(target_os = "macos")]
fn macos_bulk_in_transfer_report_from_transfer(
    transfer: &macos_usbhost::MacosUsbHostBulkTransfer,
) -> MacosBulkInTransferReport {
    MacosBulkInTransferReport {
        configure_attempted: transfer.configure_attempted,
        configure_ok: transfer.configure_ok,
        interface_found: transfer.interface_found,
        interface_opened: transfer.interface_opened,
        pipe_copied: transfer.pipe_copied,
        descriptor_available: transfer.descriptor_available,
        transfer_ok: transfer.transfer_ok,
        timed_out: transfer.timed_out,
        poll_attempts_observed: transfer.poll_attempts_observed,
        matched_interface_count: transfer.matched_interface_count,
        endpoint_address_hex: format_value(transfer.endpoint_address, 2),
        descriptor_address_hex: format_value(transfer.descriptor_address, 2),
        direction: if transfer.descriptor_address & USB_ENDPOINT_DIRECTION_IN != 0 {
            "in"
        } else {
            "out"
        },
        transfer_type: endpoint_transfer_type(transfer.attributes),
        attributes_hex: format_value(transfer.attributes, 2),
        max_packet_size: transfer.max_packet_size,
        interval: transfer.interval,
        requested_len: transfer.requested_len,
        transferred_len: transfer.transferred_len,
        data_hex: encode_hex(&transfer.data),
        error: transfer.error.clone(),
    }
}

fn macos_bulk_out_smoke_report(args: MacosBulkOutSmokeArgs) -> MacosBulkOutSmokeReport {
    let selector = args.adapter.selector();
    let counters = DiagnosticCounters::default();

    if !args.i_understand_this_may_reconfigure_usb {
        return macos_bulk_out_smoke_failure(
            &args,
            selector,
            None,
            counters,
            DiagnosticErrorReport {
                code: "missing_reconfigure_authorization",
                message: "macos-bulk-out-smoke may issue SET_CONFIGURATION and requires --i-understand-this-may-reconfigure-usb".to_string(),
            },
        );
    }

    if !args.i_understand_this_submits_bulk_out {
        return macos_bulk_out_smoke_failure(
            &args,
            selector,
            None,
            counters,
            DiagnosticErrorReport {
                code: "missing_bulk_out_authorization",
                message: "macos-bulk-out-smoke submits one zero-length bulk OUT request and requires --i-understand-this-submits-bulk-out".to_string(),
            },
        );
    }

    #[cfg(not(target_os = "macos"))]
    {
        return macos_bulk_out_smoke_failure(
            &args,
            selector,
            None,
            counters,
            DiagnosticErrorReport {
                code: "unsupported_platform",
                message: "macos-bulk-out-smoke requires macOS IOUSBHost".to_string(),
            },
        );
    }

    #[cfg(target_os = "macos")]
    {
        let Some(vid) = selector.vid else {
            return macos_bulk_out_smoke_failure(
                &args,
                selector,
                None,
                counters,
                DiagnosticErrorReport {
                    code: "missing_vid",
                    message: "macos-bulk-out-smoke requires --vid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };
        let Some(pid) = selector.pid else {
            return macos_bulk_out_smoke_failure(
                &args,
                selector,
                None,
                counters,
                DiagnosticErrorReport {
                    code: "missing_pid",
                    message: "macos-bulk-out-smoke requires --pid because IOUSBHost matching is VID/PID based".to_string(),
                },
            );
        };

        let device = match macos_usbhost::MacosUsbHostDevice::open(vid, pid) {
            Ok(device) => device,
            Err(error) => {
                return macos_bulk_out_smoke_failure(
                    &args,
                    selector,
                    None,
                    counters,
                    DiagnosticErrorReport {
                        code: "macos_usbhost_open_failed",
                        message: error,
                    },
                );
            }
        };

        let transfer = match device.bulk_write_once(macos_usbhost::MacosUsbHostBulkWriteRequest {
            vid,
            pid,
            configuration_value: args.configuration_value,
            match_interfaces: args.match_interfaces,
            interface_number: args.interface_number,
            endpoint_address: args.endpoint,
            data: &[],
            poll_attempts: args.poll_attempts,
            poll_delay: Duration::from_millis(args.poll_delay_ms),
            timeout: Duration::from_millis(args.timeout_ms),
        }) {
            Ok(transfer) => transfer,
            Err(error) => {
                return macos_bulk_out_smoke_failure(
                    &args,
                    selector,
                    None,
                    counters,
                    DiagnosticErrorReport {
                        code: "macos_bulk_write_failed",
                        message: error,
                    },
                );
            }
        };

        let counters = DiagnosticCounters {
            usb_control_writes: u64::from(transfer.configure_attempted),
            usb_bulk_out_writes: u64::from(transfer.pipe_copied),
            ..DiagnosticCounters::default()
        };
        let passed = transfer.configure_ok
            && transfer.interface_found
            && transfer.interface_opened
            && transfer.pipe_copied
            && transfer.transfer_ok;
        let error = if passed {
            None
        } else {
            Some(DiagnosticErrorReport {
                code: macos_bulk_out_error_code(&transfer),
                message: transfer.error.clone().unwrap_or_else(|| {
                    "IOUSBHost bulk-OUT smoke did not satisfy all pass criteria".to_string()
                }),
            })
        };
        let transfer = macos_bulk_out_transfer_report_from_transfer(&transfer);

        MacosBulkOutSmokeReport {
            schema_version: 1,
            command: "macos-bulk-out-smoke",
            started_at_unix_ms: started_at_unix_ms(),
            platform: platform_info(),
            selector,
            configuration_value: args.configuration_value,
            match_interfaces: args.match_interfaces,
            interface_number: args.interface_number,
            endpoint: args.endpoint,
            endpoint_hex: format_value(args.endpoint, 2),
            payload_len: 0,
            timeout_ms: args.timeout_ms,
            poll_attempts: args.poll_attempts,
            poll_delay_ms: args.poll_delay_ms,
            result: if passed {
                DiagnosticResult::Pass
            } else {
                DiagnosticResult::Fail
            },
            transfer: Some(transfer),
            counters,
            error,
            notes: vec![
                "macOS IOUSBHost bulk-OUT smoke test: SET_CONFIGURATION may be issued, interface 0 and the selected pipe are opened, then one zero-length bulk-OUT request is submitted",
                "this smoke test does not submit an RTL8812AU TX descriptor, an 802.11 frame, a nonzero payload, register writes, firmware download, channel tuning, RX loop, or RF TX operation",
            ],
        }
    }
}

fn macos_bulk_out_smoke_failure(
    args: &MacosBulkOutSmokeArgs,
    selector: DeviceSelector,
    transfer: Option<MacosBulkOutTransferReport>,
    counters: DiagnosticCounters,
    error: DiagnosticErrorReport,
) -> MacosBulkOutSmokeReport {
    MacosBulkOutSmokeReport {
        schema_version: 1,
        command: "macos-bulk-out-smoke",
        started_at_unix_ms: started_at_unix_ms(),
        platform: platform_info(),
        selector,
        configuration_value: args.configuration_value,
        match_interfaces: args.match_interfaces,
        interface_number: args.interface_number,
        endpoint: args.endpoint,
        endpoint_hex: format_value(args.endpoint, 2),
        payload_len: 0,
        timeout_ms: args.timeout_ms,
        poll_attempts: args.poll_attempts,
        poll_delay_ms: args.poll_delay_ms,
        result: DiagnosticResult::Fail,
        transfer,
        counters,
        error: Some(error),
        notes: vec![
            "macOS IOUSBHost bulk-OUT smoke test stopped before any bulk OUT request, RX loop, TX descriptor, 802.11 frame, or RF operation",
        ],
    }
}

#[cfg(target_os = "macos")]
fn macos_bulk_out_error_code(transfer: &macos_usbhost::MacosUsbHostBulkTransfer) -> &'static str {
    if !transfer.configure_ok {
        "macos_usb_configure_failed"
    } else if !transfer.interface_found {
        "macos_interface_not_found"
    } else if !transfer.interface_opened {
        "macos_interface_open_failed"
    } else if !transfer.pipe_copied {
        "macos_pipe_copy_failed"
    } else if transfer.timed_out {
        "macos_bulk_out_request_timed_out"
    } else if !transfer.transfer_ok {
        "macos_bulk_out_request_failed"
    } else {
        "macos_bulk_out_smoke_failed"
    }
}

