fn print_tx_power_control_human(tx_power: &TxPowerControlReport) {
    match tx_power.mode {
        TxPowerControlModeArg::ManualIndex => println!(
            "TX power control: mode=manual-index index={} path={:?} registers={} value={}",
            tx_power.manual_index_hex.as_deref().unwrap_or("-"),
            tx_power.path,
            tx_power.register_count,
            tx_power.repeated_value_hex.as_deref().unwrap_or("-")
        ),
        TxPowerControlModeArg::EfuseDerived => {
            let clamp = tx_power
                .efuse_plan
                .as_ref()
                .map(|plan| format!("{:?}", plan.safety_profile))
                .unwrap_or_else(|| "-".to_string());
            println!(
                "TX power control: mode=efuse-derived path={:?} registers={} clamp={}",
                tx_power.path, tx_power.register_count, clamp
            );
        }
    }
}

fn print_tx_calibration_profile_human(profile: &TxCalibrationProfileReport) {
    println!(
        "TX calibration profile: {:?} channel={} bandwidth={} MHz registers={}",
        profile.profile, profile.channel, profile.bandwidth_mhz, profile.register_count
    );
    for write in &profile.writes {
        println!(
            "  {} {}: {} -> {} (wrote {}, changed={})",
            write.register_name,
            write.address_hex,
            write.before_hex,
            write.after_hex,
            write.written_hex,
            write.changed
        );
    }
    if let Some(lck) = profile.lck.as_ref() {
        println!(
            "  LCK path {}: RF_CHNLBW {} -> {} via {} ms delay; RF_LCK {} -> {}",
            lck.rf_path_name,
            lck.rf_chnlbw_before_trigger.value_hex,
            lck.rf_chnlbw_after_restore.value_hex,
            lck.delay_ms,
            lck.rf_lck_before_enter.value_hex,
            lck.rf_lck_after_exit.value_hex
        );
    }
    if let Some(iqk) = profile.iqk.as_ref() {
        println!(
            "  IQK probe: mode={} read_only={} macbb={} afe={} rf_a={} rf_b={} latches={} restored={}",
            iqk.mode,
            iqk.read_only,
            iqk.macbb_backup.len(),
            iqk.afe_backup.len(),
            iqk.rf_backup_path_a.len(),
            iqk.rf_backup_path_b.len(),
            iqk.page_c1_latches
                .as_ref()
                .map(|page| page.latches.len())
                .unwrap_or_default(),
            iqk.page_c1_latches
                .as_ref()
                .map(|page| page.restored)
                .unwrap_or(true)
                && iqk.hssi_read_restored.unwrap_or(true)
        );
    }
    if let Some(iqk) = profile.runtime_iqk.as_ref() {
        println!(
            "  Runtime IQK: mode={} status={} cleanup={} paths={} counters={:?}",
            iqk.mode,
            iqk.status,
            iqk.cleanup_status,
            iqk.paths.len(),
            iqk.counters
        );
    }
}

