fn print_trace_compare_human(report: &TraceCompareReport) {
    println!("Trace compare: {}", report.result.as_str());
    println!("Expected: {}", report.expected_path.display());
    println!("Observed: {}", report.observed_path.display());
    if let Some(comparison) = &report.comparison {
        println!(
            "Events: expected={} observed={} compared={}",
            comparison.expected_len, comparison.observed_len, comparison.compared_len
        );
        if !comparison.mismatches.is_empty() {
            println!("Mismatches:");
            for mismatch in &comparison.mismatches {
                println!(
                    "- event {} {} expected={} observed={}",
                    mismatch.event_index, mismatch.field, mismatch.expected, mismatch.observed
                );
            }
        }
    }
    if let Some(error) = &report.error {
        println!("Error: {}: {}", error.code, error.message);
    }
}

fn print_trace_import_human(report: &TraceImportReport) {
    println!("Trace import: {}", report.result.as_str());
    println!("Input: {}", report.input_path.display());
    println!("Output: {}", report.output_path.display());
    if let Some(imported) = &report.import {
        println!(
            "Events: imported={} ignored_lines={} errors={}",
            imported.events.len(),
            imported.ignored_lines,
            imported.errors.len()
        );
        if !imported.errors.is_empty() {
            println!("Errors:");
            for error in &imported.errors {
                println!("- line {}: {}", error.line_number, error.message);
            }
        }
    }
    if let Some(error) = &report.error {
        println!("Error: {}: {}", error.code, error.message);
    }
}

fn print_trace_registers_human(report: &TraceRegistersReport) {
    println!("Trace registers: {}", report.result.as_str());
    println!("Input: {}", report.input_path.display());
    if let Some(path) = &report.output_path {
        println!("Final register map out: {}", path.display());
    }
    println!(
        "Events: imported={} ignored_lines={}",
        report.imported_events, report.ignored_lines
    );
    println!(
        "Register writes: total={} unique={}",
        report.register_write_count, report.unique_register_count
    );
    if !report.final_writes.is_empty() {
        println!("Final writes:");
        for write in report.final_writes.iter().take(40) {
            println!(
                "- {} width={} data={} le={} writes={} last_event={}",
                write.address_hex,
                write.width,
                write.data_hex,
                write.value_le_hex,
                write.write_count,
                write.last_event_index
            );
        }
        if report.final_writes.len() > 40 {
            println!(
                "- ... {} more registers",
                report.final_writes.len().saturating_sub(40)
            );
        }
    }
    if let Some(error) = &report.error {
        println!("Error: {}: {}", error.code, error.message);
    }
}

