    #[test]
    fn extract_firmware_writes_realtek_c_array() {
        let stamp = started_at_unix_ms();
        let source_path = std::env::temp_dir().join(format!(
            "wfb-radio-diag-fw-source-{}-{stamp}.c",
            std::process::id()
        ));
        let out_path = std::env::temp_dir().join(format!(
            "wfb-radio-diag-fw-out-{}-{stamp}.bin",
            std::process::id()
        ));
        fs::write(
            &source_path,
            r#"
u8 array_mp_8812a_fw_nic[] = {
    0x01, 0x95, 0x20, 0x00,
};
"#,
        )
        .expect("write source");

        let report = extract_firmware_report(ExtractFirmwareArgs {
            source: source_path.clone(),
            array: "array_mp_8812a_fw_nic".to_string(),
            out: out_path.clone(),
            overwrite: false,
        });

        assert_eq!(report.result, DiagnosticResult::Pass);
        assert_eq!(report.firmware_payload_len, Some(4));
        assert_eq!(report.firmware_signature_hex.as_deref(), Some("0x9501"));
        assert_eq!(
            fs::read(&out_path).expect("firmware out"),
            vec![0x01, 0x95, 0x20, 0x00]
        );

        let _ = fs::remove_file(source_path);
        let _ = fs::remove_file(out_path);
    }

    #[test]
    fn extract_firmware_refuses_existing_output_without_overwrite() {
        let stamp = started_at_unix_ms();
        let source_path = std::env::temp_dir().join(format!(
            "wfb-radio-diag-fw-source-existing-{}-{stamp}.c",
            std::process::id()
        ));
        let out_path = std::env::temp_dir().join(format!(
            "wfb-radio-diag-fw-out-existing-{}-{stamp}.bin",
            std::process::id()
        ));
        fs::write(
            &source_path,
            "u8 array_mp_8812a_fw_nic[] = { 0x01, 0x95 };\n",
        )
        .expect("write source");
        fs::write(&out_path, [0xaa, 0xbb]).expect("write existing");

        let report = extract_firmware_report(ExtractFirmwareArgs {
            source: source_path.clone(),
            array: "array_mp_8812a_fw_nic".to_string(),
            out: out_path.clone(),
            overwrite: false,
        });

        assert_eq!(report.result, DiagnosticResult::Fail);
        assert_eq!(
            report.error.as_ref().map(|error| error.code),
            Some("output_exists")
        );
        assert_eq!(fs::read(&out_path).expect("existing out"), vec![0xaa, 0xbb]);

        let _ = fs::remove_file(source_path);
        let _ = fs::remove_file(out_path);
    }

    #[test]
    fn bridge_same_session_init_uses_linux_order_for_wfb_paths() {
        let mut rx_args = rx_scan_args();
        rx_args.init_before_rx = true;
        let rx_init = rx_scan_init_bridge_args(&rx_args);
        assert!(rx_init.init_before_tx);
        assert!(rx_init.linux_init_order);

        let mut tx_args = bridge_tx_listen_args(true);
        tx_args.init_before_tx = true;
        tx_args.pre_tx_write8.push(PreTxRegisterWriteArg {
            address: 0x0522,
            value: 0,
        });
        tx_args.pre_tx_write16.push(PreTxRegisterWriteArg {
            address: 0x0422,
            value: 0x1234,
        });
        tx_args.pre_tx_write32.push(PreTxRegisterWriteArg {
            address: 0x0c90,
            value: 0x01817d24,
        });
        tx_args.pre_tx_rmw32.push(PreTxRegisterMaskedWriteArg {
            address: 0x08ac,
            mask: 0x003003c3,
            value: 0x00300201,
        });
        tx_args.pre_tx_rf_write.push(PreTxRfWriteArg {
            path: TxPowerPathArg::Both,
            rf_offset: RF_CHNLBW_JAGUAR,
            value: 0x10138,
        });
        let tx_init = bridge_tx_listen_init_bridge_args(&tx_args);
        assert!(tx_init.init_before_tx);
        assert!(tx_init.linux_init_order);
        assert_eq!(tx_init.pre_tx_write8, tx_args.pre_tx_write8);
        assert_eq!(tx_init.pre_tx_write16, tx_args.pre_tx_write16);
        assert_eq!(tx_init.pre_tx_write32, tx_args.pre_tx_write32);
        assert_eq!(tx_init.pre_tx_rmw32, tx_args.pre_tx_rmw32);
        assert_eq!(tx_init.pre_tx_rf_write, tx_args.pre_tx_rf_write);
    }

    #[test]
    fn parse_bandwidth_accepts_common_forms() {
        assert_eq!(parse_bandwidth("20").expect("20"), Bandwidth::Mhz20);
        assert_eq!(parse_bandwidth("40MHz").expect("40"), Bandwidth::Mhz40);
        assert_eq!(parse_bandwidth("mhz80").expect("80"), Bandwidth::Mhz80);
    }

    #[test]
    fn parse_pre_tx_rf_write_accepts_paths_and_bounds() {
        let write = parse_pre_tx_rf_write_arg("both:0x18=0x10138").expect("rf write");
        assert_eq!(write.path, TxPowerPathArg::Both);
        assert_eq!(write.rf_offset, RF_CHNLBW_JAGUAR);
        assert_eq!(write.value, 0x10138);
        assert!(parse_pre_tx_rf_write_arg("a:0x100=0x1").is_err());
        assert!(parse_pre_tx_rf_write_arg("b:0x18=0x100000").is_err());
    }

    #[test]
    fn parse_tx_rate_accepts_legacy_ht_and_vht_forms() {
        assert_eq!(parse_tx_rate_arg("ofdm6m").expect("ofdm"), TxRate::Ofdm6m);
        assert_eq!(parse_tx_rate_arg("6m").expect("ofdm short"), TxRate::Ofdm6m);
        assert_eq!(parse_tx_rate_arg("cck5.5m").expect("cck"), TxRate::Cck5_5m);
        assert_eq!(parse_tx_rate_arg("mcs7").expect("ht"), TxRate::Mcs(7));
        assert_eq!(
            parse_tx_rate_arg("vht2ss-mcs9").expect("vht"),
            TxRate::Vht { mcs: 9, nss: 2 }
        );
        assert_eq!(
            parse_tx_rate_arg("vht4ss_mcs0").expect("vht underscore"),
            TxRate::Vht { mcs: 0, nss: 4 }
        );
        assert!(parse_tx_rate_arg("mcs32").is_err());
        assert!(parse_tx_rate_arg("vht2ss-mcs10").is_err());
        assert!(parse_tx_rate_arg("vht5ss-mcs0").is_err());
    }

    #[test]
    fn parse_tx_power_index_accepts_guarded_range() {
        assert_eq!(parse_tx_power_index("0").expect("zero"), 0);
        assert_eq!(parse_tx_power_index("0x3f").expect("max"), 0x3f);
        assert!(parse_tx_power_index("0x40")
            .expect_err("above guarded max")
            .contains("0x00..=0x3f"));
    }

    #[test]
    fn rf_quality_report_serializes_without_linux_baseline() {
        let report = rf_quality_report(rf_quality_report_args());
        let json = serde_json::to_string(&report).expect("serialize report");

        assert_eq!(report.result, DiagnosticResult::Pass);
        assert_eq!(
            report.comparison.status,
            RfQualityComparisonStatus::NoBaseline
        );
        assert_eq!(
            report.acceptance.status,
            RfQualityAcceptanceStatus::NotEvaluated
        );
        assert!(json.contains("\"command\":\"rf-quality-report\""));
        assert!(json.contains("\"baseline_required_for_range_ready\":true"));
    }

    #[test]
    fn rf_quality_report_records_companion_notes() {
        let mut args = rf_quality_report_args();
        args.distance_or_geometry = Some("300 m line-of-sight between ridge and bench".to_string());
        args.antenna_orientation = Some("both vertical, broadside to path".to_string());
        args.adapter_placement =
            Some("Mac adapter on 1 m USB extension, clear of battery".to_string());
        args.environment_notes
            .push("dry, light wind, no visible 5 GHz AP nearby".to_string());
        args.companion_artifacts
            .push(PathBuf::from("/tmp/field-300m-notes.md"));

        let report = rf_quality_report(args);

        assert!(report.companion_notes.complete_for_field_run);
        assert_eq!(
            report.companion_notes.distance_or_geometry.as_deref(),
            Some("300 m line-of-sight between ridge and bench")
        );
        assert_eq!(
            report.companion_notes.artifacts,
            vec![PathBuf::from("/tmp/field-300m-notes.md")]
        );
    }

    #[test]
    fn rf_quality_report_distinguishes_context_from_observed_bandwidth() {
        let mut args = rf_quality_report_args();
        args.bandwidth = Bandwidth::Mhz40;
        args.observed_ppdu_bandwidth = Some(Bandwidth::Mhz20);
        args.observed_ppdu_source =
            Some("linux monitor radiotap plus Mac RX descriptor JSONL".to_string());
        args.observed_ppdu_artifacts
            .push(PathBuf::from("/tmp/rxmeta40.jsonl"));

        let report = rf_quality_report(args);

        assert_eq!(report.profile.bandwidth_mhz, 40);
        assert_eq!(
            report.bandwidth_evidence.observed_frame_bandwidth_mhz,
            Some(20)
        );
        assert_eq!(
            report.bandwidth_evidence.status,
            RfQualityBandwidthEvidenceStatus::ContextOnlyNarrowerObserved
        );
        assert_eq!(
            report.bandwidth_evidence.artifacts,
            vec![PathBuf::from("/tmp/rxmeta40.jsonl")]
        );
    }

    #[test]
    fn rf_quality_regression_fixtures_parse_expected_summaries() {
        let close_range: serde_json::Value = serde_json::from_str(include_str!(
            "../../../fixtures/rf-quality/rf-quality-close-range-accepted-summary.json"
        ))
        .expect("close-range summary fixture");
        let ht40: serde_json::Value = serde_json::from_str(include_str!(
            "../../../fixtures/rf-quality/rf-quality-ht40-context-evidence-summary.json"
        ))
        .expect("HT40 evidence summary fixture");

        assert_eq!(
            rf_quality_json_string(&close_range, &["acceptance", "status"]).as_deref(),
            Some("baseline_comparable")
        );
        assert_eq!(
            rf_quality_json_string(
                &close_range,
                &["comparison", "outcome", "acceptance_margin", "status"]
            )
            .as_deref(),
            Some("within_margin")
        );
        assert_eq!(
            rf_quality_json_string(&ht40, &["bandwidth_evidence", "status"]).as_deref(),
            Some("context_only_narrower_observed")
        );
        assert_eq!(
            rf_quality_json_u64(
                &ht40,
                &["bandwidth_evidence", "observed_frame_bandwidth_mhz"]
            ),
            Some(20)
        );
    }

