    #[test]
    fn rf_quality_runtime_iqk_summary_surfaces_fallback_stages() {
        let mut args = rf_quality_report_args();
        args.calibration_mode = RfQualityCalibrationMode::RuntimeApproximation;
        let mac_report = serde_json::json!({
            "tx_calibration_profile": {
                "profile": "rtl8812a_runtime_iqk",
                "runtime_iqk": {
                    "status": "fallback_applied",
                    "cleanup_status": "restored",
                    "sweep_index": 3,
                    "sweep_count": 3,
                    "max_sweeps": 3,
                    "paths": [
                        {
                            "path": "a",
                            "path_name": "A",
                            "tx": {"stage": "tx", "status": "success", "fallback_used": false},
                            "rx": {
                                "stage": "rx",
                                "status": "failed",
                                "fallback_used": true,
                                "failure_label": "rx_iqk_failed_flag",
                                "selected_iqc": {"x_hex": "0x200", "y_hex": "0x000"}
                            }
                        },
                        {
                            "path": "b",
                            "path_name": "B",
                            "tx": {"stage": "tx", "status": "success", "fallback_used": false},
                            "rx": {"stage": "rx", "status": "success", "fallback_used": false}
                        }
                    ]
                }
            }
        });

        let macos = rf_quality_macos_report(&args, Some(&mac_report), None, None);
        let summary = macos
            .calibration
            .runtime_iqk_summary
            .as_ref()
            .expect("runtime IQK summary");

        assert!(!summary.completed);
        assert!(summary.cleanup_restored);
        assert_eq!(summary.sweep_index, Some(3));
        assert_eq!(summary.sweep_count, Some(3));
        assert_eq!(summary.max_sweeps, Some(3));
        assert_eq!(summary.risk, RfQualityRuntimeIqkRiskStatus::FallbackApplied);
        assert_eq!(summary.fallback_stage_count, 1);
        assert_eq!(summary.fallback_stages[0].path.as_deref(), Some("A"));
        assert_eq!(summary.fallback_stages[0].stage.as_deref(), Some("rx"));
        assert_eq!(
            summary.fallback_stages[0].failure_label.as_deref(),
            Some("rx_iqk_failed_flag")
        );
    }

    #[test]
    fn rf_quality_calibration_comparison_detects_linux_register_mismatch() {
        let args = rf_quality_report_args();
        let profile =
            rf_quality_profile_report(&args, Some(Channel::from_number(36).expect("channel")));
        let mac_report = serde_json::json!({
            "rf_calibration_pre_tx": {
                "stage": "before_tx",
                "stop_gap": true,
                "rfe_pinmux": [
                    {"register_name": "rA_RFE_Pinmux_Jaguar", "address": REG_RFE_PINMUX_A_JAGUAR, "value_hex": "0x54337717"}
                ],
                "iqk": [
                    {"register_name": "rA_IQK_Result_Jaguar", "address": REG_OFDM0_XBAGCCORE1, "value_hex": "0x30000c1c"}
                ]
            }
        });
        let macos = rf_quality_macos_report(&args, Some(&mac_report), None, None);
        let linux_final = serde_json::json!([
            {"address": REG_RFE_PINMUX_A_JAGUAR, "value_le_hex": "0x54337717"},
            {"address": REG_OFDM0_XBAGCCORE1, "value_le_hex": "0x1c0c0030"}
        ]);
        let baseline =
            rf_quality_linux_baseline_report(Path::new("/tmp/linux-final.json"), &linux_final)
                .expect("linux baseline");

        let comparison = rf_quality_compare_profile_to_baseline(&profile, &macos, Some(&baseline));

        assert_eq!(
            comparison.calibration.status,
            RfQualityCalibrationComparisonStatus::Mismatched
        );
        assert_eq!(comparison.calibration.compared_register_count, 2);
        assert_eq!(comparison.calibration.mismatches.len(), 1);
        assert_eq!(
            comparison.calibration.mismatches[0].address,
            REG_OFDM0_XBAGCCORE1
        );
        assert_eq!(
            comparison.calibration.mismatches[0].macos_value_hex,
            "0x30000c1c"
        );
        assert_eq!(
            comparison.calibration.mismatches[0].linux_value_hex,
            "0x1c0c0030"
        );
    }

