    #[test]
    fn tx_status_register_source_merges_trace_final_writes() {
        let stamp = started_at_unix_ms();
        let input_path = std::env::temp_dir().join(format!(
            "wfb-radio-diag-tx-status-registers-{}-{stamp}.json",
            std::process::id()
        ));
        fs::write(
            &input_path,
            r#"[
  {
    "address": 3232,
    "address_hex": "0x0ca0",
    "width": 4,
    "data_hex": "407d8101",
    "value_le_hex": "0x01817d40",
    "value_be_hex": "0x407d8101",
    "write_count": 1,
    "last_event_index": 7
  },
  {
    "address": 3248,
    "address_hex": "0x0cb0",
    "width": 4,
    "data_hex": "17773354",
    "value_le_hex": "0x54337717",
    "value_be_hex": "0x17773354",
    "write_count": 2,
    "last_event_index": 8
  }
]"#,
        )
        .expect("write trace registers");

        let (requests, error) = tx_status_register_requests(&TxStatusProbeArgs {
            tx_status_registers_from: vec![input_path.clone()],
            ..TxStatusProbeArgs::default()
        });
        let _ = fs::remove_file(input_path);

        assert!(error.is_none());
        assert!(requests.iter().any(|request| {
            request.name == "TRACE_0x0ca0"
                && request.address == 0x0ca0
                && request.width == TxStatusRegisterWidth::U32
                && request
                    .expected
                    .as_ref()
                    .is_some_and(|expected| expected.value_hex == "0x01817d40")
        }));
        assert_eq!(
            requests
                .iter()
                .filter(|request| {
                    request.address == REG_RFE_PINMUX_A_JAGUAR
                        && request.width == TxStatusRegisterWidth::U32
                })
                .count(),
            1
        );
        assert!(requests.iter().any(|request| {
            request.address == REG_RFE_PINMUX_A_JAGUAR
                && request.width == TxStatusRegisterWidth::U32
                && request
                    .expected
                    .as_ref()
                    .is_some_and(|expected| expected.write_count == 2)
        }));
    }

    #[test]
    fn tx_status_trace_comparison_reports_pre_and_post_mismatches() {
        let source_path = PathBuf::from("/tmp/linux-final.json");
        let requests = vec![
            TxStatusRegisterRequest {
                name: "TRACE_0x0100".to_string(),
                address: 0x0100,
                width: TxStatusRegisterWidth::U16,
                expected: Some(TxStatusRegisterExpected {
                    source_path,
                    value: 0x06ff,
                    value_hex: "0x06ff".to_string(),
                    data_hex: "ff06".to_string(),
                    write_count: 3,
                    last_event_index: 9,
                }),
            },
            TxStatusRegisterRequest {
                name: "REG_TDECTRL".to_string(),
                address: REG_TDECTRL,
                width: TxStatusRegisterWidth::U32,
                expected: None,
            },
        ];
        let pre = vec![
            TxStatusRegisterReport {
                name: "TRACE_0x0100".to_string(),
                address: 0x0100,
                address_hex: "0x0100".to_string(),
                width: "u16",
                value: 0x06ff,
                value_hex: "0x06ff".to_string(),
            },
            TxStatusRegisterReport {
                name: "REG_TDECTRL".to_string(),
                address: REG_TDECTRL,
                address_hex: format_address(REG_TDECTRL),
                width: "u32",
                value: 0x0000_f710,
                value_hex: "0x0000f710".to_string(),
            },
        ];
        let post = vec![
            TxStatusRegisterReport {
                name: "TRACE_0x0100".to_string(),
                address: 0x0100,
                address_hex: "0x0100".to_string(),
                width: "u16",
                value: 0x04ff,
                value_hex: "0x04ff".to_string(),
            },
            TxStatusRegisterReport {
                name: "REG_TDECTRL".to_string(),
                address: REG_TDECTRL,
                address_hex: format_address(REG_TDECTRL),
                width: "u32",
                value: 0x0100_f710,
                value_hex: "0x0100f710".to_string(),
            },
        ];

        let comparison = tx_status_trace_comparison(&requests, &pre, &post).expect("comparison");

        assert_eq!(comparison.expected_register_count, 1);
        assert_eq!(comparison.pre_mismatch_count, 0);
        assert_eq!(comparison.post_mismatch_count, 1);
        assert_eq!(comparison.post_mismatches[0].expected_hex, "0x06ff");
        assert_eq!(comparison.post_mismatches[0].observed_hex, "0x04ff");
        assert_eq!(comparison.post_mismatches[0].xor_hex, "0x0200");
    }

    #[test]
    fn bridge_tx_bench_trace_apply_plan_filters_by_range_and_width() {
        let input = r#"[
  {
    "address": 256,
    "address_hex": "0x0100",
    "width": 2,
    "data_hex": "ff06",
    "value_le_hex": "0x06ff",
    "value_be_hex": "0xff06",
    "write_count": 1,
    "last_event_index": 1
  },
  {
    "address": 528,
    "address_hex": "0x0210",
    "width": 4,
    "data_hex": "01040000",
    "value_le_hex": "0x00000401",
    "value_be_hex": "0x01040000",
    "write_count": 2,
    "last_event_index": 2
  },
  {
    "address": 65104,
    "address_hex": "0xfe50",
    "width": 1,
    "data_hex": "01",
    "value_le_hex": "0x01",
    "value_be_hex": "0x01",
    "write_count": 1,
    "last_event_index": 3
  },
  {
    "address": 544,
    "address_hex": "0x0220",
    "width": 3,
    "data_hex": "000000",
    "value_le_hex": "0x000000",
    "value_be_hex": "0x000000",
    "write_count": 1,
    "last_event_index": 4
  }
]"#;

        let (report, writes) = bridge_tx_bench_trace_apply_plan(
            Path::new("/tmp/linux-final.json"),
            input,
            0x0200,
            0x02ff,
        )
        .expect("plan");

        assert_eq!(report.writes_loaded, 4);
        assert_eq!(report.writes_selected, 1);
        assert_eq!(report.skipped_out_of_range, 2);
        assert_eq!(report.skipped_unsupported_width, 1);
        assert_eq!(writes.len(), 1);
        assert_eq!(writes[0].address, 0x0210);
        assert_eq!(writes[0].width, TxStatusRegisterWidth::U32);
        assert_eq!(writes[0].value, 0x0000_0401);
    }

