    #[test]
    fn captured_tx_bringup_tail_covers_5ghz_twenty_and_forty_mhz() {
        let channel_36 = Channel::from_number(36).expect("channel 36");
        let channel_6 = Channel::from_number(6).expect("channel 6");

        assert!(should_apply_captured_tx_bringup_tail(
            channel_36,
            Bandwidth::Mhz20
        ));
        assert!(should_apply_captured_tx_bringup_tail(
            channel_36,
            Bandwidth::Mhz40
        ));
        assert!(!should_apply_captured_tx_bringup_tail(
            channel_36,
            Bandwidth::Mhz80
        ));
        assert!(!should_apply_captured_tx_bringup_tail(
            channel_6,
            Bandwidth::Mhz40
        ));
    }

    #[test]
    fn captured_tx_bringup_tail_selects_bandwidth_specific_runtime_values() {
        fn value_for(
            writes: &[CapturedTxBringupWrite],
            address: u16,
        ) -> std::result::Result<u32, &'static str> {
            writes
                .iter()
                .find(|(_, candidate, _)| *candidate == address)
                .map(|(_, _, value)| *value)
                .ok_or("missing register")
        }

        let tail20 = captured_tx_bringup_tail_8812a(Bandwidth::Mhz20).expect("20 MHz tail");
        let tail40 = captured_tx_bringup_tail_8812a(Bandwidth::Mhz40).expect("40 MHz tail");

        assert_eq!(
            value_for(tail20, REG_TX_SCALE_A_JAGUAR).expect("20 tx scale A"),
            0x2d40_0003
        );
        assert_eq!(
            value_for(tail40, REG_TX_SCALE_A_JAGUAR).expect("40 tx scale A"),
            0x35e0_0003
        );
        assert_eq!(
            value_for(tail40, REG_TX_BB_CTRL_A_JAGUAR).expect("40 tx bb A"),
            0x0423_8500
        );
        assert_eq!(
            value_for(tail40, REG_TX_AGC_B_MCS3_MCS0_JAGUAR).expect("40 txagc B mcs0-3"),
            0x2b2b_2b2b
        );
        assert!(captured_tx_bringup_tail_8812a(Bandwidth::Mhz80).is_err());
    }

    #[test]
    fn targeted_linux_parity_profile_selects_ch36_ht20_overrides() {
        fn value_for(
            writes: &[wfb_radio_runtime::Rtl8812auRegisterWriteSpec],
            address: u16,
        ) -> std::result::Result<u32, &'static str> {
            writes
                .iter()
                .find(|write| write.address == address)
                .map(|write| write.value)
                .ok_or("missing register")
        }

        let channel_36 = Channel::from_number(36).expect("channel 36");
        let writes = wfb_radio_runtime::rtl8812au_targeted_calibration_writes(
            RuntimeTxCalibrationProfile::LinuxParityCh36Ht20,
            channel_36,
            Bandwidth::Mhz20,
        )
        .expect("profile")
        .expect("writes");

        assert_eq!(writes.len(), 6);
        assert_eq!(
            value_for(writes, REG_TX_SCALE_A_JAGUAR).expect("tx scale A"),
            0x4000_0003
        );
        assert_eq!(
            value_for(writes, REG_RFE_PINMUX_A_JAGUAR).expect("rfe pinmux A"),
            0x5433_7770
        );
        assert_eq!(
            value_for(writes, REG_TX_BB_CTRL_A_JAGUAR).expect("tx bb A"),
            0x0180_7c09
        );
        assert!(wfb_radio_runtime::rtl8812au_targeted_calibration_writes(
            RuntimeTxCalibrationProfile::LinuxParityCh36Ht20,
            channel_36,
            Bandwidth::Mhz40,
        )
        .is_err());
        assert!(wfb_radio_runtime::rtl8812au_targeted_calibration_writes(
            RuntimeTxCalibrationProfile::Rtl8812aLck,
            channel_36,
            Bandwidth::Mhz40,
        )
        .expect("lck profile")
        .is_none());
        assert!(wfb_radio_runtime::rtl8812au_targeted_calibration_writes(
            RuntimeTxCalibrationProfile::Rtl8812aIqkProbe,
            channel_36,
            Bandwidth::Mhz40,
        )
        .expect("iqk probe profile")
        .is_none());
        assert!(wfb_radio_runtime::rtl8812au_targeted_calibration_writes(
            RuntimeTxCalibrationProfile::Rtl8812aRuntimeIqk,
            channel_36,
            Bandwidth::Mhz40,
        )
        .expect("runtime iqk profile")
        .is_none());
        assert_eq!(
            tx_pre_calibration_mode(
                false,
                channel_36,
                Bandwidth::Mhz20,
                TxCalibrationProfileArg::LinuxParityCh36Ht20
            ),
            RfQualityCalibrationMode::TargetedLinuxParity
        );
        assert_eq!(
            tx_pre_calibration_mode(
                false,
                channel_36,
                Bandwidth::Mhz20,
                TxCalibrationProfileArg::Rtl8812aLck
            ),
            RfQualityCalibrationMode::RuntimeApproximation
        );
        assert_eq!(
            tx_pre_calibration_mode(
                false,
                channel_36,
                Bandwidth::Mhz20,
                TxCalibrationProfileArg::Rtl8812aRuntimeIqk
            ),
            RfQualityCalibrationMode::RuntimeApproximation
        );
        assert_eq!(
            tx_pre_calibration_mode(
                true,
                channel_36,
                Bandwidth::Mhz20,
                TxCalibrationProfileArg::Rtl8812aIqkProbe
            ),
            RfQualityCalibrationMode::StopGapCaptured
        );
        assert_eq!(
            tx_pre_calibration_mode(
                false,
                channel_36,
                Bandwidth::Mhz20,
                TxCalibrationProfileArg::Rtl8812aIqkProbe
            ),
            RfQualityCalibrationMode::Unknown
        );
    }

    #[test]
    fn calibration_profiles_parse_and_require_live_write_authorization() {
        let cli = Cli::try_parse_from([
            "wfb-radio-diag",
            "bridge-tx-bench",
            "--channel",
            "36",
            "--count",
            "1",
            "--tx-calibration-profile",
            "rtl8812a-runtime-iqk",
            "--i-understand-this-transmits",
            "--i-understand-this-writes-registers",
        ])
        .expect("parse cli");

        match cli.command {
            Command::BridgeTxBench(args) => {
                assert_eq!(
                    args.tx_calibration.tx_calibration_profile,
                    TxCalibrationProfileArg::Rtl8812aRuntimeIqk
                );
                assert!(args.i_understand_this_writes_registers);
                assert!(tx_calibration_profile_requested(&args.tx_calibration));
                assert!(tx_calibration_profile_requires_write_authorization(
                    args.tx_calibration.tx_calibration_profile
                ));
            }
            other => panic!("unexpected command: {other:?}"),
        }

        assert!(!tx_calibration_profile_requires_write_authorization(
            TxCalibrationProfileArg::CurrentDefault
        ));
        assert!(tx_calibration_profile_requires_write_authorization(
            TxCalibrationProfileArg::LinuxParityCh36Ht20
        ));
        assert!(tx_calibration_profile_requires_write_authorization(
            TxCalibrationProfileArg::Rtl8812aLck
        ));
        assert!(!tx_calibration_profile_requires_write_authorization(
            TxCalibrationProfileArg::Rtl8812aIqkProbe
        ));
        assert!(tx_calibration_profile_requires_write_authorization(
            TxCalibrationProfileArg::Rtl8812aRuntimeIqk
        ));

        let mut args = bridge_tx_bench_args(true);
        args.tx_calibration.tx_calibration_profile = TxCalibrationProfileArg::Rtl8812aRuntimeIqk;
        let report = bridge_tx_bench_report(args);
        assert_eq!(report.result, DiagnosticResult::Fail);
        assert_eq!(
            report.error.as_ref().expect("error").code,
            "missing_write_authorization"
        );
        assert!(report.adapter.is_none());
        assert_eq!(report.counters.usb_control_reads, 0);
        assert_eq!(report.counters.usb_control_writes, 0);
    }

    #[test]
    fn diagnostic_calibration_profiles_map_to_runtime_policy() {
        let cases = [
            (
                TxCalibrationProfileArg::CurrentDefault,
                RuntimeTxCalibrationProfile::CurrentDefault,
            ),
            (
                TxCalibrationProfileArg::LinuxParityCh36Ht20,
                RuntimeTxCalibrationProfile::LinuxParityCh36Ht20,
            ),
            (
                TxCalibrationProfileArg::Rtl8812aLck,
                RuntimeTxCalibrationProfile::Rtl8812aLck,
            ),
            (
                TxCalibrationProfileArg::Rtl8812aIqkProbe,
                RuntimeTxCalibrationProfile::Rtl8812aIqkProbe,
            ),
            (
                TxCalibrationProfileArg::Rtl8812aRuntimeIqk,
                RuntimeTxCalibrationProfile::Rtl8812aRuntimeIqk,
            ),
        ];

        for (diag, runtime) in cases {
            assert_eq!(RuntimeTxCalibrationProfile::from(diag), runtime);
        }
    }

