    #[test]
    fn runtime_iqk_tx_fill_iqc_plan_matches_upstream_masks() {
        let plan = rtl8812a_iqk_tx_fill_iqc_plan(TxPowerPathArg::A, 0x2aa, 0x155, false)
            .expect("path A TX IQC plan");

        assert_eq!(plan.len(), 7);
        assert_eq!(plan[0].address, REG_AGC_TABLE_JAGUAR);
        assert_eq!(plan[0].mask, RTL8812A_IQK_PAGE_C1_SELECT_BIT);
        assert_eq!(plan[0].data, 1);
        assert_eq!(plan[1].address, REG_TX_BB_CTRL_A_JAGUAR);
        assert_eq!(plan[1].mask, 0x0000_0080);
        assert_eq!(plan[2].address, REG_IQK_TX_CTRL_A_CC4);
        assert_eq!(plan[2].mask, 0x0004_0000);
        assert_eq!(plan[3].address, REG_IQK_TX_CTRL_A_CC4);
        assert_eq!(plan[3].mask, 0x2000_0000);
        assert_eq!(plan[4].address, REG_IQK_TX_CTRL_A_CC8);
        assert_eq!(plan[4].mask, 0x2000_0000);
        assert_eq!(plan[5].address, REG_IQK_TX_Y_A_CCC);
        assert_eq!(plan[5].data, 0x155);
        assert_eq!(plan[6].address, REG_IQK_TX_X_A_CD4);
        assert_eq!(plan[6].data, 0x2aa);

        let path_b_dpk_done = rtl8812a_iqk_tx_fill_iqc_plan(TxPowerPathArg::B, 0x801, 0x802, true)
            .expect("path B TX IQC plan");
        assert_eq!(path_b_dpk_done.len(), 6);
        assert!(!path_b_dpk_done
            .iter()
            .any(|write| write.address == REG_IQK_TX_CTRL_B_EC4 && write.mask == 0x2000_0000));
        assert_eq!(
            path_b_dpk_done
                .iter()
                .find(|write| write.address == REG_IQK_TX_Y_B_ECC)
                .expect("path B TX_Y")
                .data,
            0x002
        );
        assert!(rtl8812a_iqk_tx_fill_iqc_plan(TxPowerPathArg::Both, 0x200, 0, false).is_err());
    }

    #[test]
    fn runtime_iqk_rx_fill_iqc_plan_matches_upstream_fallback() {
        let normal = rtl8812a_iqk_rx_fill_iqc_plan(TxPowerPathArg::B, 0x20, 0x10)
            .expect("path B RX IQC plan");
        assert_eq!(normal.len(), 3);
        assert_eq!(normal[0].address, REG_AGC_TABLE_JAGUAR);
        assert_eq!(normal[0].mask, RTL8812A_IQK_PAGE_C1_SELECT_BIT);
        assert_eq!(normal[0].data, 0);
        assert_eq!(normal[1].address, REG_IQK_RX_IQC_B_JAGUAR);
        assert_eq!(normal[1].mask, 0x0000_03ff);
        assert_eq!(normal[1].data, 0x10);
        assert_eq!(normal[2].mask, 0x03ff_0000);
        assert_eq!(normal[2].data, 0x08);

        let fallback = rtl8812a_iqk_rx_fill_iqc_plan(TxPowerPathArg::A, 0x224, 0)
            .expect("path A RX fallback plan");
        assert_eq!(fallback[1].address, REG_IQK_RX_IQC_A_JAGUAR);
        assert_eq!(fallback[1].data, 0x100);
        assert_eq!(fallback[2].data, 0);
        assert!(fallback[1].reason.contains("fallback"));
        assert!(rtl8812a_iqk_rx_fill_iqc_plan(TxPowerPathArg::Both, 0x200, 0).is_err());
    }

    #[test]
    fn runtime_iqk_report_shape_serializes_failure_labels() {
        let report = TxRuntimeIqkStageReport {
            stage: "tx",
            status: "failed",
            ready: Some(false),
            failed: Some(true),
            retry_count: 10,
            average_count: 0,
            delay_count_max: Some(21),
            attempts: vec![TxRuntimeIqkAttemptReport {
                attempt_index: 1,
                ready: Some(false),
                failed: Some(true),
                delay_count: Some(21),
                status_raw: Some(RTL8812A_IQK_TX_FAIL_MASK),
                status_raw_hex: Some(format_value(RTL8812A_IQK_TX_FAIL_MASK, 8)),
                candidate: None,
                label: Some("tx_iqk_not_ready"),
            }],
            candidates: Vec::new(),
            selected_iqc: Some(TxRuntimeIqkIqcValue {
                x: 0x200,
                x_hex: format_value(0x200_u32, 3),
                y: 0,
                y_hex: format_value(0_u32, 3),
            }),
            fallback_used: true,
            failure_label: Some("tx_iqk_not_ready"),
            fill_plan: rtl8812a_iqk_tx_fill_iqc_plan(TxPowerPathArg::A, 0x200, 0, false)
                .expect("fallback fill plan"),
        };
        let value = serde_json::to_value(&report).expect("serialize report");
        assert_eq!(value["stage"], "tx");
        assert_eq!(value["failure_label"], "tx_iqk_not_ready");
        assert_eq!(value["fallback_used"], true);
        assert_eq!(value["attempts"][0]["status_raw_hex"], "0x00001000");
        assert_eq!(value["fill_plan"].as_array().expect("fill plan").len(), 7);
    }

    #[test]
    fn runtime_iqk_candidate_selection_matches_upstream_tolerance() {
        let selected = rtl8812a_iqk_select_candidate(&[
            runtime_iqk_iqc_value(0x120, 0x080),
            runtime_iqk_iqc_value(0x122, 0x083),
            runtime_iqk_iqc_value(0x180, 0x100),
        ])
        .expect("selected candidate");
        assert_eq!(selected.x, 0x121);
        assert_eq!(selected.y, 0x081);

        assert!(rtl8812a_iqk_select_candidate(&[
            runtime_iqk_iqc_value(0x120, 0x080),
            runtime_iqk_iqc_value(0x124, 0x083),
        ])
        .is_none());

        let signed_wrap_selected = rtl8812a_iqk_select_candidate(&[
            runtime_iqk_iqc_value(0x1f7, 0x7ff),
            runtime_iqk_iqc_value(0x1f5, 0x7ee),
            runtime_iqk_iqc_value(0x1fa, 0x001),
        ])
        .expect("selected signed-wrap candidate");
        assert_eq!(signed_wrap_selected.x, 0x1f8);
        assert_eq!(signed_wrap_selected.y, 0x000);
    }

    #[test]
    fn runtime_iqk_setup_plan_ports_mac_afe_rf_prerequisites() {
        fn register_value(
            plan: &[TxRuntimeIqkSetupWritePlan],
            address: u16,
        ) -> Option<(u32, &'static str)> {
            plan.iter().find_map(|write| match write {
                TxRuntimeIqkSetupWritePlan::Register {
                    address: candidate,
                    value,
                    width,
                    ..
                } if *candidate == address => Some((*value, *width)),
                _ => None,
            })
        }

        fn masked_data(
            plan: &[TxRuntimeIqkSetupWritePlan],
            address: u16,
            mask: u32,
        ) -> Option<u32> {
            plan.iter().find_map(|write| match write {
                TxRuntimeIqkSetupWritePlan::MaskedBb { write, .. }
                    if write.address == address && write.mask == mask =>
                {
                    Some(write.data)
                }
                _ => None,
            })
        }

        fn rf_value(
            plan: &[TxRuntimeIqkSetupWritePlan],
            path: Rtl8812auRfPath,
            rf_offset: u32,
        ) -> Option<u32> {
            plan.iter().find_map(|write| match write {
                TxRuntimeIqkSetupWritePlan::Rf {
                    path: candidate_path,
                    rf_offset: candidate_offset,
                    value,
                    ..
                } if *candidate_path == path && *candidate_offset == rf_offset => Some(*value),
                _ => None,
            })
        }

        let plan = rtl8812a_runtime_iqk_setup_plan(Band::Ghz5, DEFAULT_RFE_TYPE, true, false);
        assert_eq!(register_value(&plan, REG_TXPAUSE), Some((0x3f, "u8")));
        assert_eq!(
            masked_data(&plan, REG_AGC_TABLE_JAGUAR, RTL8812A_IQK_PAGE_C1_SELECT_BIT),
            Some(0)
        );
        assert_eq!(masked_data(&plan, REG_BCN_CTRL, 0x0000_0808), Some(0));
        assert_eq!(
            register_value(&plan, REG_IQK_AFE_A_C60),
            Some((0x7777_7777, "u32"))
        );
        assert_eq!(
            masked_data(&plan, REG_RF_PI_MODE_A_JAGUAR, 0x0000_000f),
            Some(0x04)
        );
        assert_eq!(
            rf_value(&plan, Rtl8812auRfPath::A, RF_IQK_MODE_JAGUAR),
            Some(0x80002)
        );
        assert_eq!(
            rf_value(&plan, Rtl8812auRfPath::B, RF_IQK_TX_0X32_JAGUAR),
            Some(0xfe83f)
        );
        assert_eq!(
            register_value(&plan, REG_IQK_RFE_SETTING_A_C88),
            Some((0x8214_03f7, "u32"))
        );
        assert_eq!(
            register_value(&plan, REG_IQK_RFE_SETTING_A_C8C),
            Some((0x6816_3e96, "u32"))
        );
        assert_eq!(
            register_value(&plan, REG_IQK_TX_TONE_A_C80),
            Some((0x1800_8c10, "u32"))
        );
        assert_eq!(
            register_value(&plan, REG_IQK_RX_TONE_B_E84),
            Some((0x3800_8c10, "u32"))
        );

        let path_a_rf_writes = plan
            .iter()
            .filter(|write| {
                matches!(
                    write,
                    TxRuntimeIqkSetupWritePlan::Rf {
                        path: Rtl8812auRfPath::A,
                        ..
                    }
                )
            })
            .count();
        let path_b_rf_writes = plan
            .iter()
            .filter(|write| {
                matches!(
                    write,
                    TxRuntimeIqkSetupWritePlan::Rf {
                        path: Rtl8812auRfPath::B,
                        ..
                    }
                )
            })
            .count();
        assert_eq!(path_a_rf_writes, 6);
        assert_eq!(path_b_rf_writes, 6);
    }

    #[test]
    fn rtl8812a_iqk_probe_inventory_matches_upstream_backup_sets() {
        assert_eq!(RTL8812A_IQK_MACBB_BACKUP_REGISTERS.len(), 9);
        assert_eq!(RTL8812A_IQK_AFE_BACKUP_REGISTERS.len(), 12);
        assert_eq!(RTL8812A_IQK_RF_BACKUP_OFFSETS, &[0x65, 0x8f, 0x00]);
        assert_eq!(RTL8812A_IQK_PAGE_C1_SELECT_BIT, 0x8000_0000);
        assert_eq!(
            RTL8812A_IQK_MACBB_BACKUP_REGISTERS
                .iter()
                .map(|(_, address)| *address)
                .collect::<Vec<_>>(),
            vec![
                0x0520,
                REG_BCN_CTRL,
                REG_OFDMCCKEN_JAGUAR,
                REG_CCK_RX_JAGUAR,
                0x090c,
                REG_RF_PI_MODE_A_JAGUAR,
                REG_RF_PI_MODE_B_JAGUAR,
                REG_CCA_ON_SEC_JAGUAR,
                REG_AGC_TABLE_JAGUAR,
            ]
        );
        assert!(RF_CALIBRATION_IQK_REGISTERS
            .iter()
            .any(|(_, address)| *address == REG_TX_IQK_PI_B_JAGUAR));
        assert!(RF_CALIBRATION_IQK_REGISTERS
            .iter()
            .any(|(_, address)| *address == REG_IQK_RX_IQC_A_JAGUAR));
        assert!(RF_CALIBRATION_IQK_REGISTERS
            .iter()
            .any(|(_, address)| *address == REG_IQK_RX_IQC_B_JAGUAR));
        assert_eq!(
            RTL8812A_IQK_PAGE_C1_LATCH_REGISTERS,
            &[
                ("R_0xcb8_page_c1", REG_RFE_TIMING_A_JAGUAR),
                ("R_0xeb8_page_c1", REG_RFE_TIMING_B_JAGUAR),
            ]
        );
    }

    #[test]
    fn rf_quality_report_records_short_run_datagram_evidence() {
        let stamp = started_at_unix_ms();
        let mac_path = std::env::temp_dir().join(format!(
            "wfb-radio-diag-short-run-mac-{}-{stamp}.json",
            std::process::id()
        ));
        let evidence_dir = std::env::temp_dir().join(format!(
            "wfb-radio-diag-short-run-evidence-{}-{stamp}",
            std::process::id()
        ));
        fs::create_dir_all(&evidence_dir).expect("create evidence dir");
        let evidence_path = evidence_dir.join("datagram-evidence.json");
        fs::write(
            &mac_path,
            r#"{
  "command": "bridge-tx-listen",
  "result": "fail",
  "datagrams_received": 149,
  "submit_counters": {"submitted": 149},
  "bridge_counters": {"injected": 149, "dropped": 0, "malformed": 0}
}"#,
        )
        .expect("write mac report");
        fs::write(
            &evidence_path,
            r#"{
  "receiver_status": "ok",
  "receiver_session_observed": true,
  "receiver_unable_decrypt_count": 0,
  "channel_state": {
    "verify_status": "verified",
    "observed_frequency_mhz": 5180,
    "observed_width_mhz": 20
  },
  "receiver_health": {
    "counter": {"total_datagrams": 100},
    "rx_antenna_report_count": 1,
    "rx_antenna_reports": [
      {
        "freq_mhz": 5180,
        "mcs_index": 1,
        "bandwidth_mhz": 20,
        "antenna_id": 0,
        "count_all": 100,
        "rssi_avg_dbm": -42,
        "snr_avg_db": 28
      }
    ],
    "rx_antenna_summary": {
      "report_count": 1,
      "rssi_avg_dbm_min": -42,
      "rssi_avg_dbm_max": -42,
      "snr_avg_db_min": 28,
      "snr_avg_db_max": 28,
      "latest_by_antenna": [
        {
          "freq_mhz": 5180,
          "mcs_index": 1,
          "bandwidth_mhz": 20,
          "antenna_id": 0,
          "count_all": 100,
          "rssi_avg_dbm": -42,
          "snr_avg_db": 28
        }
      ]
    },
    "session_observed": true,
    "status": "ok",
    "unable_decrypt_count": 0
  }
}"#,
        )
        .expect("write receiver evidence");
        let mut args = rf_quality_report_args();
        args.mac_report = Some(mac_path.clone());
        args.receiver_artifacts.push(evidence_path.clone());
        args.fec_k = 8;
        args.fec_n = 12;
        args.expected_payloads = Some(100);
        args.recovered_payloads = Some(100);

        let report = rf_quality_report(args);
        fs::remove_file(mac_path).ok();
        fs::remove_file(evidence_path).ok();
        fs::remove_dir(evidence_dir).ok();

        assert_eq!(report.macos.wfb_outcome.expected_datagrams, Some(150));
        assert_eq!(report.macos.wfb_outcome.observed_datagrams, Some(149));
        assert_eq!(report.macos.wfb_outcome.datagram_shortfall, Some(1));
        assert_eq!(
            report.macos.wfb_outcome.receiver_status.as_deref(),
            Some("ok")
        );
        assert_eq!(
            report.macos.wfb_outcome.receiver_session_observed,
            Some(true)
        );
        assert_eq!(
            report.macos.wfb_outcome.receiver_unable_decrypt_count,
            Some(0)
        );
        assert_eq!(report.macos.wfb_outcome.receiver_total_datagrams, Some(100));
        assert_eq!(
            report
                .macos
                .wfb_outcome
                .receiver_telemetry
                .as_ref()
                .and_then(|value| rf_quality_json_u64(value, &["rx_antenna_report_count"])),
            Some(1)
        );
        assert_eq!(
            report
                .macos
                .wfb_outcome
                .receiver_telemetry
                .as_ref()
                .and_then(|value| {
                    rf_quality_json_u64(
                        value,
                        &["rx_antenna_summary", "latest_by_antenna", "0", "mcs_index"],
                    )
                }),
            Some(1)
        );
        let receiver_signal = report
            .macos
            .wfb_outcome
            .receiver_signal
            .as_ref()
            .expect("receiver signal report");
        assert_eq!(
            receiver_signal.status,
            RfQualityReceiverSignalStatus::Complete
        );
        assert_eq!(receiver_signal.issue_count, 0);
        assert!(receiver_signal.issues.is_empty());
        assert_eq!(receiver_signal.report_count, Some(1));
        assert_eq!(receiver_signal.antenna_count, 1);
        assert_eq!(receiver_signal.tuple_count, 1);
        assert_eq!(receiver_signal.tuple_consistent, Some(true));
        assert_eq!(receiver_signal.tuples[0].freq_mhz, Some(5180));
        assert_eq!(receiver_signal.tuples[0].mcs_index, Some(1));
        assert_eq!(receiver_signal.tuples[0].bandwidth_mhz, Some(20));
        assert_eq!(receiver_signal.rssi_avg_dbm_min, Some(-42));
        assert_eq!(receiver_signal.rssi_avg_dbm_max, Some(-42));
        assert_eq!(receiver_signal.rssi_avg_spread_db, Some(0));
        assert_eq!(receiver_signal.snr_avg_db_min, Some(28));
        assert_eq!(receiver_signal.snr_avg_db_max, Some(28));
        assert_eq!(
            receiver_signal.snr_status,
            RfQualityReceiverSignalSnrStatus::Available
        );
        assert_eq!(
            receiver_signal.snr_confidence,
            RfQualityReceiverSignalSnrConfidence::ReceiverReportedNonzero
        );
        assert!(receiver_signal.snr_usable);
        assert_eq!(receiver_signal.snr_avg_sample_count, 1);
        assert_eq!(receiver_signal.snr_avg_nonzero_count, 1);
        assert_eq!(
            report
                .macos
                .wfb_outcome
                .channel_state
                .as_ref()
                .and_then(|value| rf_quality_json_string(value, &["verify_status"]))
                .as_deref(),
            Some("verified")
        );
        assert_eq!(
            report
                .comparison
                .outcome
                .acceptance_margin
                .receiver_metadata_status,
            "available"
        );
        assert!(
            report
                .macos
                .wfb_outcome
                .short_run_datagram_tolerance_applied
        );
    }

    #[test]
    fn rf_quality_receiver_signal_marks_zero_snr_as_usable() {
        let receiver_evidence = serde_json::json!({
            "receiver_health": {
                "rx_antenna_report_count": 2,
                "rx_antenna_reports": [
                    {
                        "freq_mhz": 5180,
                        "mcs_index": 1,
                        "bandwidth_mhz": 20,
                        "antenna_id": 0,
                        "rssi_avg_dbm": -24,
                        "snr_avg_db": 0
                    },
                    {
                        "freq_mhz": 5180,
                        "mcs_index": 1,
                        "bandwidth_mhz": 20,
                        "antenna_id": 1,
                        "rssi_avg_dbm": -16,
                        "snr_avg_db": 0
                    }
                ],
                "rx_antenna_summary": {
                    "report_count": 2,
                    "rssi_avg_dbm_min": -24,
                    "rssi_avg_dbm_max": -16,
                    "snr_avg_db_min": 0,
                    "snr_avg_db_max": 0,
                    "latest_by_antenna": [
                        {
                            "freq_mhz": 5180,
                            "mcs_index": 1,
                            "bandwidth_mhz": 20,
                            "antenna_id": 0,
                            "rssi_avg_dbm": -24,
                            "snr_avg_db": 0
                        },
                        {
                            "freq_mhz": 5180,
                            "mcs_index": 1,
                            "bandwidth_mhz": 20,
                            "antenna_id": 1,
                            "rssi_avg_dbm": -16,
                            "snr_avg_db": 0
                        }
                    ]
                }
            }
        });
        let receiver_signal =
            rf_quality_receiver_signal(Some(&receiver_evidence)).expect("receiver signal");

        assert_eq!(
            receiver_signal.status,
            RfQualityReceiverSignalStatus::Usable
        );
        assert_eq!(
            receiver_signal.snr_status,
            RfQualityReceiverSignalSnrStatus::AllZero
        );
        assert_eq!(
            receiver_signal.snr_confidence,
            RfQualityReceiverSignalSnrConfidence::ReceiverReportedZeroOnly
        );
        assert!(!receiver_signal.snr_usable);
        assert_eq!(receiver_signal.issue_count, 1);
        assert_eq!(receiver_signal.issues, vec!["snr_all_zero"]);
        assert_eq!(receiver_signal.antenna_count, 2);
        assert_eq!(receiver_signal.tuple_consistent, Some(true));
        assert_eq!(receiver_signal.rssi_avg_spread_db, Some(8));
    }

    #[test]
    fn rf_serial_read_targets_match_rtl8812a_jaguar_registers() {
        let target_a = rf_serial_read_target(TxPowerPathArg::A).expect("path A");
        assert_eq!(target_a.3, REG_RF_PI_MODE_A_JAGUAR);
        assert_eq!(target_a.5, REG_RF_PI_READ_A_JAGUAR);
        assert_eq!(target_a.7, REG_RF_SI_READ_A_JAGUAR);

        let target_b = rf_serial_read_target(TxPowerPathArg::B).expect("path B");
        assert_eq!(target_b.3, REG_RF_PI_MODE_B_JAGUAR);
        assert_eq!(target_b.5, REG_RF_PI_READ_B_JAGUAR);
        assert_eq!(target_b.7, REG_RF_SI_READ_B_JAGUAR);

        assert!(rf_serial_read_target(TxPowerPathArg::Both).is_none());
        assert_eq!(
            encode_rf_serial_write(RF_LCK_JAGUAR, RF_REGISTER_OFFSET_MASK),
            0x0b4f_ffff
        );
    }

